module.exports = /*#__PURE__*/JSON.parse('{"translations":{"krv":{"label":"개역한글","note":"성경전서 개역한글판 (대한성서공회, 1961). 라이선스: 대한성서공회 공식 저작권 FAQ에 따라 저작재산권 보호기간 50년 경과로 저작권료 지급 없이 사용 가능 공공저작물 (개역개정판은 해당 없음). 데이터 출처: scrollmapper/bible_databases (GitHub, 2025-languages branch, sources/ko/KorRV/KorRV.json, License: Public Domain)."},"kids":{"label":"어린이","note":"어린이 번역 준비 중입니다."}},"chapters":[{"chapter":1,"title":"예레미야의 부르심","verses":{"krv":[{"n":1,"t":"베냐민 땅 아나돗의 제사장 중 힐기야의 아들 예레미야의 말이라"},{"n":2,"t":"아몬의 아들 유다 왕 요시야의 다스린지 십삼 년에 여호와의 말씀이 예레미야에게 임하였고"},{"n":3,"t":"요시야의 아들 유다 왕 여호야김 시대부터 요시야의 아들 유다 왕 시드기야의 제십일년 말까지 임하니라 이 해 오 월에 예루살렘이 사로잡히니라"},{"n":4,"t":"여호와의 말씀이 내게 임하니라 이르시되"},{"n":5,"t":"내가 너를 복중에 짓기 전에 너를 알았고 네가 태에서 나오기 전에 너를 구별하였고 너를 열방의 선지자로 세웠노라 하시기로"},{"n":6,"t":"내가 가로되 슬프도소이다 주 여호와여 보소서 나는 아이라 말할 줄을 알지 못하나이다"},{"n":7,"t":"여호와께서 내게 이르시되 너는 아이라 하지 말고 내가 너를 누구에게 보내든지 너는 가며 내가 네게 무엇을 명하든지 너는 말할지니라"},{"n":8,"t":"너는 그들을 인하여 두려워 말라 내가 너와 함께 하여 너를 구원하리라 나 여호와의 말이니라 하시고"},{"n":9,"t":"여호와께서 그 손을 내밀어 내 입에 대시며 내게 이르시되 보라 내가 내 말을 네 입에 두었노라"},{"n":10,"t":"보라 내가 오늘날 너를 열방 만국 위에 세우고 너를 뽑으며 파괴하며 파멸하며 넘어뜨리며 건설하며 심게 하였느니라"},{"n":11,"t":"여호와의 말씀이 또 내게 임하니라 이르시되 예레미야야 네가 무엇을 보느냐 대답하되 내가 살구나무 가지를 보나이다"},{"n":12,"t":"여호와께서 내게 이르시되 네가 잘 보았도다 이는 내가 내 말을 지켜 그대로 이루려 함이니라"},{"n":13,"t":"여호와의 말씀이 다시 내게 임하니라 이르시되 네가 무엇을 보느냐 대답하되 끓는 가마를 보나이다 그 면이 북에서부터 기울어졌나이다"},{"n":14,"t":"여호와께서 내게 이르시되 재앙이 북방에서 일어나 이 땅의 모든 거민에게 임하리라"},{"n":15,"t":"나 여호와가 말하노라 내가 북방 모든 나라의 족속을 부를 것인즉 그들이 와서 예루살렘 성문 어귀에 각기 자리를 정하고 그 사면 성벽과 유다 모든 성읍을 치리라"},{"n":16,"t":"무리가 나를 버리고 다른 신들에게 분향하며 자기 손으로 만든 것에 절하였은즉 내가 나의 심판을 베풀어 그들의 모든 죄악을 징계하리라"},{"n":17,"t":"그러므로 너는 네 허리를 동이고 일어나 내가 네게 명한 바를 다 그들에게 고하라 그들을 인하여 두려워 말라 두렵건대 내가 너로 그들 앞에서 두려움을 당하게 할까 하노라"},{"n":18,"t":"보라 내가 오늘날 너로 그 온 땅과 유다 왕들과 그 족장들과 그 제사장들과 그 땅 백성 앞에 견고한 성읍, 쇠기둥, 놋성벽이 되게하였은즉"},{"n":19,"t":"그들이 너를 치나 이기지 못하리니 이는 내가 너와 함께 하여 너를 구원할 것임이니라 여호와의 말이니라"}],"kids":[{"n":1,"t":"베냐민 땅 아나돗에서 살던 제사장 가운데 한 사람인 힐기야의 아들 예레미야가 한 말이에요."},{"n":2,"t":"아몬의 아들이며 유다 왕인 요시야가 다스린 지 13년이 되던 해에, 하나님의 말씀이 예레미야에게 들려왔어요."},{"n":3,"t":"그리고 요시야의 아들 유다 왕 여호야김 때부터 또 다른 요시야의 아들 유다 왕 시드기야의 11년이 끝날 때까지 계속 들려왔어요. 그 해 5월에 예루살렘 사람들이 사로잡혀 가게 되었지요."},{"n":4,"t":"하나님의 말씀이 나(예레미야)에게 들려왔어요."},{"n":5,"t":"\\"내가 너를 엄마 뱃속에 만들기도 전부터 너를 알았어. 네가 태어나기도 전에 너를 특별히 골라서, 여러 나라에 보낼 선지자(하나님 말씀을 전하는 사람)로 세웠단다.\\""},{"n":6,"t":"내가 말했어요. \\"아, 주 하나님! 저는 아직 어려서(아이여서) 어떻게 말해야 할지 잘 몰라요.\\""},{"n":7,"t":"하나님께서 내게 말씀하셨어요. \\"어리다고 하지 마라. 내가 너를 누구에게 보내든지 너는 가야 하고, 내가 무엇을 말하라고 시키든지 너는 그대로 말해야 해.\\""},{"n":8,"t":"\\"그 사람들을 무서워하지 마. 내가 너와 함께 있어서 너를 지켜 줄 거야. 이것은 나 여호와(하나님)의 말이란다.\\""},{"n":9,"t":"그러면서 하나님께서 손을 내밀어 내 입을 만지시며 말씀하셨어요. \\"보아라, 내가 내 말을 네 입 안에 넣어 주었어.\\""},{"n":10,"t":"\\"보아라, 오늘 내가 너를 모든 나라와 민족 위에 세웠어. 네가 어떤 나라는 뽑아 버리고 무너뜨리며, 어떤 나라는 망하게 하고 넘어뜨리지만, 어떤 나라는 다시 세우고 심게 될 거야.\\""},{"n":11,"t":"하나님의 말씀이 또 내게 들려왔어요. \\"예레미야야, 무엇이 보이니?\\" 내가 대답했지요. \\"살구나무 가지가 보입니다.\\""},{"n":12,"t":"하나님께서 말씀하셨어요. \\"잘 보았다. 이는 내가 한 말을 잘 지켜서 꼭 그대로 이루려고 하기 때문이야.\\" (살구나무는 깨어 있다는 뜻이 있어요.)"},{"n":13,"t":"하나님의 말씀이 또 들려왔어요. \\"무엇이 보이니?\\" 내가 대답했어요. \\"끓는 가마(큰 솥)가 보이는데, 솥 입구가 북쪽에서 이쪽으로 기울어져 있어요.\\""},{"n":14,"t":"하나님께서 말씀하셨어요. \\"북쪽에서 큰 재앙(나쁜 일)이 일어나서, 이 땅에 사는 모든 사람에게 닥칠 거야.\\""},{"n":15,"t":"\\"나 여호와가 말한다. 내가 북쪽 모든 나라의 백성을 불러들일 거야. 그러면 그들이 와서 예루살렘 성문 입구마다 자리를 잡고, 사방 성벽과 유다의 모든 성읍을 공격할 거란다.\\""},{"n":16,"t":"\\"이는 사람들이 나를 버리고 다른 신들(우상)에게 향(좋은 냄새가 나는 것)을 피우고, 자기 손으로 만든 우상에 절했기 때문이야. 그래서 내가 그들에게 벌을 내려서 그들이 저지른 모든 죄를 심판할 거야.\\""},{"n":17,"t":"\\"그러니 너는 허리띠를 바짝 동여매고(준비하고) 일어나서, 내가 시킨 모든 것을 그들에게 다 말해라. 그 사람들을 무서워하지 마. 만약 네가 무서워한다면 내가 너를 그들 앞에서 부끄럽게 만들지도 몰라.\\""},{"n":18,"t":"\\"보아라, 내가 오늘 너를 단단한 성과 같고, 쇠기둥과 같고, 놋(쇠보다 단단한 금속)으로 된 성벽처럼 만들었어. 그래서 온 땅 사람들과 유다 왕들과 높은 사람들과 제사장들과 백성들을 다 이길 수 있게 했단다.\\""},{"n":19,"t":"\\"그들이 너를 공격하겠지만 너를 이기지 못해. 이는 내가 너와 함께 있어 너를 지켜 주기 때문이야. 이것은 나 여호와의 말이란다.\\""}]}},{"chapter":2,"title":"이스라엘의 배신","verses":{"krv":[{"n":1,"t":"여호와의 말씀이 내게 임하니라 이르시되"},{"n":2,"t":"가서 예루살렘 거민의 귀에 외쳐 말할지니라 여호와께서 이같이 말씀하시기를 네 소년 때의 우의와 네 결혼 때의 사랑 곧 씨 뿌리지 못하는 땅, 광야에서 어떻게 나를 좇았음을 내가 너를 위하여 기억하노라"},{"n":3,"t":"그 때에 이스라엘은 나 여호와의 성물 곧 나의 소산 중 처음 열매가 되었나니 그를 삼키는 자면 다 벌을 받아 재앙을 만났으리라 여호와의 말이니라"},{"n":4,"t":"야곱 집과 이스라엘 집 모든 가족아 나 여호와의 말을 들으라"},{"n":5,"t":"나 여호와가 이같이 말하노라 너희 열조가 내게서 무슨 불의함을 보았관대 나를 멀리하고 허탄한 것을 따라 헛되이 행하였느냐"},{"n":6,"t":"그들이 우리를 애굽 땅에서 인도하여 내시고 광야 곧 사막과 구덩이 땅, 건조하고 사망의 음침한 땅, 사람이 다니지 아니하고 거주하지 아니하는 땅을 통과케 하시던 여호와께서 어디 계시냐 말하지 아니하였도다"},{"n":7,"t":"내가 너희를 인도하여 기름진 땅에 들여 그 과실과 그 아름다운 것을 먹게 하였거늘 너희가 이리로 들어와서는 내 땅을 더럽히고 내 기업을 가증히 만들었으며"},{"n":8,"t":"제사장들은 여호와께서 어디 계시냐 하지 아니하며 법 잡은 자들은 나를 알지 못하며 관리들도 나를 항거하며 선지자들은 바알의 이름으로 예언하고 무익한 것을 좇았느니라"},{"n":9,"t":"그러므로 내가 여전히 너희와 다투고 너희 후손과도 다투리라 여호와의 말이니라"},{"n":10,"t":"너희는 깃딤 섬들에 건너가 보며 게달에도 사람을 보내어 이같은 일의 유무를 자세히 살펴보라"},{"n":11,"t":"어느 나라가 그 신을 신 아닌 것과 바꾼 일이 있느냐 그러나 나의 백성은 그 영광을 무익한 것과 바꾸었도다"},{"n":12,"t":"너 하늘아 이 일을 인하여 놀랄지어다 심히 떨지어다 두려워할지어다 여호와의 말이니라"},{"n":13,"t":"내 백성이 두 가지 악을 행하였나니 곧 생수의 근원되는 나를 버린 것과 스스로 웅덩이를 판 것인데 그것은 물을 저축지 못할 터진 웅덩이니라"},{"n":14,"t":"이스라엘이 종이냐 씨종이냐 어찌하여 포로가 되었느냐"},{"n":15,"t":"어린 사자들이 너를 향하여 부르짖으며 수리를 날려 네 땅을 황무케 하였으며 네 성읍들은 불타서 거민이 없게 되었으며"},{"n":16,"t":"놉과 다바네스의 자손도 네 정수리를 상하였으니"},{"n":17,"t":"네 하나님 여호와가 너를 길로 인도할 때에 네가 나를 떠남으로 이를 자취함이 아니냐"},{"n":18,"t":"네가 시홀의 물을 마시려고 애굽 길에 있음은 어찜이며 또 그 하수를 마시려고 앗수르 길에 있음은 어찜이뇨"},{"n":19,"t":"네 악이 너를 징계하겠고 네 패역이 너를 책할 것이라 그런즉 네 하나님 여호와를 버림과 네 속에 나를 경외함이 없는 것이 악이요 고통인 줄 알라 주 만군의 여호와의 말이니라"},{"n":20,"t":"네가 옛적부터 네 멍에를 꺾고 네 결박을 끊으며 말하기를 나는 순복지 아니하리라 하고 모든 높은 산 위와 모든 푸른 나무 아래서 몸을 굽혀 행음하도다"},{"n":21,"t":"내가 너를 순전한 참 종자 곧 귀한 포도나무로 심었거늘 내게 대하여 이방 포도나무의 악한 가지가 됨은 어찜이뇨"},{"n":22,"t":"주 여호와 내가 말하노라 네가 잿물로 스스로 씻으며 수다한 비누를 쓸지라도 네 죄악이 오히려 내 앞에 그저 있으리니"},{"n":23,"t":"네가 어찌 말하기를 나는 더럽히지 아니하였다 바알들을 좇지 아니하였다 하겠느냐 골짜기 속에 있는 네 길을 보라 네 행한 바를 알 것이니라 너는 발이 빠른 젊은 암약대가 그 길에 어지러이 달림 같았으며"},{"n":24,"t":"너는 광야에 익숙한 들 암나귀가 그 성욕이 동하므로 헐떡거림 같았도다 그 성욕의 때에 누가 그것을 막으리요 그것을 찾는 자들이 수고치 아니하고 그것의 달에 만나리라"},{"n":25,"t":"내가 또 말하기를 네 발을 제어하여 벗은 발이 되게 말며 목을 갈하게 말라 하였으나 오직 너는 말하기를 아니라 이는 헛된 말이라 내가 이방 신을 사랑하였은즉 그를 따라 가겠노라 하도다"},{"n":26,"t":"도적이 붙들리면 수치를 당함 같이 이스라엘 집 곧 그 왕들과 족장들과 제사장들과 선지자들이 수치를 당하였느니라"},{"n":27,"t":"그들이 나무를 향하여 너는 나의 아비라 하며 돌을 향하여 너는 나를 낳았다 하고 그 등을 내게로 향하고 그 얼굴은 내게로 향치 아니하다가 환난을 당할 때에는 이르기를 일어나 우리를 구원하소서 하리라"},{"n":28,"t":"네가 만든 네 신들이 어디 있느뇨 그들이 너의 환난을 당할 때에 구원할 수 있으면 일어날 것이니라 유다여 너의 신들이 너의 성읍 수와 같도다"},{"n":29,"t":"나 여호와가 말하노라 너희가 나와 다툼은 어찜이뇨 너희가 다 내게 범과하였느니라"},{"n":30,"t":"내가 너희 자녀를 때림도 무익함은 그들도 징책을 받지 아니함이라 너희 칼이 사나운 사자 같이 너희 선지자들을 삼켰느니라"},{"n":31,"t":"너희 이 세대여 여호와의 말을 들어 보라 내가 이스라엘에게 광야가 되었었느냐 흑암한 땅이 되었었느냐 무슨 연고로 내 백성이 말하기를 우리는 놓였으니 다시 주께로 가지 않겠다 하느냐"},{"n":32,"t":"처녀가 어찌 그 패물을 잊겠느냐 신부가 어찌 그 고운 옷을 잊겠느냐 오직 내 백성은 나를 잊었나니 그 날 수는 계수할 수 없거늘"},{"n":33,"t":"네가 어찌 사랑을 얻으려고 네 행위를 아름답게 꾸미느냐 그러므로 네 행위를 악한 여자들에게까지 가르쳤으며"},{"n":34,"t":"또 네 옷단에 죄 없는 가난한 자를 죽인 피가 묻었나니 그들이 담 구멍을 뚫음을 인함이 아니라 오직 이 모든 일로 너를 책망함을 인함이니라"},{"n":35,"t":"그러나 너는 말하시기를 나는 무죄하니 그 진노가 참으로 내게서 떠났다 하거니와 보라 네 말이 나는 죄를 범치 아니하였다 함을 인하여 내가 너를 심판하리라"},{"n":36,"t":"네가 어찌하여 네 길을 바꾸어 부지런히 돌아다니느뇨 네가 앗수르로 인하여 수치를 당함 같이 애굽으로 인하여 수치를 당할 것이라"},{"n":37,"t":"네가 두 손으로 네 머리를 싸고 거기서도 나가리니 이는 네가 의지하는 자들을 나 여호와가 버렸으므로 네가 그들을 인하여 형통치 못할 것임이니라"}],"kids":[{"n":1,"t":"하나님의 말씀이 내게 들려왔어요."},{"n":2,"t":"\\"가서 예루살렘 사람들에게 큰 소리로 이렇게 외쳐라. 여호와께서 이렇게 말씀하셨다. \'네가 어렸을 때, 결혼하던 때에 나를 사랑했던 그 마음, 곡식을 심을 수 없는 광야(아무것도 자라지 않는 메마른 땅)에서도 나를 따라왔던 그 모습을 내가 너를 위해 잘 기억하고 있단다.\'\\""},{"n":3,"t":"\\"그때 이스라엘은 나 여호와에게 거룩한 것이었고, 첫 열매(가장 먼저 거둔 곡식)와 같았어. 그래서 누구든지 그를 해치려고 하면 벌을 받아 재앙을 만났단다. 이것은 나 여호와의 말이야.\\""},{"n":4,"t":"야곱(이스라엘의 또 다른 이름) 집과 이스라엘 집의 모든 사람들아, 나 여호와의 말을 들어라."},{"n":5,"t":"\\"나 여호와가 이렇게 말한다. 너희 조상들이 내게서 무슨 잘못을 보았기에 나를 멀리하고, 헛된 우상을 따라가서 헛되이 살았느냐?\\""},{"n":6,"t":"\\"그들은 \'우리를 애굽 땅에서 이끌어 내시고, 광야와 메마른 땅과 깊은 구덩이가 있는 땅, 사람도 살 수 없고 다닐 수도 없는 무서운 땅을 무사히 지나게 해 주신 여호와는 어디 계시냐?\' 하고 묻지도 않았어.\\""},{"n":7,"t":"\\"내가 너희를 이끌어 기름진(좋은) 땅에 들어가게 해서 그곳의 열매와 좋은 것을 먹게 했는데, 너희는 와서 내 땅을 더럽혔고, 내가 준 땅(기업)을 미운 것으로 만들었어.\\""},{"n":8,"t":"\\"제사장들도 \'여호와가 어디 계시냐?\'고 묻지 않고, 율법(하나님의 말씀)을 가르치는 사람들도 나를 알지 못하고, 관리(높은 사람)들도 나를 거역했어. 선지자(말씀을 전하는 사람)들은 바알(거짓 신)의 이름으로 헛된 예언을 하고, 아무 쓸모없는 것을 따라갔단다.\\""},{"n":9,"t":"\\"그러므로 내가 계속해서 너희와 다투고, 너희 자손과도 다투겠다. 이것은 나 여호와의 말이야.\\""},{"n":10,"t":"\\"너희는 깃딤(서쪽) 섬으로 건너가 보고, 게달(동쪽 사막)에도 사람을 보내서 자세히 살펴보아라. 이런 일이 있는지 없는지를.\\""},{"n":11,"t":"\\"어느 나라가 자기 신을 — 진짜 신도 아닌 것을 — 다른 것으로 바꾼 적이 있느냐? 그런데 내 백성은 그 영광스러운 하나님을 헛되고 쓸모없는 것(우상)과 바꾸어 버렸어.\\""},{"n":12,"t":"\\"하늘아, 이 일을 보고 놀라고, 크게 떨고, 무서워하여라. 이것은 나 여호와의 말이야.\\""},{"n":13,"t":"\\"내 백성이 두 가지 잘못을 했어. 첫째는 생수(살아있는 물)의 근원이신 나를 버린 것이고, 둘째는 자기 마음대로 웅덩이(물 모으는 통)를 팠는데, 그것은 물이 새 버려서 한 방울도 담을 수 없는 깨진 웅덩이였단다.\\""},{"n":14,"t":"\\"이스라엘이 종이냐? 종의 자식이냐? 그런데 어찌하여 적에게 잡혀가는 신세가 되었느냐?\\""},{"n":15,"t":"\\"어린 사자들이 그를 향해 으르렁거리며 큰 소리를 질러 그 땅을 텅 비게 만들었고, 그의 성들은 불에 타서 사는 사람이 없게 되었어.\\""},{"n":16,"t":"\\"놉(애굽의 한 도시)과 다바네스(애굽의 또 한 도시) 사람들도 네 머리(정수리)를 깨뜨렸단다.\\""},{"n":17,"t":"\\"네 하나님 여호와가 너를 바른 길로 인도하셨는데, 네가 그분을 떠난 것이 이런 일을 너 스스로 부른 것이 아니냐?\\""},{"n":18,"t":"\\"네가 이제는 시홀(애굽 강) 물을 마시려고 애굽으로 가는 길에 있고, 또 큰 강(유브라데) 물을 마시려고 앗수르로 가는 길에 있으니 무슨 까닭이냐?\\""},{"n":19,"t":"\\"네 잘못이 너를 벌할 것이고, 네가 거역(반대)한 것이 너를 꾸짖을 거야. 그러니 네 하나님 여호와를 버린 것과 나를 두려워하는 마음이 네 안에 없는 것이 정말 나쁘고 괴로운 일임을 알아라. 이것은 만군의(엄청 크고 강한) 주 여호와의 말이야.\\""},{"n":20,"t":"\\"네가 옛날부터 자기 멍에(소가 일할 때 매는 도구)를 부수고 줄을 끊으면서 \'나는 말 안 들을 거야\' 하고 모든 높은 산 위와 푸른 나무 아래에서 몸을 굽혀 음란한(부정하게 우상 섬기는) 일을 했단다.\\""},{"n":21,"t":"\\"내가 너를 좋은 씨, 귀한 포도나무로 심었는데, 어떻게 나를 배반하고 이방의 못된 가지가 되었느냐?\\""},{"n":22,"t":"\\"주 여호와가 말한다. 네가 잿물(빨래할 때 쓰는 강한 물)로 자기를 씻고, 비누(세제)를 아무리 많이 써도 네 죄는 여전히 내 앞에 그대로 남아 있을 거야.\\""},{"n":23,"t":"\\"네가 어떻게 \'나는 더럽지 않다, 바알들을 따라가지 않았다\'라고 말할 수 있느냐? 골짜기에서 네가 한 일을 보아라. 네가 한 짓을 알게 될 거야. 너는 마치 길에서 이리저리 마구 뛰어다니는 빠른 어린 암낙타 같았어.\\""},{"n":24,"t":"\\"너는 광야에 익숙한 들 암나귀(야생 당나귀)가 짝을 찾아 헐떡이는 것 같았어. 그 짝짓기 철에는 누가 그것을 막을 수 있겠느냐? 찾는 자들이 힘들이지 않고도 쉽게 만난단다.\\""},{"n":25,"t":"\\"내가 또 말했어. \'발이 닳도록 다니지 말고, 네 목이 마르도록 헐떡거리지 마라.\' 그러나 너는 \'아니, 그건 헛소리야. 나는 이방 신을 사랑했으니 그를 따라갈 거야\'라고 말했어.\\""},{"n":26,"t":"\\"도둑이 잡혔을 때 부끄러워하는 것처럼, 이스라엘 집안 — 왕들과 높은 사람들과 제사장들과 선지자들 — 도 모두 부끄러움을 당했어.\\""},{"n":27,"t":"\\"그들은 나무를 향해 \'당신은 내 아버지\'라 하고, 돌을 향해 \'당신이 나를 낳았다\'라고 말하면서 내게는 등을 돌리고 얼굴을 돌리지 않았어. 그러다가 어려움이 닥치면 \'일어나서 우리를 구해 주세요\'라고 부르짖을 거야.\\""},{"n":28,"t":"\\"네가 만든 신들은 어디 있느냐? 어려움이 닥쳤을 때 너를 구해 줄 수 있다면 일어나라고 해 봐라! 유다야, 네 신들이 네 성들 수만큼이나 많구나.\\""},{"n":29,"t":"\\"나 여호와가 말한다. 너희가 어찌하여 나와 다투느냐? 너희 모두가 다 내게 죄를 지었단다.\\""},{"n":30,"t":"\\"내가 너희 자녀들을 때려도 소용이 없었어. 그들은 가르침을 받지 않았고, 너희 칼은 사나운 사자처럼 너희 선지자들을 삼켜 버렸어.\\""},{"n":31,"t":"\\"이 시대 사람들아, 여호와의 말을 들어 봐라. 내가 이스라엘에게 광야가 된 적이 있느냐? 어두운 땅이었느냐? 그런데 어째서 내 백성이 \'우리는 자유로워졌으니 다시는 주께로 가지 않겠다\'라고 하느냐?\\""},{"n":32,"t":"\\"처녀(아가씨)가 자기 보석을 잊겠느냐? 신부가 결혼식 옷을 잊겠느냐? 그런데 내 백성은 셀 수도 없이 많은 날 동안 나를 잊었어.\\""},{"n":33,"t":"\\"네가 사랑(연인)을 얻으려고 어떻게 그렇게 길을 잘 꾸미느냐? 너는 너의 그 행동을 못된 여자들에게도 가르쳤어.\\""},{"n":34,"t":"\\"네 옷자락에는 죄 없는 가난한 사람들의 피가 묻어 있어. 그들이 도둑질하다가 들킨 것도 아닌데(담을 뚫지 않았는데도) 네가 그들을 죽인 거야. 이 모든 일 때문에 내가 너를 꾸짖는 거란다.\\""},{"n":35,"t":"\\"그래도 너는 \'나는 죄가 없으니 하나님의 화가 정말로 내게서 떠났다\'고 말해. 보아라, 네가 \'나는 죄지은 적이 없다\'라고 말하기 때문에 내가 너를 심판할 거야.\\""},{"n":36,"t":"\\"네가 어찌하여 그렇게 자주 길을 바꾸어 가며 부지런히 돌아다니느냐? 네가 앗수르 때문에 부끄러움을 당한 것처럼, 애굽 때문에도 부끄러움을 당할 거야.\\""},{"n":37,"t":"\\"네가 두 손으로 머리를 감싸 쥐고 그곳에서 나오게 될 거야. 이는 네가 의지하던 자들을 나 여호와가 버렸으므로, 그들과 함께 있어도 잘되지 못할 것이기 때문이야.\\""}]}},{"chapter":3,"title":"회개하라는 부르심","verses":{"krv":[{"n":1,"t":"세상에서 말하기를 가령 사람이 그 아내를 버리므로 그가 떠나 타인의 아내가 된다 하자 본부가 그를 다시 받겠느냐 그리하면 그 땅이 크게 더러워지지 않겠느냐 하느니라 나 여호와가 말하노라 네가 많은 무리와 행음하고도 내게로 돌아오려느냐"},{"n":2,"t":"네 눈을 들어 자산을 보라 너의 행음치 아니한 곳이 어디 있느냐 네가 길 가에 앉아 사람을 기다린 것이 광야에 있는 아라바 사람 같아서 음란과 행악으로 이 땅을 더럽혔도다"},{"n":3,"t":"그러므로 단 비가 그쳐졌고 늦은 비가 없어졌느니라 그럴지라도 네가 창녀의 낯을 가졌으므로 수치를 알지 못하느니라"},{"n":4,"t":"네가 이제부터는 내게 부르짖기를 나의 아버지여 아버지는 나의 소시의 애호자시오니"},{"n":5,"t":"노를 한 없이 계속하시겠으며 끝까지 두시겠나이까 하지 않겠느냐 보라 네가 이같이 말하여도 악을 행하여 네 욕심을 이루었느니라 하시니라"},{"n":6,"t":"요시야 왕 때에 여호와께서 또 내게 이르시되 네가 배역한 이스라엘의 행한 바를 보았느냐 그가 모든 높은 산에 오르며 모든 푸른 나무 아래로 가서 거기서 행음하였도다"},{"n":7,"t":"그가 이 모든 일을 행한 후에 내가 말하기를 그가 내게로 돌아오리라 하였으나 오히려 내게로 돌아오지 아니하였고 그 패역한 자매 유다는 그것을 보았느니라"},{"n":8,"t":"내게 배역한 이스라엘이 간음을 행하였으므로 내가 그를 내어 쫓고 이혼서까지 주었으되 그 패역한 자매 유다가 두려워 아니하고 자기도 가서 행음함을 내가 보았노라"},{"n":9,"t":"그가 돌과 나무로 더불어 행음함을 가볍게 여기고 행음하여 이 땅을 더럽혔거늘"},{"n":10,"t":"이 모든 일이 있어도 그 패역한 자매 유다가 진심으로 내게 돌아오지 아니하고 거짓으로 할 뿐이니라 여호와의 말이니라"},{"n":11,"t":"여호와께서 내게 이르시되 배역한 이스라엘은 패역한 유다보다 오히려 의로움이 나타났나니"},{"n":12,"t":"너는 가서 북을 향하여 이 말을 선포하여 이르라 여호와께서 가라사대 배역한 이스라엘아 돌아오라 나의 노한 얼굴을 너희에게로 향하지 아니하리라 나는 긍휼이 있는 자라 노를 한 없이 품지 아니하느니라 여호와의 말이니라"},{"n":13,"t":"너는 오직 네 죄를 자복하라 이는 네 하나님 여호와를 배반하고 네 길로 달려 모든 푸른 나무 아래서 이방 신에게 절하고 내 목소리를 듣지 아니하였음이니라 여호와의 말이니라"},{"n":14,"t":"나 여호와가 말하노라 배역한 자식들아 돌아오라 나는 너희 남편임이니라 내가 너희를 성읍에서 하나와 족속 중에서 둘을 택하여 시온으로 데려오겠고"},{"n":15,"t":"내가 또 내 마음에 합하는 목자를 너희에게 주리니 그들이 지식과 명철로 너희를 양육하리라"},{"n":16,"t":"나 여호와가 말하노라 너희가 이 땅에서 번성하여 많아질 때에는 사람 사람이 여호와의 언약궤를 다시는 말하지 아니할 것이요 생각지 아니할 것이요 기억지 아니할 것이요 찾지 아니할 것이요 만들지 아니할 것이며"},{"n":17,"t":"그 때에 예루살렘이 여호와의 보좌라 일컬음이 되며 열방이 그리로 모이리니 곧 여호와의 이름으로 인하여 예루살렘에 모이고 다시는 그들의 악한 마음의 강팍한 대로 행치 아니할 것이며"},{"n":18,"t":"그 때에 유다 족속이 이스라엘 족속과 동행하여 북에서부터 나와서 내가 너희 열조에게 기업으로 준 땅에 함께 이르리라"},{"n":19,"t":"내가 스스로 말하기를 내가 어떻게 하든지 너를 자녀 중에 두며 허다한 나라 중에 아름다운 산업인 이 낙토를 네게 주리라 하였고 내가 다시 말하기를 너희가 나를 나의 아버지라 하고 나를 떠나지 말 것이니라 하였노라"},{"n":20,"t":"그런데 이스라엘 족속아 마치 아내가 그 남편을 속이고 떠남 같이 너희가 정녕히 나를 속였느니라 여호와의 말이니라"},{"n":21,"t":"소리가 자산 위에서 들리니 곧 이스라엘 자손의 애곡하며 간구하는 것이라 그들이 그 길을 굽게 하며 자기 하나님 여호와를 잊어버렸음이로다"},{"n":22,"t":"배역한 자식들아 돌아오라 내가 너희의 배역함을 고치리라 보소서 우리가 주께 왔사오니 주는 우리 하나님 여호와이심이니이다"},{"n":23,"t":"작은 산들과 큰 산 위의 떠드는 무리에게 바라는 것은 참으로 허사라 이스라엘의 구원은 진실로 우리 하나님 여호와께 있나이다"},{"n":24,"t":"부끄러운 그것이 우리의 어렸을 때로부터 우리 열조의 산업인 양떼와 소떼와 아들들과 딸들을 삼켰사온즉"},{"n":25,"t":"우리는 수치 중에 눕겠고 우리는 수욕에 덮이울 것이니 이는 우리와 우리 열조가 어렸을 때로부터 오늘까지 우리 하나님 여호와께 범죄하여 우리 하나님 여호와의 목소리를 청종치 아니하였음이니이다"}],"kids":[{"n":1,"t":"\\"세상에서 \'어떤 남자가 자기 아내를 내보내서 그 여자가 다른 남자의 아내가 되었다고 하자. 그러면 본남편이 다시 그 여자를 받아들이겠느냐? 그러면 그 땅이 매우 더러워지지 않겠느냐?\'라고 한다. 그런데 너는 많은 사람들과 음란한 일(우상 섬기는 짓)을 하고도 내게로 돌아오려느냐? 이것은 나 여호와의 말이야.\\""},{"n":2,"t":"\\"네 눈을 들어 산을 봐라. 네가 음란한 짓을 하지 않은 곳이 어디 있느냐? 너는 광야의 아라바 사람(사막을 떠도는 도둑)처럼 길가에 앉아 사람을 기다렸어. 그렇게 음란하고 못된 짓으로 이 땅을 더럽혔지.\\""},{"n":3,"t":"\\"그래서 비가 내리지 않게 되었고, 늦은 비(가을비)도 그쳐 버렸어. 그런데도 너는 부끄러움도 모르는 창녀(못된 여자)처럼 얼굴을 굳혔구나.\\""},{"n":4,"t":"\\"이제부터 네가 내게 부르짖기를 \'나의 아버지여, 아버지께서는 내 어릴 적 사랑하신 분이세요.\'\\""},{"n":5,"t":"\\"\'끝까지 화내시고 영원히 노여워하시겠어요?\'라고 말하지 않겠느냐? 보아라, 네가 이렇게 말하면서도 계속 나쁜 짓을 하면서 네 욕심대로 살았어.\\""},{"n":6,"t":"요시야 왕 때에 여호와께서 또 내게 말씀하셨어요. \\"배반한 이스라엘이 한 짓을 보았느냐? 그가 모든 높은 산에 올라가고 모든 푸른 나무 아래로 가서 거기서 우상 섬기는 일을 했단다.\\""},{"n":7,"t":"\\"이 모든 일을 한 후에 내가 \'그가 내게로 돌아올 것이다\'라고 말했지만 그는 돌아오지 않았어. 그리고 그의 못된 자매 유다도 그것을 보고 있었지.\\""},{"n":8,"t":"\\"배반한 이스라엘이 죄를 지었기 때문에 내가 그를 쫓아내고 이혼증서까지 주었는데도, 못된 자매 유다는 무서워하지 않고 자기도 가서 똑같은 짓을 했어.\\""},{"n":9,"t":"\\"그가 돌과 나무로 만든 우상과 함께 음란한 짓 하는 것을 가볍게 여겨서 이 땅을 더럽혔단다.\\""},{"n":10,"t":"\\"이 모든 일이 있었는데도 그 못된 자매 유다는 진심으로 내게 돌아오지 않고 거짓으로만 돌아오는 척했어. 이것은 나 여호와의 말이야.\\""},{"n":11,"t":"여호와께서 내게 말씀하셨어요. \\"배반한 이스라엘이 못된 유다보다는 오히려 의롭게(죄가 더 적게) 보였단다.\\""},{"n":12,"t":"\\"너는 가서 북쪽을 향해 이 말을 외쳐라. \'여호와께서 말씀하신다. 배반한 이스라엘아, 돌아오너라. 내가 화난 얼굴로 너희를 보지 않을 거야. 나는 자비로운 자라서 영원히 화내지 않는단다.\' 이것은 여호와의 말이야.\\""},{"n":13,"t":"\\"오직 네 죄를 인정해라(자백해라). 네 하나님 여호와를 배반하고 네 마음대로 가서 모든 푸른 나무 아래에서 다른 신에게 절했고, 내 말을 듣지 않았다는 것을. 이것은 여호와의 말이야.\\""},{"n":14,"t":"\\"나 여호와가 말한다. 배반한 자식들아, 돌아오너라. 나는 너희 남편(주인)이란다. 내가 한 성에서 한 명, 한 가족 중에서 두 명씩 골라 시온(예루살렘)으로 데려올 거야.\\""},{"n":15,"t":"\\"내가 또 내 마음에 맞는 목자(지도자)를 너희에게 줄 거야. 그들이 지혜와 지식으로 너희를 돌볼 거란다.\\""},{"n":16,"t":"\\"나 여호와가 말한다. 그때 너희가 이 땅에서 많아지고 늘어날 때, 사람들은 더 이상 여호와의 언약궤(하나님의 약속이 담긴 거룩한 상자)를 말하지도, 생각하지도, 기억하지도, 찾지도, 만들지도 않을 거야.\\""},{"n":17,"t":"\\"그때 예루살렘이 \'여호와의 보좌(왕의 자리)\'라고 불릴 거고, 모든 나라들이 그곳으로 모일 거야. 여호와의 이름 때문에 예루살렘에 모일 것이고, 다시는 자기 마음의 못된 고집대로 살지 않을 거란다.\\""},{"n":18,"t":"\\"그때 유다 사람들이 이스라엘 사람들과 함께 북쪽 땅에서 나와, 내가 너희 조상들에게 준 땅으로 함께 돌아올 거야.\\""},{"n":19,"t":"\\"내가 마음속으로 말했었어. \'내가 너를 어떻게든 자녀처럼 두고, 모든 나라 중에 가장 아름다운 산업(소중한 땅)인 이 좋은 땅을 너에게 주리라.\' 그리고 또 말했었지. \'너희가 나를 아버지라고 부르고 나를 떠나지 않을 것이다.\'\\""},{"n":20,"t":"\\"그런데 이스라엘아, 너는 정말로 나를 배반했어. 마치 아내가 남편을 속이고 떠나는 것처럼 말이야. 이것은 나 여호와의 말이야.\\""},{"n":21,"t":"\\"산 위에서 소리가 들려. 이스라엘 사람들이 슬프게 울며 간절히 빌고 있는 소리야. 그들이 길을 잘못 들었고 자기 하나님 여호와를 잊어버렸기 때문이지.\\""},{"n":22,"t":"\\"배반한 자식들아, 돌아오너라. 내가 너희의 배반한 마음을 고쳐 줄게.\\" \\"보세요, 우리가 주께 왔어요. 주는 우리 하나님 여호와이세요.\\""},{"n":23,"t":"\\"작은 산과 큰 산에서 떠들썩하게 우상 섬기던 그 모든 일은 정말 헛된 것이었어요. 이스라엘의 구원은 정말로 우리 하나님 여호와께만 있어요.\\""},{"n":24,"t":"\\"부끄러운 것(우상)이 우리가 어렸을 때부터 우리 조상들이 모은 양 떼와 소 떼와 아들과 딸들을 다 먹어 치웠어요.\\""},{"n":25,"t":"\\"우리는 부끄러움 속에 누워 있고, 우리 위에 부끄러움이 덮여 있어요. 이는 우리와 우리 조상들이 어렸을 때부터 오늘까지 우리 하나님 여호와께 죄를 지었고, 우리 하나님 여호와의 말씀을 듣지 않았기 때문이에요.\\""}]}},{"chapter":4,"title":"북에서 오는 재앙","verses":{"krv":[{"n":1,"t":"여호와께서 가라사대 이스라엘아 네가 돌아오려거든 내게로 돌아오라 네가 만일 나의 목전에서 가증한 것을 버리고 마음이 요동치 아니하며"},{"n":2,"t":"진실과 공평과 정의로 여호와의 삶을 가리켜 맹세하면 열방이 나로 인하여 스스로 복을 빌며 나로 인하여 자랑하리라"},{"n":3,"t":"나 여호와가 유다와 예루살렘 사람에게 이같이 이르노라 너희 묵은 땅을 갈고 가시덤불 속에 파종하지 말라"},{"n":4,"t":"유다인과 예루살렘 거민들아 너희는 스스로 할례를 행하여 너희 마음 가죽을 베고 나 여호와께 속하라 그렇지 아니하면 너희 행악을 인하여 나의 분노가 불 같이 발하여 사르리니 그것을 끌 자가 없으리라"},{"n":5,"t":"너희는 유다에 선포하며 예루살렘에 공포하여 이르기를 이 땅에서 나팔을 불라 하며 또 크게 외쳐 이르기를 너희는 모이라 우리가 견고한 성으로 들어가자 하고"},{"n":6,"t":"시온을 향하여 기호를 세우라, 도피하라, 지체하지 말라, 내가 북방에서 재앙과 큰 멸망으로 이르게 할 것임이니라"},{"n":7,"t":"사자가 그 수풀에서 올라왔으며 열방을 멸하는 자가 나아왔으되 네 땅을 황폐케 하려고 이미 그 처소를 떠나 나왔은즉 네 성읍들이 황폐하여 거민이 없게 되리니"},{"n":8,"t":"이를 인하여 너희는 굵은 베를 두르고 애곡하라 대저 여호와의 맹렬한 노가 아직 너희에게서 돌이키지 아니하였음이니라"},{"n":9,"t":"나 여호와가 말하노라 그 날에 왕과 방백들은 실심할 것이며 제사장들은 놀랄 것이며 선지자들은 깜짝 놀라리라"},{"n":10,"t":"내가 가로되 슬프도소이다 주 여호와여 주께서 진실로 이 백성과 예루살렘을 크게 속이셨나이다 이르시기를 너희에게 평강이 있으리라 하시더니 칼이 생명에 미쳤나이다"},{"n":11,"t":"그 때에 이 백성과 예루살렘에 이를 자 있어서 뜨거운 바람이 광야 자산에서 내 딸 백성에게 불어온다 하리라 이는 키질하기 위함도 아니요 정결케 하려함도 아니며"},{"n":12,"t":"이보다 더 강한 바람이 나를 위하여 오리니 이제 내가 그들에게 심판을 베풀 것이라"},{"n":13,"t":"보라 그가 구름 같이 올라오나니 그 병거는 회리바람 같고 그 말들은 독수리보다 빠르도다 우리에게 화 있도다 우리는 멸망하도다 하리라"},{"n":14,"t":"예루살렘아 네 마음의 악을 씻어 버리라 그리하면 구원을 얻으리라 네 악한 생각이 네 속에 얼마나 오래 머물겠느냐"},{"n":15,"t":"단에서 소리를 선포하며 에브라임 산에서 재앙을 공포하는도다"},{"n":16,"t":"너희는 열방에 고하며 또 예루살렘에 알게 하기를 에워싸고 치는 자들이 먼 땅에서부터 와서 유다 성읍들을 향하여 소리를 지른다 하라"},{"n":17,"t":"그들이 밭을 지키는 자 같이 예루살렘을 에워싸나니 이는 그가 나를 거역한 연고니라 여호와의 말이니라"},{"n":18,"t":"네 길과 행사가 이 일들을 부르게 하였나니 이는 너의 악함이라 그 고통이 네 마음에까지 미치느니라"},{"n":19,"t":"슬프고 아프다 내 마음 속이 아프고 내 마음이 답답하여 잠잠할 수 없으니 이는 나의 심령 네가 나팔소리와 전쟁의 경보를 들음이로다"},{"n":20,"t":"패망에 패망이 연속하여 온 땅이 탈취를 당하니 나의 천막은 홀연히 파멸되며 나의 휘장은 잠시간에 열파되도다"},{"n":21,"t":"내가 저 기호를 보며 나팔소리 듣기를 어느 때까지 할꼬"},{"n":22,"t":"내 백성은 나를 알지 못하는 우준한 자요 지각이 없는 미련한 자식이라 악을 행하기에는 지각이 있으나 선을 행하기에는 무지하도다"},{"n":23,"t":"내가 땅을 본즉 혼돈하고 공허하며 하늘들을 우러른즉 거기 빛이 없으며"},{"n":24,"t":"내가 산들을 본즉 다 진동하며 작은 산들도 요동하며"},{"n":25,"t":"내가 본즉 사람이 없으며 공중의 새가 다 날아갔으며"},{"n":26,"t":"내가 본즉 좋은 땅이 황무지가 되었으며 그 모든 성읍이 여호와의 앞 그 맹렬한 진노 앞에 무너졌으니"},{"n":27,"t":"이는 여호와의 말씀에 이 온 땅이 황폐할 것이나 내가 진멸하지는 아니할 것이며"},{"n":28,"t":"이로 인하여 땅이 슬퍼할 것이며 위의 하늘이 흑암할 것이라 내가 이미 말하였으며 작정하였고 후회하지 아니하였은즉 또한 돌이키지 아니하리라 하셨음이로다"},{"n":29,"t":"기병과 활 쏘는 자의 훤화로 인하여 모든 성읍이 도망하여 수풀에 들어가고 바위에 기어오르며 각 성읍이 버림을 당하여 거기 거하는 사람이 없나니"},{"n":30,"t":"멸망을 당한 자여 네가 어떻게 하려느냐 네가 붉은 옷을 입고 금장식으로 단장하고 눈을 그려 꾸밀지라도 너의 화장한 것이 헛된 일이라 연인들이 너를 멸시하여 네 생명을 찾느니라"},{"n":31,"t":"내가 소리를 들은즉 여인의 해산하는 소리 같고 초산하는 자의 고통하는 소리 같으니 이는 딸 시온의 소리라 그가 헐떡이며 그 손을 펴고 이르기를 내게 화 있도다 살륙하는 자를 인하여 나의 심령이 피곤하도다 하는도다"}],"kids":[{"n":1,"t":"여호와께서 말씀하셨어요. \\"이스라엘아, 네가 돌아오려거든 내게로 돌아오너라. 만약 네가 내 앞에서 미워하는 더러운 우상들을 버리고, 흔들리지 않는다면,\\""},{"n":2,"t":"\\"그리고 진실하고 공평하고 바른 마음으로 \'여호와는 살아 계신다\'라고 맹세한다면, 다른 나라들이 나로 인해 복을 빌고, 나로 인해 자랑하게 될 거야.\\""},{"n":3,"t":"나 여호와가 유다와 예루살렘 사람들에게 이렇게 말한다. \\"오랫동안 묵혀 둔 땅을 갈고, 가시덤불 속에는 씨를 뿌리지 마라.\\""},{"n":4,"t":"\\"유다 사람들과 예루살렘에 사는 사람들아, 너희 마음에 할례(굳어진 것을 떼어 내는 일)를 해서 마음의 가죽(굳은 마음)을 잘라 내고 나 여호와께 속해라. 그렇지 않으면 너희가 한 못된 일 때문에 내 화가 불처럼 일어나서 너희를 태울 것이고, 그 불을 끌 사람이 없을 거야.\\""},{"n":5,"t":"\\"너희는 유다에 알리고 예루살렘에 외쳐 말해라. \'이 땅에서 나팔을 불어라!\' 그리고 크게 외쳐라. \'모두 모이자, 단단한 성으로 들어가자!\'\\""},{"n":6,"t":"\\"시온을 향해 깃발을 세우고, 빨리 도망쳐라! 머뭇거리지 마라! 내가 북쪽에서 큰 재앙(나쁜 일)과 큰 멸망을 가져올 거야.\\""},{"n":7,"t":"\\"사자가 수풀에서 나왔어. 나라들을 멸망시키는 자가 이미 자기 자리를 떠나서 너의 땅을 텅 비게 하려고 오고 있어. 네 성들은 폐허가 되어 사는 사람이 없게 될 거야.\\""},{"n":8,"t":"\\"이 일 때문에 너희는 굵은 베옷(슬플 때 입는 거친 옷)을 입고 슬프게 울어라. 여호와의 큰 분노가 아직 너희에게서 떠나지 않았기 때문이야.\\""},{"n":9,"t":"\\"나 여호와가 말한다. 그 날에 왕과 높은 사람들은 정신을 잃고, 제사장들은 놀라며, 선지자들은 깜짝 놀랄 거야.\\""},{"n":10,"t":"내가 말했어요. \\"아, 주 여호와님! 주께서 정말로 이 백성과 예루살렘을 크게 속이셨네요. \'너희에게 평안이 있을 것이다\'라고 하시더니 칼이 우리 목숨까지 위협하고 있어요.\\""},{"n":11,"t":"\\"그때에 이 백성과 예루살렘에게 이런 말이 들릴 거야. \'광야의 산에서 뜨거운 바람이 내 딸 백성에게 불어 온다.\' 이 바람은 곡식을 까불러서 좋은 알맹이를 골라내는 바람도 아니고, 깨끗하게 하는 바람도 아니야.\\""},{"n":12,"t":"\\"이보다 더 강한 바람이 나에게 올 것이다. 이제 내가 그들을 심판할 거야.\\""},{"n":13,"t":"\\"보아라, 그(적군)가 구름처럼 올라온다. 그의 병거(전쟁용 마차)는 회오리바람 같고, 그의 말들은 독수리보다 빨라. \'아! 우리에게 화가 닥쳤다, 우리는 망했다\' 하리라.\\""},{"n":14,"t":"\\"예루살렘아, 네 마음의 악함을 씻어 내라. 그러면 구원을 받게 될 거야. 너의 못된 생각이 네 안에 얼마나 오래 머물러 있을 거니?\\""},{"n":15,"t":"\\"단(이스라엘 북쪽 도시)에서 소리가 들리고, 에브라임 산에서 재앙(나쁜 일)이 다가온다는 소식이 들려.\\""},{"n":16,"t":"\\"너희는 다른 나라들에게 알리고, 예루살렘에도 알려라. \'먼 땅에서 적들이 와서 유다 성들을 둘러싸고 소리 지른다.\'\\""},{"n":17,"t":"\\"그들이 밭을 지키는 사람들처럼 예루살렘을 둘러쌌어. 이는 그가 나를 거역했기 때문이야. 이것은 여호와의 말이야.\\""},{"n":18,"t":"\\"네 길과 네 행동이 이 일을 불러왔어. 이는 네가 나쁜 짓을 했기 때문이야. 그 고통이 네 마음 깊이까지 미친 거란다.\\""},{"n":19,"t":"\\"아, 슬프고 아파! 내 마음이 정말 아파, 가슴이 답답해서 잠잠히 있을 수가 없어. 내 영혼아, 너는 나팔 소리와 전쟁의 경보(위험을 알리는 소리)를 듣고 있구나.\\""},{"n":20,"t":"\\"패망(망함) 위에 또 패망이 계속 와서 온 땅이 빼앗기고 있어. 내 천막은 갑자기 무너지고, 내 휘장(천막의 커튼)은 한순간에 찢어졌어.\\""},{"n":21,"t":"\\"내가 저 깃발을 보고 나팔 소리를 듣는 것이 언제까지인가요?\\""},{"n":22,"t":"\\"내 백성은 나를 알지 못하는 어리석은 자이고, 생각이 없는 미련한 자식이야. 나쁜 짓을 하는 데는 똑똑하지만, 좋은 일을 하는 데는 모른다.\\""},{"n":23,"t":"\\"내가 땅을 보니 어지럽고 텅 비어 있고, 하늘을 우러러보니 거기에는 빛이 없었어.\\""},{"n":24,"t":"\\"내가 산들을 보니 다 흔들리고, 작은 산들도 흔들리고 있었어.\\""},{"n":25,"t":"\\"내가 보니 사람도 없고, 하늘의 새들도 다 날아가 버렸어.\\""},{"n":26,"t":"\\"내가 보니 좋은 땅이 폐허(아무것도 없는 곳)가 되었고, 그 모든 성들이 여호와 앞에서, 그분의 강한 분노 앞에서 다 무너졌어.\\""},{"n":27,"t":"\\"여호와께서 이렇게 말씀하셨어. \'이 온 땅이 황폐해질 거야. 그러나 내가 완전히 멸망시키지는 않을 거야.\'\\""},{"n":28,"t":"\\"이 때문에 땅이 슬퍼할 것이고 위의 하늘은 어두워질 거야. 내가 이미 말했고, 결정했고, 후회하지 않으니 다시 돌이키지도 않을 거야.\\""},{"n":29,"t":"\\"기마병과 활 쏘는 자들이 떠드는 소리에 모든 성 사람들이 도망쳐서 숲으로 들어가고, 바위 위로 기어오를 거야. 모든 성이 버려지고 거기에 사는 사람이 없게 될 거야.\\""},{"n":30,"t":"\\"멸망당할 자야, 너는 어떻게 하려느냐? 네가 빨간 옷을 입고, 금 장식으로 꾸미고, 눈을 그려 화장해도, 그것은 다 헛된 일이야. 너를 사랑하던 자들이 너를 무시하고 너의 목숨을 노리고 있어.\\""},{"n":31,"t":"\\"내가 들으니, 마치 아기를 낳는 여인의 소리 같고, 첫아이를 낳는 여인이 아파하는 소리 같았어. 이는 시온의 딸의 소리야. 그가 헐떡이며 손을 펼치고 \'아, 내게 화가 닥쳤구나! 죽이는 자들 때문에 내 영혼이 피곤하다\'라고 하더라.\\""}]}},{"chapter":5,"title":"사회적 부패에 대한 책망","verses":{"krv":[{"n":1,"t":"너희는 예루살렘 거리로 빨리 왕래하며 그 넓은 거리에서 찾아보고 알라 너희가 만일 공의를 행하며 진리를 구하는 자를 한 사람이라도 찾으면 내가 이 성을 사하리라"},{"n":2,"t":"그들이 여호와의 사심으로 맹세할지라도 실상은 거짓 맹세니라"},{"n":3,"t":"여호와여 주의 눈이 성실을 돌아보지 아니하시나이까 주께서 그들을 치셨을지라도 그들이 아픈 줄을 알지 못하며 그들을 거의 멸하셨을지라도 그들이 징계를 받지 아니하고 그 얼굴을 반석보다 굳게 하여 돌아오기를 싫어하므로"},{"n":4,"t":"내가 말하기를 이 무리는 비천하고 우준한 것뿐이라 여호와의 길, 자기 하나님의 법을 알지 못하니"},{"n":5,"t":"내가 귀인들에게 가서 그들에게 말하리라 그들은 여호와의 길, 자기 하나님의 법을 안다 하였더니 그들도 일제히 그 멍에를 꺾고 결박을 끊은지라"},{"n":6,"t":"그러므로 수풀에서 나오는 사자가 그들을 죽이며 사막의 이리가 그들을 멸하며 표범이 성읍들을 엿보온즉 그리로 나오는 자마다 찢기오리니 이는 그들의 허물이 많고 패역이 심함이니이다"},{"n":7,"t":"내가 어찌 너를 사하겠느냐 네 자녀가 나를 버리고 신이 아닌 것들로 맹세하였으며 내가 그들을 배불리 먹인즉 그들이 행음하며 창기의 집에 허다히 모이며"},{"n":8,"t":"그들은 살찌고 두루 다니는 수 말 같이 각기 이웃의 아내를 따라 부르짖는도다"},{"n":9,"t":"나 여호와가 이르노라 내가 어찌 이 일들을 인하여 벌하지 아니하겠으며 내 마음이 이런 나라에 보수하지 않겠느냐"},{"n":10,"t":"너희는 그 성벽에 올라가 훼파하되 다 훼파하지 말고 그 가지만 꺾어버리라 여호와의 것이 아님이니라"},{"n":11,"t":"나 여호와가 말하노라 이스라엘 족속과 유다 족속이 내게 심히 패역하였느니라"},{"n":12,"t":"그들이 여호와를 인정치 아니하며 말하기를 여호와는 계신 것이 아닌즉 재앙이 우리에게 임하지 않을 것이요 우리가 칼과 기근을 보지 아니할 것이며"},{"n":13,"t":"선지자들은 바람이라 말씀이 그들의 속에 있지 아니한즉 그같이 그들이 당하리라 하느니라"},{"n":14,"t":"그러므로 만군의 하나님 여호와가 이같이 말하노라 그들이 이 말을 하였은즉 볼지어다 내가 네 입에 있는 나의 말로 불이 되게 하고 이 백성으로 나무가 되게 하리니 그 불이 그들을 사르리라"},{"n":15,"t":"나 여호와가 말하노라 이스라엘 족속아 보라 내가 한 나라를 원방에서 너희에게로 오게 하리니 곧 강하고 오랜 나라이라 그 방언을 네가 알지 못하며 그 말을 네가 깨닫지 못하느니라"},{"n":16,"t":"그 전통은 열린 묘실이요 그 사람들은 다 용사라"},{"n":17,"t":"그들이 네 자녀들의 먹을 추수 곡물과 양식을 먹으며 네 양떼와 소떼를 먹으며 네 포도나무와 무화과나무 열매를 먹으며 네가 의뢰하는 견고한 성들을 칼로 파멸하리라"},{"n":18,"t":"나 여호와가 말하노라 그 때에도 내가 너희를 진멸치는 아니하리라"},{"n":19,"t":"그들이 만일 이르기를 우리 하나님 여호와께서 어찌하여 이 모든 일을 우리에게 행하셨느뇨 하거든 너는 그들에게 이르기를 너희가 여호와를 버리고 너희 땅에서 이방 신들을 섬겼은즉 이와 같이 너희 것이 아닌 땅에서 이방인들을 섬기리라 하라"},{"n":20,"t":"너는 이를 야곱 집에 선포하며 유다에 공포하여 이르기를"},{"n":21,"t":"우준하여 지각이 없으며 눈이 있어도 보지 못하며 귀가 있어도 듣지 못하는 백성이여 이를 들을지어다"},{"n":22,"t":"여호와께서 말씀하시되 너희가 나를 두려워 아니하느냐 내 앞에서 떨지 아니하겠느냐 내가 모래를 두어 바다의 계한을 삼되 그것으로 영원한 계한을 삼고 지나치지 못하게 하였으므로 파도가 흉용하나 그것을 이기지 못하며 뛰노나 그것을 넘지 못하느니라"},{"n":23,"t":"그러나 너희 백성은 배반하며 패역하는 마음이 있어서 이미 배반하고 갔으며"},{"n":24,"t":"또 너희 마음으로 우리에게 이른 비와 늦은 비를 때를 따라 주시며 우리를 위하여 추수 기한을 정하시는 우리 하나님 여호와를 경외하자 말하지도 아니하니"},{"n":25,"t":"너희 허물이 이러한 일들을 물리쳤고 너희 죄가 너희에게 오는 좋은 것을 막았느니라"},{"n":26,"t":"내 백성 너희 중에 악인이 있어서 새 사냥꾼의 매복함 같이 지키며 덫을 놓아 사람을 잡으며"},{"n":27,"t":"조롱에 새들이 가득함 같이 너희 집들에 속임이 가득하도다 그러므로 너희가 창대하고 거부가 되어"},{"n":28,"t":"살찌고 윤택하며 또 행위가 심히 악하여 자기 이익을 얻으려고 송사 곧 고아의 송사를 공정히 하지 아니하며 빈민의 송사를 공평히 판결치 아니하니"},{"n":29,"t":"내가 이 일들을 인하여 벌하지 아니하겠으며 내 마음이 이같은 나라에 보수하지 않겠느냐 여호와의 말이니라"},{"n":30,"t":"이 땅에 기괴하고 놀라운 일이 있도다"},{"n":31,"t":"선지자들은 거짓을 예언하며 제사장들은 자기 권력으로 다스리며 내 백성은 그것을 좋게 여기니 그 결국에는 너희가 어찌 하려느냐"}],"kids":[{"n":1,"t":"\\"너희는 예루살렘 거리를 빨리 다니며 그 넓은 거리를 자세히 살펴봐라. 만약 공의(바른 일)를 행하고 진리를 찾는 사람을 한 명이라도 찾으면 내가 이 성을 용서해 줄게.\\""},{"n":2,"t":"\\"그들이 \'여호와의 살아 계심\'으로 맹세할지라도 사실은 거짓 맹세란다.\\""},{"n":3,"t":"\\"여호와여, 주의 눈이 진실(성실)을 살피지 않으세요? 주께서 그들을 치셨는데도 그들은 아픈 줄도 모르고, 그들을 거의 멸망시키셨는데도 그들은 가르침을 받지 않았어요. 그들이 얼굴을 바위보다 더 굳게 해서 돌아오기를 싫어해요.\\""},{"n":4,"t":"내가 말했어요. \\"이 사람들은 가난하고 어리석은 자들일 뿐이야. 여호와의 길과 자기 하나님의 법(가르침)을 알지 못해.\\""},{"n":5,"t":"\\"내가 귀한 사람들(높은 사람들)에게 가서 말해 보겠어. 그들은 여호와의 길과 자기 하나님의 법을 알 거야.\\" 그러나 그들도 똑같이 멍에(매는 줄)를 부수고 줄을 끊었어요."},{"n":6,"t":"\\"그래서 숲에서 나오는 사자가 그들을 죽이고, 사막의 이리(늑대)가 그들을 멸망시키고, 표범이 성들을 노려보며 거기서 나오는 사람마다 다 찢어 버릴 거야. 이는 그들의 잘못이 많고 거역이 심하기 때문이야.\\""},{"n":7,"t":"\\"내가 어떻게 너를 용서할 수 있겠느냐? 네 자녀들이 나를 버리고 신도 아닌 것들로 맹세를 했어. 내가 그들을 배부르게 먹였더니 그들은 음란한 짓을 하며 창녀의 집에 떼지어 모였구나.\\""},{"n":8,"t":"\\"그들은 살찐 채로 돌아다니는 수말처럼, 모두 자기 이웃의 아내를 따라가며 욕심을 부르짖는다.\\""},{"n":9,"t":"\\"나 여호와가 말한다. 내가 어찌 이런 일을 가지고 벌하지 않겠느냐? 내 마음이 이런 나라에 어찌 갚지 않겠느냐?\\""},{"n":10,"t":"\\"너희는 그 성벽에 올라가서 부숴라. 그러나 완전히 부수지는 말고 그 가지(일부)만 꺾어 버려라. 그것은 여호와의 것이 아니기 때문이야.\\""},{"n":11,"t":"\\"나 여호와가 말한다. 이스라엘 집안과 유다 집안이 나를 정말 많이 거역(반대)했어.\\""},{"n":12,"t":"\\"그들이 여호와를 인정하지 않고 말하기를, \'여호와가 안 계신 것이니 우리에게 재앙이 닥치지 않을 것이고, 우리는 칼이나 기근(굶주림)을 보지 않을 거야.\'\\""},{"n":13,"t":"\\"\'선지자들은 바람일 뿐이고, 그들 안에는 진짜 말씀이 없으니 그들이 말한 그대로 그들 자신이 당할 거야\'라고 한단다.\\""},{"n":14,"t":"\\"그러므로 만군의 하나님 여호와가 이렇게 말한다. 그들이 이런 말을 했기 때문에, 보아라, 내가 네 입에 있는 내 말씀을 불처럼 만들고 이 백성을 나무처럼 만들어서 그 불이 그들을 태우게 할 것이다.\\""},{"n":15,"t":"\\"나 여호와가 말한다. 이스라엘아, 보아라. 내가 한 나라를 먼 곳에서 너희에게로 오게 할 거야. 그것은 강하고 오래된 나라야. 너는 그들이 쓰는 말을 알아듣지 못하고 그들의 말이 무슨 뜻인지도 모를 거야.\\""},{"n":16,"t":"\\"그들의 화살통은 (시체를 묻는) 무덤처럼 입을 벌리고 있고, 그 사람들은 모두 용사(전쟁 잘하는 군인)란다.\\""},{"n":17,"t":"\\"그들이 네 자녀들이 먹어야 할 곡식과 양식을 먹어 치우고, 네 양 떼와 소 떼를 먹으며, 네 포도나무와 무화과나무 열매를 먹고, 네가 의지하는 단단한 성들을 칼로 부술 거야.\\""},{"n":18,"t":"\\"나 여호와가 말한다. 그러나 그때에도 내가 너희를 완전히 멸망시키지는 않을 거야.\\""},{"n":19,"t":"\\"그들이 \'우리 하나님 여호와께서 왜 이 모든 일을 우리에게 행하셨을까?\'라고 묻거든, 너는 그들에게 말해라. \'너희가 여호와를 버리고 너희 땅에서 이방 신들을 섬겼으니, 이렇게 너희 것이 아닌 땅에서 이방인을 섬기게 될 것이다.\'\\""},{"n":20,"t":"\\"너는 이것을 야곱 집안에 선포하고 유다에 알려서 말해라.\\""},{"n":21,"t":"\\"어리석고 생각이 없으며 눈이 있어도 보지 못하고 귀가 있어도 듣지 못하는 백성아, 이것을 들어라.\\""},{"n":22,"t":"\\"여호와께서 말씀하신다. \'너희가 나를 두려워하지 않느냐? 내 앞에서 떨지 않겠느냐? 내가 모래를 두어 바다의 경계로 삼고, 그것을 영원한 경계로 정해서 넘지 못하게 했어. 그래서 파도가 거세게 일어나도 그것을 이기지 못하고, 뛰어도 그것을 넘지 못한단다.\'\\""},{"n":23,"t":"\\"그러나 이 백성은 배반하며 거역하는 마음이 있어서 이미 배반하고 떠나갔어.\\""},{"n":24,"t":"\\"또 마음속으로 \'우리에게 이른 비(봄비)와 늦은 비(가을비)를 때에 맞게 주시고, 우리를 위해 추수할 때를 정해 주시는 우리 하나님 여호와를 두려워하자\'라고 말하지도 않았어.\\""},{"n":25,"t":"\\"너희의 잘못이 이 좋은 것들을 물리쳤고, 너희의 죄가 너희에게 올 좋은 것을 막아 버렸어.\\""},{"n":26,"t":"\\"내 백성 너희 가운데 못된 사람들이 있어서, 새 사냥꾼이 숨어 기다리듯이 지켜보고, 덫을 놓아 사람을 잡고 있어.\\""},{"n":27,"t":"\\"새장에 새들이 가득한 것처럼 너희 집에는 속임수가 가득해. 그래서 너희는 점점 부자가 되고 강해지고\\""},{"n":28,"t":"\\"살이 찌고 윤기가 나며, 또 행동이 매우 못되어 자기 이익만 챙기려고 송사(재판)에서, 특히 고아의 송사를 공정하게 처리하지 않고, 가난한 사람의 송사를 공평하게 판결해 주지 않아.\\""},{"n":29,"t":"\\"내가 어찌 이런 일들 때문에 벌하지 않겠느냐? 내 마음이 이런 나라에 어찌 갚지 않겠느냐? 이것은 여호와의 말이야.\\""},{"n":30,"t":"\\"이 땅에 이상하고 놀라운 일이 일어나고 있어.\\""},{"n":31,"t":"\\"선지자들은 거짓을 예언하고, 제사장들은 자기들 마음대로 권력을 휘두르며, 내 백성은 그것을 좋게 여기고 있어. 그렇다면 끝에 너희가 어떻게 하겠느냐?\\""}]}},{"chapter":6,"title":"예루살렘의 함락 예언","verses":{"krv":[{"n":1,"t":"베냐민 자손들아 예루살렘 중에서 피난하라 드고아에서 나팔을 불고 벧학게렘에서 기호를 들라 재앙과 큰 파멸이 북방에서 엿보아 옴이니라"},{"n":2,"t":"아름답고 묘한 딸 시온을 내가 멸절하리니"},{"n":3,"t":"목자들이 그 무리 양을 몰고 와서 그 사면에 자기 장막을 치고 각기 처소에서 먹이리로다"},{"n":4,"t":"너희는 그를 치기를 준비하라 일어나라 우리가 정오에 올라가자 아하 아깝다 날이 기울어 저녁볕 그늘이 길었구나"},{"n":5,"t":"일어나라 우리가 밤으로 올라가서 그 전각들을 헐자 하도다"},{"n":6,"t":"나 만군의 여호와가 이같이 말하노라 너희는 나무를 베어서 예루살렘을 향하여 흉벽을 쌓으라 이는 벌 받을 성이라 그 중에는 오직 포학한 것뿐이니라"},{"n":7,"t":"샘이 그 물을 솟쳐냄 같이 그가 그 악을 발하니 강포와 탈취가 거기서 들리며 질병과 창상이 내 앞에 계속하느니라"},{"n":8,"t":"예루살렘아 너는 훈계를 받으라 그리하지 아니하면 내 마음이 너를 싫어하고 너로 황무케 하여 거민이 없는 땅을 만들리라"},{"n":9,"t":"만군의 여호와께서 이같이 말씀하시되 포도를 땀 같이 그들이 이스라엘의 남은 자를 말갛게 주우리라 너는 포도 따는 자처럼 네 손을 광주리에 자주자주 놀리라 하시나니"},{"n":10,"t":"내가 누구에게 말하며 누구에게 경책하여 듣게 할꼬 보라 그 귀가 할례를 받지 못하였으므로 듣지 못하는도다 보라 여호와의 말씀을 그들이 자기에게 욕으로 여기고 이를 즐겨 아니하니"},{"n":11,"t":"그러므로 여호와의 분노가 내게 가득하여 참기 어렵도다 그것을 거리에 있는 아이들과 모인 청년들에게 부으리니 지아비와 지어미와 노인과 늙은이가 다 잡히리로다"},{"n":12,"t":"여호와께서 말씀하시되 내가 그 땅 거민에게 내 손을 펼 것인즉 그들의 집과 전지와 아내가 타인의 소유로 이전되리니"},{"n":13,"t":"이는 그들이 가장 작은 자로부터 큰 자까지 다 탐남하며 선지자로부터 제사장까지 다 거짓을 행함이라"},{"n":14,"t":"그들이 내 백성의 상처를 심상히 고쳐 주며 말하기를 평강하다 평강하다 하나 평강이 없도다"},{"n":15,"t":"그들이 가증한 일을 행할 때에 부끄러워하였느냐 아니라 조금도 부끄러워 아니할뿐 아니라 얼굴도 붉어지지 않았느니라 그러므로 그들이 엎드러지는 자와 함께 엎드러질 것이라 내가 그들을 벌하리니 그 때에 그들이 거꾸러지리라 여호와의 말이니라"},{"n":16,"t":"여호와께서 이같이 말씀하시되 너희는 길에 서서 보며 옛적 길 곧 선한 길이 어디인지 알아보고 그리로 행하라 너희 심령이 평강을 얻으리라 하나 그들의 대답이 우리는 그리로 행치 않겠노라 하였으며"},{"n":17,"t":"내가 또 너희 위에 파수꾼을 세웠으니 나팔소리를 들으라 하나 그들의 대답이 우리는 듣지 않겠노라 하였도다"},{"n":18,"t":"그러므로 너희 열방아 들으라 회중아 그들의 당할 일을 알라"},{"n":19,"t":"땅이여 들으라 내가 이 백성에게 재앙을 내리리니 이것이 그들의 생각의 결과라 그들이 내 말을 듣지 아니하며 내 법을 버렸음이니라"},{"n":20,"t":"시바에서 유향과 원방에서 향품을 내게로 가져옴은 어찜이뇨 나는 그들의 번제를 받지 아니하며 그들의 희생을 달게 여기지 않노라"},{"n":21,"t":"그러므로 나 여호와가 이같이 말하노라 보라 내가 이 백성 앞에 거침을 두리니 아비와 아들들이 한 가지로 거기 거치며 이웃과 그 친구가 함께 멸망하리라"},{"n":22,"t":"여호와께서 이같이 말씀하시되 보라 한 민족이 북방에서 오며 큰 나라가 땅 끝에서부터 떨쳐 일어나나니"},{"n":23,"t":"그들은 활과 창을 잡았고 잔인하여 자비가 없으며 그 목소리는 바다가 흉용함 같은 자라 그들이 말을 타고 전사 같이 다 항오를 벌이고 딸 시온 너를 치려하느니라 하시도다"},{"n":24,"t":"우리가 그 소문을 들었으므로 손이 약하여졌고 고통이 우리를 잡았으므로 아픔이 해산하는 여인 같도다"},{"n":25,"t":"너희는 밭에도 나가지 말라 길로도 행치 말라 대적의 칼이 있고 사방에 두려움이 있음이니라"},{"n":26,"t":"딸 내 백성이 굵은 베를 두르고 재에서 굴며 독자를 잃음 같이 슬퍼하며 통곡할지어다 멸망시킬 자가 홀연히 우리에게 올 것임이니라"},{"n":27,"t":"주께서 가라사대 내가 이미 너로 내 백성 중에 살피는 자와 요새를 삼아 그들의 길을 알고 살피게 하였노라"},{"n":28,"t":"그들은 다 심히 패역한 자며 다니며 비방하는 자며 그들은 놋과 철이며 다 사악한 자라"},{"n":29,"t":"풀무를 맹렬히 불면 그 불에 납이 살라져서 단련하는 자의 일이 헛되게 되느니라 이와 같이 악한 자가 제하여지지 아니하나니"},{"n":30,"t":"사람들이 그들을 내어버린 은이라 칭하게 될 것은 나 여호와가 그들을 버렸음이니라"}],"kids":[{"n":1,"t":"\\"베냐민 자손들아, 예루살렘에서 빨리 도망쳐라! 드고아에서 나팔을 불고 벧학게렘에서 깃발을 들어라. 재앙(나쁜 일)과 큰 멸망이 북쪽에서 다가오고 있어.\\""},{"n":2,"t":"\\"아름답고 사랑스러운 딸 시온(예루살렘)을 내가 멸망시킬 거야.\\""},{"n":3,"t":"\\"목자(양치는 사람)들이 양 떼를 몰고 와서 그 사방에 천막을 치고, 각자 자기 자리에서 양에게 풀을 먹일 거야.\\""},{"n":4,"t":"\\"너희(적군)는 그를 칠 준비를 해라. 일어나라, 우리가 한낮에 올라가자! 아, 안타깝다. 해가 기울어 저녁 그늘이 길어졌구나.\\""},{"n":5,"t":"\\"일어나라, 우리가 밤에라도 올라가서 그 궁전(전각)들을 부수자.\\""},{"n":6,"t":"\\"나 만군의(엄청 크고 강한) 여호와가 이렇게 말한다. 너희는 나무를 베어서 예루살렘을 향해 흙벽(공격용 흙더미)을 쌓아라. 이는 벌 받을 성이야. 그 안에는 못된 일들만 가득해.\\""},{"n":7,"t":"\\"샘에서 물이 솟아 나오듯이 그 성에서 못된 일이 솟아 나와. 폭력과 도둑질 소리가 거기서 들리고, 병들고 다친 모습이 늘 내 앞에 있어.\\""},{"n":8,"t":"\\"예루살렘아, 너는 가르침(훈계)을 받아라. 그렇지 않으면 내 마음이 너를 싫어해서, 너를 폐허로 만들어 사람이 살지 않는 땅으로 만들 거야.\\""},{"n":9,"t":"\\"만군의 여호와께서 이렇게 말씀하셨어. \'포도를 깨끗이 따듯이 그들이 이스라엘에 남은 사람들까지 다 잡아갈 거야. 너는 포도 따는 사람처럼 네 손을 광주리에 자주자주 넣어라.\'\\""},{"n":10,"t":"\\"내가 누구에게 말하고 누구에게 경고해서 듣게 할까? 보아라, 그들의 귀가 할례를 받지 않아(닫혀 있어) 듣지 못하고, 여호와의 말씀을 자기들에게는 모욕(부끄러운 말)으로 여기고 즐겨 듣지 않아.\\""},{"n":11,"t":"\\"그러므로 여호와의 분노가 내게 가득해서 참기가 힘들어. 그것을 거리의 아이들과 모인 청년들에게 부어 줄 거야. 남편과 아내, 노인과 늙은이까지 다 잡혀갈 거야.\\""},{"n":12,"t":"\\"여호와께서 말씀하셨어. \'내가 그 땅에 사는 사람들에게 손을 펼 것이니, 그들의 집과 밭과 아내가 다른 사람의 것이 될 거야.\\""},{"n":13,"t":"\\"이는 그들이 가장 작은 자(낮은 사람)부터 큰 자(높은 사람)까지 모두 욕심을 부리고, 선지자부터 제사장까지 모두 거짓을 행했기 때문이야.\\""},{"n":14,"t":"\\"그들은 내 백성의 상처를 가볍게 치료해 주면서 \'평안하다, 평안하다\' 말하지만 사실은 평안이 없단다.\\""},{"n":15,"t":"\\"그들이 미운(가증한) 짓을 하고도 부끄러워했느냐? 아니, 조금도 부끄러워하지 않았고, 얼굴도 빨개지지 않았어. 그러므로 그들은 넘어지는 자들과 함께 넘어질 것이고, 내가 그들을 벌할 때 거꾸러질 거야. 이것은 여호와의 말이야.\\""},{"n":16,"t":"\\"여호와께서 이렇게 말씀하셨어. \'너희는 길에 서서 살펴보고, 옛 길 곧 좋은 길이 어디인지 알아보고 그 길로 가라. 그러면 너희 마음이 평안을 얻을 것이다.\' 그러나 그들은 \'우리는 그 길로 가지 않겠다\'라고 대답했어.\\""},{"n":17,"t":"\\"내가 또 너희 위에 파수꾼(망보는 사람)을 세웠으니 \'나팔 소리를 들어라\' 하였지만, 그들은 \'우리는 듣지 않겠다\'라고 대답했어.\\""},{"n":18,"t":"\\"그러므로 너희 나라들아, 들어라. 모인 사람들아, 그들이 당할 일을 알아라.\\""},{"n":19,"t":"\\"땅이여, 들어라. 내가 이 백성에게 재앙을 내릴 거야. 이는 그들 생각의 결과란다. 그들이 내 말을 듣지 않고 내 법(가르침)을 버렸기 때문이야.\\""},{"n":20,"t":"\\"시바(먼 나라)에서 유향(좋은 향)을 가져오고 먼 곳에서 향품(좋은 냄새 나는 것)을 내게 가져오는 게 무슨 소용이냐? 나는 그들의 번제(제물)도 받지 않고, 그들의 희생도 좋게 여기지 않는단다.\\""},{"n":21,"t":"\\"그러므로 나 여호와가 이렇게 말한다. 보아라, 내가 이 백성 앞에 걸림돌(넘어지게 하는 것)을 둘 거야. 아버지와 아들들이 함께 거기에 걸려 넘어지고, 이웃과 친구가 함께 멸망할 거야.\\""},{"n":22,"t":"\\"여호와께서 이렇게 말씀하셨어. \'보아라, 한 민족이 북쪽에서 오고, 큰 나라가 땅 끝에서부터 일어나고 있어.\'\\""},{"n":23,"t":"\\"그들은 활과 창을 잡고 있고, 잔인하여 자비가 없으며, 그들의 목소리는 거센 바다 소리 같아. 그들이 말을 타고 군인처럼 줄을 지어, 시온의 딸 너를 치려고 와.\\""},{"n":24,"t":"\\"우리가 그 소문을 듣고 손이 약해졌고, 고통이 우리를 사로잡아 아기를 낳는 여인처럼 아프단다.\\""},{"n":25,"t":"\\"너희는 밭에도 나가지 말고 길도 다니지 마라. 적의 칼이 있고 사방에 두려움이 있기 때문이야.\\""},{"n":26,"t":"\\"내 백성, 딸 시온아, 굵은 베옷(슬플 때 입는 거친 옷)을 입고 재 위에서 뒹굴며, 외동아들을 잃은 것처럼 슬프게 울고 통곡해라. 멸망시킬 자가 갑자기 우리에게 올 거야.\\""},{"n":27,"t":"\\"주께서 말씀하셨어. \'내가 너를 내 백성 가운데서 살피는 자(검사하는 사람)와 단단한 요새로 삼아, 그들의 길을 알고 살피게 했다.\'\\""},{"n":28,"t":"\\"그들은 모두 매우 거역(반대)하는 자들이고, 돌아다니며 남을 헐뜯는 자들이며, 모두 놋과 철처럼 굳어 있고, 다 못된 짓을 하는 자들이야.\\""},{"n":29,"t":"\\"풀무(쇠를 녹이는 화로)에 거센 불을 붙이면 납이 그 불에 다 녹아 없어져서, 단련하는(쇠를 정련하는) 사람의 일이 헛되게 되는구나. 이처럼 그 못된 자들도 깨끗이 사라지지 않아.\\""},{"n":30,"t":"\\"사람들이 그들을 \'버려진 은(쓸모없는 은)\'이라고 부르게 될 거야. 이는 나 여호와가 그들을 버렸기 때문이야.\\""}]}},{"chapter":7,"title":"성전을 의지하지 말라","verses":{"krv":[{"n":1,"t":"여호와께로서 예레미야에게 말씀이 임하니라 가라사대"},{"n":2,"t":"너는 여호와의 집 문에 서서 이 말을 선포하여 이르기를 여호와께 경배하러 이 문으로 들어가는 유다인아 다 여호와의 말씀을 들으라"},{"n":3,"t":"만군의 여호와 이스라엘의 하나님이 이같이 말씀하시되 너희 길과 행위를 바르게 하라 그리하면 내가 너희로 이곳에 거하게 하리라"},{"n":4,"t":"너희는 이것이 여호와의 전이라, 여호와의 전이라, 여호와의 전이라 하는 거짓말을 믿지 말라"},{"n":5,"t":"너희가 만일 길과 행위를 참으로 바르게 하여 이웃들 사이에 공의를 행하며"},{"n":6,"t":"이방인과 고아와 과부를 압제하지 말며 무죄한 자의 피를 이곳에서 흘리지 아니하며 다른 신들을 좇아 스스로 해하지 아니하면"},{"n":7,"t":"내가 너희를 이곳에 거하게 하리니 곧 너희 조상에게 영원 무궁히 준 이 땅에니라"},{"n":8,"t":"너희가 무익한 거짓말을 의뢰하는도다"},{"n":9,"t":"너희가 도적질하며 살인하며 간음하며 거짓 맹세하며 바알에게 분향하며 너희의 알지 못하는 다른 신들을 좇으면서"},{"n":10,"t":"내 이름으로 일컬음을 받는 이 집에 들어와서 내 앞에 서서 말하기를 우리가 구원을 얻었나이다 하느냐 이는 이 모든 가증한 일을 행하려 함이로다"},{"n":11,"t":"내 이름으로 일컬음을 받는 이 집이 너희 눈에는 도적의 굴혈로 보이느냐 보라 나 곧 내가 그것을 보았노라 여호와의 말이니라"},{"n":12,"t":"너희는 내가 처음으로 내 이름을 둔 처소 실로에 가서 내 백성 이스라엘의 악을 인하여 내가 어떻게 행한 것을 보라"},{"n":13,"t":"나 여호와가 말하노라 이제 너희가 그 모든 일을 행하였으며 내가 너희에게 말하되 새벽부터 부지런히 말하여도 듣지 아니하였고 너희를 불러도 대답지 아니하였느니라"},{"n":14,"t":"그러므로 내가 실로에 행함 같이 너희가 의뢰하는 바 내 이름으로 일컬음을 받는 이 집 곧 너희와 너희 열조에게 준 이곳에 행하겠고"},{"n":15,"t":"내가 너희 모든 형제 곧 에브라임 온 자손을 쫓아냄 같이 내 앞에서 너희를 쫓아내리라 하셨다 할지니라"},{"n":16,"t":"그런즉 너는 이 백성을 위하여 기도하지 말라 그들을 위하여 부르짖어 구하지 말라 내게 간구하지 말라 내가 너를 듣지 아니하리라"},{"n":17,"t":"너는 그들이 유다 성읍들과 예루살렘 거리에서 행하는 일을 보지 못하느냐"},{"n":18,"t":"자식들은 나무를 줍고 아비들은 불을 피우며 부녀들은 가루를 반죽하여 하늘 황후를 위하여 과자를 만들며 그들이 또 다른 신들에게 전제를 부음으로 나의 노를 격동하느니라"},{"n":19,"t":"나 여호와가 말하노라 그들이 나를 격노케 함이냐 어찌 자기 얼굴에 수욕을 자취함이 아니냐"},{"n":20,"t":"그러므로 주 여호와 내가 이같이 말하노라 보라 나의 진노와 분한을 이곳에 붓되 사람과 짐승과 들나무와 땅의 소산에 부으리니 불 같이 살라지고 꺼지지 아니하리라 하시니라"},{"n":21,"t":"만군의 여호와 이스라엘의 하나님이 이같이 말씀하시되 너희 희생에 번제물을 아울러 그 고기를 먹으라"},{"n":22,"t":"대저 내가 너희 열조를 애굽 땅에서 인도하여 낸 날에 번제나 희생에 대하여 말하지 아니하며 명하지 아니하고"},{"n":23,"t":"오직 내가 이것으로 그들에게 명하여 이르기를 너희는 내 목소리를 들으라 그리하면 나는 너희 하나님이 되겠고 너희는 내 백성이 되리라 너희는 나의 명한 모든 길로 행하라 그리하면 복을 받으리라 하였으나"},{"n":24,"t":"그들이 청종치 아니하며 귀를 기울이지도 아니하고 자기의 악한 마음의 꾀와 강퍅한 대로 행하여 그 등을 내게로 향하고 그 얼굴을 향치 아니하였으며"},{"n":25,"t":"너희 열조가 애굽 땅에서 나온 날부터 오늘까지 내가 내 종 선지자들을 너희에게 보내었으되 부지런히 보내었으나"},{"n":26,"t":"너희가 나를 청종치 아니하며 귀를 기울이지 아니하고 목을 굳게 하여 너희 열조보다 악을 더 행하였느니라"},{"n":27,"t":"네가 그들에게 이 모든 말을 할지라도 그들이 너를 청종치 아니할 것이요 네가 그들을 불러도 그들이 네게 대답지 아니하리니"},{"n":28,"t":"너는 그들에게 말하기를 너희는 너희 하나님 여호와의 목소리를 청종치 아니하며 교훈을 받지 아니하는 국민이라 진실이 없어져 너희 입에서 끊어졌다 할지니라"},{"n":29,"t":"예루살렘아 너의 머리털을 베어 버리고 자산 위에서 호곡할지어다 여호와께서 그 노하신 바 이 세대를 끊어버리셨음이니라"},{"n":30,"t":"여호와께서 말씀하시되 유다 자손이 나의 목전에 악을 행하여 내이름으로 일컬음을 받는 집에 그들의 가증한 것을 두어 집을 더럽혔으며"},{"n":31,"t":"힌놈의 아들 골짜기에 도벳 사당을 건축하고 그 자녀를 불에 살랐나니 내가 명하지 아니하였고 내 마음에 생각지도 아니한 일이니라"},{"n":32,"t":"그러므로 나 여호와가 말하노라 날이 이르면 이곳을 도벳이라 하거나 힌놈의 아들의 골짜기라 칭하지 아니하고 살륙의 골짜기라 칭하리니 매장할 자리가 없도록 도벳에 장사함을 인함이니라"},{"n":33,"t":"이 백성의 시체가 공중의 새와 땅 짐승의 밥이 될 것이나 그것을 쫓을 자가 없을 것이라"},{"n":34,"t":"그 때에 내가 유다 성읍들과 예루살렘 거리에 기뻐하는 소리, 즐기는 소리, 신랑의 소리, 신부의 소리가 끊쳐지게 하리니 땅이 황폐하리라"}],"kids":[{"n":1,"t":"여호와께서 예레미야에게 말씀하셨어요."},{"n":2,"t":"\\"너는 여호와의 집(성전) 문에 서서 이 말을 외쳐라. \'여호와께 경배하러 이 문으로 들어오는 유다 사람들아, 모두 여호와의 말씀을 들어라.\'\\""},{"n":3,"t":"\\"만군의 여호와 이스라엘의 하나님이 이렇게 말씀하신다. \'너희가 사는 길과 행동을 바르게 해라. 그러면 내가 너희를 이곳에 살게 해 주겠다.\'\\""},{"n":4,"t":"\\"너희는 \'여호와의 성전이다, 여호와의 성전이다, 여호와의 성전이다\'라고 하는 거짓말을 믿지 마라.\\""},{"n":5,"t":"\\"너희가 만일 정말로 길과 행동을 바르게 해서 이웃들 사이에서 공의(바른 일)를 행하고,\\""},{"n":6,"t":"\\"외국인(이방인)과 고아와 과부를 못살게 굴지 않으며, 죄 없는 사람의 피를 이곳에서 흘리지 않고, 다른 신들을 따라가서 자기를 해치지 않는다면,\\""},{"n":7,"t":"\\"내가 너희를 이곳에, 너희 조상에게 영원히 준 이 땅에 살게 해 줄 거야.\\""},{"n":8,"t":"\\"너희는 쓸모없는 거짓말을 의지하고 있구나.\\""},{"n":9,"t":"\\"너희가 도둑질하고 사람을 죽이고 부정한 짓(간음)을 하고 거짓 맹세를 하며, 바알(거짓 신)에게 향을 피우고 너희가 알지도 못하는 다른 신들을 따라가면서\\""},{"n":10,"t":"\\"내 이름이 붙은 이 집(성전)에 들어와 내 앞에 서서 \'우리가 구원을 얻었어요\'라고 말한다면, 그것은 이 모든 미운 짓을 또 하려는 것 아니냐?\\""},{"n":11,"t":"\\"내 이름이 붙은 이 집이 너희 눈에는 도둑들의 소굴(숨는 곳)로 보이느냐? 보아라, 나도 그것을 다 봤단다. 이것은 여호와의 말이야.\\""},{"n":12,"t":"\\"너희는 내가 처음에 내 이름을 둔 곳, 실로(옛 성소가 있던 곳)에 가서 내 백성 이스라엘의 악함 때문에 내가 어떻게 했는지 보아라.\\""},{"n":13,"t":"\\"나 여호와가 말한다. 이제 너희가 그 모든 일을 행했고, 내가 너희에게 새벽부터 부지런히 말해도 듣지 않았고, 너희를 불러도 대답하지 않았어.\\""},{"n":14,"t":"\\"그러므로 내가 실로에 행한 것처럼, 너희가 의지하는 바 내 이름이 붙은 이 집, 곧 너희와 너희 조상에게 준 이곳에도 똑같이 할 거야.\\""},{"n":15,"t":"\\"내가 너희의 모든 형제, 곧 에브라임의 온 자손을 쫓아낸 것처럼 너희를 내 앞에서 쫓아내겠다.\\""},{"n":16,"t":"\\"그런즉 너는 이 백성을 위해 기도하지 마라. 그들을 위해 부르짖어 구하지도 말고, 내게 빌지도 마라. 내가 너의 말을 듣지 않을 거야.\\""},{"n":17,"t":"\\"너는 그들이 유다 성들과 예루살렘 거리에서 무슨 짓을 하는지 보지 못하느냐?\\""},{"n":18,"t":"\\"자식들은 나무를 줍고, 아버지들은 불을 피우며, 여자들은 가루를 반죽해서 \'하늘의 여왕(거짓 여신)\'을 위해 과자를 만들고, 다른 신들에게 술도 부어 바쳐서 나를 화나게 하고 있어.\\""},{"n":19,"t":"\\"나 여호와가 말한다. 그들이 나를 화나게 하는 거냐? 자기 자신에게 부끄러움을 가져오는 게 아니냐?\\""},{"n":20,"t":"\\"그러므로 주 여호와가 이렇게 말한다. 보아라, 내 분노와 노여움을 이곳에 부을 것이니, 사람과 짐승, 들의 나무와 땅의 소산(곡식과 열매)에 부어서, 불처럼 타오르고 꺼지지 않게 할 거야.\\""},{"n":21,"t":"\\"만군의 여호와 이스라엘의 하나님이 이렇게 말씀하신다. \'너희 희생 제물에 번제(다 태우는 제물)도 함께 합쳐서 그 고기를 너희가 먹어 버려라.\'\\""},{"n":22,"t":"\\"이는 내가 너희 조상들을 애굽 땅에서 이끌어 낸 날에 번제나 희생에 대해서 말하지 않았고 명령하지도 않았기 때문이야.\\""},{"n":23,"t":"\\"오직 내가 이것을 그들에게 명령했어. \'너희는 내 목소리를 들어라. 그러면 나는 너희 하나님이 되겠고, 너희는 내 백성이 될 거야. 너희는 내가 명한 모든 길로 행하라. 그러면 복을 받을 것이다.\'\\""},{"n":24,"t":"\\"그런데 그들은 듣지도 않고, 귀를 기울이지도 않고, 자기들의 못된 마음의 꾀와 고집대로 행해서, 내게 등을 돌리고 얼굴을 향하지 않았어.\\""},{"n":25,"t":"\\"너희 조상들이 애굽 땅에서 나온 날부터 오늘까지 내가 내 종 선지자들을 너희에게 부지런히 보냈어.\\""},{"n":26,"t":"\\"그런데 너희가 내 말을 듣지 않고 귀도 기울이지 않으며, 목을 굳게 해서 너희 조상보다 더 못된 짓을 했어.\\""},{"n":27,"t":"\\"네가 그들에게 이 모든 말을 해도 그들은 너의 말을 듣지 않을 것이고, 네가 불러도 그들이 대답하지 않을 거야.\\""},{"n":28,"t":"\\"그러므로 너는 그들에게 말해라. \'너희는 너희 하나님 여호와의 말을 듣지 않고 가르침을 받지 않는 백성이고, 진실이 사라져 너희 입에서 끊어진 자들이다.\'\\""},{"n":29,"t":"\\"예루살렘아, 네 머리털을 잘라 버리고 산 위에서 슬피 울어라. 여호와께서 화가 나서 이 세대(이 시대 사람들)를 끊어 버리셨으니까.\\""},{"n":30,"t":"\\"여호와께서 말씀하셨어. \'유다 자손이 내 눈앞에서 못된 짓을 했어. 그들이 내 이름이 붙은 집(성전)에 미운(가증한) 우상들을 두어서 그 집을 더럽혔어.\\""},{"n":31,"t":"\\"또 힌놈의 아들 골짜기에 도벳 사당을 짓고 자기 자녀들을 불에 태웠는데, 이것은 내가 명령한 적도 없고 내 마음에 생각한 적도 없는 일이야.\\""},{"n":32,"t":"\\"그러므로 나 여호와가 말한다. 날이 오면 이곳을 더 이상 도벳이나 힌놈의 아들 골짜기라고 부르지 않고 \'죽임의 골짜기\'라고 부를 거야. 묻을 자리가 없어서 도벳에 시신을 묻을 정도가 될 거야.\\""},{"n":33,"t":"\\"이 백성의 시체가 하늘의 새와 땅의 짐승의 먹이가 될 것이고, 그것을 쫓아낼 사람이 없을 거야.\\""},{"n":34,"t":"\\"그때에 내가 유다 성들과 예루살렘 거리에서 기뻐하는 소리, 즐거워하는 소리, 신랑과 신부의 소리가 끊어지게 할 거야. 그래서 땅이 폐허가 될 거야.\\""}]}},{"chapter":8,"title":"치료될 수 없는 상처","verses":{"krv":[{"n":1,"t":"나 여호와가 말하노라 그 때에 사람들이 유다 왕들의 뼈와 그 방백들의 뼈와 제사장들의 뼈와 선지자들의 뼈와 예루살렘 거민의 뼈를 그 묘실에서 끌어내어"},{"n":2,"t":"그들의 사랑하며 섬기며 순종하며 구하며 경배하던 해와 달과 하늘의 뭇 별 아래 쬐리니 그 뼈가 거두이거나 묻히지 못하여 지면에서 분토 같을 것이며"},{"n":3,"t":"이 악한 족속의 남아 있는 자, 무릇 내게 쫓겨나서 각처에 남아 있는 자가 사는 것보다 죽는 것을 원하리라 만군의 여호와의 말이니라"},{"n":4,"t":"너는 또 그들에게 말하기를 여호와의 말씀에 사람이 엎드러지면 어찌 일어나지 아니하겠으며 사람이 떠나갔으면 어찌 돌아오지 아니하겠느냐"},{"n":5,"t":"이 예루살렘 백성이 항상 나를 떠나 물러감은 어찜이뇨 그들이 거짓을 고집하고 돌아오기를 거절하도다"},{"n":6,"t":"내가 귀를 기울여 들은즉 그들이 정직을 말하지 아니하며 그 악을 뉘우쳐서 나의 행한 것이 무엇인고 말하는 자가 없고 전장을 향하여 달리는 말 같이 각각 그 길로 행하도다"},{"n":7,"t":"공중의 학은 그 정한 시기를 알고 반구와 제비와 두루미는 그 올 때를 지키거늘 내 백성은 여호와의 규례를 알지 못하도다 하셨다 하라"},{"n":8,"t":"너희가 어찌 우리는 지혜가 있고 우리에게는 여호와의 율법이 있다 말하겠느뇨 참으로 서기관의 거짓 붓이 거짓되게 하였나니"},{"n":9,"t":"지혜롭다 하는 자들은 수욕을 받으며 경황 중에 잡히리라 보라 그들이 나 여호와의 말을 버렸으니 그들에게 무슨 지혜가 있으랴"},{"n":10,"t":"그러므로 내가 그들의 아내를 타인에게 주겠고 그들의 전지를 그 차지할 자들에게 주리니 그들은 가장 작은 자로부터 큰 자까지 다 탐남하며 선지자로부터 제사장까지 다 거짓을 행함이라"},{"n":11,"t":"그들이 딸 내 백성의 상처를 심상히 고쳐주며 말하기를 평강하다, 평강하다 하나 평강이 없도다"},{"n":12,"t":"그들이 가증한 일을 행할 때에 부끄러워하였느냐 아니라 조금도 부끄러워 아니할 뿐 아니라 얼굴도 붉어지지 아니하였느니라 그러므로 그들이 엎드러질 자와 함께 엎드러질 것이라 내가 그들을 벌할 때에 그들이 거꾸러지리라 여호와의 말이니라"},{"n":13,"t":"여호와께서 말씀하시되 내가 그들을 진멸하리니 포도나무에 포도가 없을 것이며 무화과 나무에 무화과가 없을 것이며 그 잎사귀가 마를 것이라 내가 그들에게 준 것이 없어지리라 하셨나니"},{"n":14,"t":"우리가 어찌 가만히 앉았으랴 모일지어다 우리가 견고한 성읍들로나 들어가서 거기서 멸망하자 우리가 여호와께 범죄하였으므로 우리 하나님 여호와께서 우리를 멸하시며 우리에게 독한 물을 마시우심이니라"},{"n":15,"t":"우리가 평강을 바라나 좋은 것이 없으며 고치심을 입을 때를 바라나 놀라움뿐이로다"},{"n":16,"t":"그 말의 부르짖음이 단에서부터 들리고 그 준마들의 우는 소리에 온 땅이 진동하며 그들이 이르러 이 땅과 그 소유와 성읍과 그 중의 거민을 삼켰도다"},{"n":17,"t":"여호와께서 말씀하시되 내가 술법으로도 제어할 수 없는 뱀과 독사를 너희 중에 보내리니 그것들이 너희를 물리라 하시도다"},{"n":18,"t":"슬프다 나의 근심이여 어떻게 위로를 얻을 수 있을까 나의 중심이 번뇌하도다"},{"n":19,"t":"딸 내 백성의 심히 먼 땅에서 부르짖는 소리로다 이르기를 여호와께서 시온에 계시지 아니한가 그 왕이 그 중에 계시지 아니한가 그러나 여호와께서는 이르시기를 그들이 어찌하여 그 조각한 신상과 이방의 헛된 것들로 나를 격노케 하였는고 하시니"},{"n":20,"t":"추수할 때가 지나고 여름이 다하였으나 우리는 구원을 얻지 못한다 하는도다"},{"n":21,"t":"딸 내 백성이 상하였으므로 나도 상하여 슬퍼하며 놀라움에 잡혔도다"},{"n":22,"t":"길르앗에는 유향이 있지 아니한가 그곳에는 의사가 있지 아니한가 딸 내 백성이 치료를 받지 못함은 어찜인고"}],"kids":[{"n":1,"t":"\\"나 여호와가 말한다. 그때에 사람들이 유다 왕들의 뼈와 높은 사람들의 뼈, 제사장들의 뼈, 선지자들의 뼈, 예루살렘 사람들의 뼈를 무덤에서 꺼낼 거야.\\""},{"n":2,"t":"\\"그들이 사랑하고 섬기고 따르며 구하고 절했던 해와 달과 하늘의 별들 아래에 그 뼈들을 펼쳐 놓을 거야. 그 뼈는 거두어 묻히지도 못하고 땅 위에서 거름(분토)처럼 될 거야.\\""},{"n":3,"t":"\\"이 못된 백성 중에 살아남은 사람들, 내가 쫓아내서 여기저기 흩어져 있는 사람들이 사는 것보다 차라리 죽는 것을 더 원하게 될 거야. 만군의 여호와의 말이야.\\""},{"n":4,"t":"\\"너는 또 그들에게 말해라. \'여호와께서 이렇게 말씀하셨다. 사람이 넘어지면 다시 일어나지 않겠느냐? 사람이 떠났으면 돌아오지 않겠느냐?\'\\""},{"n":5,"t":"\\"이 예루살렘 백성이 늘 나를 떠나 멀어지는 이유가 뭐냐? 그들이 거짓을 고집하고 돌아오기를 거절하는구나.\\""},{"n":6,"t":"\\"내가 귀를 기울여 들어보니 그들은 바른 말을 하지 않고, 자기의 잘못을 뉘우치며 \'내가 무슨 짓을 했나?\'라고 말하는 자가 한 명도 없어. 모두 마치 전쟁터로 달려가는 말처럼 자기 마음대로 가고 있어.\\""},{"n":7,"t":"\\"하늘의 학은 자기가 와야 할 때를 알고, 산비둘기와 제비와 두루미는 돌아올 때를 잘 지키는데, 내 백성은 여호와의 규례(법)를 알지 못하는구나.\' 이렇게 말해라.\\""},{"n":8,"t":"\\"너희가 어찌 \'우리는 지혜가 있고 우리에게는 여호와의 율법(가르침)이 있다\'라고 말할 수 있느냐? 보아라, 서기관(글 쓰는 사람)들의 거짓된 붓이 그 말씀을 거짓으로 만들어 놓았구나.\\""},{"n":9,"t":"\\"지혜롭다고 하는 자들이 부끄러움을 당할 것이고 깜짝 놀라며 잡힐 거야. 보아라, 그들이 나 여호와의 말씀을 버렸으니, 그들에게 무슨 지혜가 있겠느냐?\\""},{"n":10,"t":"\\"그러므로 내가 그들의 아내를 다른 사람에게 주고, 그들의 밭을 차지할 다른 사람에게 줄 거야. 이는 그들이 가장 작은 자부터 큰 자까지 다 욕심을 부리고, 선지자부터 제사장까지 다 거짓을 행했기 때문이야.\\""},{"n":11,"t":"\\"그들이 내 백성, 딸의 상처를 가볍게 치료하면서 \'평안하다, 평안하다\' 하지만, 사실은 평안이 없단다.\\""},{"n":12,"t":"\\"그들이 미운 짓을 하면서 부끄러워했느냐? 아니야. 조금도 부끄러워하지 않고 얼굴도 빨개지지 않았어. 그러므로 그들이 넘어지는 자들과 함께 넘어지고, 내가 벌할 때에 거꾸러질 거야. 이것은 여호와의 말이야.\\""},{"n":13,"t":"\\"여호와께서 말씀하셨어. \'내가 그들을 깨끗이 없앨 거야. 포도나무에 포도가 없을 것이고, 무화과나무에 무화과가 없을 것이고, 그 잎사귀가 마를 거야. 내가 준 모든 것을 잃을 거야.\'\\""},{"n":14,"t":"\\"우리가 어떻게 가만히 앉아 있겠느냐? 함께 모이자. 단단한 성으로라도 들어가서 거기서 죽자. 우리가 여호와께 죄를 지었기 때문에 우리 하나님 여호와께서 우리를 멸하시고 독한 물을 마시게 하셨다.\\""},{"n":15,"t":"\\"우리가 평안을 바랐는데 좋은 것이 없고, 낫게 될 때를 바랐는데 놀라운 일(나쁜 일)뿐이로다.\\""},{"n":16,"t":"\\"적군의 말이 부르짖는 소리가 단(이스라엘 북쪽)에서부터 들리고, 그 좋은 말들이 우는 소리에 온 땅이 흔들려. 그들이 와서 이 땅과 그 안에 있는 모든 것과 성과 그 안의 사람들을 다 삼켜 버렸어.\\""},{"n":17,"t":"\\"여호와께서 말씀하셨어. \'보아라, 내가 마법(술법)으로도 막을 수 없는 뱀과 독사를 너희에게 보내겠다. 그것들이 너희를 물 것이다.\'\\""},{"n":18,"t":"\\"슬프다, 나의 근심이여. 어떻게 위로를 받을 수 있을까? 내 마음이 너무 괴롭다.\\""},{"n":19,"t":"\\"내 백성, 딸의 부르짖는 소리가 아주 먼 땅에서 들려. \'여호와께서 시온에 안 계신가? 그 왕이 그 안에 안 계신가?\' 하는구나. 그러나 여호와께서 말씀하셔. \'그들이 어찌하여 그 새긴 우상들과 이방의 헛된 것들로 나를 화나게 했느냐?\'\\""},{"n":20,"t":"\\"추수할 때가 지나고 여름도 다 갔는데, 우리는 구원을 얻지 못했다고 말하는구나.\\""},{"n":21,"t":"\\"내 백성, 딸이 다쳤기 때문에 나도 다친 것처럼 슬프고 놀랍다.\\""},{"n":22,"t":"\\"길르앗(좋은 약초가 나는 곳)에 유향(좋은 약)이 없느냐? 거기에 의사가 없느냐? 그런데 내 백성, 딸이 어찌하여 치료를 받지 못했단 말이냐?\\""}]}},{"chapter":9,"title":"거짓 학자들에 대한 책망","verses":{"krv":[{"n":1,"t":"어찌하면 내 머리는 물이 되고 내 눈은 눈물 근원이 될꼬 그렇게 되면 살륙 당한 딸 내 백성을 위하여 주야로 곡읍하리로다"},{"n":2,"t":"어찌하면 내가 광야에서 나그네의 유할 곳을 얻을꼬 그렇게 되면 내 백성을 떠나 가리니 그들은 다 행음하는 자요 패역한 자의 무리가 됨이로다"},{"n":3,"t":"여호와께서 말씀하시되 그들이 활을 당김 같이 그 혀를 놀려 거짓을 말하며 그들이 이 땅에서 강성하나 진실하지 아니하고 악에서 악으로 진행하며 또 나를 알지 아니하느니라"},{"n":4,"t":"너희는 각기 이웃을 삼가며 아무 형제든지 믿지 말라 형제마다 온전히 속이며 이웃마다 다니며 비방함이니라"},{"n":5,"t":"그들은 각기 이웃을 속이며 진실을 말하지 아니하며 그 혀로 거짓말 하기를 가르치며 악을 행하기에 수고하거늘"},{"n":6,"t":"네 처소는 궤휼 가운데 있도다 그들은 궤휼로 인하여 나 알기를 싫어하느니라 나 여호와의 말이니라 하시니라"},{"n":7,"t":"만군의 여호와께서 이같이 말씀하시되 보라 내가 내 딸 백성을 어떻게 처치할꼬 그들을 녹이고 연단하리라"},{"n":8,"t":"그들의 혀는 죽이는 살이라 거짓을 말하며 입으로는 그 이웃에게 평화를 말하나 중심에는 해를 도모하는도다"},{"n":9,"t":"내가 이 일들을 인하여 그들에게 벌하지 아니하겠으며 내 마음이 이런 나라에 보수하지 않겠느냐 여호와의 말이니라"},{"n":10,"t":"내가 산들을 위하여 곡하며 부르짖으며 광야 목장을 위하여 슬퍼하나니 이는 그것들이 불에 탔으므로 지나는 자가 없으며 거기서 가축의 소리가 들리지 아니하며 공중의 새도 짐승도 다 도망하여 없어졌음이니라"},{"n":11,"t":"내가 예루살렘으로 무더기를 만들며 시랑의 굴혈이 되게 하겠고 유다 성읍들로 황폐케 하여 거민이 없게 하리라"},{"n":12,"t":"지혜가 있어서 이 일을 깨달을 만한 자가 누구며 여호와의 입의 말씀을 받아서 광포할 자가 누구인고 이 땅이 어찌하여 멸망하여 광야 같이 타서 지나는 자가 없게 되었느뇨"},{"n":13,"t":"여호와께서 말씀하시되 이는 그들이 내가 그들의 앞에 세운 나의 법을 버리고 내 목소리를 청종치 아니하며 그대로 행치 아니하고"},{"n":14,"t":"그 마음의 강퍅함을 따라 그 열조가 자기에게 가르친 바알들을 좇았음이라"},{"n":15,"t":"그러므로 만군의 여호와 이스라엘의 하나님 내가 말하노라 보라 내가 그들 곧 이 백성에게 쑥을 먹이며 독한 물을 마시우고"},{"n":16,"t":"그들과 그들의 조상이 알지 못하던 열국 중에 그들을 헤치고 진멸되기까지 그 뒤로 칼을 보내리라 하셨느니라"},{"n":17,"t":"만군의 여호와께서 이같이 말씀하시되 너희는 잘 생각하고 곡하는 부녀를 불러오며 또 보내어 지혜로운 부녀를 불러오되"},{"n":18,"t":"그들로 빨리 와서 우리를 위하여 애곡하게 하여 우리의 눈에서 눈물이 떨어지게 하며 우리 눈꺼풀에서 물이 쏟아지게 하라"},{"n":19,"t":"이는 시온에서 호곡하는 소리가 들려 이르기를 우리가 아주 망하였구나 우리가 크게 수욕을 당하였구나 우리가 그 땅을 떠난 것은 그들이 우리 주택을 헐었음이로다 함이로다"},{"n":20,"t":"부녀들이여 여호와의 말씀을 들으라 너희 귀에 그 입의 말씀을 받으라 너희 딸 들에게 애곡을 가르치며 각기 이웃에게 애가를 가르치라"},{"n":21,"t":"대저 사망이 우리 창문에 올라오며 우리 궁실에 들어오며 밖에서는 자녀와 거리에서는 청년들을 멸절하려 하느니라"},{"n":22,"t":"너는 이같이 이르라 여호와의 말씀에 사람의 시체가 분토 같이 들에 떨어질 것이며 추수하는 자의 뒤에 떨어지고 거두지 못한 뭇 같이 되리라 하셨느니라"},{"n":23,"t":"여호와께서 이같이 말씀하시되 지혜로운 자는 그 지혜를 자랑치 말라 용사는 그 용맹을 자랑치 말라 부자는 그 부함을 자랑치 말라"},{"n":24,"t":"자랑하는 자는 이것으로 자랑할지니 곧 명철하여 나를 아는 것과 나 여호와는 인애와 공평과 정직을 땅에 행하는 자인줄 깨닫는 것이라 나는 이 일을 기뻐하노라 여호와의 말이니라"},{"n":25,"t":"여호와께서 말씀하시되 날이 이르면 할례 받은 자와 할례 받지 못한 자를 내가 다 벌하리니"},{"n":26,"t":"곧 애굽과 유다와 에돔과 암몬 자손과 모압과 및 광야에 거하여 그 머리털을 모지게 깎은 자들에게라 대저 열방은 할례를 받지 못하였고 이스라엘은 마음에 할례를 받지 못하였느니라 하셨느니라"}],"kids":[{"n":1,"t":"\\"어떻게 하면 내 머리가 물이 되고 내 눈이 눈물의 샘이 될까? 그러면 내가 죽임당한 내 백성, 딸을 위해 밤낮으로 슬피 울 텐데.\\""},{"n":2,"t":"\\"어떻게 하면 광야에 나그네 머무는 곳을 얻을까? 그러면 내가 내 백성을 떠나 그곳으로 갈 텐데. 그들은 모두 음란한(부정한) 자들이고, 거역하는 자들의 무리야.\\""},{"n":3,"t":"\\"여호와께서 말씀하셨어. \'그들이 활을 당기듯이 그 혀를 놀려 거짓을 말하고, 이 땅에서 강해졌지만 진실하지 않고, 못된 일에서 더 못된 일로 나아가며 나를 알지 못한다.\'\\""},{"n":4,"t":"\\"너희는 각자 이웃을 조심하고, 어떤 형제도 믿지 마라. 형제마다 완전히 속이고, 이웃마다 돌아다니며 남을 헐뜯기 때문이야.\\""},{"n":5,"t":"\\"그들은 각자 이웃을 속이고 진실을 말하지 않으며, 자기 혀로 거짓말하는 것을 가르치고, 못된 짓을 하느라고 힘쓰는구나.\\""},{"n":6,"t":"\\"네가 사는 곳은 거짓(궤휼)으로 가득하고, 그들은 거짓 때문에 나를 아는 것을 싫어해. 이것은 나 여호와의 말이야.\\""},{"n":7,"t":"\\"만군의 여호와께서 이렇게 말씀하셨어. \'보아라, 내가 내 딸 백성을 어떻게 할까? 그들을 녹이고 단련(쇠를 정련하듯)할 거야.\'\\""},{"n":8,"t":"\\"그들의 혀는 사람을 죽이는 화살이라, 거짓을 말한다. 입으로는 이웃에게 평화를 말하지만, 마음속으로는 해칠 일을 꾸미는구나.\\""},{"n":9,"t":"\\"내가 이런 일 때문에 그들을 벌하지 않겠느냐? 내 마음이 이런 나라에 어찌 갚지 않겠느냐? 이것은 여호와의 말이야.\\""},{"n":10,"t":"\\"내가 산들을 위해 통곡하고 부르짖으며, 광야의 목장을 위해 슬퍼한다. 이는 그것들이 불에 타서 지나가는 사람도 없고, 거기서 가축 소리도 들리지 않으며, 하늘의 새와 짐승도 다 도망쳐서 없어졌기 때문이야.\\""},{"n":11,"t":"\\"내가 예루살렘을 돌무더기로 만들고, 시랑(이리, 자칼)들이 사는 굴이 되게 할 거야. 또 유다 성읍들도 폐허로 만들어 사는 사람이 없게 할 거야.\\""},{"n":12,"t":"\\"이 일을 깨달을 만큼 지혜로운 사람이 누구냐? 여호와의 입의 말씀을 받아서 알릴 사람이 누구냐? 이 땅이 어찌하여 멸망해서 광야처럼 타 버리고 지나가는 사람도 없게 되었을까?\\""},{"n":13,"t":"\\"여호와께서 말씀하셨어. \'이는 그들이 내가 그들 앞에 세운 내 법(가르침)을 버리고, 내 목소리를 듣지 않고, 그대로 행하지 않으며,\'\\""},{"n":14,"t":"\\"\'자기 마음의 고집대로 행해서, 그 조상들이 가르쳤던 바알들을 따라갔기 때문이야.\'\\""},{"n":15,"t":"\\"그러므로 만군의 여호와 이스라엘의 하나님이 말한다. 보아라, 내가 그들, 곧 이 백성에게 쑥(쓴 풀)을 먹이고 독한 물을 마시게 하겠다.\\""},{"n":16,"t":"\\"그들과 그들의 조상이 알지 못하던 나라들 가운데로 그들을 흩어 버리고, 그들이 다 망할 때까지 그 뒤로 칼을 보내겠다.\\""},{"n":17,"t":"\\"만군의 여호와께서 이렇게 말씀하셨어. \'너희는 잘 생각하고 곡하는(슬피 우는) 여인들을 부르고, 또 사람을 보내 지혜로운 여인들을 부르라.\\""},{"n":18,"t":"\\"\'그들이 빨리 와서 우리를 위해 슬피 울게 해서, 우리 눈에서 눈물이 흐르게 하고, 우리 눈꺼풀에서 물이 쏟아지게 해라.\'\\""},{"n":19,"t":"\\"이는 시온에서 통곡하는 소리가 들려서 \'우리가 완전히 망했구나, 크게 부끄러움을 당했구나. 우리가 그 땅을 떠난 이유는 그들이 우리 집을 헐었기 때문이다\'라고 말하는구나.\\""},{"n":20,"t":"\\"여인들아, 여호와의 말씀을 들어라. 너희 귀에 그분의 입의 말씀을 받아라. 너희 딸들에게 슬피 우는 법을 가르치고, 각자 이웃에게 슬픈 노래(애가)를 가르쳐라.\\""},{"n":21,"t":"\\"이는 죽음(사망)이 우리 창문에 올라오고, 우리 궁궐(집)에 들어오며, 밖에서는 자녀들을, 거리에서는 젊은이들을 없애려 하기 때문이야.\\""},{"n":22,"t":"\\"너는 이렇게 말해라. \'여호와께서 말씀하시기를, 사람의 시체가 거름처럼 들에 떨어질 것이고, 추수하는 자 뒤에 떨어져 거두지 못한 곡식 묶음(뭇)처럼 될 거야.\'\\""},{"n":23,"t":"\\"여호와께서 이렇게 말씀하셨어. \'지혜로운 자는 자기의 지혜를 자랑하지 말고, 용사(힘센 군인)는 자기의 힘을 자랑하지 말고, 부자는 자기의 부유함을 자랑하지 마라.\'\\""},{"n":24,"t":"\\"\'자랑하는 자는 이것으로 자랑해라. 곧 슬기로워서 나를 알고, 나 여호와는 사랑(인애)과 공평과 정직을 땅에 행하는 자인 줄을 깨닫는 것이다. 나는 이런 일을 기뻐한다. 이것은 여호와의 말이야.\'\\""},{"n":25,"t":"\\"여호와께서 말씀하셨어. \'날이 오면 내가 할례를 받은 자와 할례를 받지 못한 자를 모두 벌할 거야.\'\\""},{"n":26,"t":"\\"\'곧 애굽과 유다와 에돔과 암몬 자손과 모압과 광야에 살면서 머리털을 둥글게 깎은 자들이야. 모든 나라들은 몸에 할례를 받지 못했고, 이스라엘은 마음에 할례를 받지 못했어.\'\\""}]}},{"chapter":10,"title":"참 하나님과 우상","verses":{"krv":[{"n":1,"t":"이스라엘 집이여 여호와께서 너희에게 이르시는 말씀을 들을지어다"},{"n":2,"t":"여호와께서 이같이 말씀하시되 열방의 길을 배우지 말라 열방인은 하늘의 징조를 두려워하거니와 너희는 그것을 두려워 말라"},{"n":3,"t":"열방의 규례는 헛된 것이라 그 위하는 것은 삼림에서 벤 나무요 공장의 손이 도끼로 만든 것이라"},{"n":4,"t":"그들이 은과 금으로 그것에 꾸미고 못과 장도리로 그것을 든든히 하여 요동치 않게 하나니"},{"n":5,"t":"그것이 갈린 기둥 같아서 말도 못하며 걸어 다니지도 못하므로 사람에게 메임을 입느니라 그것이 화를 주거나 복을 주지 못하나니 너희는 두려워 말라 하셨느니라"},{"n":6,"t":"여호와여 주와 같은 자 없나이다 주는 크시니 주의 이름이 그 권능으로 인하여 크시니이다"},{"n":7,"t":"열방의 왕이시여 주를 경외치 아니할 자가 누구리이까 이는 주께 당연한 일이라 열방의 지혜로운 자들과 왕족 중에 주와 같은 자 없음이니이다"},{"n":8,"t":"그들은 다 무지하고 어리석은 것이니 우상의 도는 나무뿐이라"},{"n":9,"t":"다시스에서 가져온 은박과 우바스에서 가져온 금으로 꾸미되 공장과 장색의 손으로 만들었고 청색 자색 감으로 그 옷을 삼았나니 이는 공교한 사람의 만든 것이어니와"},{"n":10,"t":"오직 여호와는 참 하나님이시요 사시는 하나님이시요 영원한 왕이시라 그 진노하심에 땅이 진동하며 그 분노하심을 열방이 능히 당치 못하느니라"},{"n":11,"t":"너희는 이같이 그들에게 이르기를 천지를 짓지 아니한 신들은 땅 위에서, 이 하늘 아래서 망하리라 하라"},{"n":12,"t":"여호와께서 그 권능으로 땅을 지으셨고 그 지혜로 세계를 세우셨고 그 명철로 하늘들을 펴셨으며"},{"n":13,"t":"그가 목소리를 발하신즉 하늘에 많은 물이 생기나니 그는 땅 끝에서 구름이 오르게 하시며 비를 위하여 번개하게 하시며 그 곳간에서 바람을 내시거늘"},{"n":14,"t":"사람마다 우준하고 무식하도다 금장색마다 자기의 조각한 신상으로 인하여 수치를 당하나니 이는 그 부어 만든 우상은 거짓 것이요 그 속에 생기가 없음이라"},{"n":15,"t":"그것들은 헛 것이요 망령되이 만든 것인즉 징벌하실 때에 멸망할 것이나"},{"n":16,"t":"야곱의 분깃은 이같지 아니하시니 그는 만물의 조성자요 이스라엘은 그 산업의 지파라 그 이름은 만군의 여호와시니라"},{"n":17,"t":"에워싸인 가운데 앉은 자여 네 꾸러미를 이 땅에서 수습하라"},{"n":18,"t":"여호와께서 이같이 말씀하시되 보라 내가 이 땅에 거하는 자를 이번에는 내어던질 것이라 그들을 괴롭게 하여 깨닫게 하리라 하셨느니라"},{"n":19,"t":"슬프다 내 상처여 내가 중상을 당하였도다 그러나 내가 말하노라 이는 참으로 나의 고난이라 내가 참아야 하리로다"},{"n":20,"t":"내 장막이 훼파되고 나의 모든 줄이 끊어졌으며 내 자녀가 나를 떠나가고 있지 아니하니 내 장막을 세울 자와 내 장을 칠 자가 다시 없도다"},{"n":21,"t":"목자들은 우준하여 여호와를 찾지 아니하므로 형통치 못하며 그 모든 양떼는 흩어졌도다"},{"n":22,"t":"들을지어다 북방에서부터 크게 떠드는 풍성이 오니 유다 성읍들로 황폐케 하여 시랑의 거처가 되게 하리로다"},{"n":23,"t":"여호와여 내가 알거니와 인생의 길이 자기에게 있지 아니하니 걸음을 지도함이 걷는 자에게 있지 아니하니이다"},{"n":24,"t":"여호와여 나를 징계하옵시되 너그러이 하시고 진노로 하지 마옵소서 주께서 나로 없어지게 하실까 두려워하나이다"},{"n":25,"t":"주를 알지 못하는 열방과 주의 이름으로 기도하지 아니하는 족속들에게 주의 분노를 부으소서 그들은 야곱을 씹어 삼켜 멸하고 그 거처를 황폐케 하였나이다"}],"kids":[{"n":1,"t":"이스라엘 집안아, 여호와께서 너희에게 하시는 말씀을 들어라."},{"n":2,"t":"\\"여호와께서 이렇게 말씀하셨어. \'다른 나라들의 길(살아가는 방식)을 배우지 마라. 그들은 하늘의 별이나 달이 보이는 일들을 무서워하지만, 너희는 그것들을 무서워하지 마라.\'\\""},{"n":3,"t":"\\"이방 나라들의 종교 풍습은 헛된 거야. 그들이 섬기는 우상은 숲에서 베어 온 나무이고, 사람의 손이 도끼로 만든 것일 뿐이야.\\""},{"n":4,"t":"\\"그들은 그것을 은과 금으로 꾸미고, 못과 망치(장도리)로 단단히 박아서 흔들리지 않게 해.\\""},{"n":5,"t":"\\"그것은 마치 박아 놓은 기둥(허수아비) 같아서 말도 못 하고 걷지도 못해서 사람이 들어 옮겨야 해. 그것은 화를 주지도 못하고 복을 주지도 못하니, 너희는 무서워하지 마라.\\""},{"n":6,"t":"\\"여호와여, 주와 같은 분이 없으세요. 주는 크시고, 주의 이름은 그 능력 때문에 위대해요.\\""},{"n":7,"t":"\\"여러 나라의 왕이시여, 누가 주를 두려워하지 않겠어요? 이는 주께 마땅한 일이에요. 모든 나라의 지혜로운 사람들과 모든 왕족 중에 주와 같은 분이 없어요.\\""},{"n":8,"t":"\\"그들은 모두 어리석고 무지해요. 우상을 섬기는 가르침은 그저 나무일 뿐이에요.\\""},{"n":9,"t":"\\"다시스에서 가져온 은박과 우바스에서 가져온 금으로 우상을 꾸미고, 장인(만드는 사람)의 손으로 만들고, 푸른색과 보라색 천으로 옷을 입혔어요. 다 솜씨 좋은 사람이 만든 거예요.\\""},{"n":10,"t":"\\"그러나 오직 여호와는 참 하나님이시고, 살아 계신 하나님이시며, 영원한 왕이세요. 그분이 화내시면 땅이 흔들리고, 그분의 분노를 다른 나라들이 견디지 못해요.\\""},{"n":11,"t":"\\"너희는 그들에게 이렇게 말해라. \'하늘과 땅을 만들지 못한 신들은 땅 위에서, 이 하늘 아래서 망할 거야.\'\\""},{"n":12,"t":"\\"여호와께서는 그 능력으로 땅을 지으시고, 그 지혜로 세상을 세우셨고, 그 명철(슬기)로 하늘을 펴셨어요.\\""},{"n":13,"t":"\\"그분이 목소리를 내시면 하늘에 많은 물이 생겨요. 땅 끝에서 구름을 올라오게 하시고, 비를 위해 번개를 치게 하시며, 그 창고에서 바람을 내보내세요.\\""},{"n":14,"t":"\\"사람들은 모두 어리석고 무지해요. 금장식을 만드는 사람은 자기가 새긴 우상 때문에 부끄러움을 당해요. 이는 그가 부어 만든 우상이 거짓이고, 그 안에 생명(생기)이 없기 때문이에요.\\""},{"n":15,"t":"\\"그것들은 헛된 것이고 망령되이(터무니없이) 만든 것이라, 벌하실 때에 다 망할 거예요.\\""},{"n":16,"t":"\\"야곱의 분깃(몫)은 그렇지 않아요. 그분은 만물(모든 것)을 지으신 분이고, 이스라엘은 그분의 산업(귀한 것)인 지파예요. 그분의 이름은 만군의 여호와예요.\\""},{"n":17,"t":"\\"포위된 가운데 앉아 있는 자야, 네 짐 보따리를 이 땅에서 챙겨라.\\""},{"n":18,"t":"\\"여호와께서 이렇게 말씀하셨어. \'보아라, 내가 이번에는 이 땅에 사는 사람들을 던져 버릴 거야. 그들을 괴롭게 해서 깨닫게 할 거야.\'\\""},{"n":19,"t":"\\"슬프다, 내 상처여! 내가 큰 상처를 입었구나. 그러나 내가 말한다. 이는 정말로 내가 견뎌야 할 고난(괴로움)이로다.\\""},{"n":20,"t":"\\"내 천막이 다 부서지고 모든 줄이 끊어졌으며, 내 자녀들이 나를 떠나가서 없어. 내 천막을 다시 세울 사람도 없고, 휘장(천막의 커튼)을 칠 사람도 없구나.\\""},{"n":21,"t":"\\"목자(지도자)들이 어리석어서 여호와를 찾지 않았기 때문에 잘되지 못했고, 그들의 모든 양 떼는 흩어졌어.\\""},{"n":22,"t":"\\"들어라! 북쪽에서 큰 소동(소문) 소리가 와서 유다 성들을 폐허로 만들고 시랑(이리)들의 거처가 되게 할 거야.\\""},{"n":23,"t":"\\"여호와여, 제가 알아요. 사람의 길은 자기에게 있지 않고, 걸음을 인도하는 것은 걷는 자에게 있지 않다는 것을요.\\""},{"n":24,"t":"\\"여호와여, 저를 가르치시되 너그럽게 해 주세요. 화내심으로 하지 마세요. 주께서 저를 없애 버리실까 두려워요.\\""},{"n":25,"t":"\\"주를 알지 못하는 나라들과 주의 이름으로 기도하지 않는 백성들에게 주의 분노를 부어 주세요. 그들이 야곱을 씹어 삼켜 멸했고 그 거처를 폐허로 만들었어요.\\""}]}},{"chapter":11,"title":"언약을 어긴 백성","verses":{"krv":[{"n":1,"t":"여호와께로부터 예레미야에게 임한 말씀이라 가라사대"},{"n":2,"t":"너희는 이 언약의 말을 듣고 유다인과 예루살렘 거민에게 고하라"},{"n":3,"t":"그들에게 이르기를 이스라엘의 하나님 여호와께서 이같이 말씀하시되 이 언약의 말을 좇지 않는 자는 저주를 받을 것이니라"},{"n":4,"t":"이 언약은 내가 너희 열조를 쇠풀무 애굽 땅에서 이끌어 내던 날에 그들에게 명한 것이라 곧 내가 이르기를 너희는 나의 목소리를 청종하고 나의 모든 명령을 좇아 행하라 그리하면 너희는 내 백성이 되겠고 나는 너희 하나님이 되리라"},{"n":5,"t":"내가 또 너희 열조에게 한 맹세 곧 그들에게 젖과 꿀이 흐르는 땅을 주리라 한 언약을 이루리라 한 것인데 오늘날이 그것을 증거하느니라 하라 하시기로 내가 대답하여 가로되 아멘 여호와여 하였노라"},{"n":6,"t":"여호와께서 내게 이르시되 너는 이 모든 말로 유다 성읍들과 예루살렘 거리에서 선포하여 이르기를 너희는 이 언약의 말을 듣고 준행하라"},{"n":7,"t":"내가 너희 열조를 애굽 땅에서 인도하여 낸 날부터 오늘까지 간절히 경계하며 부지런히 경계하기를 너희는 내 목소리를 청종하라 하였으나"},{"n":8,"t":"그들이 청종치 아니하며 귀를 기울이지도 아니하고 각각 그 악한 마음의 강퍅한 대로 행하였으므로 내가 그들에게 행하라 명하였어도 그들이 행치 아니한 이 언약의 모든 말로 그들에게 응하게 하였느니라 하라"},{"n":9,"t":"여호와께서 또 내게 이르시되 유다인과 예루살렘 거민 중에 반역이 있도다"},{"n":10,"t":"그들이 내 말 듣기를 거절한 자기들의 선조의 죄악에 돌아가서 다른 신들을 좇아 섬겼은즉 이스라엘 집과 유다 집이 내가 그 열조와 맺은 언약을 파하였도다"},{"n":11,"t":"그러므로 나 여호와가 이같이 말하노라 보라 내가 재앙을 그들에게 내리리니 그들이 피할 수 없을 것이라 그들이 내게 부르짖을 지라도 내가 듣지 아니할 것인즉"},{"n":12,"t":"유다 성읍들과 예루살렘 거민이 그 분향하는 신들에게 가서 부르짖을지라도 그 신들이 그 곤액 중에서 절대로 그들을 구원치 못하리라"},{"n":13,"t":"유다야 네 신들이 네 성읍의 수효와 같도다 너희가 예루살렘 거리의 수효대로 그 수치되는 물건의 단 곧 바알에게 분향하는 단을 쌓았도다"},{"n":14,"t":"그러므로 너는 이 백성을 위하여 기도하지 말라 그들을 위하여 부르짖거나 구하지 말라 그들이 그 곤액을 인하여 내게 부르짖을 때에 내가 그들을 듣지 아니하리라"},{"n":15,"t":"나의 사랑하는 자가 많이 행음하였으므로 거룩한 제육이 그에게서 떠났거늘 나의 집에서 무엇을 하는고 그가 악을 행하며 기뻐하도다"},{"n":16,"t":"나 여호와가 그 이름을 일컬어 좋은 행실 맺는 아름다운 푸른 감람나무라 하였었으나 큰 소동 중에 그 위에 불을 피웠고 그 가지는 꺾였도다"},{"n":17,"t":"바알에게 분향함으로 나의 노를 격동한 이스라엘 집과 유다 집의 악을 인하여 그를 심은 만군의 여호와 내가 그에게 재앙을 선언하였느니라"},{"n":18,"t":"여호와께서 내게 알게 하셨으므로 내가 그것을 알았나이다 그 때에 주께서 그들의 행위를 내게 보이셨나이다"},{"n":19,"t":"나는 끌려서 잡히러 가는 순한 어린 양과 같으므로 그들이 나를 해하려고 꾀하기를 우리가 그 나무와 과실을 함께 박멸하자 그를 산 자의 땅에서 끊어서 그 이름으로 다시 기억되지 못하게 하자 함을 내가 알지 못하였나이다"},{"n":20,"t":"공의로 판단하시며 사람의 심장을 감찰하시는 만군의 여호와여 나의 원정을 주께 아뢰었사오니 그들에게 대한 주의 보수를 내가 보리이다 하였더니"},{"n":21,"t":"여호와께서 아나돗 사람들에 대하여 이같이 말씀하시되 그들이 네 생명을 취하려고 찾아 이르기를 너는 여호와의 이름으로 예언하지 말라 두렵건대 우리 손에 죽을까 하노라 하도다"},{"n":22,"t":"그러므로 만군의 여호와가 이같이 말하노라 보라 내가 그들을 벌하리니 청년들은 칼에 죽으며 자녀들은 기근에 죽고"},{"n":23,"t":"남는 자가 없으리라 내가 아나돗 사람에게 재앙을 내리리니 곧 그들을 벌할 해에니라"}],"kids":[{"n":1,"t":"여호와께서 예레미야에게 말씀하셨어요."},{"n":2,"t":"\\"너희는 이 언약(약속)의 말을 듣고, 유다 사람들과 예루살렘에 사는 사람들에게 알려라.\\""},{"n":3,"t":"\\"그들에게 말해라. \'이스라엘의 하나님 여호와께서 이렇게 말씀하셨다. 이 언약의 말을 따르지 않는 자는 저주를 받을 거야.\\""},{"n":4,"t":"\\"\'이 언약은 내가 너희 조상들을 쇠 풀무(매우 뜨거운 화로) 같은 애굽 땅에서 이끌어 내던 날에 그들에게 준 거야. 내가 말했지. 너희는 내 목소리를 듣고 내 모든 명령을 따라 행하라. 그러면 너희는 내 백성이 되고, 나는 너희의 하나님이 될 것이다.\\""},{"n":5,"t":"\\"\'내가 또 너희 조상들에게 한 맹세, 곧 그들에게 젖과 꿀이 흐르는 (좋은) 땅을 주겠다고 한 언약을 이루겠다.\' 오늘이 그것을 증거해.\\" 내가 대답했어요. \\"네, 여호와여. 그렇게 하세요!\\""},{"n":6,"t":"여호와께서 내게 말씀하셨어요. \\"너는 이 모든 말을 유다 성과 예루살렘 거리에 외쳐서 말해라. \'너희는 이 언약의 말을 듣고 그대로 행하라.\'\\""},{"n":7,"t":"\\"내가 너희 조상들을 애굽 땅에서 이끌어 낸 날부터 오늘까지 간절히, 부지런히 경고하기를 \'너희는 내 목소리를 들어라\'라고 했어.\\""},{"n":8,"t":"\\"그러나 그들이 듣지 않고 귀도 기울이지 않으며, 각자 자기 못된 마음의 고집대로 행했어. 그래서 그들이 따르지 않은 이 언약의 모든 말씀이 그들에게 그대로 이루어지게 했어.\\""},{"n":9,"t":"여호와께서 또 내게 말씀하셨어요. \\"유다 사람들과 예루살렘에 사는 사람들 가운데 반역(거역하는 일)이 있구나.\\""},{"n":10,"t":"\\"그들이 내 말 듣기를 거절했던 자기 조상의 죄로 다시 돌아가서 다른 신들을 따라 섬겼어. 그러므로 이스라엘 집안과 유다 집안이 내가 그 조상과 맺은 언약을 깨버렸어.\\""},{"n":11,"t":"\\"그러므로 나 여호와가 이렇게 말한다. 보아라, 내가 그들에게 재앙을 내릴 것이고, 그들은 그것을 피할 수 없을 거야. 그들이 내게 부르짖어도 내가 듣지 않을 거야.\\""},{"n":12,"t":"\\"유다 성과 예루살렘 사람들이 그들에게 향을 피우던 신들에게 가서 부르짖어도, 그 신들이 어려움에서 그들을 절대로 구해 주지 못할 거야.\\""},{"n":13,"t":"\\"유다야, 네 신들이 네 성의 수만큼이나 많구나. 너희가 예루살렘 거리의 수만큼 부끄러운 우상의 단(우상에게 제사 드리는 곳), 곧 바알에게 향을 피우는 단을 쌓았어.\\""},{"n":14,"t":"\\"그러므로 너는 이 백성을 위해 기도하지 마라. 그들을 위해 부르짖거나 구하지도 마라. 그들이 어려움 때문에 내게 부르짖을 때 내가 그들을 듣지 않을 거야.\\""},{"n":15,"t":"\\"내가 사랑하는 자가 많은 음란한 일(우상 섬기는 짓)을 했기 때문에 거룩한 제물의 고기가 그에게서 떠났는데도, 그가 내 집에서 무엇을 한다는 거냐? 그가 못된 짓을 하면서 기뻐하는구나.\\""},{"n":16,"t":"\\"나 여호와가 그 이름을 \'좋은 열매를 맺는 푸르고 아름다운 감람나무(올리브나무)\'라고 불렀는데, 큰 소동 가운데 그 위에 불을 피웠고, 그 가지가 꺾여 버렸구나.\\""},{"n":17,"t":"\\"바알에게 향을 피워서 나를 화나게 한 이스라엘 집안과 유다 집안의 악함 때문에, 그들을 심은 만군의 여호와인 내가 그에게 재앙을 선포했어.\\""},{"n":18,"t":"\\"여호와께서 내게 알려 주셨기 때문에 제가 그것을 알았어요. 그때 주께서 그들이 한 짓을 제게 보여 주셨어요.\\""},{"n":19,"t":"\\"저는 도살장으로 끌려가는 순한 어린 양 같은데, 그들이 저를 해치려고 음모를 꾸미는 줄을 몰랐어요. \'우리가 그 나무와 열매를 함께 박멸(없애)하자, 그를 산 자의 땅에서 끊어서 그 이름이 다시 기억되지 않게 하자\' 했어요.\\""},{"n":20,"t":"\\"공의(바른 일)로 판단하시고 사람의 마음(심장)을 살피시는 만군의 여호와여, 제 사정을 주께 아뢰었으니 주께서 그들에게 갚으시는 것을 제가 보겠습니다.\\""},{"n":21,"t":"여호와께서 아나돗 사람들(예레미야의 고향 사람들)에 대해 이렇게 말씀하셨어요. \\"그들이 너의 목숨을 빼앗으려고 와서 \'너는 여호와의 이름으로 예언(말씀 전하기)을 하지 마라. 그러지 않으면 너는 우리 손에 죽을 거야\'라고 했어.\\""},{"n":22,"t":"\\"그러므로 만군의 여호와가 이렇게 말한다. 보아라, 내가 그들을 벌할 거야. 청년들은 칼에 죽고, 자녀들은 기근(굶주림)에 죽을 거야.\\""},{"n":23,"t":"\\"남는 자가 없을 거야. 내가 아나돗 사람들에게 재앙을 내릴 것이니, 곧 그들을 벌하는 그해에 그렇게 할 것이다.\\""}]}},{"chapter":12,"title":"예레미야의 호소","verses":{"krv":[{"n":1,"t":"여호와여 내가 주와 쟁변할 때에는 주는 의로우시니이다 그러나 내가 주께 질문하옵나니 악한 자의 길이 형통하며 패역한 자가 다 안락함은 무슨 연고니이까"},{"n":2,"t":"주께서 그들을 심으시므로 그들이 뿌리가 박히고 장성하여 열매를 맺었거늘 그들의 입은 주께 가까우나 그 마음은 머니이다"},{"n":3,"t":"여호와여 주께서 나를 아시고 나를 보시며 내 마음이 주를 향하여 어떠함을 감찰하시오니 양을 잡으려고 끌어냄과 같이 그들을 끌어 내시되 죽일 날을 위하여 그들을 예비하옵소서"},{"n":4,"t":"언제까지 이 땅이 슬퍼하며 온 지방의 채소가 마르리이까 짐승과 새들도 멸절하게 되었사오니 이는 이 땅 거민이 악하여 스스로 말하기를 그가 우리의 결국을 보지 못하리라 함이니이다"},{"n":5,"t":"네가 보행자와 함께 달려도 피곤하면 어찌 능히 말과 경주하겠느냐 네가 평안한 땅에서는 무사하려니와 요단의 창일한 중에서는 어찌하겠느냐"},{"n":6,"t":"네 형제와 아비의 집이라도 너를 속이며 네 뒤에서 크게 외치나니 그들이 네게 좋은 말을 할지라도 너는 믿지 말지니라"},{"n":7,"t":"내가 내 집을 버리며 내 산업을 내어던져 내 마음의 사랑하는 것을 그 대적의 손에 붙였노니"},{"n":8,"t":"내 산업이 삼림 중의 사자 같이 되어서 나를 향하여 그 소리를 발하는고로 내가 그를 미워하였음이로다"},{"n":9,"t":"내 산업이 내게 대하여는 무늬 있는 매가 아니냐 매들이 그를 에워싸지 아니하느냐 너희는 가서 들짐승들을 모아다가 그것을 삼키게 하라"},{"n":10,"t":"많은 목자가 내 포도원을 훼파하며 내 분깃을 유린하여 나의 낙토로 황무지를 만들었도다"},{"n":11,"t":"그들이 이를 황무케 하였으므로 그 황무지가 나를 향하여 슬퍼하는도다 온 땅이 황무함은 이를 개의하는 자가 없음이로다"},{"n":12,"t":"훼멸하는 자들이 광야 모든 자산 위에 이르렀고 여호와의 칼이 땅 이 끝에서 저 끝까지 삼키니 무릇 혈육 있는 자가 평안치 못하도다"},{"n":13,"t":"무리가 밀을 심어도 가시를 거두며 수고하여도 소득이 없은즉 그 소산으로 인하여 스스로 수치를 당하리니 이는 여호와의 분노를 인함이니라"},{"n":14,"t":"내가 내 백성 이스라엘에게 산업으로 준 산업을 다치는 나의 모든 악한 이웃에게 대하여 나 여호와가 이같이 말하노라 보라 내가 그들을 그 땅에서 뽑아버리겠고 유다 집은 그들 중에서 뽑아내리라"},{"n":15,"t":"내가 그들을 뽑아낸 후에 내가 돌이켜 그들을 긍휼히 여겨서 각 사람을 그 산업으로, 각 사람을 그 땅으로 다시 인도하리니"},{"n":16,"t":"그들이 내 백성의 도를 부지런히 배우며 사는 여호와 내 이름으로 맹세하기를 자기들이 내 백성을 가리켜 바알로 맹세하게 한 것 같이 하면 그들이 내 백성 중에 세움을 입으려니와"},{"n":17,"t":"그들이 그리하지 아니하면 내가 반드시 그 나라를 뽑으리라 뽑아 멸하리라 여호와의 말이니라"}],"kids":[{"n":1,"t":"\\"여호와여, 제가 주와 다투어도(따져도) 주는 의로우세요. 그러나 제가 주께 묻고 싶어요. 왜 못된 자들의 길은 잘되고, 거역하는 자들이 모두 편하게 사는 거예요?\\""},{"n":2,"t":"\\"주께서 그들을 심으셔서 그들이 뿌리를 내리고 자라서 열매를 맺었어요. 그들의 입은 주께 가깝지만 그 마음은 주에게서 멀어요.\\""},{"n":3,"t":"\\"여호와여, 주께서는 저를 아시고, 저를 보시고, 제 마음이 주를 향한 것을 살피세요. 양을 잡으려고 끌어내듯 그들을 끌어내셔서, 죽일 날을 위해 그들을 따로 떼어 두세요.\\""},{"n":4,"t":"\\"이 땅이 언제까지 슬퍼해야 하나요? 온 지방의 풀이 언제까지 마를까요? 짐승과 새들도 사라지게 되었어요. 이는 이 땅 사람들이 못된 짓을 하면서 \'그가 우리의 끝을 보지 못할 것이다\'라고 말했기 때문이에요.\\""},{"n":5,"t":"\\"네가 보행자(걷는 사람)와 함께 달려도 피곤하다면, 어떻게 말과 경주(달리기 시합)할 수 있겠느냐? 네가 평안한 땅에서는 안전하지만, 요단 강물이 넘쳐 흐르는 곳에서는 어떻게 하겠느냐?\\""},{"n":6,"t":"\\"네 형제와 네 아버지의 집안 사람들조차 너를 속이고, 네 뒤에서 큰 소리로 외치니, 그들이 네게 좋은 말을 해도 너는 믿지 마라.\\""},{"n":7,"t":"\\"내가 내 집을 버리고 내 산업(소중한 것)을 던져 버리고, 내 마음이 사랑하는 것(이스라엘)을 그 적의 손에 넘겨 주었어.\\""},{"n":8,"t":"\\"내 산업이 숲 속의 사자처럼 되어서 내게 으르렁댔기 때문에 내가 그를 미워하게 되었어.\\""},{"n":9,"t":"\\"내 산업이 내게 무늬가 있는 매(맹금) 같지 않으냐? 다른 매들이 그를 둘러싸지 않느냐? 너희는 가서 들짐승들을 모아다가 그것을 삼키게 해라.\\""},{"n":10,"t":"\\"많은 목자(외국 지도자들)가 내 포도원을 망쳐 버렸고, 내 분깃(몫)을 짓밟아서, 내 좋은 땅(낙토)을 황무지(폐허)로 만들었어.\\""},{"n":11,"t":"\\"그들이 이를 황무지로 만들어 버려서 그 황무지가 나를 향해 슬퍼하는구나. 온 땅이 황무한데도 이를 마음에 두는 사람이 없어.\\""},{"n":12,"t":"\\"멸망시키는 자들이 광야의 모든 산 위에 이르렀고, 여호와의 칼이 땅 이쪽 끝에서 저쪽 끝까지 다 삼키니, 살아 있는 모든 사람이 평안하지 못해.\\""},{"n":13,"t":"\\"사람들이 밀을 심어도 가시를 거두고, 수고해도 얻는 것이 없으니, 그 곡식 때문에 부끄러움을 당할 거야. 이는 여호와의 분노 때문이야.\\""},{"n":14,"t":"\\"내가 내 백성 이스라엘에게 산업으로 준 그 땅을 빼앗으려 하는 모든 못된 이웃 나라들에 대하여 나 여호와가 이렇게 말한다. 보아라, 내가 그들을 그 땅에서 뽑아 버리고, 유다 집은 그들 중에서 뽑아낼 거야.\\""},{"n":15,"t":"\\"내가 그들을 뽑아낸 후에 다시 마음을 돌이켜 그들을 불쌍히 여겨서, 각 사람을 자기 산업으로, 각 사람을 자기 땅으로 다시 인도할 거야.\\""},{"n":16,"t":"\\"그들이 내 백성의 길(가르침)을 부지런히 배우고, 옛날에 자기들이 내 백성에게 바알의 이름으로 맹세하라고 가르친 것처럼, 이제 살아 계신 여호와의 이름으로 맹세하면, 그들도 내 백성 가운데 세워지게 될 거야.\\""},{"n":17,"t":"\\"그러나 그들이 그렇게 하지 않으면 내가 반드시 그 나라를 뽑아내고, 뽑아 멸할 거야. 이것은 여호와의 말이야.\\""}]}},{"chapter":13,"title":"허리띠 비유","verses":{"krv":[{"n":1,"t":"여호와께서 이같이 내게 이르시되 너는 가서 베띠를 사서 네 허리에 띠고 물에 두지 말라 하시기로"},{"n":2,"t":"내가 여호와의 말씀대로 띠를 사서 내 허리에 띠니라"},{"n":3,"t":"여호와의 말씀이 다시 내게 임하니라 가라사대"},{"n":4,"t":"너는 사서 네 허리에 띤 띠를 가지고 일어나 유브라데로 가서 거기서 그것을 바위 틈에 감추라 하시기로"},{"n":5,"t":"내가 여호와께서 내게 명하신 대로 가서 그것을 유브라데 물 가에 감추니라"},{"n":6,"t":"여러 날 후에 여호와께서 내게 이르시되 일어나 유브라데로 가서 내가 네게 명하여 거기 감추게 한 띠를 취하라 하시기로"},{"n":7,"t":"내가 유브라데로 가서 그 감추었던 곳을 파고 띠를 취하니 띠가 썩어서 쓸데 없이 되었더라"},{"n":8,"t":"여호와의 말씀이 내게 임하니라 가라사대"},{"n":9,"t":"나 여호와가 말하노라 내가 유다의 교만과 예루살렘의 큰 교만을 이같이 썩게 하리라"},{"n":10,"t":"이 악한 백성이 내 말 듣기를 거절하고 그 마음의 강퍅한 대로 행하며 다른 신들을 좇아 그를 섬기며 그에게 절하니 그들이 이 띠의 쓸데 없음 같이 되리라"},{"n":11,"t":"나 여호와가 말하노라 띠가 사람의 허리에 속함 같이 내가 이스라엘 온 집과 유다 온 집으로 내게 속하게 하여 그들로 내 백성이 되게 하며 내 이름과 칭예와 영광이 되게 하려 하였으나 그들이 듣지 아니하였느니라"},{"n":12,"t":"그러므로 너는 이 말로 그들에게 이르기를 이스라엘의 하나님 여호와의 말씀에 모든 병이 포도주로 차리라 하셨다 하라 그리하면 그들이 네게 이르기를 모든 병이 포도주로 찰줄을 우리가 어찌 알지 못하리요 하리니"},{"n":13,"t":"너는 다시 그들에게 이르기를 여호와의 말씀에 보라 내가 이 땅의 모든 거민과 다윗의 위에 앉은 왕들과 제사장들과 선지자들과 예루살렘 모든 거민으로 잔뜩 취하게 하고"},{"n":14,"t":"또 그들로 피차 충돌하여 상하게 하되 부자간에도 그러하게 할 것이라 내가 그들을 불쌍히 여기지 아니하며 관용치 아니하며 아끼지 아니하고 멸하리라 하셨다 하라 여호와의 말이니라"},{"n":15,"t":"너희는 들을지어다, 귀를 기울일지어다, 교만하지 말지어다, 여호와께서 이같이 말씀하시느니라"},{"n":16,"t":"그가 흑암을 일으키시기전, 너희 발이 흑암한 산에 거치기전, 너희 바라는 빛이 사망의 그늘로 변하여 침침한 흑암이 되게 하시기 전에 너희 하나님 여호와께 영광을 돌리라"},{"n":17,"t":"너희가 이를 듣지 아니하면 나의 심령이 너희 교만을 인하여 은근히 곡할 것이며 여호와의 양무리가 사로잡힘을 인하여 눈물을 흘려 통곡하리라"},{"n":18,"t":"너는 왕과 왕후에게 고하기를 스스로 낮추어 앉으라 관 곧 영광의 면류관이 내려졌다 하라"},{"n":19,"t":"남방의 성읍들이 봉쇄되고 열 자가 없고 유다가 다 잡혀가되 온전히 잡혀가도다"},{"n":20,"t":"너는 눈을 들어 북방에서 오는 자들을 보라 네가 받았던 떼, 네 아름다운 양떼는 어디 있느뇨"},{"n":21,"t":"너의 친구 삼았던 자를 그가 네 위에 수령으로 세우실 때에 네가 무슨 말을 하겠느냐 너의 고통에 잡힘이 구로하는 여인 같지 않겠느냐"},{"n":22,"t":"네가 심중에 이르기를 어찌하여 이런 일이 내게 임하였는고 하겠으나 네 죄악이 크므로 네 치마가 들리고 네 발뒤꿈치가 상함이니라"},{"n":23,"t":"구스인이 그 피부를, 표범이 그 반점을 변할 수 있느뇨 할 수 있을진대 악에 익숙한 너희도 선을 행할 수 있으리라"},{"n":24,"t":"그러므로 내가 그들을 사막 바람에 불려가는 초개 같이 흩으리로다"},{"n":25,"t":"여호와께서 가라사대 이는 네 응득이요 내가 헤아려 정하여 네게 준 분깃이니 네가 나를 잊어버리고 거짓을 신뢰하는 연고라"},{"n":26,"t":"그러므로 내가 네 치마를 네 얼굴에까지 들춰서 네 수치를 드러내리라"},{"n":27,"t":"내가 너의 간음과 사특한 소리와 들의 작은 산 위에서 행한 네 음행의 비루하고 가증한 것을 보았노라 화 있을진저 예루살렘이여 네가 얼마나 오랜 후에야 정결하게 되겠느뇨"}],"kids":[{"n":1,"t":"여호와께서 내게 이렇게 말씀하셨어요. \\"너는 가서 베(천)로 만든 띠(허리띠)를 사서 네 허리에 매고, 물에는 담그지 마라.\\""},{"n":2,"t":"그래서 내가 여호와의 말씀대로 띠를 사서 허리에 맸어요."},{"n":3,"t":"여호와의 말씀이 다시 내게 들려왔어요."},{"n":4,"t":"\\"네가 사서 허리에 맨 띠를 가지고 일어나 유브라데(큰 강)로 가서, 그것을 바위 틈에 감춰라.\\""},{"n":5,"t":"내가 여호와께서 내게 명령하신 대로 가서 그것을 유브라데 강가에 감췄어요."},{"n":6,"t":"여러 날이 지난 후에 여호와께서 내게 말씀하셨어요. \\"일어나 유브라데로 가서, 내가 너에게 거기 감추라고 명령한 띠를 가져와라.\\""},{"n":7,"t":"내가 유브라데로 가서 감춰 둔 곳을 파고 띠를 꺼냈는데, 그 띠가 다 썩어서 쓸모없게 되어 있었어요."},{"n":8,"t":"여호와의 말씀이 내게 들려왔어요."},{"n":9,"t":"\\"나 여호와가 말한다. 내가 유다의 교만과 예루살렘의 큰 교만을 이렇게 썩게 만들 거야.\\""},{"n":10,"t":"\\"이 못된 백성이 내 말 듣기를 거절하고, 자기 마음의 고집대로 행하며, 다른 신들을 따라가서 그들을 섬기고 그들에게 절했어. 그래서 그들이 이 띠처럼 쓸모없게 될 거야.\\""},{"n":11,"t":"\\"나 여호와가 말한다. 띠가 사람의 허리에 딱 붙어 있는 것처럼, 내가 이스라엘 온 집안과 유다 온 집안을 내게 속하게 해서 그들이 내 백성이 되게 하고, 내 이름의 자랑(칭예)과 영광이 되게 하려 했지만, 그들이 듣지 않았어.\\""},{"n":12,"t":"\\"그러므로 너는 이 말로 그들에게 말해라. \'이스라엘의 하나님 여호와께서 모든 병(가죽 부대)에 포도주가 가득 찰 거라고 말씀하신다.\' 그러면 그들이 너에게 \'모든 병에 포도주가 가득 찬다는 것을 우리가 어찌 모르겠느냐?\'라고 할 거야.\\""},{"n":13,"t":"\\"너는 다시 그들에게 말해라. \'여호와께서 이렇게 말씀하셨다. 보아라, 내가 이 땅의 모든 사람과 다윗의 자리(왕좌)에 앉은 왕들과 제사장들과 선지자들과 예루살렘의 모든 사람을 잔뜩 취하게 만들 거야.\'\\""},{"n":14,"t":"\\"\'그리고 그들이 서로 부딪쳐 다치게 할 것이고, 아버지와 아들 사이도 그렇게 할 거야. 내가 그들을 불쌍히 여기지 않고, 봐주지도 않고, 아끼지도 않고 멸할 거야.\' 이것은 여호와의 말씀이야.\\""},{"n":15,"t":"\\"너희는 들어라, 귀를 기울여라, 교만하지 마라. 여호와께서 이렇게 말씀하셨어.\\""},{"n":16,"t":"\\"그분이 어둠을 일으키시기 전, 너희 발이 어두운 산에서 걸려 넘어지기 전, 너희가 바라는 빛이 죽음의 그늘로 바뀌어 침침한 어둠이 되기 전에, 너희 하나님 여호와께 영광을 돌려라.\\""},{"n":17,"t":"\\"너희가 이것을 듣지 않으면, 내 영혼이 너희의 교만 때문에 몰래 슬퍼할 것이고, 여호와의 양 떼가 사로잡혀 갔기 때문에 눈물을 흘리며 통곡할 거야.\\""},{"n":18,"t":"\\"너는 왕(여호야긴)과 왕비(왕후)에게 말해라. \'낮은 자리에 앉아라. 너희의 관, 곧 영광스러운 왕관(면류관)이 떨어졌다.\'\\""},{"n":19,"t":"\\"남쪽 성들이 닫혀서 들어갈 사람이 없어졌고, 유다가 다 잡혀가서 완전히 끌려갔구나.\\""},{"n":20,"t":"\\"너는 눈을 들어 북쪽에서 오는 자들을 보아라. 너에게 맡겨졌던 양 떼, 네 아름다운 양 떼는 어디 있느냐?\\""},{"n":21,"t":"\\"네가 친구로 삼았던 자(외국 동맹국)를 그분께서 너 위에 우두머리로 세우실 때, 네가 무슨 말을 하겠느냐? 네가 고통에 사로잡혀 마치 아기를 낳으려는 여인처럼 아프지 않겠느냐?\\""},{"n":22,"t":"\\"네가 마음속으로 \'왜 이런 일이 내게 일어났을까?\'라고 말하겠지만, 그건 네 죄가 크기 때문이야. 그래서 네 치마가 들춰지고 네 발뒤꿈치가 상하게 되는 거야.\\""},{"n":23,"t":"\\"에티오피아 사람(구스인)이 자기 피부 색깔을 바꿀 수 있겠느냐? 표범이 자기 점을 바꿀 수 있겠느냐? 그렇게 할 수 있다면, 못된 일에 익숙해진 너희도 좋은 일을 할 수 있을 거야.\\""},{"n":24,"t":"\\"그러므로 내가 그들을 사막의 바람에 날리는 지푸라기(초개)처럼 흩어 버릴 거야.\\""},{"n":25,"t":"\\"여호와께서 말씀하셨어. \'이것은 네가 받을 만한 것이고, 내가 측량해서 너에게 정해 준 몫이야. 네가 나를 잊어버리고 거짓을 의지했기 때문이야.\'\\""},{"n":26,"t":"\\"그러므로 내가 네 치마를 네 얼굴까지 들춰서 너의 부끄러움을 드러내겠다.\\""},{"n":27,"t":"\\"내가 너의 간음(부정한 짓)과 음란한 소리, 들의 작은 산 위에서 행한 너의 음란한 일과 미운(가증한) 일을 다 보았다. 화 있을진저, 예루살렘이여! 네가 얼마나 더 오랜 후에야 깨끗하게 되겠느냐?\\""}]}},{"chapter":14,"title":"가뭄과 거짓 선지자","verses":{"krv":[{"n":1,"t":"가뭄에 대하여 예레미야에게 임한 여호와의 말씀이라"},{"n":2,"t":"유다가 슬퍼하며 성문의 무리가 곤비하여 땅에 앉아 애통하니 예루살렘의 부르짖음이 위에 오르도다"},{"n":3,"t":"귀인들은 자기 사환들을 보내어 물을 길으라 하나 그들이 우물에 갔어도 물을 얻지 못하여 빈 그릇으로 돌아오니 부끄럽고 근심하여 그 머리를 가리우며"},{"n":4,"t":"땅에 비가 없어 지면이 갈라지니 밭가는 자가 부끄러워서 그 머리를 가리는도다"},{"n":5,"t":"들의 암사슴은 새끼를 낳아도 풀이 없으므로 내어버리며"},{"n":6,"t":"들나귀들은 자산 위에 서서 시랑 같이 헐떡이며 풀이 없으므로 눈이 아득하여 하는도다"},{"n":7,"t":"여호와여 우리의 죄악이 우리에게 대하여 증거할지라도 주는 주의 이름을 위하여 일하소서 우리의 타락함이 많으니이다 우리가 주께 범죄하였나이다"},{"n":8,"t":"이스라엘의 소망이시요 곤란한 때의 구원자시여 어찌하여 이 땅에서 거류하는 자 같이, 하룻밤을 유숙하는 행인 같이 하시나이까"},{"n":9,"t":"어찌하여 놀라 벙벙하는 자 같으시며 구원치 못하는 용사 같으시니이까 여호와여 주는 오히려 우리 중에 계시고 우리는 주의 이름으로 일컬음을 받는 자이오니 우리를 버리지 마옵소서"},{"n":10,"t":"여호와께서 이 백성에 대하여 말씀하시되 그들이 어그러진 길을 사랑하여 그 발을 금하지 아니하므로 나 여호와가 그들을 받지 아니하고 이제 그들의 죄를 기억하고 그 죄를 벌하리라 하시고"},{"n":11,"t":"여호와께서 또 내게 이르시되 너는 이 백성을 위하여 복을 구하지 말라"},{"n":12,"t":"그들이 금식할지라도 내가 그 부르짖음을 듣지 아니하겠고 번제와 소제를 드릴지라도 내가 그것을 받지 아니할 뿐 아니라 칼과 기근과 염병으로 그들을 멸하리라"},{"n":13,"t":"이에 내가 가로되 슬프도소이다 주 여호와여 보시옵소서 선지자들이 그들에게 이르기를 너희가 칼을 보지 아니하겠고 기근은 너희에게 이르지 아니할 것이라 여호와께서 이곳에서 너희에게 확실한 평강을 주시리라 하나이다"},{"n":14,"t":"여호와께서 내게 이르시되 선지자들이 내 이름으로 거짓 예언을 하도다 나는 그들을 보내지 아니하였고 그들에게 명하거나 이르지 아니하였거늘 그들이 거짓 계시와 복술과 허탄한 것과 자기 마음의 속임으로 너희에게 예언하도다"},{"n":15,"t":"그러므로 내가 보내지 아니하였어도 내 이름으로 예언하여 이르기를 칼과 기근이 이 땅에 이르지 아니하리라 하는 선지자들에 대하여 나 여호와가 이같이 이르노라 그 선지자들은 칼과 기근에 멸망할 것이요"},{"n":16,"t":"그들의 예언을 받은 백성은 기근과 칼로 인하여 예루살렘 거리에 던짐을 입을 것인즉 그들을 장사할 자가 없을 것이요 그 아내와 그 아들과 그 딸도 그렇게 되리니 이는 내가 그들의 악을 그 위에 부음이니라"},{"n":17,"t":"너는 이 말로 그들에게 이르라 내 눈이 밤낮으로 끊치지 아니하고 눈물을 흘리리니 이는 처녀 딸 내 백성이 큰 파멸, 중한 창상을 인하여 망함이라"},{"n":18,"t":"내가 들에 나간즉 칼에 죽은 자요 내가 성에 들어간즉 기근으로 병든 자며 선지자나 제사장이나 다 땅에 두루 다니며 어찌할 바를 알지 못하는도다"},{"n":19,"t":"주께서 유다를 온전히 버리시나이까 주의 심령이 시온을 싫어하시나이까 어찌하여 우리를 치시고 치료하지 아니하시나이까 우리가 평강을 바라도 좋은 것이 없고 치료받기를 기다려도 놀람을 보나이다"},{"n":20,"t":"여호와여 우리가 우리의 악과 우리 조상의 죄악을 인정하나이다 우리가 주께 범죄하였나이다"},{"n":21,"t":"주의 이름을 위하여 우리를 미워하지 마옵소서 주의 영광의 위를 욕되게 마옵소서 우리와 세우신 주의 언약을 기억하시고 폐하지 마옵소서"},{"n":22,"t":"열방의 허무한 것 중에 능히 비를 내리게 할 자가 있나이까 하늘이 능히 소나기를 내릴 수 있으리이까 우리 하나님 여호와여 그리하는 자가 주가 아니시니이까 그러므로 우리가 주를 앙망하옵는 것은 주께서 이 모든 것을 만드셨음이니이다"}],"kids":[{"n":1,"t":"가뭄(비가 오지 않는 일)에 대해 예레미야에게 하나님께서 하신 말씀이에요."},{"n":2,"t":"\\"유다가 슬퍼하고, 성문 앞에 모인 사람들이 지쳐서 땅에 주저앉아 슬퍼하는데, 예루살렘의 부르짖는 소리가 위로 올라가는구나.\\""},{"n":3,"t":"\\"귀한(신분 높은) 사람들이 자기 일꾼들을 보내 물을 길어 오라고 했지만, 그들이 우물에 가도 물을 얻지 못해 빈 그릇을 들고 돌아오니, 부끄럽고 걱정이 되어 머리를 가렸어.\\""},{"n":4,"t":"\\"땅에 비가 오지 않아 땅바닥이 갈라졌고, 밭 가는 농부도 부끄러워서 머리를 가리는구나.\\""},{"n":5,"t":"\\"들의 암사슴은 새끼를 낳고도 풀이 없어서 새끼를 버리고,\\""},{"n":6,"t":"\\"들나귀(야생 당나귀)들은 산 위에 서서 시랑(이리)처럼 헐떡거리고, 풀이 없어서 눈이 흐려져.\\""},{"n":7,"t":"\\"여호와여, 우리의 죄가 우리를 고발하더라도 주의 이름을 위하여 일해 주세요. 우리의 잘못이 많고, 우리가 주께 죄를 지었어요.\\""},{"n":8,"t":"\\"이스라엘의 소망이시고, 어려울 때 구원해 주시는 분이여! 어찌하여 이 땅에서 잠깐 머무는 나그네처럼, 하룻밤만 묵고 가는 사람처럼 행동하세요?\\""},{"n":9,"t":"\\"어찌하여 깜짝 놀라 정신을 차리지 못하는 사람처럼, 구하지 못하는 용사(군인)처럼 보이세요? 여호와여, 주는 우리 가운데 계시고, 우리는 주의 이름이 붙은 사람들이에요. 우리를 버리지 마세요!\\""},{"n":10,"t":"여호와께서 이 백성에 대해 말씀하셨어요. \\"그들이 잘못된 길을 좋아해서 발걸음을 멈추지 않으니, 나 여호와가 그들을 받지 않는다. 이제 그들의 죄를 기억하고 그 죄를 벌할 거야.\\""},{"n":11,"t":"여호와께서 또 내게 말씀하셨어요. \\"너는 이 백성을 위해 복을 구하지 마라.\\""},{"n":12,"t":"\\"그들이 금식(밥 안 먹기)을 해도 내가 그들의 부르짖음을 듣지 않을 것이고, 번제(불사르는 제물)와 소제(곡식 제물)를 드려도 내가 받지 않을 거야. 오히려 칼과 기근(굶주림)과 염병(전염병)으로 그들을 멸할 거야.\\""},{"n":13,"t":"내가 말했어요. \\"아, 슬퍼요! 주 여호와여, 보세요. 선지자들이 그들에게 \'너희는 칼을 보지 않을 것이고, 기근(굶주림)도 너희에게 오지 않을 것이며, 여호와께서 이곳에서 너희에게 진짜 평안을 주실 거야\'라고 말하고 있어요.\\""},{"n":14,"t":"여호와께서 내게 말씀하셨어요. \\"선지자들이 내 이름으로 거짓 예언을 하고 있구나. 나는 그들을 보내지 않았고, 그들에게 명령하거나 말한 적도 없어. 그런데 그들이 거짓 환상과 점쟁이의 말과 헛된 것과 자기 마음의 속임수로 너희에게 예언하고 있어.\\""},{"n":15,"t":"\\"그러므로 나 여호와가 이렇게 말한다. 내가 보내지 않았는데도 내 이름으로 예언하면서 \'칼과 기근이 이 땅에 오지 않을 것이다\'라고 하는 그 선지자들에 대해서는, 그 선지자들이 칼과 기근으로 멸망당할 거야.\\""},{"n":16,"t":"\\"그들의 예언을 들은 백성도 기근과 칼 때문에 예루살렘 거리에 던져질 것이고, 그들을 묻어 줄 사람이 없을 거야. 그들의 아내와 아들과 딸도 그렇게 될 거야. 이는 내가 그들의 죄를 그들 위에 부어 버릴 것이기 때문이야.\\""},{"n":17,"t":"\\"너는 이 말로 그들에게 말해라. \'내 눈이 밤낮으로 그치지 않고 눈물을 흘릴 거야. 이는 처녀 딸 내 백성이 큰 재앙과 깊은 상처로 망했기 때문이야.\'\\""},{"n":18,"t":"\\"내가 들에 나가니 칼에 죽은 사람들이 있고, 성에 들어가니 굶주려 병든 사람들이 있어. 선지자나 제사장이나 모두 어찌할 줄 모르고 땅을 헤매고 있구나.\\""},{"n":19,"t":"\\"주께서 유다를 완전히 버리시는 거예요? 주의 마음이 시온을 싫어하시는 거예요? 어찌하여 우리를 치시고 치료해 주지 않으시나요? 우리가 평안을 바라도 좋은 것이 없고, 치료받기를 기다려도 무서운 일만 보여요.\\""},{"n":20,"t":"\\"여호와여, 우리가 우리의 잘못과 우리 조상의 죄를 인정해요. 우리가 주께 죄를 지었어요.\\""},{"n":21,"t":"\\"주의 이름을 위해 우리를 미워하지 마세요. 주의 영광스러운 자리를 부끄럽게 하지 마세요. 우리와 세우신 주의 언약을 기억하시고 깨지 말아 주세요.\\""},{"n":22,"t":"\\"이방 나라들의 헛된 우상 가운데 비를 내리게 할 수 있는 것이 있어요? 하늘이 스스로 소나기를 내릴 수 있어요? 우리 하나님 여호와여, 그리하시는 분이 주가 아니세요? 그러므로 우리가 주를 바라보아요. 주께서 이 모든 것을 만드셨기 때문이에요.\\""}]}},{"chapter":15,"title":"선지자의 탄식","verses":{"krv":[{"n":1,"t":"여호와께서 내게 이르시되 모세와 사무엘이 내 앞에 섰다 할지라도 내 마음은 이 백성을 향할 수 없나니 그들을 내 앞에서 쫓아내치라"},{"n":2,"t":"그들이 만일 네게 말하기를 우리가 어디로 나아가리요 하거든 너는 그들에게 이르기를 여호와의 말씀에 사망할 자는 사망으로 나아가고 칼을 받을 자는 칼로 나아가고 기근을 당할 자는 기근으로 나아가고 포로 될 자는 포로 됨으로 나아갈지니라 하셨다 하라"},{"n":3,"t":"나 여호와가 말하노라 내가 그들을 네 가지로 벌하리니 곧 죽이는 칼과 찢는 개와 삼켜 멸하는 공중의 새와 땅의 짐승으로 할 것이며"},{"n":4,"t":"유다 왕 히스기야의 아들 므낫세가 예루살렘에 행한 바를 인하여 내가 그들을 세계 열방 중에 흩으리라"},{"n":5,"t":"예루살렘아 너를 불쌍히 여길 자 누구며 너를 곡할 자 누구며 돌이켜 네 평안을 물을 자 누구뇨"},{"n":6,"t":"여호와께서 가라사대 네가 나를 버렸고 내게서 물러갔으므로 네게로 내 손을 펴서 너를 멸하였노니 이는 내가 뜻을 돌이키기에 염증이 났음이로다"},{"n":7,"t":"내가 그들을 그 땅의 여러 성문에서 키로 까불러 그 자식을 끊어서 내 백성을 멸하였나니 이는 그들이 그 길에서 돌이키지 아니하였음이라"},{"n":8,"t":"그들의 과부가 내 앞에 바다 모래보다 더 많아졌느니라 내가 대낮에 훼멸할 자를 그들에게로 데려다가 그들과 청년들의 어미를 쳐서 놀람과 두려움을 그들에게 졸지에 임하게 하였으며"},{"n":9,"t":"일곱 자식을 생산한 여인으로는 쇠약하여 기절하게 하며 오히려 백주에 그의 해로 떨어져서 그로 수치와 근심을 당케 하였느니라 그 남은 자는 그 대적의 칼에 붙이리라 여호와의 말이니라"},{"n":10,"t":"내게 재앙이로다 나의 모친이여 모친이 나를 온 세계에게 다툼과 침을 당할 자로 낳으셨도다 내가 뀌어 주지도 아니하였고 사람이 내게 뀌이지도 아니하였건마는 다 나를 저주하는도다"},{"n":11,"t":"여호와께서 가라사대 내가 진실로 너를 강하게 할 것이요 너로 복을 얻게 할 것이며 내가 진실로 네 대적으로 재앙과 환난의 때에 간구하게 하리라"},{"n":12,"t":"누가 능히 철 곧 북방의 철과 놋을 꺾으리요"},{"n":13,"t":"그러나 네 모든 죄로 인하여 네 사경의 모든 재산과 보물로 값 없이 탈취를 당하게 할 것이며"},{"n":14,"t":"너로 네 대적과 함께 네가 알지 못하는 땅에 이르게 하리니 이는 나의 진노의 맹렬한 불이 너희를 사르려 함이니라"},{"n":15,"t":"여호와여 주께서 아시오니 원컨대 주는 나를 기억하시며 권고하사 나를 박해하는 자에게 보복하시고 주의 오래 참으심을 인하여 나로 멸망치 말게 하옵시며 주를 위하여 내가 치욕 당하는 줄을 아시옵소서"},{"n":16,"t":"만군의 하나님 여호와시여 나는 주의 이름으로 일컬음을 받는 자라 내가 주의 말씀을 얻어 먹었사오니 주의 말씀은 내게 기쁨과 내 마음의 즐거움이오나"},{"n":17,"t":"내가 기뻐하는 자의 회에 앉지 아니하며 즐거워하지도 아니하고 주의 손을 인하여 홀로 앉았사오니 이는 주께서 분노로 내게 채우셨음이니이다"},{"n":18,"t":"나의 고통이 계속하며 상처가 중하여 낫지 아니함은 어찜이니이까 주께서는 내게 대하여 물이 말라서 속이는 시내 같으시리이까"},{"n":19,"t":"여호와께서 이같이 말씀하시되 네가 만일 돌아오면 내가 너를 다시 이끌어서 내 앞에 세울 것이며 네가 만일 천한 것에서 귀한 것을 취할 것 같으면 너는 내 입 같이 될 것이라 그들은 네게로 돌아오려니와 너는 그들에게로 돌아가지 말지니라"},{"n":20,"t":"내가 너로 이 백성 앞에 견고한 놋 성벽이 되게 하리니 그들이 너를 칠지라도 이기지 못할 것은 내가 너와 함께 하여 너를 구하여 건짐이니라 여호와의 말이니라"},{"n":21,"t":"내가 너를 악한 자의 손에서 건지며 무서운 자의 손에서 구속하리라"}],"kids":[{"n":1,"t":"여호와께서 내게 말씀하셨어요. \\"모세와 사무엘(과거에 백성을 위해 기도해 준 큰 종들)이 내 앞에 선다 해도, 내 마음은 이 백성을 향할 수 없으니 그들을 내 앞에서 쫓아내라.\\""},{"n":2,"t":"\\"그들이 너에게 \'우리가 어디로 가야 하나요?\'라고 묻거든, 너는 이렇게 말해라. \'여호와께서 말씀하셨다. 죽을 자는 죽음으로, 칼 맞을 자는 칼로, 굶주림을 당할 자는 기근으로, 사로잡힐 자는 사로잡힘으로 가라.\'\\""},{"n":3,"t":"\\"나 여호와가 말한다. 내가 그들을 네 가지로 벌할 거야. 곧 죽이는 칼, 찢는 개, 삼켜 멸하는 하늘의 새와 땅의 짐승이야.\\""},{"n":4,"t":"\\"유다 왕 히스기야의 아들 므낫세가 예루살렘에서 한 짓 때문에 내가 그들을 세계 모든 나라로 흩어 버릴 거야.\\""},{"n":5,"t":"\\"예루살렘아, 너를 불쌍히 여길 사람이 누구며, 너를 위해 슬피 울 사람이 누구며, 돌이켜 네 평안(안부)을 물어 줄 사람이 누구겠느냐?\\""},{"n":6,"t":"\\"여호와께서 말씀하셨어. \'네가 나를 버리고 내게서 떠났기 때문에, 내가 손을 펴서 너를 멸했어. 이는 내가 뜻을 바꾸는 것에 지쳤기 때문이야.\'\\""},{"n":7,"t":"\\"내가 그들을 그 땅의 여러 성문에서 키질하듯 까불러서, 자식들을 끊고 내 백성을 멸했어. 이는 그들이 자기 길에서 돌이키지 않았기 때문이야.\\""},{"n":8,"t":"\\"그들의 과부가 내 앞에 바다의 모래보다 더 많아졌어. 내가 대낮에 멸망시키는 자를 그들에게 데려와서, 그들과 청년들의 어머니들을 쳐서, 놀람과 두려움이 갑자기 그들에게 닥치게 했어.\\""},{"n":9,"t":"\\"일곱 자식을 낳은 여인이 약해져 기절하고, 한낮에 그의 해(빛)가 졌으며, 그가 부끄러움과 슬픔을 당하게 했어. 그 남은 자도 적의 칼에 넘기겠다. 이것은 여호와의 말이야.\\""},{"n":10,"t":"\\"내게 재앙이 닥쳤구나! 어머니, 어머니께서 저를 온 세상이 다투고 비난하는 자로 낳으셨네요. 제가 누구에게 빌려준 것도 없고, 사람이 제게 빌려준 것도 없는데 모두가 저를 저주해요.\\""},{"n":11,"t":"\\"여호와께서 말씀하셨어. \'내가 정말 너를 강하게 해 줄 것이고, 너에게 복을 얻게 할 거야. 내가 진정 네 적이 재앙과 환난(어려움) 때에 너에게 와서 빌게 할 거야.\'\\""},{"n":12,"t":"\\"누가 쇠, 곧 북쪽의 쇠나 놋을 꺾을 수 있겠느냐?\\""},{"n":13,"t":"\\"네 모든 죄 때문에 네 영토 안에 있는 모든 재산과 보물을 값없이(공짜로) 빼앗기게 할 거야.\\""},{"n":14,"t":"\\"네가 적과 함께 네가 알지 못하는 땅으로 끌려가게 할 거야. 이는 내 분노의 거센 불이 너희를 태우려 하기 때문이야.\\""},{"n":15,"t":"\\"여호와여, 주께서 아시잖아요. 주는 저를 기억하시고 돌봐 주세요. 저를 괴롭히는 자에게 갚아 주세요. 주의 오래 참으심 때문에 저를 멸망하게 하지 말아 주세요. 주를 위해 제가 부끄러움을 당하는 것을 알아주세요.\\""},{"n":16,"t":"\\"만군의 하나님 여호와여, 저는 주의 이름이 붙은 자예요. 제가 주의 말씀을 얻어 먹었더니, 주의 말씀이 제게 기쁨이 되고 마음의 즐거움이 되었어요.\\""},{"n":17,"t":"\\"제가 기뻐하는 사람들의 모임에 앉지도 않고 즐거워하지도 않으며, 주의 손이 저를 누르셔서 홀로 앉아 있어요. 주께서 분노로 저를 채우셨기 때문이에요.\\""},{"n":18,"t":"\\"제 고통이 계속되고 상처가 깊어 낫지 않는 이유가 뭐예요? 주께서는 제게 마치 물이 말라 버려 사람을 속이는 시내(개울) 같으세요?\\""},{"n":19,"t":"여호와께서 이렇게 말씀하셨어요. \\"네가 만일 돌아오면 내가 너를 다시 이끌어 내 앞에 세울 것이고, 네가 만일 천한 것에서 귀한 것을 골라낸다면 너는 내 입(대변자)처럼 될 거야. 그들이 너에게 돌아올지언정, 너는 그들에게 돌아가지 마라.\\""},{"n":20,"t":"\\"내가 너를 이 백성 앞에 단단한 놋 성벽이 되게 할 것이니, 그들이 너를 쳐도 이기지 못할 거야. 이는 내가 너와 함께해서 너를 구해 주기 때문이야. 이것은 여호와의 말이야.\\""},{"n":21,"t":"\\"내가 너를 못된 자의 손에서 구해 내고, 무서운 자의 손에서 너를 자유롭게 할 거야.\\""}]}},{"chapter":16,"title":"결혼하지 말라는 명령","verses":{"krv":[{"n":1,"t":"여호와의 말씀이 또 내게 임하니라 가라사대"},{"n":2,"t":"너는 이 땅에서 아내를 취하지 말며 자녀를 두지 말지니라"},{"n":3,"t":"이곳에서 생산한 자녀와 이 땅에서 그들을 해산한 어미와 그들을 낳은 아비에 대하여 나 여호와가 이같이 말하노라"},{"n":4,"t":"그들은 독한 병으로 죽고 슬퍼함을 입지 못하며 매장함을 얻지 못하여 지면의 분토와 같을 것이며 칼과 기근에 망하고 그 시체는 공중의 새와 땅 짐승의 밥이 되리라"},{"n":5,"t":"여호와께서 이같이 말씀하시되 상가에 들어가지 말라 가서 통곡하지 말며 그들을 위하여 애곡하지 말라 내가 이 백성에게서 나의 평강을 빼앗으며 인자와 긍휼을 제함이니라 여호와의 말이니라"},{"n":6,"t":"큰 자든지 작은 자든지 이 땅에서 죽으리니 그들이 매장되지 못할 것이며 그들을 위하여 애곡하는 자도 없겠고 자기 몸을 베거나 대머리 되게 하는 자도 없을 것이며"},{"n":7,"t":"슬플 때에 떡을 떼며 그 죽은 자를 인하여 그들을 위로하는 자가 없을 것이며 그들의 아비나 어미의 상사를 위하여 위로의 잔을 그들에게 마시울 자가 없으리라"},{"n":8,"t":"너는 잔치집에 들어가서 그들과 함께 앉아 먹거나 마시지 말라"},{"n":9,"t":"만군의 여호와 이스라엘의 하나님이 이같이 말하노라 보라 기뻐하는 소리와 즐거워하는 소리와 신랑의 소리와 신부의 소리를 내가 네 목전, 네 시대에 이곳에서 끊어지게 하리라"},{"n":10,"t":"네가 이 모든 말로 백성에게 고할 때에 그들이 네게 묻기를 여호와께서 우리에게 이 모든 큰 재앙을 광포하심은 어찜이며 우리의 죄악은 무엇이며 우리가 우리 하나님 여호와께 범한 죄는 무엇이뇨 하거든"},{"n":11,"t":"너는 그들에게 대답하기를 여호와께서 말씀하시되 너희 열조가 나를 버리고 다른 신들을 좇아서 그들을 섬기며 그들에게 절하고 나를 버려 내 법을 지키지 아니하였음이라"},{"n":12,"t":"너희가 너희 열조보다 더욱 악을 행하였도다 보라 너희가 각기 악한 마음의 강퍅함을 따라 행하고 나를 청종치 아니하였으므로"},{"n":13,"t":"내가 너희를 이 땅에서 쫓아 내어 너희와 너희 열조의 알지 못하던 땅에 이르게 할 것이라 너희가 거기서 주야로 다른 신들을 섬기리니 이는 내가 너희에게 은혜를 베풀지 아니함이라 하셨다 하라"},{"n":14,"t":"여호와께서 가라사대 그러나 보라 날이 이르리니 다시는 이스라엘 자손을 애굽 땅에서 인도하여 내신 여호와의 사심으로 맹세하지 아니하고"},{"n":15,"t":"이스라엘 자손을 북방 땅과 그 모든 쫓겨났던 나라에서 인도하여 내신 여호와의 사심으로 맹세하리라 내가 그들을 그 열조에게 준 그들의 땅으로 인도하여 들이리라"},{"n":16,"t":"여호와께서 가라사대 보라 내가 많은 어부를 불러다가 그들을 낚게 하며 그 후에 많은 포수를 불러다가 그들을 모든 산과 모든 작은 산과 암혈에서 사냥하게 하리니"},{"n":17,"t":"내 눈이 그들의 행위를 감찰하므로 그들이 내 얼굴 앞에서 숨김을 얻지 못하며 그들의 죄악이 내 목전에서 은폐되지 못함이라"},{"n":18,"t":"내가 위선 그들의 악과 죄를 배나 갚을 것은 그들이 그 미운 물건의 시체로 내 땅을 더럽히며 그들의 가증한 것으로 내 산업에 가득하게 하였음이니라"},{"n":19,"t":"여호와 나의 힘, 나의 보장, 환난날의 피난처시여 열방이 땅 끝에서 주께 이르러 말하기를 우리 열조의 계승한 바는 허무하고 망탄하고 무익한 것뿐이라"},{"n":20,"t":"인생이 어찌 신 아닌 것을 자기의 신으로 삼겠나이까 하리이다"},{"n":21,"t":"여호와께서 가라사대 보라 이번에 그들에게 내 손과 내 능을 알려서 그들로 내 이름이 여호와인 줄 알게 하리라"}],"kids":[{"n":1,"t":"여호와의 말씀이 또 내게 들려왔어요."},{"n":2,"t":"\\"너는 이 땅에서 결혼하지 말고, 자녀를 두지 마라.\\""},{"n":3,"t":"\\"이곳에서 태어난 자녀들과 그들을 낳은 어머니와 그들을 낳은 아버지에 대해 나 여호와가 이렇게 말한다.\\""},{"n":4,"t":"\\"그들은 무서운 병으로 죽고, 슬퍼해 주는 사람도 없고, 묻히지도 못해 땅의 거름처럼 될 거야. 칼과 기근(굶주림)으로 망할 것이고, 그 시체는 하늘의 새와 땅의 짐승의 먹이가 될 거야.\\""},{"n":5,"t":"\\"여호와께서 이렇게 말씀하셨어. \'상가(누가 죽은 집)에 가지 마라. 가서 통곡(슬피 우는 일)하지 말고, 그들을 위해 슬피 울지도 마라. 내가 이 백성에게서 내 평안을 빼앗고, 사랑(인자)과 자비(긍휼)도 거두었기 때문이야. 이것은 여호와의 말이야.\'\\""},{"n":6,"t":"\\"큰 자든 작은 자든 이 땅에서 죽을 것이고, 묻히지도 못할 것이며, 그들을 위해 슬피 울 사람도 없을 거야. 자기 몸을 베거나 머리를 미는(슬픔의 표현) 사람도 없을 거야.\\""},{"n":7,"t":"\\"슬플 때에 떡(빵)을 떼서 죽은 자를 생각하며 그들을 위로해 줄 사람이 없을 것이고, 부모가 돌아가셨을 때 위로의 잔(컵)을 마시게 해 줄 사람도 없을 거야.\\""},{"n":8,"t":"\\"너는 잔치집에도 들어가서 그들과 함께 앉아 먹거나 마시지 마라.\\""},{"n":9,"t":"\\"만군의 여호와 이스라엘의 하나님이 이렇게 말한다. 보아라, 내가 너희 눈앞에서, 너희 시대에, 이곳에서 기뻐하는 소리, 즐거워하는 소리, 신랑의 소리, 신부의 소리를 끊어 버릴 거야.\\""},{"n":10,"t":"\\"네가 이 모든 말로 백성에게 알릴 때, 그들이 너에게 \'왜 여호와께서 우리에게 이런 큰 재앙을 선포하시나요? 우리가 무슨 잘못을 했고, 우리 하나님 여호와께 무슨 죄를 지었나요?\'라고 물으면,\\""},{"n":11,"t":"\\"너는 그들에게 대답해라. \'여호와께서 말씀하셨다. 너희 조상들이 나를 버리고 다른 신들을 따라가서 그들을 섬기고 그들에게 절했고, 나를 버리고 내 법(가르침)을 지키지 않았기 때문이야.\'\\""},{"n":12,"t":"\\"\'너희는 너희 조상보다 더 못된 짓을 했어. 보아라, 너희가 각자 못된 마음의 고집대로 행하고 내 말을 듣지 않았기 때문에,\'\\""},{"n":13,"t":"\\"\'내가 너희를 이 땅에서 쫓아내서 너희와 너희 조상이 알지 못하는 땅으로 보낼 거야. 너희가 그곳에서 밤낮으로 다른 신들을 섬기게 될 거야. 이는 내가 너희에게 은혜를 베풀지 않을 것이기 때문이야.\' 이렇게 말해라.\\""},{"n":14,"t":"\\"여호와께서 말씀하셨어. \'그러나 보아라, 날이 오면 다시는 이스라엘 자손을 애굽 땅에서 이끌어 내신 여호와의 살아 계심으로 맹세하지 않고,\'\\""},{"n":15,"t":"\\"\'이스라엘 자손을 북쪽 땅과 그들이 쫓겨났던 모든 나라에서 이끌어 내신 여호와의 살아 계심으로 맹세할 거야. 내가 그들을 그 조상들에게 준 그 땅으로 다시 데려올 거야.\'\\""},{"n":16,"t":"\\"여호와께서 말씀하셨어. \'보아라, 내가 많은 어부를 불러서 그들을 잡게 할 것이고, 그 후에 많은 사냥꾼(포수)을 불러서 그들을 모든 산과 모든 작은 산과 바위 굴(암혈)에서 사냥하게 할 거야.\'\\""},{"n":17,"t":"\\"\'내 눈이 그들의 행동을 살피고 있어서, 그들이 내 얼굴 앞에서 숨을 수 없고, 그들의 죄가 내 눈앞에서 가려질 수 없어.\'\\""},{"n":18,"t":"\\"\'내가 우선 그들의 죄와 잘못을 두 배로 갚을 거야. 이는 그들이 미운(가증한) 우상의 시체로 내 땅을 더럽혔고, 그들의 미운 것들로 내 산업을 가득 채웠기 때문이야.\'\\""},{"n":19,"t":"\\"여호와여, 저의 힘이시고, 저의 요새이시며, 어려운 날의 피난처(숨는 곳)이세요! 모든 나라들이 땅 끝에서 주께 와서 말할 거예요. \'우리 조상이 물려준 것은 헛되고 거짓되며 쓸모없는 것뿐이었어요.\'\\""},{"n":20,"t":"\\"\'사람이 어찌 신도 아닌 것을 자기의 신으로 삼겠어요?\'\\""},{"n":21,"t":"\\"여호와께서 말씀하셨어. \'보아라, 이번에 내가 그들에게 내 손과 내 능력을 알려서, 그들이 내 이름이 여호와인 줄 알게 할 거야.\'\\""}]}},{"chapter":17,"title":"유다의 굳은 마음","verses":{"krv":[{"n":1,"t":"유다의 죄는 금강석 끝 철필로 기록되되 그들의 마음 판과 그들의 단 뿔에 새겨졌거늘"},{"n":2,"t":"그들의 자녀가 높은 메 위 푸른 나무곁에 있는 그 단들과 아세라들을 생각하도다"},{"n":3,"t":"들에 있는 나의 산아 네 온 지경의 죄로 인하여 내가 네 재산과 네 모든 보물과 산당들로 노략을 당하게 하리니"},{"n":4,"t":"내가 네게 준 네 기업에서 네 손을 뗄 것이며 또 내가 너로 너의 알지 못하는 땅에서 네 대적을 섬기게 하리니 이는 너희가 내 노로 맹렬케 하여 영영히 타는 불을 일으켰음이니라"},{"n":5,"t":"나 여호와가 이같이 말하노라 무릇 사람을 믿으며 혈육으로 그 권력을 삼고 마음이 여호와에게서 떠난 그 사람은 저주를 받을 것이라"},{"n":6,"t":"그는 사막의 떨기나무 같아서 좋은 일의 오는 것을 보지 못하고 광야 간조한 곳, 건건한 땅, 사람이 거하지 않는 땅에 거하리라"},{"n":7,"t":"그러나 무릇 여호와를 의지하며 여호와를 의뢰하는 그 사람은 복을 받을 것이라"},{"n":8,"t":"그는 물가에 심기운 나무가 그 뿌리를 강변에 뻗치고 더위가 올지라도 두려워 아니하며 그 잎이 청청하며 가무는 해에도 걱정이 없고 결실이 그치지 아니함 같으리라"},{"n":9,"t":"만물보다 거짓되고 심히 부패한 것은 마음이라 누가 능히 이를 알리요마는"},{"n":10,"t":"나 여호와는 심장을 살피며 폐부를 시험하고 각각 그 행위와 그 행실대로 보응하나니"},{"n":11,"t":"불의로 치부하는 자는 자고새가 낳지 아니한 알을 품음 같아서 그 중년에 그것이 떠나겠고 필경은 어리석은 자가 되리라"},{"n":12,"t":"영화로우신 보좌여 원시부터 높이 계시며 우리의 성소이시며"},{"n":13,"t":"이스라엘의 소망이신 여호와여 무릇 주를 버리는 자는 다 수치를 당할 것이라 무릇 여호와를 떠나는 자는 흙에 기록이 되오리니 이는 생수의 근원이신 여호와를 버림이니이다"},{"n":14,"t":"여호와여 주는 나의 찬송이시오니 나를 고치소서 그리하시면 내가 낫겠나이다 나를 구원하소서 그리하시면 내가 구원을 얻으리이다"},{"n":15,"t":"그들이 내게 이르기를 여호와의 말씀이 어디 있느뇨 이제 임하게 할지어다 하나이다"},{"n":16,"t":"나는 목자의 직분에서 물러가지 아니하고 주를 좇았사오며 재앙의 날도 내가 원치 아니하였음을 주께서 아시는 바라 내 입술에서 나온 것이 주의 목전에 있나이다"},{"n":17,"t":"주는 내게 두려움이 되지 마옵소서 재앙의 날에 주는 나의 피난처시니이다"},{"n":18,"t":"나를 박해하는 자로 수욕을 당케 하시고 나로 수욕을 당케 마옵소서 그들로 놀라게 하시고 나로 놀라게 마시옵소서 재앙의 날을 그들에게 임하게 하시며 배나 되는 멸망으로 그들을 멸하소서"},{"n":19,"t":"여호와께서 내게 이같이 말씀하시되 너는 가서 유다 왕들의 출입하는 평민의 문과 예루살렘 모든 문에 서서"},{"n":20,"t":"무리에게 이르기를 이 문으로 들어오는 유다 왕들과 유다 모든 백성과 예루살렘 모든 거민 너희는 여호와의 말씀을 들을지어다"},{"n":21,"t":"여호와께서 이같이 말씀하시되 너희는 스스로 삼가서 안식일에 짐을 지고 예루살렘 문으로 들어오지 말며"},{"n":22,"t":"안식일에 너희 집에서 짐을 내지 말며 아무 일이든지 하지 말아서 내가 너희 열조에게 명함 같이 안식일을 거룩히 할지어다"},{"n":23,"t":"그들은 청종치 아니하며 귀를 기울이지 아니하며 그 목을 곧게 하여 듣지 아니하며 교훈을 받지 아니하였느니라"},{"n":24,"t":"나 여호와가 말하노라 너희가 만일 삼가 나를 청종하여 안식일에 짐을 지고 이 성문으로 들어오지 아니하며 안식일을 거룩히 하여 아무 일이든지 하지 아니하면"},{"n":25,"t":"다윗의 위에 앉는 왕들과 방백들이 병거와 말을 타고 이 성문으로 들어오되 그들과 유다 모든 백성과 예루살렘 거민들이 함께 그리할 것이요 이 성은 영영히 있을 것이며"},{"n":26,"t":"사람들이 유다 성읍들과 예루살렘에 둘린 곳들과 베냐민 땅과 평지와 산지와 남방에서 이르러서 번제와 희생과 소제와 유향과 감사의 희생을 가지고 여호와의 집으로 오려니와"},{"n":27,"t":"너희가 나를 청종치 아니하고 안식일을 거룩케 아니하여 안식일에 짐을 지고 예루살렘 문으로 들어오면 내가 성문에 불을 놓아 예루살렘 궁전을 삼키게 하리니 그 불이 꺼지지 아니하리라 하셨다 할지니라"}],"kids":[{"n":1,"t":"\\"유다의 죄는 다이아몬드(금강석) 끝의 철펜으로 새긴 것 같아서, 그들의 마음 판과 그들의 (우상) 단 뿔에 새겨졌어.\\""},{"n":2,"t":"\\"그들의 자녀들이 높은 산 위와 푸른 나무 곁에 있는 그 단들과 아세라(나무 우상)를 생각하고 있어.\\""},{"n":3,"t":"\\"들에 있는 내 산아, 네 모든 영토 안의 죄 때문에 내가 네 재산과 모든 보물과 산당(우상 섬기는 곳)을 약탈당하게 할 거야.\\""},{"n":4,"t":"\\"내가 너에게 준 너의 산업(소중한 땅)에서 네 손을 떼게 하고, 또 내가 너로 알지 못하는 땅에서 네 적을 섬기게 할 거야. 이는 너희가 내 분노를 일으켜서 영원히 타는 불을 일으켰기 때문이야.\\""},{"n":5,"t":"\\"나 여호와가 이렇게 말한다. 사람을 믿고, 사람의 힘(혈육)을 의지하며, 마음이 여호와에게서 떠난 그 사람은 저주를 받을 거야.\\""},{"n":6,"t":"\\"그는 사막의 떨기나무(작은 나무) 같아서 좋은 일이 와도 보지 못하고, 광야의 메마른 곳, 짠 땅, 사람이 살지 않는 땅에 머물게 될 거야.\\""},{"n":7,"t":"\\"그러나 여호와를 의지하고 여호와를 신뢰하는 사람은 복을 받을 거야.\\""},{"n":8,"t":"\\"그는 물가에 심긴 나무 같아서, 그 뿌리를 강가로 뻗치고, 더위가 와도 두려워하지 않고, 그 잎사귀가 푸르고, 가뭄이 든 해에도 걱정이 없고, 열매 맺기를 그치지 않을 거야.\\""},{"n":9,"t":"\\"세상에서 가장 거짓되고 매우 부패(망가짐)한 것이 마음이야. 누가 그것을 알 수 있을까?\\""},{"n":10,"t":"\\"나 여호와는 심장(마음)을 살피고 속(폐부)을 시험해서, 각자 그 행동과 행실에 따라 갚아 준단다.\\""},{"n":11,"t":"\\"부정한(불의한) 방법으로 부자가 된 사람은 자기가 낳지 않은 알을 품는 자고새(꿩)와 같아서, 한창 좋을 때(중년) 그것이 떠나 버리고, 결국에는 어리석은 자가 될 거야.\\""},{"n":12,"t":"\\"영광스러운 보좌(왕의 자리)이시여! 처음부터 높이 계시고, 우리의 거룩한 곳(성소)이세요!\\""},{"n":13,"t":"\\"이스라엘의 소망이신 여호와여, 주를 버리는 자는 모두 부끄러움을 당할 거예요. 여호와를 떠나는 자는 흙에 기록될 거예요. 이는 그들이 생수(살아있는 물)의 근원이신 여호와를 버렸기 때문이에요.\\""},{"n":14,"t":"\\"여호와여, 주는 저의 찬송(자랑)이세요. 저를 고쳐 주세요. 그러면 제가 낫겠어요. 저를 구해 주세요. 그러면 제가 구원을 얻을 거예요.\\""},{"n":15,"t":"\\"그들이 제게 말해요. \'여호와의 말씀이 어디 있느냐? 어디 한 번 이루어지게 해 봐라!\'\\""},{"n":16,"t":"\\"저는 목자의 일에서 물러나지 않고 주를 따랐고, 재앙의 날도 제가 원하지 않은 줄을 주께서 아세요. 제 입술에서 나온 말은 다 주의 눈앞에 있어요.\\""},{"n":17,"t":"\\"주께서 제게 두려움이 되지 마세요. 재앙의 날에 주는 저의 피난처(숨는 곳)이세요.\\""},{"n":18,"t":"\\"저를 괴롭히는 자에게 부끄러움을 당하게 하시고, 저는 부끄러움을 당하지 않게 해 주세요. 그들을 놀라게 하시고, 저는 놀라지 않게 해 주세요. 재앙의 날을 그들에게 가게 하시고, 두 배의 멸망으로 그들을 멸해 주세요.\\""},{"n":19,"t":"여호와께서 내게 이렇게 말씀하셨어요. \\"너는 가서 유다 왕들이 드나드는 평민들의 문과 예루살렘의 모든 문에 서서,\\""},{"n":20,"t":"\\"무리에게 말해라. \'이 문으로 들어오는 유다 왕들과 모든 유다 백성과 예루살렘에 사는 모든 사람들아, 너희는 여호와의 말씀을 들어라.\'\\""},{"n":21,"t":"\\"여호와께서 이렇게 말씀하셨다. \'너희는 조심해서 안식일(일을 쉬는 거룩한 날)에 짐을 지고 예루살렘 문으로 들어오지 말고,\\""},{"n":22,"t":"\\"\'안식일에 너희 집에서 짐을 내가지 말고, 어떤 일도 하지 마라. 내가 너희 조상들에게 명령한 대로 안식일을 거룩하게 지켜라.\'\\""},{"n":23,"t":"\\"그러나 그들은 듣지도 않고, 귀도 기울이지 않으며, 목을 곧게 굳혀 듣지 않고 가르침도 받지 않았어.\\""},{"n":24,"t":"\\"나 여호와가 말한다. 너희가 만일 조심해서 내 말을 듣고, 안식일에 짐을 지고 이 성문으로 들어오지 않으며, 안식일을 거룩하게 해서 어떤 일도 하지 않으면,\\""},{"n":25,"t":"\\"다윗의 자리(왕좌)에 앉는 왕들과 높은 사람들이 병거(전쟁용 마차)와 말을 타고 이 성문으로 들어올 것이고, 그들과 모든 유다 백성과 예루살렘 사람들이 함께 그렇게 할 것이며, 이 성은 영원히 있을 거야.\\""},{"n":26,"t":"\\"사람들이 유다 성과 예루살렘 주변과 베냐민 땅과 평지(낮은 땅)와 산지(산의 땅)와 남쪽 지방에서 와서, 번제(불사르는 제물)와 희생과 소제(곡식 제물)와 유향(좋은 향)과 감사 제물을 가지고 여호와의 집(성전)으로 올 거야.\\""},{"n":27,"t":"\\"그러나 너희가 내 말을 듣지 않고, 안식일을 거룩하게 하지 않고 안식일에 짐을 지고 예루살렘 문으로 들어오면, 내가 성문에 불을 놓아 예루살렘 궁전을 삼키게 하고, 그 불이 꺼지지 않게 할 거야.\' 이렇게 말해라.\\""}]}},{"chapter":18,"title":"토기장이의 비유","verses":{"krv":[{"n":1,"t":"여호와께로부터 예레미야에게 임한 말씀에 가라사대"},{"n":2,"t":"너는 일어나 토기장이의 집으로 내려가라 내가 거기서 내 말을 네게 들리리라 하시기로"},{"n":3,"t":"내가 토기장이의 집으로 내려가서 본즉 그가 녹로로 일을 하는데"},{"n":4,"t":"진흙으로 만든 그릇이 토기장이의 손에서 파상하매 그가 그것으로 자기 의견에 선한 대로 다른 그릇을 만들더라"},{"n":5,"t":"때에 여호와의 말씀이 내게 임하니라 가라사대"},{"n":6,"t":"나 여호와가 이르노라 이스라엘 족속아 이 토기장이의 하는 것 같이 내가 능히 너희에게 행하지 못하겠느냐 이스라엘 족속아 진흙이 토기장이의 손에 있음 같이 너희가 내 손에 있느니라"},{"n":7,"t":"내가 언제든지 어느 민족이나 국가를 뽑거나 파하거나 멸하리라 한다고 하자"},{"n":8,"t":"만일 나의 말한 그 민족이 그 악에서 돌이키면 내가 그에게 내리기로 생각하였던 재앙에 대하여 뜻을 돌이키겠고"},{"n":9,"t":"내가 언제든지 어느 민족이나 국가를 건설하거나 심으리라 한다고 하자"},{"n":10,"t":"만일 그들이 나 보기에 악한 것을 행하여 내 목소리를 청종치 아니하면 내가 그에게 유익케 하리라 한 선에 대하여 뜻을 돌이키리라"},{"n":11,"t":"그러므로 이제 너는 유다 사람들과 예루살렘 거민들에게 말하여 이르기를 여호와의 말씀에 보라 내가 너희에게 재앙을 내리며 계책을 베풀어 너희를 치려하노니 너희는 각기 악한 길에서 돌이키며 너희 길과 행위를 선하게 하라 하셨다 하라"},{"n":12,"t":"그러나 그들이 말하기를 이는 헛된 말이라 우리는 우리의 도모대로 행하며 우리는 각기 악한 마음의 강퍅한 대로 행하리라 하느니라"},{"n":13,"t":"그러므로 나 여호와가 이같이 말하노라 너희는 누가 이러한 일을 들었는가 열방 중에 물어보라 처녀 이스라엘이 심히 가증한 일을 행하였도다"},{"n":14,"t":"레바논의 눈이 어찌 들의 반석을 떠나겠으며 원방에서 흘러 내리는 찬물이 어찌 마르겠느냐"},{"n":15,"t":"대저 내 백성은 나를 잊고 허무한 것에게 분향하거니와 이러한 것들은 그들로 그 길 곧 그 옛길에서 넘어지게 하며 곁길 곧 닦지 아니한 길로 행케 하여"},{"n":16,"t":"그들의 땅으로 놀랍고 영영한 치소가 되게 하리니 그리로 지나는 자마다 놀라서 그 머리를 흔들리라"},{"n":17,"t":"내가 그들을 그 원수 앞에서 흩기를 동풍으로 함 같이 할 것이며 그들의 재난의 날에는 내가 그들에게 등을 보이고 얼굴을 보이지 아니하리라"},{"n":18,"t":"그들이 말하기를 오라 우리가 꾀를 내어 예레미야를 치자 제사장에게서 율법이, 지혜로운 자에게서 모략이, 선지자에게서 말씀이 끊어지지 아니할 것이니 오라 우리가 혀로 그를 치고 그의 아무 말에도 주의치 말자 하나이다"},{"n":19,"t":"여호와여 나를 돌아보사 나로 더불어 다투는 그들의 목소리를 들어보옵소서"},{"n":20,"t":"어찌 악으로 선을 갚으리이까마는 그들이 나의 생명을 해하려고 구덩이를 팠나이다 내가 주의 분노를 그들에게서 돌이키려 하고 주의 앞에 서서 그들을 위하여 선한 말씀 한 것을 기억하옵소서"},{"n":21,"t":"그러하온즉 그들의 자녀를 기근에 내어주시며 그들을 칼의 세력에 붙이시며 그들의 아내들은 자녀를 잃고 과부가 되며 그 장정은 사망을 당하며 그 청년은 전장에서 칼을 맞게 하시며"},{"n":22,"t":"주께서 군대로 졸지에 그들에게 임하게 하사 그들의 집에서 부르짖음이 들리게 하옵소서 이는 그들이 나를 취하려고 구덩이를 팠고 내 발을 빠치려고 올무를 베풀었음이니이다"},{"n":23,"t":"여호와여 그들이 나를 죽이려 하는 계략을 주께서 다 아시오니 그 악을 사하지 마시며 그 죄를 주의 목전에서 도말치 마시고 그들로 주의 앞에 넘어지게 하시되 주의 노하시는 때에 이같이 그들에게 행하옵소서"}],"kids":[{"n":1,"t":"여호와의 말씀이 예레미야에게 들려왔어요."},{"n":2,"t":"\\"너는 일어나 토기장이(흙으로 그릇 만드는 사람)의 집으로 내려가라. 내가 거기서 내 말을 너에게 들려주겠다.\\""},{"n":3,"t":"내가 토기장이의 집으로 내려가서 보니, 그가 녹로(돌리는 판)로 일하고 있었어요."},{"n":4,"t":"진흙으로 만든 그릇이 토기장이의 손에서 망가지자, 그는 그것으로 자기 마음에 좋은 대로 다른 그릇을 다시 만들었어요."},{"n":5,"t":"그때 여호와의 말씀이 내게 들려왔어요."},{"n":6,"t":"\\"나 여호와가 말한다. 이스라엘 집안아, 이 토기장이가 한 것처럼 내가 너희에게 그렇게 하지 못하겠느냐? 이스라엘 집안아, 진흙이 토기장이의 손에 있는 것처럼, 너희도 내 손에 있단다.\\""},{"n":7,"t":"\\"내가 어떤 민족이나 나라에 대해 \'뽑거나 부수거나 멸하겠다\'라고 말한 적이 있다고 해 보자.\\""},{"n":8,"t":"\\"만일 내가 말한 그 민족이 자기 잘못에서 돌이키면, 내가 그들에게 내리려고 했던 재앙에 대해 마음을 바꿀 거야.\\""},{"n":9,"t":"\\"또 내가 어떤 민족이나 나라에 대해 \'세우거나 심겠다\'라고 말한 적이 있다고 해 보자.\\""},{"n":10,"t":"\\"만일 그들이 내가 보기에 못된 일을 행하고 내 말을 듣지 않으면, 내가 그들에게 좋은 일을 해 주려고 했던 마음을 돌이킬 거야.\\""},{"n":11,"t":"\\"그러므로 이제 너는 유다 사람들과 예루살렘 사람들에게 이렇게 말해라. \'여호와께서 이렇게 말씀하셨다. 보아라, 내가 너희에게 재앙을 내리고 너희를 칠 계획을 세우고 있다. 그러니 너희는 각자 못된 길에서 돌이키고, 너희 길과 행동을 좋게 해라.\'\\""},{"n":12,"t":"\\"그러나 그들은 \'이는 헛소리야. 우리는 우리 마음대로 할 거고, 각자 못된 마음의 고집대로 행할 거야\'라고 말한단다.\\""},{"n":13,"t":"\\"그러므로 나 여호와가 이렇게 말한다. 너희는 누가 이런 일을 들었는지 다른 나라들에게 물어봐라. 처녀 이스라엘이 정말 미운 짓(가증한 일)을 했어.\\""},{"n":14,"t":"\\"레바논 산의 눈이 어찌 그 들의 바위에서 떠나겠으며, 먼 곳에서 흘러내리는 차가운 물이 어찌 마르겠느냐?\\""},{"n":15,"t":"\\"그런데 내 백성은 나를 잊어버리고 헛된 우상에게 향을 피우고 있구나. 그것들이 그들을 옛 길에서 넘어지게 하고, 옆길로, 닦이지 않은 길로 가게 만들어서,\\""},{"n":16,"t":"\\"그들의 땅을 놀랍고도 영원히 부끄러운 곳(치소)으로 만들 거야. 그곳을 지나가는 사람마다 놀라서 머리를 흔들 거야.\\""},{"n":17,"t":"\\"내가 그들을 적 앞에서 동풍에 흩어지게 하듯이 흩어 버릴 것이고, 그들이 재앙을 당하는 날에 나는 등을 보이고 얼굴을 보이지 않겠다.\\""},{"n":18,"t":"\\"그들이 말했어요. \'오너라, 우리가 꾀(계획)를 내서 예레미야를 치자. 제사장에게서 율법(가르침)이 끊어지지 않을 것이고, 지혜로운 자에게서 좋은 의견(모략)이 끊어지지 않을 것이며, 선지자에게서 말씀이 끊어지지 않을 거야. 오너라, 우리가 혀로 그를 치고, 그가 하는 어떤 말도 신경 쓰지 말자.\'\\""},{"n":19,"t":"\\"여호와여, 저를 살펴 주시고, 저와 다투는 자들의 목소리를 들어 주세요.\\""},{"n":20,"t":"\\"어떻게 악으로 선을 갚을 수 있겠어요? 그런데 그들이 제 목숨을 노리고 구덩이를 팠어요. 제가 주의 분노를 그들에게서 돌이키려고 주 앞에 서서 그들을 위해 좋은 말을 한 것을 기억해 주세요.\\""},{"n":21,"t":"\\"그러므로 그들의 자녀를 기근(굶주림)에 내어 주시고, 그들을 칼의 힘에 넘겨 주시고, 그들의 아내들은 자녀를 잃고 과부가 되게 하시고, 그들의 장정(어른 남자)은 죽임을 당하게 하시고, 청년들은 전쟁터에서 칼을 맞게 해 주세요.\\""},{"n":22,"t":"\\"주께서 군대를 보내셔서 갑자기 그들에게 닥치게 하셔서, 그들의 집에서 부르짖는 소리가 들리게 해 주세요. 이는 그들이 저를 잡으려고 구덩이를 팠고, 제 발을 걸리게 하려고 덫(올무)을 놓았기 때문이에요.\\""},{"n":23,"t":"\\"여호와여, 그들이 저를 죽이려고 꾸민 계획을 주께서 다 아세요. 그 악을 용서하지 마시고, 그 죄를 주의 눈앞에서 지우지 마세요. 그들을 주 앞에서 넘어지게 하시되, 주께서 화내시는 때에 이렇게 그들에게 행해 주세요.\\""}]}},{"chapter":19,"title":"옹기를 깨뜨리는 표적","verses":{"krv":[{"n":1,"t":"여호와께서 이같이 말씀하시되 가서 토기장이의 오지병을 사고 백성의 어른들과 제사장의 어른 몇 사람을 데리고"},{"n":2,"t":"하시드 문 어귀 곁에 있는 힌놈의 아들의 골짜기로 가서 거기서 내가 네게 이른 말을 선포하여"},{"n":3,"t":"이르기를 너희 유다 왕들과 예루살렘 거민아 여호와의 말씀을 들으라 만군의 여호와 이스라엘의 하나님이 이같이 말씀하시되 보라 내가 이곳에 재앙을 내릴 것이라 무릇 그것을 듣는 자의 귀가 진동하리니"},{"n":4,"t":"이는 그들이 나를 버리고 이곳을 불결케 하며 이곳에서 자기와 자기 열조와 유다 왕들의 알지 못하던 다른 신들에게 분향하며 무죄한 자의 피로 이곳에 채웠음이며"},{"n":5,"t":"또 그들이 바알을 위하여 산당을 건축하고 자기 아들들을 바알에게 번제로 불살라 드렸나니 이는 내가 명하거나 뜻한 바가 아니니라"},{"n":6,"t":"그러므로 나 여호와가 말하노라 보라 다시는 이곳을 도벳이나 힌놈의 아들의 골짜기라 칭하지 아니하고 살륙의 골짜기라 칭하는 날이 이를 것이라"},{"n":7,"t":"내가 이곳에서 유다와 예루살렘의 모계를 무효케 하여 그들로 그 대적 앞과 생명을 찾는 자의 손의 칼에 엎드러지게 하고 그 시체를 공중의 새와 땅 짐승의 밥이 되게 하며"},{"n":8,"t":"이 성으로 놀람과 모욕거리가 되게 하리니 그 모든 재앙을 인하여 지나는 자마다 놀라며 모욕할 것이며"},{"n":9,"t":"그들이 그 대적과 그들의 생명을 찾는 자에게 둘러싸여 곤핍을 당할 때에 내가 그들로 그 아들의 고기, 딸의 고기를 먹게 하고 또 각기 친구의 고기를 먹게 하리라 하셨다 하고"},{"n":10,"t":"너는 함께 가는 자의 목전에서 그 오지병을 깨뜨리고"},{"n":11,"t":"그들에게 이르기를 만군의 여호와께서 이같이 말씀하시되 사람이 토기장이의 그릇을 한번 깨뜨리면 다시 완전하게 할 수 없나니 이와 같이 내가 이 백성과 이 성을 파하리니 그들을 매장할 자리가 없도록 도벳에 장사하리라"},{"n":12,"t":"나 여호와가 말하노라 내가 이곳과 그 중 거민에게 이같이 행하여 이 성으로 도벳 같게 할 것이라"},{"n":13,"t":"예루살렘 집들과 유다 왕들의 집들 곧 그 집들이 그 집 위에서 하늘의 만상에 분향하고 다른 신들에게 전제를 부음으로 더러워졌은즉 도벳 땅처럼 되리라 하셨다 하라"},{"n":14,"t":"예레미야가 여호와께서 자기를 보내사 예언하게 하신 도벳에서 돌아와 여호와의 집 뜰에 서서 모든 백성에게 말하되"},{"n":15,"t":"만군의 여호와 이스라엘의 하나님이 말씀하시되 보라 내가 이 성에 대하여 선언한 모든 재앙을 이 성과 그 모든 촌락에 내리리니 이는 그 목을 곧게 하여 내 말을 듣지 아니함이니라 하셨다 하라"}],"kids":[{"n":1,"t":"여호와께서 이렇게 말씀하셨어요. \\"가서 토기장이가 만든 오지병(흙 그릇)을 사고, 백성의 어른들과 제사장의 어른 몇 사람을 데리고 가라.\\""},{"n":2,"t":"\\"그리고 하시드 문(질그릇 조각 문) 입구 옆에 있는 힌놈의 아들 골짜기로 가서 내가 네게 말한 것을 거기서 외쳐라.\\""},{"n":3,"t":"\\"이렇게 말해라. \'너희 유다 왕들과 예루살렘 사람들아, 여호와의 말씀을 들어라. 만군의 여호와 이스라엘의 하나님이 이렇게 말씀하셨다. 보아라, 내가 이곳에 재앙을 내릴 거야. 그것을 듣는 사람마다 귀가 울릴 정도로(놀라서) 될 거야.\'\\""},{"n":4,"t":"\\"\'이는 그들이 나를 버리고 이곳을 더럽혔으며, 자기와 자기 조상과 유다 왕들이 알지 못하던 다른 신들에게 향을 피우고, 죄 없는 자의 피로 이곳을 가득 채웠기 때문이야.\'\\""},{"n":5,"t":"\\"\'또 그들이 바알을 위해 산당(우상의 단)을 짓고 자기 아들들을 바알에게 번제(불사르는 제물)로 태워 바쳤어. 이는 내가 명령한 적도 없고, 마음에 둔 적도 없는 일이야.\'\\""},{"n":6,"t":"\\"\'그러므로 나 여호와가 말한다. 보아라, 다시는 이곳을 도벳이나 힌놈의 아들 골짜기라고 부르지 않고 살륙(죽이는)의 골짜기라고 부를 날이 올 거야.\'\\""},{"n":7,"t":"\\"\'내가 이곳에서 유다와 예루살렘의 계획(모계)을 헛되게 만들고, 그들을 적 앞에서, 그리고 그들의 목숨을 노리는 자의 칼 앞에서 쓰러지게 할 것이며, 그들의 시체를 하늘의 새와 땅의 짐승의 먹이가 되게 할 거야.\'\\""},{"n":8,"t":"\\"\'이 성을 놀람과 비웃음거리(모욕거리)가 되게 할 거야. 그 모든 재앙 때문에 지나가는 사람마다 놀라며 비웃을 거야.\'\\""},{"n":9,"t":"\\"\'적과 그들의 목숨을 노리는 자에게 둘러싸여 어려움(곤핍)을 당할 때, 내가 그들로 자기 아들의 고기와 딸의 고기를 먹게 하고, 또 각자 친구의 고기를 먹게 할 거야.\' 이렇게 말해라.\\""},{"n":10,"t":"\\"그리고 너는 함께 간 사람들 앞에서 그 오지병을 깨뜨려라.\\""},{"n":11,"t":"\\"그들에게 말해라. \'만군의 여호와께서 이렇게 말씀하셨다. 사람이 토기장이의 그릇을 한 번 깨뜨리면 다시 완전하게 할 수 없는 것처럼, 내가 이 백성과 이 성을 깨뜨릴 거야. 그래서 묻을 자리가 없을 정도로 도벳에 시신을 묻을 거야.\'\\""},{"n":12,"t":"\\"\'나 여호와가 말한다. 내가 이곳과 여기 사는 사람들에게 이렇게 행해서, 이 성을 도벳처럼 만들 거야.\'\\""},{"n":13,"t":"\\"\'예루살렘의 집들과 유다 왕들의 집들, 곧 그 집들이 옥상에서 하늘의 별들(만상)에게 향을 피우고 다른 신들에게 술(전제)을 부어서 더러워졌으니, 도벳 땅처럼 될 거야.\' 이렇게 말해라.\\""},{"n":14,"t":"예레미야가 여호와께서 자기를 보내 예언(말씀 전하기)하게 하신 도벳에서 돌아와 여호와의 집 뜰에 서서 모든 백성에게 말했어요."},{"n":15,"t":"\\"만군의 여호와 이스라엘의 하나님이 말씀하셨어. \'보아라, 내가 이 성에 대해 선포한 모든 재앙을 이 성과 그 모든 마을(촌락)에 내릴 거야. 이는 그들이 목을 굳게 해서 내 말을 듣지 않았기 때문이야.\' 이렇게 말해라.\\""}]}},{"chapter":20,"title":"바스훌과의 충돌","verses":{"krv":[{"n":1,"t":"제사장 임멜의 아들 바스훌은 여호와의 집 유사장이라 그가 예레미야의 이 일 예언함을 들은지라"},{"n":2,"t":"이에 바스훌이 선지자 예레미야를 때리고 여호와의 집 베냐민의 윗문에 있는 착고에 채웠더니"},{"n":3,"t":"다음날 바스훌이 예레미야를 착고에서 놓아 주매 예레미야가 그에게 이르되 여호와께서 네 이름을 바스훌이라 아니하시고 마골밋사빕이라 하시느니라"},{"n":4,"t":"대저 여호와께서 이같이 말씀하시되 보라 내가 너로 너와 네 모든 친구에게 두려움이 되게 하리니 그들이 그 원수의 칼에 엎드러질 것이요 네 눈은 그것을 볼 것이며 내가 온 유다를 바벨론 왕의 손에 붙이리니 그가 그들을 사로잡아 바벨론으로 옮겨 칼로 죽이리라"},{"n":5,"t":"내가 또 이 성의 모든 부와 그 모든 소득과 그 모든 귀물과 유다 왕들의 모든 보물을 그 원수의 손에 붙이리니 그들이 그것을 탈취하여 바벨론으로 가져가리라"},{"n":6,"t":"바스훌아 너와 네 집에 거하는 모든 자가 포로 되어 옮기우리니 네가 바벨론에 이르러 거기서 죽어 거기 묻힐 것이라 너와 네가 거짓 예언을 하여 들린 네 모든 친구도 일반이리라 하셨느니라"},{"n":7,"t":"여호와여 주께서 나를 권유하시므로 내가 그 권유를 받았사오며 주께서 나보다 강하사 이기셨으므로 내가 조롱거리가 되니 사람마다 종일토록 나를 조롱하나이다"},{"n":8,"t":"대저 내가 말할 때마다 외치며 강포와 멸망을 부르짖으오니 여호와의 말씀으로 하여 내가 종일토록 치욕과 모욕거리가 됨이니이다"},{"n":9,"t":"내가 다시는 여호와를 선포하지 아니하며 그 이름으로 말하지 아니하리라 하면 나의 중심이 불붙는 것 같아서 골수에 사무치니 답답하여 견딜 수 없나이다"},{"n":10,"t":"나는 무리의 비방과 사방의 두려움을 들었나이다 그들이 이르기를 고소하라 우리도 고소하리라 하오며 나의 친한 벗도 다 나의 타락하기를 기다리며 피차 이르기를 그가 혹시 유혹을 받으리니 우리가 그를 이기어 우리 원수를 갚자 하나이다"},{"n":11,"t":"그러하오나 여호와는 두려운 용사 같으시며 나와 함께하시는고로 나를 박해하는 자가 넘어지고 이기지 못할 것이오며 그들은 지혜롭게 행치 못하므로 큰 수욕을 당하오리니 그 수욕은 영영히 잊지 못할 것이니이다"},{"n":12,"t":"의인을 시험하사 그 폐부와 심장을 보시는 만군의 여호와여 나의 사정을 주께 아뢰었사온즉 주께서 그들에게 보수하심을 나로 보게 하옵소서"},{"n":13,"t":"여호와께 노래하라 너희는 여호와를 찬양하라 가난한 자의 생명을 행악자의 손에서 구원하셨음이니라"},{"n":14,"t":"내 생일이 저주를 받았더면, 나의 어미가 나를 생산하던 날이 복이 없었더면,"},{"n":15,"t":"나의 아비에게 소식을 전하여 이르기를 네가 생남하였다 하여 아비를 즐겁게 하던 자가 저주를 받았더면,"},{"n":16,"t":"그 사람은 여호와께서 훼파하시고 후회치 아니하신 성읍 같이 되었더면, 그로 아침에는 부르짖는 소리, 낮에는 떠드는 소리를 듣게 하였더면,"},{"n":17,"t":"이는 그가 나를 태에서 죽이지 아니하셨으며 나의 어미로 내 무덤이 되게 하지 아니하셨으며 그 배로 항상 부르게 하지 아니하신 연고로다"},{"n":18,"t":"어찌하여 내가 태에서 나와서 고생과 슬픔을 보며 나의 날을 수욕으로 보내는고"}],"kids":[{"n":1,"t":"제사장 임멜의 아들 바스훌은 여호와의 집(성전)을 책임지는 우두머리(유사장)였어요. 그가 예레미야의 이런 예언(말씀)을 들었어요."},{"n":2,"t":"그래서 바스훌이 선지자 예레미야를 때리고, 여호와의 집 베냐민의 윗문에 있는 착고(목과 손발을 가두는 형틀)에 채워 넣었어요."},{"n":3,"t":"다음 날 바스훌이 예레미야를 착고에서 풀어 주자, 예레미야가 그에게 말했어요. \\"여호와께서 너의 이름을 더 이상 바스훌이라고 하지 않으시고 \'마골밋사빕(사방에서 두려움)\'이라고 부르신단다.\\""},{"n":4,"t":"\\"이는 여호와께서 이렇게 말씀하셨기 때문이야. \'보아라, 내가 너로 너 자신과 너의 모든 친구에게 두려움이 되게 할 것이고, 그들이 적의 칼에 쓰러질 것이며 네 눈이 그것을 볼 거야. 또 내가 온 유다를 바벨론 왕의 손에 넘겨 줄 것이고, 그가 그들을 사로잡아 바벨론으로 끌고 가서 칼로 죽일 거야.\'\\""},{"n":5,"t":"\\"\'내가 또 이 성의 모든 부유함과 모든 소득(수확)과 모든 귀한 물건과 유다 왕들의 모든 보물을 적의 손에 넘겨 줄 것이고, 그들이 그것을 약탈해서 바벨론으로 가져갈 거야.\'\\""},{"n":6,"t":"\\"\'바스훌아, 너와 네 집에 사는 모든 사람이 사로잡혀 끌려갈 것이고, 너는 바벨론에 가서 거기서 죽어 거기에 묻힐 거야. 너와, 네가 거짓 예언을 해 주었던 모든 친구도 마찬가지일 거야.\' 이렇게 말씀하셨다.\\""},{"n":7,"t":"\\"여호와여, 주께서 저를 권하셔서 제가 그 권하심을 받아들였고, 주께서 저보다 강하셔서 이기셨기 때문에 제가 비웃음거리(조롱거리)가 되어 사람마다 종일토록 저를 비웃어요.\\""},{"n":8,"t":"\\"이는 제가 말할 때마다 외치며 폭력(강포)과 멸망을 부르짖었기 때문이에요. 여호와의 말씀 때문에 제가 종일토록 부끄러움과 모욕거리가 되었어요.\\""},{"n":9,"t":"\\"제가 \'다시는 여호와를 알리지 않고, 그분의 이름으로 말하지 않겠다\'라고 하면, 제 마음속에 불이 붙는 것 같아서 뼛속(골수)까지 사무쳐서 답답해 견딜 수가 없어요.\\""},{"n":10,"t":"\\"많은 사람이 저를 헐뜯는 말과 사방에 있는 두려움을 제가 들어요. 그들이 \'저 사람을 고발하라, 우리도 고발하자\' 하고, 제 가까운 친구들도 모두 제가 넘어지기를 기다리며 서로 \'그가 혹시 유혹을 받을 거야, 우리가 그를 이겨서 원수를 갚자\' 하고 있어요.\\""},{"n":11,"t":"\\"그러나 여호와는 두려운 용사 같으시고, 저와 함께해 주시기 때문에 저를 괴롭히는 자들이 넘어져 이기지 못할 거예요. 그들이 지혜롭게 행하지 않았기 때문에 큰 부끄러움을 당할 것이고, 그 부끄러움은 영원히 잊혀지지 않을 거예요.\\""},{"n":12,"t":"\\"의로운 사람을 시험하셔서 그 속과 마음을 보시는 만군의 여호와여, 제 사정을 주께 아뢰었으니 주께서 그들에게 갚으시는 것을 제가 보게 해 주세요.\\""},{"n":13,"t":"\\"여호와께 노래하여라! 너희는 여호와를 찬양해라! 가난한 사람의 생명을 못된 자의 손에서 구해 주셨기 때문이야.\\""},{"n":14,"t":"\\"내가 태어난 날이 저주를 받았더라면! 우리 어머니가 나를 낳으신 날이 복이 없었더라면!\\""},{"n":15,"t":"\\"내 아버지에게 소식을 전하면서 \'아들을 낳으셨어요\'라고 해서 아버지를 기쁘게 한 그 사람이 저주를 받았더라면!\\""},{"n":16,"t":"\\"그 사람이 여호와께서 멸하시고 후회하지 않으신 성처럼 되었더라면! 그가 아침에는 부르짖는 소리를, 낮에는 떠드는 소리를 듣게 되었더라면!\\""},{"n":17,"t":"\\"이는 그가 나를 어머니 뱃속에서 죽이지 않았고, 어머니의 몸을 내 무덤이 되게 하지 않았으며, 어머니의 배가 영원히 부르도록(임신 상태로) 두지 않았기 때문이야.\\""},{"n":18,"t":"\\"어찌하여 내가 태에서 나와 고생과 슬픔을 보며, 내 날들을 부끄러움 속에서 보내고 있는 걸까?\\""}]}},{"chapter":21,"title":"여호야김에 대한 경고","verses":{"krv":[{"n":1,"t":"시드기야 왕이 말기야의 아들 바스훌과 제사장 마아세야의 아들 스바냐를 보내어 예레미야에게 말하기를 바벨론 왕 느부갓네살이 우리를 치니 청컨대 너는 우리를 위하여 여호와께 간구하라 여호와께서 혹시 그 모든 기사로 우리를 도와 행하시면 그가 우리를 떠나리라 하던 그 때에 여호와께로부터 예레미야에게 말씀이 임하니라"},{"n":2,"t":""},{"n":3,"t":"예레미야가 그들에게 대답하되 너희는 시드기야에게 이같이 말하라"},{"n":4,"t":"이스라엘의 하나님 여호와께서 이같이 말씀하시되 보라 너희가 성밖에서 바벨론 왕과 또 너희를 에운 갈대아인과 싸우는 바 너희 손에 가진 병기를 내가 돌이킬 것이요 그들을 이 성 중에 모아 들이리라"},{"n":5,"t":"내가 든 손과 강한 팔 곧 노와 분과 대노로 친히 너희를 칠 것이며"},{"n":6,"t":"내가 또 이 성에 거주하는 자를 사람이나 짐승이나 다 치리니 그들이 큰 염병에 죽으리라 하셨다 하라"},{"n":7,"t":"여호와께서 또 말씀하시되 그 후에 내가 유다 왕 시드기야와 그 신하들과 백성과 및 이 성읍에서 염병과 칼과 기근에서 남은 자를 바벨론 왕 느부갓네살의 손과 그 대적의 손과 그 생명을 찾는 자들의 손에 붙이리니 그가 칼날로 그들을 치되 아끼지 아니하며 긍휼히 여기지 아니하며 불쌍히 여기지 아니하리라 하셨느니라"},{"n":8,"t":"여호와께서 가라사대 너는 또 백성에게 여호와께서 이같이 말씀하신다 하라 보라 내가 너희 앞에 생명의 길과 사망의 길을 두었노니"},{"n":9,"t":"이 성에 거주하는 자는 칼과 기근과 염병에 죽으려니와 너희를 에운 갈대아인에게 나가서 항복하는 자는 살리니 그의 생명은 노략한 것 같이 얻으리라"},{"n":10,"t":"나 여호와가 말하노라 내가 나의 얼굴을 이 성으로 향함은 복을 위함이 아니요 화를 위함이라 이 성이 바벨론 왕의 손에 붙임이 될 것이요 그는 그것을 불로 사르리라"},{"n":11,"t":"유다 왕의 집에 대한 여호와의 말을 들으라"},{"n":12,"t":"나 여호와가 이같이 말하노라 다윗의 집이여 너는 아침마다 공평히 판결하여 탈취 당한 자를 압박자의 손에서 건지라 그리하지 아니하면 너희는 악행을 인하여 내 노가 불 같이 일어나서 사르리니 능히 끌 자가 없으리라"},{"n":13,"t":"나 여호와가 이르노라 골짜기와 평원 반석의 거민아 보라 너희가 말하기를 누가 내려와서 우리를 치리요 누가 우리의 거처에 들어오리요 하거니와 나는 네 대적이라"},{"n":14,"t":"내가 너희 행위대로 벌할 것이요 내가 또 수풀에 불을 놓아 그 사경을 사르리라 여호와의 말이니라"}],"kids":[{"n":1,"t":"시드기야 왕이 말기야의 아들 바스훌과 제사장 마아세야의 아들 스바냐를 보내 예레미야에게 말했어요. \\"바벨론 왕 느부갓네살이 우리를 치고 있으니, 청하건대 우리를 위해 여호와께 빌어 줘. 여호와께서 혹시 그분의 모든 놀라운 일로 우리를 도와주신다면 그(느부갓네살)가 우리에게서 떠나갈 거야.\\" 그때 여호와의 말씀이 예레미야에게 들려왔어요."},{"n":2,"t":""},{"n":3,"t":"예레미야가 그들에게 대답했어요. \\"너희는 시드기야에게 이렇게 말해라.\\""},{"n":4,"t":"\\"이스라엘의 하나님 여호와께서 이렇게 말씀하셨다. \'보아라, 너희가 성 밖에서 바벨론 왕과 너희를 둘러싼 갈대아 사람들과 싸우려고 손에 든 무기를, 내가 돌이켜 그것들을 이 성 안으로 모아들일 거야.\'\\""},{"n":5,"t":"\\"\'내가 손을 들고 강한 팔, 곧 화와 분노와 큰 노여움으로 친히 너희를 칠 거야.\'\\""},{"n":6,"t":"\\"\'또 내가 이 성에 사는 자를 사람이나 짐승이나 다 칠 것이고, 그들이 큰 염병(전염병)에 걸려 죽을 거야.\' 이렇게 말씀하셨다.\\""},{"n":7,"t":"\\"여호와께서 또 말씀하셨어. \'그 후에 내가 유다 왕 시드기야와 그 신하들과 백성, 그리고 이 성에서 염병과 칼과 기근(굶주림)에서 살아남은 자들을 바벨론 왕 느부갓네살의 손과 그 적의 손과 그들의 목숨을 노리는 자들의 손에 넘겨줄 거야. 그가 칼날로 그들을 칠 것이고 봐주지 않고, 자비도 베풀지 않으며, 불쌍히 여기지도 않을 거야.\'\\""},{"n":8,"t":"\\"여호와께서 말씀하셨어. \'너는 또 백성에게 이렇게 말해라. 여호와께서 이렇게 말씀하셨다. 보아라, 내가 너희 앞에 생명의 길과 죽음(사망)의 길을 두었다.\'\\""},{"n":9,"t":"\\"\'이 성에 사는 자는 칼과 기근과 염병으로 죽겠지만, 너희를 둘러싼 갈대아 사람에게 나가서 항복하는 자는 살 것이고, 그의 생명은 약탈물(노략한 것)처럼 얻을 거야.\'\\""},{"n":10,"t":"\\"\'나 여호와가 말한다. 내가 이 성을 향한 것은 복을 주려는 것이 아니라 화를 주려는 거야. 이 성이 바벨론 왕의 손에 넘겨질 것이고, 그가 그것을 불로 태울 거야.\'\\""},{"n":11,"t":"\\"유다 왕의 집(왕실)에 대한 여호와의 말을 들어라.\\""},{"n":12,"t":"\\"\'나 여호와가 이렇게 말한다. 다윗의 집안아, 너는 아침마다 공평하게 판결해서, 빼앗긴 자를 누르는 자(압박자)의 손에서 건져라. 그렇지 않으면 너희의 못된 행동 때문에 내 분노가 불처럼 일어나 태워 버릴 것이고, 그것을 끌 사람이 없을 거야.\'\\""},{"n":13,"t":"\\"\'나 여호와가 말한다. 골짜기와 평원의 바위 위에 사는 자들아, 보아라. 너희가 누가 내려와서 우리를 치겠느냐, 누가 우리 사는 곳에 들어오겠느냐 하지만, 나는 너의 적이다.\'\\""},{"n":14,"t":"\\"\'내가 너희가 한 행동대로 벌할 거야. 내가 또 그 숲에 불을 놓아 그 주변 모든 곳을 태울 거야.\' 이것은 여호와의 말이야.\\""}]}},{"chapter":22,"title":"왕가에 대한 경고","verses":{"krv":[{"n":1,"t":"여호와께서 이같이 말씀하시되 너는 유다 왕의 집에 내려가서 거기서 이를 선언하여"},{"n":2,"t":"이르기를 다윗의 위에 앉은 유다 왕이여 너와 네 신하와 이 문들로 들어오는 네 백성은 여호와의 말씀을 들을지니라"},{"n":3,"t":"여호와께서 이같이 말씀하시되 너희가 공평과 정의를 행하여 탈취 당한 자를 압박하는 자의 손에서 건지고 이방인과 고아와 과부를 압박하거나 학대하지 말며 이곳에서 무죄한 피를 흘리지 말라"},{"n":4,"t":"너희가 참으로 이 말을 준행하면 다윗의 위에 앉을 왕들과 신하들과 백성이 병거와 말을 타고 이 집 문으로 들어오게 되리라마는"},{"n":5,"t":"너희가 이 말을 듣지 아니하면 내가 나로 맹세하노니 이 집이 황무하리라 나 여호와의 말이니라"},{"n":6,"t":"나 여호와가 유다 왕의 집에 대하여 이같이 말하노라 네가 내게 길르앗 같고 레바논의 꼭대기 같으나 내가 정녕히 너로 광야와 거민이 없는 성을 만들 것이라"},{"n":7,"t":"내가 너 파멸할 자를 준비하리니 그들이 각기 손에 병기를 가지고 네 아름다운 백향목을 찍어 불에 던지리라"},{"n":8,"t":"여러 나라 사람이 이 성으로 지나며 피차 말하기를 여호와가 이 큰 성에 이같이 행함은 어찜인고 하겠고"},{"n":9,"t":"대답하기는 이는 그들이 자기 하나님 여호와의 언약을 버리고 다른 신들에게 절하고 그를 섬긴 연고라 하리라 하셨다 할찌니라"},{"n":10,"t":"너희는 죽은 자를 위하여 울지 말며 그를 위하여 애통하지 말고 잡혀간 자를 위하여 슬피 울라 그는 다시 돌아와서 그 고국을 보지 못할 것임이니라"},{"n":11,"t":"나 여호와가 유다 왕 요시야의 아들 곧 그 아비 요시야를 이어 왕이 되었다가 이곳에서 나간 살룸에 대하여 말하노라 그가 이곳으로 다시 돌아오지 못하고"},{"n":12,"t":"잡혀간 곳에서 죽으리니 이 땅을 다시 보지 못하리라"},{"n":13,"t":"불의로 그 집을 세우며 불공평으로 그 다락방을 지으며 그 이웃을 고용하고 그 고가를 주지 아니하는 자에게 화 있을진저"},{"n":14,"t":"그가 이르기를 내가 나를 위하여 광대한 집과 광활한 다락방을 지으리라 하고 자기를 위하여 창을 만들고 그것에 백향목으로 입히고 붉은 빛으로 칠하도다"},{"n":15,"t":"네가 백향목으로 집 짓기를 경쟁하므로 왕이 될 수 있겠느냐 네 아비가 먹으며 마시지 아니하였으며 공평과 의리를 행치 아니하였느냐 그 때에 그가 형통하였었느니라"},{"n":16,"t":"그는 가난한 자와 궁핍한 자를 신원하고 형통하였나니 이것이 나를 앎이 아니냐 여호와의 말이니라"},{"n":17,"t":"그러나 네 눈과 마음은 탐남과 무죄한 피를 흘림과 압박과 강포를 행하려 할 뿐이니라"},{"n":18,"t":"그러므로 나 여호와가 유다 왕 요시야의 아들 여호야김에게 대하여 이같이 말하노라 무리가 그를 위하여 슬프다 내 형제여 슬프다 내 자매여 하며 통곡하지 아니할 것이며 그를 위하여 슬프다 주여 슬프다 그 영광이여 하며 통곡하지도 아니할 것이라"},{"n":19,"t":"그가 끌려 예루살렘 문 밖에 던지우고 나귀 같이 매장함을 당하리라"},{"n":20,"t":"너는 레바논에 올라 외치며 바산에서 네 소리를 높이며 아바림에서 외치라 이는 너를 사랑하는 자가 다 멸망하였음이니라"},{"n":21,"t":"네가 평안할 때에 내가 네게 말하였으나 네 말이 나는 듣지 아니하리라 하였나니 네가 어려서부터 내 목소리를 청종치 아니함이 네 습관이라"},{"n":22,"t":"네 목자들은 다 바람에 삼키울 것이요 너를 사랑하는 자들은 사로잡혀 가리니 그 때에 네가 반드시 네 모든 악을 인하여 수치와 욕을 당하리라"},{"n":23,"t":"레바논에 거하여 백향목에 깃들이는 자여 여인의 해산하는 고통같은 고통이 네게 임할 때에 너의 가련함이 얼마나 심하랴"},{"n":24,"t":"나 여호와가 말하노라 나의 삶으로 맹세하노니 유다 왕 여호야김의 아들 너 고니야가 나의 오른손의 인장반지라 할지라도 내가 빼어"},{"n":25,"t":"네 생명을 찾는 자의 손과 너의 두려워하는 자의 손 곧 바벨론 왕 느부갓네살의 손과 갈대아인의 손에 줄 것이라"},{"n":26,"t":"내가 너와 너를 낳은 어미를 너희가 나지 아니한 다른 지방에 쫓아내리니 너희가 거기서 죽고"},{"n":27,"t":"너희 마음에 돌아오기를 사모하는 땅에 돌아오지 못하리라"},{"n":28,"t":"이 사람 고니야는 천한 파기냐 좋아하지 아니하는 그릇이냐 어찌하여 그와 그 자손이 쫓겨나서 알지 못하는 땅에 들어갔는고"},{"n":29,"t":"땅이여, 땅이여, 땅이여 여호와의 말을 들을지니라"},{"n":30,"t":"나 여호와가 이같이 말하노라 너희는 이 사람이 무자하겠고 그 평생에 형통치 못할 자라 기록하라 이는 그 자손 중 형통하여 다윗의 위에 앉아 유다를 다스릴 사람이 다시는 없을 것임이니라"}],"kids":[{"n":1,"t":"여호와께서 이렇게 말씀하셨어요. \\"너는 유다 왕의 집(왕궁)으로 내려가서 거기서 이 말을 외쳐 알려라.\\""},{"n":2,"t":"\\"이렇게 말해라. \'다윗의 자리(왕좌)에 앉은 유다 왕이여, 너와 네 신하와 이 문으로 들어오는 네 백성은 여호와의 말씀을 들어라.\'\\""},{"n":3,"t":"\\"여호와께서 이렇게 말씀하셨다. \'너희는 공평과 정의(바른 일)를 행해서 빼앗긴 자를 누르는 자(압박자)의 손에서 건져 주고, 외국인(이방인)과 고아와 과부를 못살게 굴거나 학대하지 마라. 또 이곳에서 죄 없는 사람의 피를 흘리지 마라.\'\\""},{"n":4,"t":"\\"\'너희가 정말로 이 말을 따르면, 다윗의 자리에 앉을 왕들과 신하들과 백성이 병거(전쟁용 마차)와 말을 타고 이 집의 문으로 들어오게 될 거야.\'\\""},{"n":5,"t":"\\"\'그러나 너희가 이 말을 듣지 않으면 내가 나 자신을 두고 맹세하노니, 이 집이 폐허가 될 거야. 이것은 나 여호와의 말이야.\'\\""},{"n":6,"t":"\\"나 여호와가 유다 왕의 집에 대해 이렇게 말한다. \'네가 내게는 길르앗 같고 레바논의 꼭대기처럼 (아름답게) 보이지만, 내가 정말 너를 광야와 사람이 살지 않는 성으로 만들 거야.\'\\""},{"n":7,"t":"\\"\'내가 너를 부수는 자들을 준비할 것이고, 그들이 각자 손에 무기를 들고 너의 아름다운 백향목(좋은 나무)을 찍어 불에 던질 거야.\'\\""},{"n":8,"t":"\\"\'여러 나라 사람들이 이 성을 지나가며 서로 말할 거야. 여호와께서 이 큰 성에 어찌하여 이렇게 행하셨을까?\'\\""},{"n":9,"t":"\\"\'그러면 대답이 있을 거야. 이는 그들이 자기 하나님 여호와의 언약(약속)을 버리고 다른 신들에게 절하고 그들을 섬겼기 때문이야.\' 이렇게 말해라.\\""},{"n":10,"t":"\\"너희는 죽은 자(요시야 왕)를 위해 울지 말고, 그를 위해 슬퍼하지 마라. 잡혀간 자(여호아하스)를 위해 슬피 울어라. 그가 다시는 돌아와서 자기 고국을 보지 못할 것이기 때문이야.\\""},{"n":11,"t":"\\"나 여호와가 유다 왕 요시야의 아들, 그 아버지 요시야의 뒤를 이어 왕이 되었다가 이곳에서 끌려간 살룸(여호아하스)에 대해서 말한다. 그가 이곳으로 다시 돌아오지 못하고,\\""},{"n":12,"t":"\\"끌려간 그곳에서 죽을 것이며, 이 땅을 다시 보지 못할 거야.\\""},{"n":13,"t":"\\"부정한(불의한) 방법으로 자기 집을 짓고 공평하지 않게 다락방을 짓고, 이웃을 일하게 하고도 일한 값(품삯)을 주지 않는 자에게 화 있을진저!\\""},{"n":14,"t":"\\"그가 \'내가 나를 위해 큰 집과 넓은 다락방을 짓겠다\'라고 하면서 자기 집을 위해 창문을 만들고, 백향목으로 입히고, 빨간 색으로 칠하는구나.\\""},{"n":15,"t":"\\"네가 백향목으로 집 짓기를 경쟁한다고 해서 왕이 될 수 있겠느냐? 네 아버지(요시야)는 잘 먹고 마시지 않았느냐? 그러면서도 공평과 의로운 일을 행하지 않았느냐? 그래서 그때 그가 잘되었단다.\\""},{"n":16,"t":"\\"그는 가난한 자와 어려운 자를 돕고 잘되었어. 이것이 나를 아는 게 아니냐? 이것은 여호와의 말이야.\\""},{"n":17,"t":"\\"그러나 네 눈과 네 마음은 욕심을 부리고, 죄 없는 자의 피를 흘리며, 누르고 폭력을 행하려는 데에만 가 있구나.\\""},{"n":18,"t":"\\"그러므로 나 여호와가 유다 왕 요시야의 아들 여호야김에 대해 이렇게 말한다. \'사람들이 그를 위해서 ‘아, 슬프다 내 형제여, 슬프다 내 자매여’ 하며 통곡하지 않을 것이고, 그를 위해서 ‘아, 슬프다 주여, 슬프다 그 영광이여’ 하며 통곡하지도 않을 거야.\'\\""},{"n":19,"t":"\\"\'그가 끌려가서 예루살렘 문 밖에 던져지고 나귀처럼 묻힐 거야.\'\\""},{"n":20,"t":"\\"너는 레바논에 올라가 외치고, 바산에서 네 목소리를 높이며, 아바림에서도 외쳐라. 너를 사랑하던 자(동맹국)들이 모두 멸망했기 때문이야.\\""},{"n":21,"t":"\\"네가 평안할 때 내가 너에게 말했지만, 너는 \'나는 듣지 않겠다\'라고 했지. 네가 어렸을 때부터 내 목소리를 듣지 않은 것이 네 습관이 되었구나.\\""},{"n":22,"t":"\\"네 목자(지도자)들은 모두 바람에 삼켜질 것이고, 너를 사랑하던 자들은 사로잡혀 갈 거야. 그때 네가 정말로 너의 모든 못된 짓 때문에 부끄러움과 욕을 당할 거야.\\""},{"n":23,"t":"\\"레바논에 살면서 백향목으로 둥지를 튼 자(예루살렘)야, 여인이 아기를 낳을 때 같은 고통이 너에게 닥치면, 너의 가련함(불쌍함)이 얼마나 심할까?\\""},{"n":24,"t":"\\"나 여호와가 말한다. 내 삶을 두고 맹세하건대, 유다 왕 여호야김의 아들 너 고니야(여호야긴)가 내 오른손의 인장반지(왕의 도장)일지라도 내가 빼어\\""},{"n":25,"t":"\\"네 목숨을 노리는 자의 손과 네가 무서워하는 자의 손, 곧 바벨론 왕 느부갓네살의 손과 갈대아 사람의 손에 줄 거야.\\""},{"n":26,"t":"\\"내가 너와 너를 낳은 어머니를 너희가 태어나지 않은 다른 지방으로 쫓아낼 것이고, 너희가 거기서 죽을 거야.\\""},{"n":27,"t":"\\"너희가 마음으로 돌아오기를 원하는 그 땅에 다시 돌아오지 못할 거야.\\""},{"n":28,"t":"\\"이 사람 고니야는 천한 깨진 그릇이냐? 아무도 좋아하지 않는 그릇이냐? 어찌하여 그와 그 자손이 쫓겨나서 알지 못하는 땅으로 들어갔느냐?\\""},{"n":29,"t":"\\"땅이여, 땅이여, 땅이여! 여호와의 말을 들어라.\\""},{"n":30,"t":"\\"나 여호와가 이렇게 말한다. 너희는 이 사람을 자식이 없을(무자할) 것이고, 평생 잘되지 못할 자라고 기록해라. 이는 그의 자손 중에 잘되어서 다윗의 자리에 앉아 유다를 다스릴 사람이 다시는 없을 것이기 때문이야.\\""}]}},{"chapter":23,"title":"거짓 선지자에 대한 경고","verses":{"krv":[{"n":1,"t":"나 여호와가 말하노라 내 목장의 양무리를 멸하며 흩는 목자에게 화 있으리라"},{"n":2,"t":"그러므로 이스라엘 하나님 나 여호와가 내 백성을 기르는 목자에게 이같이 말하노라 너희가 내 양무리를 흩으며 그것을 몰아내고 돌아보지 아니하였도다 보라 내가 너희의 악행을 인하여 너희에게 보응하리라 여호와의 말이니라"},{"n":3,"t":"내가 내 양무리의 남은 자를 그 몰려갔던 모든 지방에서 모아 내어 다시 그 우리로 돌아오게 하리니 그들의 생육이 번성할 것이며"},{"n":4,"t":"내가 그들을 기르는 목자들을 그들 위에 세우리니 그들이 다시는 두려워하거나 놀라거나 축이 나지 아니하리라 여호와의 말이니라"},{"n":5,"t":"나 여호와가 말하노라 보라 때가 이르리니 내가 다윗에게 한 의로운 가지를 일으킬 것이라 그가 왕이 되어 지혜롭게 행사하며 세상에서 공평과 정의를 행할 것이며"},{"n":6,"t":"그의 날에 유다는 구원을 얻겠고 이스라엘은 평안히 거할 것이며 그 이름은 여호와 우리의 의라 일컬음을 받으리라"},{"n":7,"t":"그러므로 나 여호와가 말하노라 보라 날이 이르리니 그들이 다시는 이스라엘 자손을 애굽 땅에서 인도하여 내신 여호와의 사심으로 맹세하지 아니하고"},{"n":8,"t":"이스라엘 집 자손을 북방 땅 그 모든 쫓겨났던 나라에서 인도하여 내신 여호와의 사심으로 맹세할 것이며 그들이 자기 땅에 거하리라 하시니라"},{"n":9,"t":"선지자들에 대한 말씀이라 내 중심이 상하며 내 모든 뼈가 떨리며 내가 취한 사람 같으며 포도주에 잡힌 사람 같으니 이는 여호와와 그 거룩한 말씀을 인함이라"},{"n":10,"t":"이 땅에 행음하는 자가 가득하도다 저주로 인하여 땅이 슬퍼하며 광야의 초장들이 마르나니 그들의 행위가 악하고 힘쓰는 것이 정직하지 못함이로다"},{"n":11,"t":"여호와께서 말씀하시되 선지자와 제사장이 다 사특한지라 내가 내 집에서도 그들의 악을 발견하였노라"},{"n":12,"t":"그러므로 그들의 길이 그들에게 흑암 중에 미끄러운 곳과 같이 되고 그들이 밀침을 받아 그 길에 엎드러질 것이라 그들을 벌하는 해에 내가 그들에게 재앙을 내리리라 여호와의 말이니라"},{"n":13,"t":"내가 사마리아 선지자들 중에 우매함이 있음을 보았나니 그들은 바알을 의탁하고 예언하여 내 백성 이스라엘을 그릇되게 하였고"},{"n":14,"t":"내가 예루살렘 선지자들 중에도 가증한 일이 있음을 보았나니 그들은 간음을 행하며 행악자의 손을 굳게 하여 사람으로 그 악에서 돌이킴이 없게 하였은즉 그들은 다 내 앞에서 소돔 사람과 다름이 없고 그 거민은 고모라 사람과 다름이 없느니라"},{"n":15,"t":"그러므로 만군의 여호와 내가 선지자에 대하여 이같이 말하노라 보라 내가 그들에게 쑥을 먹이며 독한 물을 마시우리니 이는 사악이 예루살렘 선지자들에게로서 나와서 온 땅에 퍼짐이라 하시니라"},{"n":16,"t":"만군의 여호와께서 이같이 말씀하시되 너희에게 예언하는 선지자들의 말을 듣지 말라 그들은 너희에게 헛된 것을 가르치나니 그들의 말한 묵시는 자기 마음으로 말미암은 것이요 여호와의 입에서 나온 것이 아니니라"},{"n":17,"t":"항상 그들이 나를 멸시하는 자에게 이르기를 너희가 평안하리라 여호와의 말씀이니라 하며 또 자기 마음의 강퍅한 대로 행하는 모든 사람에게 이르기를 재앙이 너희에게 임하지 아니하리라 하였느니라"},{"n":18,"t":"누가 여호와의 회의에 참여하여 그 말을 알아들었으며 누가 귀를 기울여 그 말을 들었느뇨"},{"n":19,"t":"보라 나 여호와의 노가 발하여 폭풍과 회리바람처럼 악인의 머리를 칠 것이라"},{"n":20,"t":"나 여호와의 노는 내 마음의 뜻하는 바를 행하여 이루기까지는 쉬지 아니하나니 너희가 말일에 그것을 완전히 깨달으리라"},{"n":21,"t":"이 선지자들은 내가 보내지 아니하였어도 달음질하며 내가 그들에게 이르지 아니하였어도 예언하였은즉"},{"n":22,"t":"그들이 만일 나의 회의에 참예하였더면 내 백성에게 내 말을 들려서 그들로 악한 길과 악한 행위에서 돌이키게 하였으리라"},{"n":23,"t":"나 여호와가 말하노라 나는 가까운데 하나님이요 먼데 하나님은 아니냐"},{"n":24,"t":"나 여호와가 말하노라 사람이 내게 보이지 아니하려고 누가 자기를 은밀한 곳에 숨길 수 있겠느냐 나 여호와가 말하노라 나는 천지에 충만하지 아니하냐"},{"n":25,"t":"내 이름으로 거짓을 예언하는 선지자들의 말에 내가 몽사를 얻었다 함을 내가 들었노라"},{"n":26,"t":"거짓을 예언하는 선지자들이 언제까지 이 마음을 품겠느냐 그들은 그 마음의 간교한 것을 예언하느니라"},{"n":27,"t":"그들이 서로 몽사를 말하니 그 생각인즉 그들의 열조가 바알로 인하여 내 이름을 잊어버린 것 같이 내 백성으로 내 이름을 잊게 하려 함이로다"},{"n":28,"t":"나 여호와가 말하노라 몽사를 얻은 선지자는 몽사를 말할 것이요 내 말을 받은 자는 성실함으로 내 말을 말할 것이라 겨와 밀을 어찌 비교하겠느냐"},{"n":29,"t":"나 여호와가 말하노라 내 말이 불같지 아니하냐 반석을 쳐서 부스러뜨리는 방망이 같지 아니하냐"},{"n":30,"t":"나 여호와가 말하노라 그러므로 보라 서로 내 말을 도적질하는 선지자들을 내가 치리라"},{"n":31,"t":"나 여호와가 말하노라 보라 그들이 혀를 놀려 그가 말씀하셨다 하는 선지자들을 내가 치리라"},{"n":32,"t":"나 여호와가 말하노라 보라 거짓 몽사를 예언하여 이르며 거짓과 헛된 자만으로 내 백성을 미혹하게 하는 자를 내가 치리라 내가 그들을 보내지 아니하였으며 명하지 아니하였나니 그들이 이 백성에게 아무 유익이 없느니라 여호와의 말이니라"},{"n":33,"t":"이 백성이나 선지자나 제사장이 네게 물어 이르기를 여호와의 엄중한 말씀이 무엇이뇨 하거든 너는 그들에게 대답하기를 엄중한 말씀이 무엇이냐 하느냐 여호와의 말씀에 내가 너희를 버리리라 하셨고"},{"n":34,"t":"또 여호와의 엄중한 말씀이라 하는 선지자에게나 제사장에게나 백성에게는 내가 그 사람과 그 집에 벌하리라 하셨다 하고"},{"n":35,"t":"너는 또 말하기를 너희는 서로 이웃과 형제에게 묻기를 여호와께서 무엇이라 응답하셨으며 무엇이라 말씀하셨느뇨 하고"},{"n":36,"t":"다시는 여호와의 엄중한 말씀이라 말하지 말라 각 사람의 말이 자기에게 중벌이 되리니 이는 너희가 사시는 하나님 만군의 여호와 우리 하나님의 말씀을 망령되이 씀이니라 하고"},{"n":37,"t":"너는 또 선지자에게 말하기를 여호와께서 네게 무엇이라 대답하셨으며 여호와께서 무엇이라 말씀하셨느뇨"},{"n":38,"t":"너희는 여호와의 엄중한 말씀이라 말하도다 그러므로 여호와께서 가라사대 내가 너희에게 보내어 여호와의 엄중한 말씀이라 하지 말라 하였어도 너희가 여호와의 엄중한 말씀이라 하였은즉"},{"n":39,"t":"내가 너희를 온전히 잊어버리며 내가 너희와 너희 열조에게 준 이 성읍을 내 앞에서 내어버려"},{"n":40,"t":"너희로 영원한 치욕과 잊지 못할 영구한 수치를 당케 하리라 하셨다 할지니라"}],"kids":[{"n":1,"t":"\\"나 여호와가 말한다. 내 목장의 양 떼를 멸하며 흩는 목자(못된 지도자)들에게 화 있을진저!\\""},{"n":2,"t":"\\"그러므로 이스라엘의 하나님 나 여호와가 내 백성을 기르는 목자들에게 이렇게 말한다. \'너희가 내 양 떼를 흩어 버리고 몰아내며 돌보지 않았어. 보아라, 내가 너희의 못된 행동에 따라 너희에게 갚아 줄 거야.\' 이것은 여호와의 말이야.\\""},{"n":3,"t":"\\"내가 내 양 떼의 남은 자들을 그들이 쫓겨갔던 모든 지방에서 모아 다시 그 우리(양이 사는 곳)로 돌아오게 할 것이고, 그들이 많이 늘어나고 번성하게 될 거야.\\""},{"n":4,"t":"\\"내가 그들을 돌보는 목자들을 세울 것이고, 그들이 다시는 두려워하지 않고 놀라지 않으며 한 명도 잃지(축이 나지) 않을 거야. 이것은 여호와의 말이야.\\""},{"n":5,"t":"\\"나 여호와가 말한다. 보아라, 때가 올 거야. 그때에 내가 다윗에게 의로운 가지(메시아)를 일으킬 것이고, 그가 왕이 되어 지혜롭게 다스리며 세상에서 공평과 정의를 행할 거야.\\""},{"n":6,"t":"\\"그분의 날에 유다는 구원을 얻고, 이스라엘은 평안히 살게 될 것이며, 그분의 이름은 \'여호와 우리의 의\'라고 불릴 거야.\\""},{"n":7,"t":"\\"그러므로 나 여호와가 말한다. 보아라, 날이 오면 그들이 다시는 \'이스라엘 자손을 애굽 땅에서 이끌어 내신 여호와의 살아 계심\'으로 맹세하지 않고,\\""},{"n":8,"t":"\\"\'이스라엘 집의 자손을 북쪽 땅과 그들이 쫓겨났던 모든 나라에서 이끌어 내신 여호와의 살아 계심\'으로 맹세할 거야. 그리고 그들이 자기 땅에서 살게 될 거야.\\""},{"n":9,"t":"\\"선지자들에 대한 말씀이야. 내 마음이 무너지고 내 모든 뼈가 떨리며, 내가 마치 술 취한 사람처럼, 포도주에 사로잡힌 사람처럼 되었어. 이는 여호와와 그분의 거룩한 말씀 때문이야.\\""},{"n":10,"t":"\\"이 땅이 음란한(부정한) 자들로 가득해. 저주 때문에 땅이 슬퍼하고, 광야의 풀밭이 마르는구나. 그들의 행동이 못되고, 그들이 힘쓰는 일이 정직하지 못하기 때문이야.\\""},{"n":11,"t":"\\"여호와께서 말씀하셨어. \'선지자와 제사장이 모두 못되었어. 내가 내 집(성전)에서도 그들의 못된 짓을 발견했단다.\'\\""},{"n":12,"t":"\\"\'그러므로 그들의 길이 어둠 속의 미끄러운 곳처럼 되어, 그들이 거기서 밀려 넘어질 거야. 내가 그들을 벌하는 해에 그들에게 재앙을 내릴 거야. 이것은 여호와의 말이야.\'\\""},{"n":13,"t":"\\"내가 사마리아 선지자들 중에 어리석은 짓이 있음을 보았어. 그들은 바알에게 의지해서 예언했고, 내 백성 이스라엘을 잘못된 길로 이끌었어.\\""},{"n":14,"t":"\\"내가 또 예루살렘 선지자들 중에 미운(가증한) 일이 있음을 보았어. 그들은 부정한 일(간음)을 행하고 거짓을 말하며, 못된 자들의 손을 굳게 해서 사람이 못된 길에서 돌아오지 못하게 했어. 그러므로 그들은 모두 내 앞에서 소돔 사람과 다름이 없고, 그곳에 사는 사람들은 고모라 사람과 다름이 없단다.\\""},{"n":15,"t":"\\"그러므로 만군의 여호와인 내가 선지자들에 대해 이렇게 말한다. \'보아라, 내가 그들에게 쑥(쓴 풀)을 먹이고 독한 물을 마시게 할 거야. 이는 사악함이 예루살렘 선지자들에게서 나와 온 땅에 퍼졌기 때문이야.\'\\""},{"n":16,"t":"\\"만군의 여호와께서 이렇게 말씀하셨어. \'너희는 너희에게 예언하는 선지자들의 말을 듣지 마라. 그들은 너희에게 헛된 것을 가르쳐. 그들이 말하는 환상(묵시)은 자기 마음에서 나온 것이고, 여호와의 입에서 나온 것이 아니야.\'\\""},{"n":17,"t":"\\"그들은 늘 나를 무시하는 자들에게 \'너희가 평안할 거야. 여호와의 말씀이다\'라고 말하고, 자기 마음의 고집대로 행하는 모든 사람에게 \'너희에게 재앙이 닥치지 않을 거야\'라고 말한단다.\\""},{"n":18,"t":"\\"그러나 누가 여호와의 회의(모임)에 참여해서 그분의 말씀을 알아들었느냐? 누가 귀를 기울여 그분의 말씀을 들었느냐?\\""},{"n":19,"t":"\\"보아라, 나 여호와의 분노가 폭풍과 회오리바람처럼 일어나서 못된 자의 머리를 칠 거야.\\""},{"n":20,"t":"\\"나 여호와의 분노는 내 마음이 뜻한 것을 다 이루기까지 그치지 않을 거야. 너희가 마지막 날에 그것을 완전히 깨닫게 될 거야.\\""},{"n":21,"t":"\\"이 선지자들은 내가 보내지 않았는데도 달려갔고, 내가 그들에게 말하지 않았는데도 예언했어.\\""},{"n":22,"t":"\\"그들이 만일 내 회의에 참여했더라면, 내 백성에게 내 말을 들려주어 그들을 못된 길과 못된 행동에서 돌이키게 했을 거야.\\""},{"n":23,"t":"\\"나 여호와가 말한다. 나는 가까이 있는 하나님이지, 멀리 있는 하나님만이 아니지 않으냐?\\""},{"n":24,"t":"\\"나 여호와가 말한다. 사람이 내게 보이지 않으려고 어떤 비밀스런 곳에 자기를 숨길 수 있겠느냐? 나 여호와가 말한다. 나는 하늘과 땅에 가득하지 않느냐?\\""},{"n":25,"t":"\\"내가 들었어. 내 이름으로 거짓 예언하는 선지자들이 \'내가 꿈을 꾸었다, 내가 꿈을 꾸었다\'라고 말하는 것을.\\""},{"n":26,"t":"\\"거짓을 예언하는 선지자들이 언제까지 이런 마음을 품을 거냐? 그들은 자기 마음의 간교한 것(못된 꾀)을 예언하고 있어.\\""},{"n":27,"t":"\\"그들이 서로 꿈 이야기를 하면서, 마치 그 조상들이 바알 때문에 내 이름을 잊어버렸던 것처럼, 내 백성도 내 이름을 잊게 하려고 해.\\""},{"n":28,"t":"\\"나 여호와가 말한다. 꿈을 꾼 선지자는 꿈을 말할 것이고, 내 말을 받은 자는 진실하게(성실하게) 내 말을 전할 거야. 겨와 알곡(밀)을 어찌 비교할 수 있겠느냐?\\""},{"n":29,"t":"\\"나 여호와가 말한다. 내 말이 불 같지 않느냐? 바위를 쳐서 부수는 망치 같지 않느냐?\\""},{"n":30,"t":"\\"나 여호와가 말한다. 그러므로 보아라, 내 말을 서로 도둑질하는 선지자들을 내가 칠 거야.\\""},{"n":31,"t":"\\"나 여호와가 말한다. 보아라, 자기 혀를 놀려 \'여호와께서 말씀하셨다\'라고 거짓말하는 선지자들을 내가 칠 거야.\\""},{"n":32,"t":"\\"나 여호와가 말한다. 보아라, 거짓 꿈을 예언하며 거짓과 헛된 자만(우쭐댐)으로 내 백성을 잘못된 길로 이끄는 자들을 내가 칠 거야. 내가 그들을 보내지도 않았고 명령하지도 않았으니, 그들이 이 백성에게 아무 도움이 되지 않아. 이것은 여호와의 말이야.\\""},{"n":33,"t":"\\"이 백성이나 선지자나 제사장이 너에게 \'여호와의 엄중한 말씀(짐 같은 무거운 말씀)이 무엇이냐?\'라고 묻거든, 너는 그들에게 대답해라. \'엄중한 말씀이 무엇이냐? 여호와께서 말씀하시기를 내가 너희를 버리겠다.\'\\""},{"n":34,"t":"\\"또 \'여호와의 엄중한 말씀이라\'라고 하는 선지자나 제사장이나 백성에게는 내가 그 사람과 그 집안을 벌하겠다고 하셨어.\\""},{"n":35,"t":"\\"너는 또 이렇게 말해라. \'너희는 서로 이웃과 형제에게 이렇게 물어라. 여호와께서 무엇이라고 응답하셨느냐? 여호와께서 무엇이라고 말씀하셨느냐?\'\\""},{"n":36,"t":"\\"다시는 \'여호와의 엄중한 말씀이라\'라고 말하지 마라. 각 사람의 그 말이 자기에게 큰 벌이 될 거야. 이는 너희가 살아 계신 하나님 만군의 여호와, 우리 하나님의 말씀을 함부로 사용하는 것이기 때문이야.\\""},{"n":37,"t":"\\"너는 또 선지자에게 이렇게 물어라. \'여호와께서 너에게 무엇이라고 대답하셨느냐? 여호와께서 무엇이라고 말씀하셨느냐?\'\\""},{"n":38,"t":"\\"너희가 \'여호와의 엄중한 말씀이라\'라고 말한다면, 그러므로 여호와께서 이렇게 말씀하셨다. \'내가 너희에게 사람을 보내어 여호와의 엄중한 말씀이라고 말하지 말라고 했어도 너희가 여호와의 엄중한 말씀이라고 했으니,\'\\""},{"n":39,"t":"\\"\'내가 너희를 완전히 잊어버리고, 내가 너희와 너희 조상에게 준 이 성을 내 앞에서 던져 버려서,\'\\""},{"n":40,"t":"\\"\'너희에게 영원한 부끄러움(치욕)과 잊지 못할 영원한 수치를 당하게 할 거야.\' 이렇게 말해라.\\""}]}},{"chapter":24,"title":"좋은 무화과와 나쁜 무화과","verses":{"krv":[{"n":1,"t":"바벨론 왕 느부갓네살이 유다 왕 여호야김의 아들 여고냐와 유다 방백들과 목공들과 철공들을 예루살렘에서 바벨론으로 옮긴 후에 여호와께서 여호와의 전 앞에 놓인 무화과 두 광주리로 내게 보이셨는데"},{"n":2,"t":"한 광주리에는 처음 익은 듯한 극히 좋은 무화과가 있고 한 광주리에는 악하여 먹을 수 없는 극히 악한 무화과가 있더라"},{"n":3,"t":"여호와께서 내게 이르시되 예레미야야 네가 무엇을 보느냐 내가 대답하되 무화과이온데 그 좋은 무화과는 극히 좋고 그 악한 것은 극히 악하여 먹을 수 없게 악하니라"},{"n":4,"t":"여호와의 말씀이 또 내게 임하니라 가라사대"},{"n":5,"t":"이스라엘의 하나님 여호와가 이같이 말하노라 내가 이곳에서 옮겨 갈대아인의 땅에 이르게 한 유다 포로를 이 좋은 무화과 같이 보아 좋게 할 것이라"},{"n":6,"t":"내가 그들을 돌아보아 좋게 하여 다시 이 땅으로 인도하고 세우고 헐지 아니하며 심고 뽑지 아니하겠고"},{"n":7,"t":"내가 여호와인 줄 아는 마음을 그들에게 주어서 그들로 전심으로 내게 돌아오게 하리니 그들은 내 백성이 되겠고 나는 그들의 하나님이 되리라"},{"n":8,"t":"나 여호와가 이같이 말하노라 내가 유다 왕 시드기야와 그 방백들과 예루살렘의 남은 자로서 이 땅에 남아 있는 자와 애굽 땅에 거하는 자들을 이 악하여 먹을 수 없는 악한 무화과 같이 버리되"},{"n":9,"t":"세상 모든 나라 중에 흩어서 그들로 환난을 당하게 할 것이며 또 그들로 내가 쫓아보낼 모든 곳에서 치욕을 당케 하며 말거리가 되게 하며 조롱과 저주를 받게 할 것이며"},{"n":10,"t":"내가 칼과 기근과 염병을 그들 중에 보내어 그들로 내가 그들과 그 열조에게 준 땅에서 멸절하기까지 이르게 하리라 하시니라"}],"kids":[{"n":1,"t":"바벨론 왕 느부갓네살이 유다 왕 여호야김의 아들 여고냐(여호야긴)와 유다의 높은 사람들과 목공(나무 일하는 사람)들과 철공(쇠 일하는 사람)들을 예루살렘에서 바벨론으로 끌고 간 후에, 여호와께서 여호와의 성전 앞에 놓인 무화과 두 광주리를 내게 보여 주셨어요."},{"n":2,"t":"한 광주리에는 처음 익은 것 같은 아주 좋은 무화과가 있었고, 또 한 광주리에는 너무 나빠서 먹을 수 없을 정도로 매우 못된 무화과가 있었어요."},{"n":3,"t":"여호와께서 내게 말씀하셨어요. \\"예레미야야, 무엇이 보이느냐?\\" 내가 대답했어요. \\"무화과예요. 좋은 무화과는 정말 좋고, 나쁜 것은 너무 나빠서 먹을 수 없을 정도예요.\\""},{"n":4,"t":"여호와의 말씀이 또 내게 들려왔어요."},{"n":5,"t":"\\"이스라엘의 하나님 여호와가 이렇게 말한다. 내가 이곳에서 갈대아 사람들의 땅으로 끌려간 유다의 포로들을 이 좋은 무화과처럼 보고 좋게 여길 거야.\\""},{"n":6,"t":"\\"내가 그들을 돌보고 좋게 여겨서 다시 이 땅으로 데려와 세우고 헐지 않을 것이며, 심고 뽑지 않을 거야.\\""},{"n":7,"t":"\\"내가 여호와인 줄 아는 마음을 그들에게 주어, 그들이 마음을 다해 내게 돌아오게 할 거야. 그러면 그들은 내 백성이 되고, 나는 그들의 하나님이 될 거야.\\""},{"n":8,"t":"\\"나 여호와가 이렇게 말한다. 내가 유다 왕 시드기야와 그 높은 사람들과 예루살렘에서 살아남아 이 땅에 남아 있는 자들과 애굽 땅에 사는 자들을, 너무 나빠서 먹을 수 없는 못된 무화과처럼 버릴 거야.\\""},{"n":9,"t":"\\"세상 모든 나라 가운데로 흩어 그들이 어려움을 당하게 할 것이며, 또 그들로 내가 쫓아 보낼 모든 곳에서 부끄러움을 당하게 하고, 사람들의 입에 오르내리는(말거리가 되는) 일이 되게 하며, 비웃음과 저주를 받게 할 거야.\\""},{"n":10,"t":"\\"내가 칼과 기근(굶주림)과 염병(전염병)을 그들 가운데 보내어, 내가 그들과 그 조상에게 준 땅에서 그들이 다 멸망할 때까지 그렇게 할 거야.\\""}]}},{"chapter":25,"title":"포로 70년의 예언","verses":{"krv":[{"n":1,"t":"유다 왕 요시야의 아들 여호야김 사년 곧 바벨론 왕 느부갓네살 원년에 유다 모든 백성에 관한 말씀이 예레미야에게 임하니라"},{"n":2,"t":"선지자 예레미야가 유다 모든 백성과 예루살렘 모든 거민에게 고하여 가로되"},{"n":3,"t":"유다 왕 아몬의 아들 요시야의 십삼년부터 오늘까지 이십삼 년 동안에 여호와의 말씀이 내게 임하기로 내가 너희에게 이르되 부지런히 일렀으나 너희가 듣지 아니하였으며"},{"n":4,"t":"여호와께서 그 모든 종 선지자를 너희에게 보내시되 부지런히 보내셨으나 너희가 듣지 아니하였으며 귀를 기울여 들으려고도 아니하였도다"},{"n":5,"t":"이르시기를 너희는 각기 악한 길과 너희 악행에서 돌이키라 그리하면 나 여호와가 너희와 너희 열조에게 옛적에 주어 영원히 있게 한 그 땅에 거하리니"},{"n":6,"t":"너희는 다른 신을 좇아 섬기거나 숭배하지 말며 너희 손으로 만든 것을 인하여 나의 노를 격동치 말라 그리하면 내가 너희를 해치 아니하리라 하였으나"},{"n":7,"t":"너희가 내 말을 듣지 아니하고 너희 손으로 만든 것으로 나의 노를 격동하여 스스로 해하였느니라 여호와의 말이니라"},{"n":8,"t":"그러므로 나 만군의 여호와가 이같이 말하노라 너희가 내 말을 듣지 아니하였은즉"},{"n":9,"t":"보라 내가 보내어 북방 모든 족속과 내 종 바벨론 왕 느부갓네살을 불러다가 이 땅과 그 거민과 사방 모든 나라를 쳐서 진멸하여 그들로 놀램과 치소거리가 되게 하며 땅으로 영영한 황무지가 되게 할 것이라"},{"n":10,"t":"내가 그들 중에서 기뻐하는 소리와 즐거워하는 소리와 신랑의 소리와 신부의 소리와 맷돌소리와 등불 빛이 끊쳐지게 하리니"},{"n":11,"t":"이 온 땅이 황폐하여 놀램이 될 것이며 이 나라들은 칠십 년 동안 바벨론 왕을 섬기리라"},{"n":12,"t":"나 여호와가 말하노라 칠십 년이 마치면 내가 바벨론 왕과 그 나라와 갈대아인의 땅을 그 죄악으로 인하여 벌하여 영영히 황무케 하되"},{"n":13,"t":"내가 그 땅에 대하여 선고한 바 곧 예레미야가 열방에 대하여 예언하고 이 책에 기록한 나의 모든 말을 그 땅에 임하게 하리니"},{"n":14,"t":"여러 나라와 큰 왕들이 그들로 자기 역군을 삼으리라 내가 그들의 행위와 그들의 손의 행한 대로 보응하리라 하시니라"},{"n":15,"t":"이스라엘의 하나님 여호와께서 이같이 내게 이르시되 너는 내 손에서 이 진노의 잔을 받아 가지고 내가 너를 보내는 바 그 모든 나라로 마시게 하라"},{"n":16,"t":"그들이 마시고 비틀거리며 미치리니 이는 내가 그들 중에 칼을 보냄을 인함이니라 하시기로"},{"n":17,"t":"내가 여호와의 손에서 그 잔을 받아서 여호와께서 나를 보내신 바 그 모든 나라로 마시게 하되"},{"n":18,"t":"예루살렘과 유다 성읍들과 그 왕들과 그 방백들로 마시게 하였더니 그들이 멸망과 놀램과 치소와 저주를 당함이 오늘날과 같으니라"},{"n":19,"t":"또 애굽 왕 바로와 그의 신하들과 그의 방백들과 그의 모든 백성과"},{"n":20,"t":"모든 잡족과 우스 땅 모든 왕과 블레셋 사람의 땅 모든 왕과 아스글론과 가사와 에그론과 아스돗의 남은 자와"},{"n":21,"t":"에돔과 모압과 암몬 자손과"},{"n":22,"t":"두로의 모든 왕과 시돈의 모든 왕과 바다 저편 섬의 왕들과"},{"n":23,"t":"드단과 데마와 부스와 털을 모지게 깎은 모든 자와"},{"n":24,"t":"아라비아 모든 왕과 광야에 거하는 잡족의 모든 왕과"},{"n":25,"t":"시므리의 모든 왕과 엘람의 모든 왕과 메대의 모든 왕과"},{"n":26,"t":"북방 원근의 모든 왕과 지면에 있는 세상의 모든 나라로 마시게 하니라 세삭 왕은 그 후에 마시리라"},{"n":27,"t":"너는 그들에게 이르기를 만군의 여호와 이스라엘의 하나님의 말씀에 너희는 마시라 취하라 토하라 엎드러지고 다시는 일어나지 말라 이는 내가 너희 중에 칼을 보냄을 인함이니라 하셨다 하라"},{"n":28,"t":"그들이 만일 네 손에서 잔을 받아 마시기를 거절하거든 너는 그들에게 이르기를 만군의 여호와의 말씀에 너희가 반드시 마시리라"},{"n":29,"t":"보라 내가 내 이름으로 일컬음을 받는 성에서부터 재앙 내리기를 시작하였은즉 너희가 어찌 능히 형벌을 면할 수 있느냐 면치 못하리니 이는 내가 칼을 불러 세상의 모든 거민을 칠 것임이니라 하셨다 하라 만군의 여호와의 말이니라"},{"n":30,"t":"그러므로 너는 그들에게 이 모든 말로 예언하여 이르기를 여호와께서 높은 데서 부르시며 그 거룩한 처소에서 소리를 발하시며 그 양의 우리를 향하여 크게 부르시며 세상 모든 거민을 대하여 포도 밟는 자 같이 외치시리니"},{"n":31,"t":"요란한 소리가 땅 끝까지 이름은 여호와께서 열국과 다투시며 모든 육체를 심판하시며 악인을 칼에 붙이심을 인함이라 하라 여호와의 말이니라"},{"n":32,"t":"나 만군의 여호와가 말하노라 보라 재앙이 나서 나라에서 나라에 미칠 것이며 대풍이 땅 끝에서 일어날 것이라"},{"n":33,"t":"그 날에 나 여호와에게 살륙을 당한 자가 땅 이 끝에서 땅 저 끝에 미칠 것이나 그들이 슬퍼함을 받지 못하며 염습함을 입지 못하며 매장함을 얻지 못하고 지면에서 분토가 되리로다"},{"n":34,"t":"너희 목자들아 외쳐 애곡하라 너희 양떼의 인도자들아 재에 굴라 이는 너희 도륙을 당할 날과 흩음을 당할 기한이 찼음인즉 너희가 귀한 그릇의 떨어짐 같이 될 것이라"},{"n":35,"t":"목자들은 도망할 수 없겠고 양떼의 인도자들은 도피할 수 없으리로다"},{"n":36,"t":"목자들의 부르짖음과 양떼의 인도자들의 애곡하는 소리여 나 여호와가 그들의 초장으로 황폐케 함이로다"},{"n":37,"t":"평안한 목장들이 적막하니 이는 여호와의 진노의 연고로다"},{"n":38,"t":"그가 사자 같이 그 소혈에서 나오셨도다 그 잔멸하는 자의 진노와 그 극렬한 분으로 인하여 그들의 땅이 황량하였도다"}],"kids":[{"n":1,"t":"유다 왕 요시야의 아들 여호야김 4년, 곧 바벨론 왕 느부갓네살 1년에, 유다 모든 백성에 관한 말씀이 예레미야에게 들려왔어요."},{"n":2,"t":"선지자 예레미야가 유다 모든 백성과 예루살렘에 사는 모든 사람들에게 말했어요."},{"n":3,"t":"\\"유다 왕 아몬의 아들 요시야 13년부터 오늘까지 23년 동안 여호와의 말씀이 내게 들려왔고, 내가 너희에게 부지런히 말했지만 너희는 듣지 않았어.\\""},{"n":4,"t":"\\"여호와께서 그 모든 종 선지자를 너희에게 부지런히 보내셨지만, 너희는 듣지 않고 귀를 기울여 들으려고도 하지 않았어.\\""},{"n":5,"t":"\\"여호와께서 말씀하시기를 \'너희는 각자 못된 길과 못된 행동에서 돌이켜라. 그러면 나 여호와가 너희와 너희 조상에게 옛날부터 영원히 주어 살게 한 그 땅에서 살게 될 거야.\'\\""},{"n":6,"t":"\\"\'너희는 다른 신을 따라 섬기거나 절하지 말고, 너희 손으로 만든 것 때문에 내 분노를 일으키지 마라. 그러면 내가 너희를 해치지 않겠다.\' 그러나 너희가 듣지 않았어.\\""},{"n":7,"t":"\\"너희가 내 말을 듣지 않고, 너희 손으로 만든 것으로 내 분노를 일으켜서 너희 자신을 해쳤어. 이것은 여호와의 말이야.\\""},{"n":8,"t":"\\"그러므로 나 만군의 여호와가 이렇게 말한다. 너희가 내 말을 듣지 않았기 때문에,\\""},{"n":9,"t":"\\"보아라, 내가 사람을 보내 북쪽의 모든 백성들과 내 종 바벨론 왕 느부갓네살을 불러다가 이 땅과 그 백성과 사방 모든 나라를 쳐서 깨끗이 멸할 것이고, 그들을 놀람과 비웃음거리가 되게 하며, 이 땅을 영원한 폐허(황무지)가 되게 할 거야.\\""},{"n":10,"t":"\\"내가 그들 가운데서 기뻐하는 소리, 즐거워하는 소리, 신랑과 신부의 소리, 맷돌(곡식을 가는 도구) 소리, 등불 빛이 끊어지게 할 거야.\\""},{"n":11,"t":"\\"이 온 땅이 황폐해서 놀라운 일이 될 것이고, 이 나라들이 70년 동안 바벨론 왕을 섬기게 될 거야.\\""},{"n":12,"t":"\\"나 여호와가 말한다. 70년이 끝나면 내가 바벨론 왕과 그 나라와 갈대아 사람의 땅을 그 죄 때문에 벌해서 영원히 폐허로 만들고,\\""},{"n":13,"t":"\\"내가 그 땅에 대해 선포한 바, 곧 예레미야가 모든 나라에 대해 예언하고 이 책에 기록한 내 모든 말을 그 땅에 이루어지게 할 거야.\\""},{"n":14,"t":"\\"여러 나라와 큰 왕들이 그들을 자기 일꾼(역군)으로 삼게 될 거야. 내가 그들이 한 행동과 그 손이 한 일대로 갚을 거야.\\""},{"n":15,"t":"이스라엘의 하나님 여호와께서 내게 이렇게 말씀하셨어요. \\"너는 내 손에서 이 분노의 잔(컵)을 받아 가지고, 내가 너를 보내는 모든 나라로 가서 그들에게 마시게 해라.\\""},{"n":16,"t":"\\"그들이 마시고 비틀거리며 미친 듯이 될 것이다. 이는 내가 그들 중에 칼을 보낼 것이기 때문이다.\\""},{"n":17,"t":"그래서 내가 여호와의 손에서 그 잔을 받아 여호와께서 나를 보내신 모든 나라로 가서 그들에게 마시게 했어요."},{"n":18,"t":"예루살렘과 유다 성과 그 왕들과 높은 사람들에게 마시게 했고, 그들이 멸망과 놀라움과 비웃음과 저주를 당하게 되어 오늘날과 같이 되었어요."},{"n":19,"t":"또 애굽 왕 바로와 그 신하들과 높은 사람들과 그 모든 백성과,"},{"n":20,"t":"모든 다른 민족(잡족)과 우스 땅의 모든 왕과 블레셋 사람의 땅의 모든 왕과 아스글론과 가사와 에그론과 아스돗의 남은 사람과,"},{"n":21,"t":"에돔과 모압과 암몬 자손과,"},{"n":22,"t":"두로의 모든 왕과 시돈의 모든 왕과 바다 건너편 섬의 왕들과,"},{"n":23,"t":"드단과 데마와 부스와, 머리털을 둥글게 깎은 모든 사람과,"},{"n":24,"t":"아라비아의 모든 왕과 광야에 사는 다른 민족(잡족)의 모든 왕과,"},{"n":25,"t":"시므리의 모든 왕과 엘람의 모든 왕과 메대의 모든 왕과,"},{"n":26,"t":"북쪽의 가깝고 먼 모든 왕과 땅 위에 있는 세상의 모든 나라가 마시게 했어요. 세삭(바벨론) 왕은 그 후에 마실 거예요."},{"n":27,"t":"\\"너는 그들에게 이렇게 말해라. \'만군의 여호와 이스라엘의 하나님이 이렇게 말씀하셨다. 너희는 마셔라, 취해라, 토해라, 엎드러져서 다시는 일어나지 마라. 이는 내가 너희 가운데 칼을 보낼 것이기 때문이야.\'\\""},{"n":28,"t":"\\"그들이 만일 네 손에서 잔 받기를 거절하면, 너는 그들에게 이렇게 말해라. \'만군의 여호와께서 너희가 반드시 마셔야 한다고 말씀하셨다.\'\\""},{"n":29,"t":"\\"\'보아라, 내가 내 이름이 붙은 성에서부터 재앙 내리기를 시작했는데, 너희가 어찌 벌을 면할 수 있겠느냐? 면하지 못할 거야. 이는 내가 칼을 불러 세상에 사는 모든 사람을 칠 것이기 때문이야. 이렇게 말해라. 만군의 여호와의 말이야.\'\\""},{"n":30,"t":"\\"그러므로 너는 그들에게 이 모든 말로 예언해서 이렇게 말해라. \'여호와께서 높은 곳에서 부르짖으시고, 그 거룩한 처소에서 소리를 내시며, 그 양 떼의 우리를 향해 크게 외치시고, 세상의 모든 사람을 향해 마치 포도 밟는 자처럼 외치실 거야.\'\\""},{"n":31,"t":"\\"\'요란한 소리가 땅 끝까지 이를 거야. 이는 여호와께서 모든 나라들과 다투시며, 모든 육체(사람)를 심판하시며, 못된 자를 칼에 넘기시기 때문이야.\' 이렇게 말해라. 이것은 여호와의 말이야.\\""},{"n":32,"t":"\\"나 만군의 여호와가 말한다. 보아라, 재앙이 나서 나라에서 나라로 미칠 것이며, 큰 폭풍이 땅 끝에서 일어날 거야.\\""},{"n":33,"t":"\\"그날에 나 여호와에게 죽임을 당한 자가 땅 이쪽 끝에서 저쪽 끝까지 가득할 것이지만, 그들을 위해 슬퍼해 줄 사람이 없고, 시신을 정리할 사람도 없으며, 묻어 줄 사람도 없어, 땅 위에서 거름(분토)이 될 거야.\\""},{"n":34,"t":"\\"너희 목자(지도자)들아, 외쳐 슬피 울어라. 양 떼의 지도자들아, 재 위에서 뒹굴어라. 너희가 도살 당할 날과 흩어질 때가 다 차서, 너희가 귀한 그릇이 떨어져 깨지는 것처럼 될 거야.\\""},{"n":35,"t":"\\"목자들은 도망할 수 없을 것이고, 양 떼의 지도자들은 피할 수 없을 거야.\\""},{"n":36,"t":"\\"목자들의 부르짖는 소리와 양 떼의 지도자들의 슬피 우는 소리가 들리는구나. 이는 나 여호와가 그들의 풀밭(초장)을 황폐하게 만들기 때문이야.\\""},{"n":37,"t":"\\"평안하던 목장들이 조용해졌으니, 이는 여호와의 분노 때문이야.\\""},{"n":38,"t":"\\"그분이 사자(사자처럼)처럼 자기 굴(소혈)에서 나오셨다. 멸망시키는 자의 분노와 그분의 큰 노여움 때문에 그들의 땅이 황량해졌구나.\\""}]}},{"chapter":26,"title":"예레미야가 죽음을 면함","verses":{"krv":[{"n":1,"t":"유다 왕 요시야의 아들 여호야김의 즉위 초에 여호와께로서 이 말씀이 임하니라 가라사대"},{"n":2,"t":"나 여호와가 이같이 이르노라 너는 여호와의 집 뜰에 서서 유다 모든 성읍에서 여호와의 집에 와서 경배하는 자에게 내가 네게 명하여 이르게 한 모든 말을 고하되 한 말도 감하지 말라"},{"n":3,"t":"그들이 듣고 혹시 각각 그 악한 길에서 떠나리라 그리하면 내가 그들의 악행으로 인하여 재앙을 그들에게 내리려 하던 뜻을 돌이키리라"},{"n":4,"t":"너는 그들에게 이르기를 여호와의 말씀에 너희가 나를 청종치 아니하며 내가 너희 앞에 둔 내 법을 행치 아니하며"},{"n":5,"t":"내가 너희에게 보내고 부지런히 보낸 나의 종 선지자들의 말을 이미 듣지 아니하였거니와 너희가 만일 다시 듣지 아니하면"},{"n":6,"t":"내가 이 집을 실로 같이 되게 하고 이 성으로 세계 열방의 저줏거리가 되게 하리라 하셨다 하라"},{"n":7,"t":"예레미야가 여호와의 집에서 이 말을 하매 제사장들과 선지자들과 모든 백성이 듣더라"},{"n":8,"t":"에레미야가 여호와께서 명하신 말씀을 모든 백성에게 고하기를 마치매 제사장들과 선지자들과 모든 백성이 그를 붙잡고 이르되 네가 반드시 죽으리라"},{"n":9,"t":"어찌하여 네가 여호와의 이름을 의탁하고 예언하여 이르기를 이 집이 실로 같이 되겠고 이 성이 황무하여 거민이 없으리라 하느뇨 하며 그 모든 백성이 여호와의 집에서 예레미야에게로 모여드니라"},{"n":10,"t":"유다 방백들이 이 일을 듣고 왕궁에서 여호와의 집으로 올라와서 여호와의 집 새문 어귀에 앉으매"},{"n":11,"t":"제사장들과 선지자들이 방백들과 모든 백성에게 말하여 가로되 이 사람은 죽음이 합당하니 너희 귀로 들음 같이 이 성을 쳐서 예언하였느니라"},{"n":12,"t":"예레미야가 모든 방백과 백성에게 일러 가로되 여호와께서 나를 보내사 너희의 들은 바 모든 말로 이 집과 이 성을 쳐서 예언하게 하셨느니라"},{"n":13,"t":"그런즉 너희는 너희 길과 행위를 고치고 너희 하나님 여호와의 목소리를 청종하라 그리하면 여호와께서 너희에게 선고하신 재앙에 대하여 뜻을 돌이키시리라"},{"n":14,"t":"보라 나는 너희 손에 있으니 너희 소견에 선한 대로, 옳은 대로 하려니와"},{"n":15,"t":"너희는 분명히 알라 너희가 나를 죽이면 정녕히 무죄한 피로 너희 몸과 이 성과 이 성 거민에게로 돌아가게 하리라 이는 여호와께서 진실로 나를 보내사 이 모든 말을 너희 귀에 이르게 하셨음이니라"},{"n":16,"t":"방백들과 모든 백성이 제사장들과 선지자들에게 이르되 이 사람이 우리 하나님 여호와의 이름을 의탁하고 우리에게 말하였으니 죽음이 부당하니라"},{"n":17,"t":"때에 그 땅 장로 중 몇 사람이 일어나 백성의 온 회중에 말하여 가로되"},{"n":18,"t":"유다 왕 히스기야 시대에 모레셋 사람 미가가 유다 모든 백성에게 예언하여 가로되 만군의 여호와께서 이같이 말씀하시기를 시온은 밭 같이 경작함을 당하며 예루살렘은 무더기가 되며 이 전의 산은 수풀의 높은 곳들 같이 되리라 하였으나"},{"n":19,"t":"유다 왕 히스기야와 모든 유다가 그를 죽였느냐 히스기야가 여호와를 두려워하여 여호와께 간구하매 여호와께서 그들에게 선고한 재앙에 대하여 뜻을 돌이키지 아니하셨느냐 우리가 이같이 하면 우리 생명을 스스로 크게 해하는 일이니라"},{"n":20,"t":"또 여호와의 이름을 의탁하고 예언한 사람이 있었는데 곧 기럇여아림 스마야의 아들 우리야라 그가 예레미야의 모든 말과 같이 이 성과 이 땅을 쳐서 예언하매"},{"n":21,"t":"여호야김 왕과 그 모든 용사와 모든 방백이 그 말을 듣고는 왕이 그를 죽이려 하매 우리야가 이를 듣고 두려워 애굽으로 도망하여 간지라"},{"n":22,"t":"여호야김 왕이 사람을 애굽으로 보내되 곧 악볼의 아들 엘라단과 몇 사람을 함께 애굽으로 보내었더니"},{"n":23,"t":"그들이 우리야를 애굽에서 끌어내어 여호야김 왕께로 데려오매 왕이 칼로 그를 죽이고 그 시체를 평민의 묘실에 던지게 하였다 하니라"},{"n":24,"t":"사반의 아들 아히감이 예레미야를 보호하여 예레미야를 백성의 손에 내어주지 아니하여 죽이지 못하게 하니라"}],"kids":[{"n":1,"t":"유다 왕 요시야의 아들 여호야김이 막 왕이 되었을 때에 여호와로부터 이 말씀이 들려왔어요."},{"n":2,"t":"\\"나 여호와가 이렇게 말한다. 너는 여호와의 집(성전) 뜰에 서서, 유다 모든 성에서 여호와의 집에 와서 경배하는 자들에게 내가 너에게 명령해서 말하게 한 모든 말을 전해라. 한 마디도 빼지 마라.\\""},{"n":3,"t":"\\"그들이 듣고 혹시 각자 못된 길에서 떠나리니, 그러면 내가 그들의 못된 행동 때문에 재앙을 내리려 했던 마음을 돌이킬 거야.\\""},{"n":4,"t":"\\"너는 그들에게 말해라. \'여호와께서 이렇게 말씀하셨다. 너희가 내 말을 듣지 않고, 내가 너희 앞에 둔 내 법(가르침)을 따르지 않으며,\\""},{"n":5,"t":"\\"\'내가 너희에게 부지런히 보낸 내 종 선지자들의 말을 너희가 이미 듣지 않았는데, 너희가 만일 다시 듣지 않으면,\\""},{"n":6,"t":"\\"\'내가 이 집을 실로(폐허가 된 옛 성소)처럼 되게 하고, 이 성을 세상 모든 나라들의 저주거리가 되게 할 거야.\' 이렇게 말해라.\\""},{"n":7,"t":"예레미야가 여호와의 집에서 이 말을 했고, 제사장들과 선지자들과 모든 백성이 들었어요."},{"n":8,"t":"예레미야가 여호와께서 명령하신 말씀을 모든 백성에게 다 전한 후에, 제사장들과 선지자들과 모든 백성이 그를 붙잡고 말했어요. \\"너는 반드시 죽어야 한다!\\""},{"n":9,"t":"\\"네가 어찌하여 여호와의 이름으로 예언하면서 \'이 집이 실로처럼 되겠고 이 성이 폐허가 되어 사는 사람이 없게 될 것이다\'라고 하느냐?\\" 그리고 모든 백성이 여호와의 집에서 예레미야에게 모여들었어요."},{"n":10,"t":"유다의 높은 사람들이 이 일을 듣고 왕궁에서 여호와의 집으로 올라와 여호와의 집 새 문 입구에 앉았어요."},{"n":11,"t":"제사장들과 선지자들이 높은 사람들과 모든 백성에게 말했어요. \\"이 사람은 죽어 마땅합니다. 너희 귀로 들은 것처럼 그가 이 성을 쳐서(공격하는 말로) 예언했습니다.\\""},{"n":12,"t":"예레미야가 모든 높은 사람들과 백성에게 말했어요. \\"여호와께서 나를 보내셔서 너희가 들은 모든 말로 이 집과 이 성에 대해 예언하게 하셨어요.\\""},{"n":13,"t":"\\"그러므로 너희는 너희 길과 행동을 고치고, 너희 하나님 여호와의 목소리를 들어 따르세요. 그러면 여호와께서 너희에게 선포하신 재앙에 대해 마음을 돌이키실 거예요.\\""},{"n":14,"t":"\\"보세요, 저는 여러분의 손에 있어요. 여러분이 보기에 좋고 옳은 대로 하세요.\\""},{"n":15,"t":"\\"그러나 여러분은 분명히 아세요. 여러분이 저를 죽이면 정말로 죄 없는 피가 여러분 자신과 이 성과 이 성에 사는 사람들에게 돌아갈 거예요. 이는 여호와께서 정말로 저를 보내셔서 이 모든 말을 여러분의 귀에 들리게 하셨기 때문이에요.\\""},{"n":16,"t":"높은 사람들과 모든 백성이 제사장들과 선지자들에게 말했어요. \\"이 사람이 우리 하나님 여호와의 이름으로 우리에게 말했으니, 죽어서는 안 됩니다.\\""},{"n":17,"t":"그때 그 땅의 장로(어른) 중 몇 사람이 일어나 백성의 모든 무리에게 말했어요."},{"n":18,"t":"\\"유다 왕 히스기야 시대에 모레셋 사람 미가가 유다 모든 백성에게 예언해서 이렇게 말했어요. \'만군의 여호와께서 이렇게 말씀하셨다. 시온은 밭처럼 갈리고, 예루살렘은 돌무더기가 되며, 이 성전이 있는 산은 숲이 우거진 높은 곳들처럼 될 거야.\'\\""},{"n":19,"t":"\\"그렇지만 유다 왕 히스기야와 모든 유다 사람이 그를 죽였어요? 히스기야가 여호와를 두려워해서 여호와께 빌었더니, 여호와께서 그들에게 선포하신 재앙에 대해 마음을 돌이키지 않으셨나요? 우리가 이렇게 (예레미야를 죽이는) 일을 하면 우리 자신의 생명을 크게 해치는 거예요.\\""},{"n":20,"t":"또 여호와의 이름으로 예언한 사람이 있었는데, 곧 기럇여아림 사람 스마야의 아들 우리야였어요. 그가 예레미야의 모든 말과 같이 이 성과 이 땅을 쳐서 예언했어요."},{"n":21,"t":"여호야김 왕과 그 모든 용사(군인)와 모든 높은 사람들이 그 말을 듣고는, 왕이 그를 죽이려고 했어요. 우리야가 그것을 듣고 무서워서 애굽으로 도망쳤어요."},{"n":22,"t":"여호야김 왕이 사람을 애굽으로 보냈어요. 곧 악볼의 아들 엘라단과 몇 사람을 함께 애굽으로 보냈는데,"},{"n":23,"t":"그들이 우리야를 애굽에서 끌어내어 여호야김 왕에게 데려왔어요. 왕은 칼로 그를 죽이고, 그의 시신을 평민들의 무덤에 던져 버렸어요."},{"n":24,"t":"그러나 사반의 아들 아히감이 예레미야를 보호해서, 예레미야를 백성의 손에 넘겨 주지 않아 죽이지 못하게 했어요."}]}},{"chapter":27,"title":"이방에게 굴복하라","verses":{"krv":[{"n":1,"t":"유다 왕 요시야의 아들 여호야김의 즉위한 지 오래지 아니하여서 여호와께서 말씀으로 나 예레미야에게 이르시니라"},{"n":2,"t":"여호와께서 이같이 내게 이르시되 너는 줄과 멍에를 만들어 네 목에 얹고"},{"n":3,"t":"유다 왕 시드기야를 보러 예루살렘에 온 사신들의 손에도 그것을 붙여 에돔 왕과 모압 왕과 암몬 자손의 왕과 두로 왕과 시돈 왕에게 보내며"},{"n":4,"t":"그들에게 명하여 그 주에게 이르게 하기를 만군의 여호와 이스라엘의 하나님이 말씀하시되 너희는 너희 주에게 이같이 고하라"},{"n":5,"t":"나는 내 큰 능과 나의 든 팔로 땅과 그 위에 있는 사람과 짐승들을 만들고 나의 소견에 옳은 대로 땅을 사람에게 주었노라"},{"n":6,"t":"이제 내가 이 모든 땅을 내 종 바벨론 왕 느부갓네살의 손에 주고 또 들짐승들을 그에게 주어서 부리게 하였나니"},{"n":7,"t":"열방이 그와 그 아들과 손자를 섬기리라 그의 땅의 기한이 이르면 여러 나라와 큰 왕이 그로 자기를 섬기게 하리라마는"},{"n":8,"t":"나 여호와가 이르노라 바벨론 왕 느부갓네살을 섬기지 아니하는 국민이나 그 목으로 바벨론 왕의 멍에를 메지 아니하는 백성은 내가 그의 손으로 진멸시키기까지 칼과 기근과 염병으로 벌하리라"},{"n":9,"t":"너희는 너희 선지자나 너희 복술이나 너희 꿈꾸는 자나 너희 술사나 너희 요술객이 너희에게 이르기를 너희가 바벨론 왕을 섬기지 아니하리라 하여도 듣지 말라"},{"n":10,"t":"그들은 너희에게 거짓을 예언하여서 너희로 너희 땅에서 멀리 떠나게 하며 또 나로 너희를 몰아내게 하며 너희를 멸하게 하느니라"},{"n":11,"t":"오직 그 목으로 바벨론 왕의 멍에를 메고 그를 섬기는 나라는 내가 그들을 그 땅에 머물러서 밭을 갈며 거기 거하게 하리라 하셨다 하라 여호와의 말이니라"},{"n":12,"t":"내가 이 모든 말씀대로 유다 왕 시드기야에게 고하여 가로되 왕과 백성은 목으로 바벨론 왕의 멍에를 메고 그와 그 백성을 섬기소서 그리하면 살리이다"},{"n":13,"t":"어찌하여 왕과 왕의 백성이 여호와께서 바벨론 왕을 섬기지 아니하는 나라에 대하여 하신 말씀 같이 칼과 기근과 염병에 죽으려 하나이까"},{"n":14,"t":"왕과 백성에게 바벨론 왕을 섬기지 아니하리라 하는 선지자의 말을 듣지 마소서 그들은 거짓을 예언하나이다"},{"n":15,"t":"여호와께서 말씀하시되 내가 그들을 보내지 아니하였거늘 그들이 내 이름으로 거짓을 예언하니 내가 너희를 몰아내며 너희와 너희에게 예언하는 선지자들을 멸망시키기에 이르리라 하셨나이다"},{"n":16,"t":"내가 또 제사장들과 그 모든 백성에게 고하여 가로되 여호와께서 이같이 말씀하시되 여호와의 집 기구를 이제 바벨론에서 속히 돌려오리라고 너희에게 예언하는 선지자들의 말을 듣지 말라 이는 그들이 거짓을 예언함이니라 하셨나니"},{"n":17,"t":"너희는 그들을 듣지 말고 바벨론 왕을 섬기라 그리하면 살리라 어찌하여 이 성으로 황무지가 되게 하겠느냐"},{"n":18,"t":"만일 그들이 선지자이고 여호와의 말씀이 그들에게 있을진대 그들이 여호와의 집에와 유다 왕의 집에와 예루살렘에 남아 있는 기구가 바벨론으로 옮겨가지 않도록 만군의 여호와께 구하여야 할 것이니라"},{"n":19,"t":"만군의 여호와께서 기둥들과 놋바다와 받침들과 및 이 성에 남아있는 기구에 대하여 이같이 말씀하시나니"},{"n":20,"t":"이것은 바벨론 왕 느부갓네살이 유다 왕 여호야김의 아들 여고니야와 유다와 예루살렘 모든 귀족을 예루살렘에서 바벨론으로 사로잡아 옮길 때에 취하지 아니하였던 것이라"},{"n":21,"t":"만군의 여호와 이스라엘의 하나님이 여호와의 집에와 유다 왕의 집에와 예루살렘에 남아 있는 그 기구에 대하여 이같이 말씀하시되"},{"n":22,"t":"그것들이 바벨론으로 옮김을 입고 내가 이것을 돌아보는 날까지 거기 있을 것이니라 그 후에 내가 그것을 옮겨 이곳에 다시 두리라 여호와의 말이니라"}],"kids":[{"n":1,"t":"유다 왕 요시야의 아들 여호야김이 왕이 된 지 얼마 되지 않아, 여호와께서 말씀으로 나 예레미야에게 말씀하셨어요."},{"n":2,"t":"여호와께서 내게 이렇게 말씀하셨어요. \\"너는 줄과 멍에(소가 일할 때 매는 도구)를 만들어 네 목에 얹고,\\""},{"n":3,"t":"\\"유다 왕 시드기야를 보러 예루살렘에 온 사신(외교 사절)들의 손에도 그것을 들려 보내서, 에돔 왕과 모압 왕과 암몬 자손의 왕과 두로 왕과 시돈 왕에게 보내라.\\""},{"n":4,"t":"\\"그들에게 명령해서 그들의 주인(왕)에게 가서 이렇게 말하게 해라. \'만군의 여호와 이스라엘의 하나님이 이렇게 말씀하셨다. 너희는 너희 주인에게 이렇게 전하라.\'\\""},{"n":5,"t":"\\"\'나는 내 큰 능력과 펴신 팔로 땅과 그 위에 있는 사람과 짐승들을 만들었고, 내가 보기에 옳은 대로 그 땅을 사람에게 주었어.\'\\""},{"n":6,"t":"\\"\'이제 내가 이 모든 땅을 내 종 바벨론 왕 느부갓네살의 손에 주고, 또 들짐승들도 그에게 주어 부리게 했어.\'\\""},{"n":7,"t":"\\"\'모든 나라가 그와 그의 아들과 손자를 섬길 거야. 그의 땅의 때가 끝나면 여러 나라와 큰 왕들이 그를 자기들의 종으로 삼게 될 거야.\'\\""},{"n":8,"t":"\\"\'나 여호와가 말한다. 바벨론 왕 느부갓네살을 섬기지 않는 나라나, 자기 목으로 바벨론 왕의 멍에를 매지 않는 백성은, 내가 그의 손으로 그들이 멸망할 때까지 칼과 기근과 염병으로 벌할 거야.\'\\""},{"n":9,"t":"\\"\'너희는 너희 선지자나 점쟁이(복술자), 꿈꾸는 자, 술사(마법사), 요술객이 너희에게 너희가 바벨론 왕을 섬기지 않을 거라고 말해도 듣지 마라.\'\\""},{"n":10,"t":"\\"\'그들은 너희에게 거짓을 예언해서 너희를 너희 땅에서 멀리 떠나게 하고, 또 내가 너희를 몰아내고 너희를 멸하게 만든단다.\'\\""},{"n":11,"t":"\\"\'오직 자기 목으로 바벨론 왕의 멍에를 매고 그를 섬기는 나라는, 내가 그들을 그 땅에 머물러 밭을 갈며 거기 살게 하겠다.\' 이렇게 말해라. 이것은 여호와의 말이야.\\""},{"n":12,"t":"내가 이 모든 말을 유다 왕 시드기야에게 전했어요. \\"왕과 백성은 목으로 바벨론 왕의 멍에를 매고 그와 그 백성을 섬기세요. 그러면 살게 될 거예요.\\""},{"n":13,"t":"\\"어찌하여 왕과 왕의 백성이 여호와께서 바벨론 왕을 섬기지 않는 나라에 대해 하신 말씀처럼 칼과 기근과 염병에 죽으려고 하세요?\\""},{"n":14,"t":"\\"왕과 백성에게 \'바벨론 왕을 섬기지 않을 거예요\'라고 말하는 선지자의 말을 듣지 마세요. 그들은 거짓을 예언하고 있어요.\\""},{"n":15,"t":"\\"여호와께서 말씀하셨어요. \'내가 그들을 보내지 않았는데도 그들이 내 이름으로 거짓을 예언하고 있으니, 내가 너희를 몰아내고, 너희와 너희에게 예언하는 선지자들을 멸망시킬 거야.\'\\""},{"n":16,"t":"내가 또 제사장들과 모든 백성에게 말했어요. \\"여호와께서 이렇게 말씀하셨어요. \'여호와의 집의 기구(성전 도구)들을 이제 바벨론에서 속히 돌려올 거라고 예언하는 선지자들의 말을 듣지 마라. 그들은 거짓을 예언하고 있어.\'\\""},{"n":17,"t":"\\"너희는 그들의 말을 듣지 말고 바벨론 왕을 섬기세요. 그러면 살게 될 거예요. 어찌하여 이 성을 폐허(황무지)로 만들려고 하세요?\\""},{"n":18,"t":"\\"만일 그들이 진짜 선지자이고 여호와의 말씀이 그들에게 있다면, 그들은 여호와의 집과 유다 왕의 집과 예루살렘에 남아 있는 기구들이 바벨론으로 옮겨가지 않도록 만군의 여호와께 빌어야 할 거예요.\\""},{"n":19,"t":"\\"만군의 여호와께서 기둥들과 놋(쇠) 바다(큰 그릇)와 받침들과 이 성에 남아 있는 기구에 대해 이렇게 말씀하셨어요.\\""},{"n":20,"t":"\\"이것은 바벨론 왕 느부갓네살이 유다 왕 여호야김의 아들 여고니야(여호야긴)와 유다와 예루살렘의 모든 귀족(높은 사람)을 예루살렘에서 바벨론으로 사로잡아 갈 때 가져가지 않은 것이에요.\\""},{"n":21,"t":"\\"만군의 여호와 이스라엘의 하나님이 여호와의 집과 유다 왕의 집과 예루살렘에 남아 있는 그 기구들에 대해 이렇게 말씀하셨어요.\\""},{"n":22,"t":"\\"\'그것들이 바벨론으로 옮겨질 것이고, 내가 이것을 돌보는 날까지 거기 있을 거야. 그 후에 내가 그것을 다시 옮겨서 이곳에 두겠다.\' 이것은 여호와의 말이야.\\""}]}},{"chapter":28,"title":"한 해 안에 죽은 하나냐","verses":{"krv":[{"n":1,"t":"이 해 유다 왕 시드기야의 즉위한 지 오래지 않은 해 곧 사년 오월에 기브온 앗술의 아들 선지자 하나냐가 여호와의 집에서 제사장들과 모든 백성 앞에서 내게 말하여 가로되"},{"n":2,"t":"만군의 여호와 이스라엘의 하나님이 이같이 말씀하여 가라사대 내가 바벨론 왕의 멍에를 꺾었느니라"},{"n":3,"t":"내가 바벨론 왕 느부갓네살의 이곳에서 바벨론으로 옮겨간 여호와의 집 모든 기구를 두 해가 차기 전에 다시 이곳으로 가져오게 하겠고"},{"n":4,"t":"내가 또 유다 왕 여호야김의 아들 여고니야와 바벨론으로 간 유다 모든 포로를 다시 이곳으로 돌아오게 하리니 이는 내가 바벨론 왕의 멍에를 꺾을 것임이니라 여호와의 말이니라 하셨다 하는지라"},{"n":5,"t":"선지자 예레미야가 여호와의 집에 선 제사장들의 앞과 모든 백성 앞에서 선지자 하나냐에게 말할쌔"},{"n":6,"t":"선지자 예레미야가 말하되 아멘 여호와는 이같이 하옵소서 여호와께서 네 예언대로 이루사 여호와의 집 기구와 모든 포로를 바벨론에서 이곳으로 다시 옮겨 오시기를 원하노라"},{"n":7,"t":"그러나 너는 이제 내가 네 귀와 모든 백성의 귀에 이르는 이 말을 들으라"},{"n":8,"t":"나와 너 이전 선지자들이 자고로 여러 나라와 큰 국가들에 대하여 전쟁과 재앙과 염병을 예언하였느니라"},{"n":9,"t":"평화를 예언하는 선지자는 그 예언자의 말이 응한 후에야 그는 진실로 여호와의 보내신 선지자로 알게 되리라"},{"n":10,"t":"선지자 하나냐가 선지자 예레미야의 목에서 멍에를 취하여 꺾고"},{"n":11,"t":"모든 백성 앞에서 말하여 가로되 여호와께서 이같이 말씀하시되 내가 두 해가 차기 전에 열방의 목에서 바벨론 왕 느부갓네살의 멍에를 이같이 꺾어 버리리라 하셨느니라 하매 선지자 예레미야가 자기 길을 가니라"},{"n":12,"t":"선지자 하나냐가 선지자 예레미야의 목에서 멍에를 꺾어버린 후에 여호와의 말씀이 예레미야에게 임하니라 가라사대"},{"n":13,"t":"너는 가서 하나냐에게 말하여 이르기를 여호와의 말씀에 네가 나무 멍에를 꺾었으나 그 대신 쇠 멍에를 만들었느니라"},{"n":14,"t":"만군의 여호와 이스라엘의 하나님이 이같이 말하노라 내가 쇠 멍에로 이 모든 나라의 목에 메워 바벨론 왕 느부갓네살을 섬기게 하였으니 그들이 그를 섬기리라 내가 들짐승도 그에게 주었느니라 하신다 하라"},{"n":15,"t":"선지자 예레미야가 선지자 하나냐에게 이르되 하나냐여 들으라 여호와께서 너를 보내지 아니하셨거늘 네가 이 백성으로 거짓을 믿게 하는도다"},{"n":16,"t":"그러므로 여호와께서 말씀하시되 내가 너를 지면에서 제하리니 네가 여호와께 패역하는 말을 하였음이라 금년에 죽으리라 하셨느니라 하더니"},{"n":17,"t":"선지자 하나냐가 그 해 칠월에 죽었더라"}],"kids":[{"n":1,"t":"그 해, 곧 유다 왕 시드기야가 왕이 된 지 오래지 않은 그 해 4년 5월에, 기브온 출신 앗술의 아들이며 선지자인 하나냐가 여호와의 집(성전)에서 제사장들과 모든 백성 앞에서 내게 말했어요."},{"n":2,"t":"\\"만군의 여호와 이스라엘의 하나님이 이렇게 말씀하셨다. \'내가 바벨론 왕의 멍에를 꺾었다.\'\\""},{"n":3,"t":"\\"내가 바벨론 왕 느부갓네살이 이곳에서 바벨론으로 가져간 여호와의 집의 모든 기구를 2년이 차기 전에 다시 이곳으로 돌려놓겠다.\\""},{"n":4,"t":"\\"내가 또 유다 왕 여호야김의 아들 여고니야와 바벨론으로 끌려간 모든 유다 포로를 다시 이곳으로 돌아오게 하겠다. 이는 내가 바벨론 왕의 멍에를 꺾을 것이기 때문이다. 이것은 여호와의 말이다.\\""},{"n":5,"t":"선지자 예레미야가 여호와의 집에 서 있는 제사장들 앞과 모든 백성 앞에서 선지자 하나냐에게 말했어요."},{"n":6,"t":"\\"아멘! 여호와께서 그렇게 해 주시기를! 여호와께서 네 예언대로 이루셔서 여호와의 집의 기구와 모든 포로를 바벨론에서 이곳으로 다시 돌아오게 해 주시기를 바라.\\""},{"n":7,"t":"\\"그러나 너는 이제 내가 너의 귀와 모든 백성의 귀에 들려주는 이 말을 들어라.\\""},{"n":8,"t":"\\"나와 너 이전의 선지자들이 옛날부터 여러 나라와 큰 나라들에 대해 전쟁과 재앙과 염병을 예언했어.\\""},{"n":9,"t":"\\"평화를 예언하는 선지자는, 그 예언자가 한 말이 그대로 이루어진 후에야 정말로 여호와께서 보내신 선지자라는 걸 알게 될 거야.\\""},{"n":10,"t":"그러자 선지자 하나냐가 선지자 예레미야의 목에서 멍에를 빼앗아 부수고,"},{"n":11,"t":"모든 백성 앞에서 말했어요. \\"여호와께서 이렇게 말씀하셨어요. \'내가 2년이 차기 전에 모든 나라들의 목에서 바벨론 왕 느부갓네살의 멍에를 이렇게 꺾어 버리겠다.\'\\" 그러자 선지자 예레미야는 자기 길을 갔어요."},{"n":12,"t":"선지자 하나냐가 선지자 예레미야의 목에서 멍에를 부숴 버린 후에 여호와의 말씀이 예레미야에게 들려왔어요."},{"n":13,"t":"\\"너는 가서 하나냐에게 말해라. \'여호와께서 이렇게 말씀하셨다. 네가 나무 멍에는 꺾었지만, 그 대신 쇠 멍에를 만든 셈이 되었다.\'\\""},{"n":14,"t":"\\"\'만군의 여호와 이스라엘의 하나님이 이렇게 말한다. 내가 쇠 멍에로 이 모든 나라들의 목에 메워 바벨론 왕 느부갓네살을 섬기게 했어. 그래서 그들이 그를 섬기게 될 거야. 또 들짐승도 그에게 주었다.\' 이렇게 말해라.\\""},{"n":15,"t":"선지자 예레미야가 선지자 하나냐에게 말했어요. \\"하나냐야, 들어라. 여호와께서 너를 보내지 않으셨는데, 네가 이 백성으로 거짓을 믿게 만들고 있구나.\\""},{"n":16,"t":"\\"그러므로 여호와께서 이렇게 말씀하셨어. \'내가 너를 땅 위에서 없애 버릴 거야. 네가 여호와께 거역하는 말을 했으니, 너는 올해에 죽게 될 거야.\'\\""},{"n":17,"t":"선지자 하나냐는 그 해 7월에 죽었어요."}]}},{"chapter":29,"title":"포로들에게 보내는 편지","verses":{"krv":[{"n":1,"t":"선지자 예레미야가 예루살렘에서 이같은 편지를 느부갓네살이 예루살렘에서 바벨론으로 옮겨간 포로 중 남아 있는 장로들과 제사장들과 선지자들과 모든 백성에게 보내었는데"},{"n":2,"t":"때는 여고니야 왕과 국모와 환관들과 및 유다와 예루살렘 방백들과 목공들과 철공들이 예루살렘에서 떠난 후라"},{"n":3,"t":"유다 왕 시드기야가 바벨론으로 보내어 바벨론 왕 느부갓네살에게로 가게 한 사반의 아들 엘라사와 힐기야의 아들 그마랴의 손에 위탁하였더라 이렀으되"},{"n":4,"t":"만군의 여호와 이스라엘의 하나님 내가 예루살렘에서 바벨론으로 사로잡혀 가게 한 모든 포로에게 이같이 이르노라"},{"n":5,"t":"너희는 집을 짓고 거기 거하며 전원을 만들고 그 열매를 먹으라"},{"n":6,"t":"아내를 취하여 자녀를 생산하며 너희 아들로 아내를 취하며 너희 딸로 남편을 맞아 그들로 자녀를 생산케 하여 너희로 거기서 번성하고 쇠잔하지 않게 하라"},{"n":7,"t":"너희는 내가 사로잡혀 가게 한 그 성읍의 평안하기를 힘쓰고 위하여 여호와께 기도하라 이는 그 성이 평안함으로 너희도 평안할 것임이니라"},{"n":8,"t":"만군의 여호와 이스라엘의 하나님이 이같이 말하노라 너희 중 선지자들에게와 복술에게 혹하지 말며 너희가 꾼 바 꿈도 신청하지 말라"},{"n":9,"t":"내가 그들을 보내지 아니하였어도 그들이 내 이름으로 거짓을 예언함이니라 여호와의 말이니라"},{"n":10,"t":"나 여호와가 이같이 말하노라 바벨론에서 칠십 년이 차면 내가 너희를 권고하고 나의 선한 말을 너희에게 실행하여 너희를 이곳으로 돌아오게 하리라"},{"n":11,"t":"나 여호와가 말하노라 너희를 향한 나의 생각은 내가 아나니 재앙이 아니라 곧 평안이요 너희 장래에 소망을 주려하는 생각이라"},{"n":12,"t":"너희는 내게 부르짖으며 와서 내게 기도하면 내가 너희를 들을 것이요"},{"n":13,"t":"너희가 전심으로 나를 찾고 찾으면 나를 만나리라"},{"n":14,"t":"나 여호와가 말하노라 내가 너희에게 만나지겠고 너희를 포로된 중에서 다시 돌아오게 하되 내가 쫓아 보내었던 열방과 모든 곳에서 모아 사로잡혀 떠나게 하던 본 곳으로 돌아오게 하리라 여호와의 말이니라 하셨느니라"},{"n":15,"t":"너희가 말하기를 여호와께서 바벨론에서 우리를 위하여 선지자들을 일으키셨다 하므로"},{"n":16,"t":"여호와께서 다윗의 위에 앉은 왕과 이 성에 거하는 모든 백성 곧 너희와 함께 포로되어 가지 아니한 너희 형제에게 대하여 이같이 말씀하시느니라"},{"n":17,"t":"만군의 여호와께서 이같이 말씀하시되 보라 내가 칼과 기근과 염병을 그들에게 보내어 그들로 악하여 먹을 수 없는 악한 무화과 같게 하겠고"},{"n":18,"t":"내가 칼과 기근과 염병으로 그들을 따르게 하며 그들을 세계 열방 중에 흩어 학대를 당하게 할 것이며 내가 그들을 쫓아 보낸 열방 중에서 저줏거리와 놀램과 치소와 모욕거리가 되게 하리니"},{"n":19,"t":"이는 내가 내 종 선지자들을 그들에게 보내되 부지런히 보내었으나 그들이 나 여호와의 말을 듣지 아니하며 듣지 아니함이니라 여호와의 말이니라"},{"n":20,"t":"그런즉 내가 예루살렘에서 바벨론으로 보낸 너희 모든 포로여 나 여호와의 말을 들을지니라"},{"n":21,"t":"만군의 여호와 이스라엘의 하나님 내가 골라야의 아들 아합과 마아세야의 아들 시드기야에 대하여 말하노라 그들은 내 이름으로 너희에게 거짓을 예언한 자라 보라 내가 그들을 바벨론 왕 느부갓네살의 손에 붙이리니 그가 너희 목전에서 그들을 죽일 것이라"},{"n":22,"t":"너희 바벨론에 있는 유다 모든 포로가 그들로 저줏거리를 삼아서 이르기를 여호와께서 너로 바벨론 왕이 불살라 죽인 시드기야와 아합 같게 하시기를 원하노라 하리니"},{"n":23,"t":"이는 그들이 이스라엘 중에서 망령되이 행하여 그 이웃의 아내와 행음하며 내가 그들에게 명하지 아니한 거짓을 내 이름으로 말함이니라 나는 아는 자요 증거인이니라 여호와의 말이니라 하셨다 하였더라"},{"n":24,"t":"너는 느헬람 사람 스마야에게 이같이 말하여 이르라"},{"n":25,"t":"만군의 여호와 이스라엘의 하나님이 이같이 말씀하여 가라사대 네가 네 이름으로 예루살렘에 있는 모든 백성과 제사장 마아세야의 아들 스바냐와 모든 제사장에게 글을 보내어 이르기를"},{"n":26,"t":"여호와께서 너로 제사장 여호야다를 대신하여 제사장을 삼아 여호와의 집 유사로 세우심은 무릇 미친 자와 자칭 선지자를 착고에 채우며 칼을 메우게 하심이어늘"},{"n":27,"t":"이제 네가 어찌하여 너희 중에 자칭 선지자라 하는 아나돗 사람 예레미야를 책망하지 아니하느냐"},{"n":28,"t":"대저 그가 바벨론에 있는 우리에게 편지하기를 때가 오래리니 너희는 집을 짓고 거기 거하며 전원을 만들고 그 열매를 먹으라 하였다 하였느니라"},{"n":29,"t":"제사장 스바냐가 스마야의 글을 선지자 예레미야에게 읽어 들릴 때에"},{"n":30,"t":"여호와의 말씀이 예레미야에게 임하여 가라사대"},{"n":31,"t":"너는 모든 포로에게 글을 보내어 이르기를 여호와께서 느헬람 사람 스마야에 대하여 이같이 말씀하시되 내가 스마야를 보내지 아니하였거늘 그가 너희에게 예언하고 너희로 거짓을 믿게 하였도다"},{"n":32,"t":"그러므로 나 여호와가 이같이 말하노라 보라 내가 느헬람 사람 스마야와 그 자손을 벌하리니 그가 나 여호와께 패역한 말을 하였음을 인하여 이 백성 중에 거할 그의 사람이 하나도 없을 것이라 내가 내 백성에게 행하려 하는 선한 일을 그가 보지 못하리라 하셨다 하라 여호와의 말이니라"}],"kids":[{"n":1,"t":"선지자 예레미야가 예루살렘에서 이런 편지를, 느부갓네살이 예루살렘에서 바벨론으로 끌고 간 포로들 가운데 살아남은 장로(어른)들과 제사장들과 선지자들과 모든 백성에게 보냈어요."},{"n":2,"t":"이때는 여고니야 왕과 왕의 어머니(국모)와 환관(궁궐의 일꾼)들과, 그리고 유다와 예루살렘의 높은 사람들과 목공(나무 일꾼)들과 철공(쇠 일꾼)들이 예루살렘을 떠난 후였어요."},{"n":3,"t":"이 편지는 유다 왕 시드기야가 바벨론 왕 느부갓네살에게 보낸 사반의 아들 엘라사와 힐기야의 아들 그마랴의 손에 맡긴 거였어요. 편지의 내용은 이래요."},{"n":4,"t":"\\"만군의 여호와 이스라엘의 하나님인 내가 예루살렘에서 바벨론으로 사로잡혀 가게 한 모든 포로에게 이렇게 말한다.\\""},{"n":5,"t":"\\"너희는 집을 짓고 거기 살아라. 또 밭(전원)을 만들고 그 열매를 먹어라.\\""},{"n":6,"t":"\\"결혼해서 자녀를 낳고, 너희 아들들도 결혼시키고, 너희 딸들도 결혼시켜 그들이 자녀를 낳게 해서, 너희가 거기서 늘어나고 줄어들지 않게 해라.\\""},{"n":7,"t":"\\"너희는 내가 너희를 사로잡혀 가게 한 그 성의 평안을 위해 힘쓰고, 그 성을 위해 여호와께 기도해라. 이는 그 성이 평안해야 너희도 평안할 것이기 때문이야.\\""},{"n":8,"t":"\\"만군의 여호와 이스라엘의 하나님이 이렇게 말한다. 너희 가운데 있는 선지자들과 점쟁이들에게 속지 말고, 너희가 꾼 꿈에도 귀 기울이지 마라.\\""},{"n":9,"t":"\\"내가 그들을 보내지 않았는데도 그들이 내 이름으로 거짓을 예언하고 있어. 이것은 여호와의 말이야.\\""},{"n":10,"t":"\\"나 여호와가 이렇게 말한다. 바벨론에서 70년이 차면 내가 너희를 돌볼 것이고, 너희에게 좋은 말을 이루어 주어 너희를 이곳으로 돌아오게 할 거야.\\""},{"n":11,"t":"\\"나 여호와가 말한다. 너희에 대한 내 생각을 내가 안다. 그것은 재앙이 아니라 평안이고, 너희에게 미래에 대한 소망을 주려는 생각이란다.\\""},{"n":12,"t":"\\"너희가 내게 부르짖으며 와서 내게 기도하면, 내가 너희 말을 들을 거야.\\""},{"n":13,"t":"\\"너희가 마음을 다해 나를 찾고 또 찾으면 나를 만나게 될 거야.\\""},{"n":14,"t":"\\"나 여호와가 말한다. 내가 너희에게 만나 줄 것이고, 너희를 사로잡힌 곳에서 다시 돌아오게 할 거야. 내가 너희를 쫓아 보냈던 모든 나라와 모든 곳에서 너희를 모아, 사로잡혀 떠났던 본래의 자리로 돌아오게 할 거야. 이것은 여호와의 말이야.\\""},{"n":15,"t":"\\"너희가 \'여호와께서 바벨론에서 우리를 위해 선지자들을 일으키셨다\'라고 말했기 때문에,\\""},{"n":16,"t":"\\"여호와께서 다윗의 자리에 앉은 왕과 이 성에 사는 모든 백성, 곧 너희와 함께 포로로 끌려가지 않은 너희 형제들에 대해 이렇게 말씀하셨어.\\""},{"n":17,"t":"\\"만군의 여호와께서 이렇게 말씀하셨어. \'보아라, 내가 칼과 기근(굶주림)과 염병(전염병)을 그들에게 보내, 그들을 너무 나빠서 먹을 수 없는 못된 무화과 같게 만들겠다.\'\\""},{"n":18,"t":"\\"\'내가 칼과 기근과 염병으로 그들을 따라가게 하고, 그들을 세상의 모든 나라에 흩어 학대받게 할 것이며, 내가 그들을 쫓아 보낸 모든 나라에서 저주거리와 놀람과 비웃음과 모욕거리가 되게 할 거야.\'\\""},{"n":19,"t":"\\"\'이는 내가 내 종 선지자들을 그들에게 부지런히 보냈는데도 그들이 나 여호와의 말을 듣지 않았고, 듣지 않았기 때문이야. 이것은 여호와의 말이야.\'\\""},{"n":20,"t":"\\"그러므로 내가 예루살렘에서 바벨론으로 보낸 너희 모든 포로들아, 나 여호와의 말을 들어라.\\""},{"n":21,"t":"\\"만군의 여호와 이스라엘의 하나님인 내가 골라야의 아들 아합과 마아세야의 아들 시드기야에 대해서 말한다. 그들은 내 이름으로 너희에게 거짓을 예언한 자들이야. 보아라, 내가 그들을 바벨론 왕 느부갓네살의 손에 넘길 것이고, 그가 너희 보는 앞에서 그들을 죽일 거야.\\""},{"n":22,"t":"\\"바벨론에 있는 너희 모든 유다 포로가 그들의 일을 가지고 저주의 말을 만들어 \'여호와께서 너를 바벨론 왕이 불에 태워 죽인 시드기야와 아합 같게 하시기를 원한다\'라고 할 거야.\\""},{"n":23,"t":"\\"이는 그들이 이스라엘 가운데서 망령된(터무니없는) 짓을 하고, 이웃의 아내와 부정한 일을 하며, 내가 그들에게 명령하지 않은 거짓을 내 이름으로 말했기 때문이야. 나는 아는 자이고 증인이다. 이것은 여호와의 말이야.\\""},{"n":24,"t":"\\"너는 느헬람 사람 스마야에게 이렇게 말해라.\\""},{"n":25,"t":"\\"만군의 여호와 이스라엘의 하나님이 이렇게 말씀하셨다. \'네가 네 이름으로 예루살렘에 있는 모든 백성과, 제사장 마아세야의 아들 스바냐와 모든 제사장에게 편지를 보내 이렇게 말했지.\'\\""},{"n":26,"t":"\\"\'여호와께서 너를 제사장 여호야다 대신 제사장으로 삼아 여호와의 집을 책임지는 사람(유사)으로 세우신 것은, 미친 자나 스스로 선지자라고 하는 자를 착고(형틀)에 채우고 칼(목에 메는 형틀)을 매게 하시려는 것이다.\'\\""},{"n":27,"t":"\\"\'그런데 이제 네가 어찌하여 너희 가운데 자칭 선지자라고 하는 아나돗 사람 예레미야를 꾸짖지(책망하지) 않느냐?\'\\""},{"n":28,"t":"\\"\'그가 바벨론에 있는 우리에게 편지를 써서 〈오랜 시간이 걸릴 거니까 너희는 집을 짓고 거기 살고, 밭을 만들어 그 열매를 먹어라〉라고 말했단다.\'\\""},{"n":29,"t":"제사장 스바냐가 스마야의 편지를 선지자 예레미야에게 읽어 줬어요."},{"n":30,"t":"여호와의 말씀이 예레미야에게 들려왔어요."},{"n":31,"t":"\\"너는 모든 포로에게 편지를 보내 이렇게 말해라. \'여호와께서 느헬람 사람 스마야에 대해 이렇게 말씀하셨다. 내가 스마야를 보내지 않았는데도 그가 너희에게 예언하고 너희가 거짓을 믿게 만들었다.\'\\""},{"n":32,"t":"\\"\'그러므로 나 여호와가 이렇게 말한다. 보아라, 내가 느헬람 사람 스마야와 그 자손을 벌하겠다. 그가 나 여호와께 거역하는 말을 했기 때문에, 이 백성 가운데 그의 자손이 한 명도 살아남지 못할 것이고, 내가 내 백성에게 행할 좋은 일을 그가 보지 못할 거야.\' 이렇게 말해라. 이것은 여호와의 말이야.\\""}]}},{"chapter":30,"title":"이스라엘의 회복 약속","verses":{"krv":[{"n":1,"t":"여호와께로서 말씀이 예레미야에게 임하여 이르시니라"},{"n":2,"t":"이스라엘의 하나님 여호와께서 이같이 일러 가라사대 내가 네게 이른 모든 말을 책에 기록하라"},{"n":3,"t":"나 여호와가 말하노라 내가 내 백성 이스라엘과 유다의 포로를 돌이킬 때가 이르리니 내가 그들을 그 열조에게 준 땅으로 돌아오게 할 것이라 그들이 그것을 차지하리라 여호와의 말이니라"},{"n":4,"t":"여호와께서 이스라엘과 유다에 대하여 하신 말씀이 이러하니라"},{"n":5,"t":"여호와께서 이같이 말씀하시되 우리가 떨리는 소리를 들으니 두려움이요 평안함이 아니로다"},{"n":6,"t":"너희는 자식을 해산하는 남자가 있는가 물어보라 남자마다 해산하는 여인 같이 손으로 각기 허리를 짚고 그 얼굴 빛이 창백하여 보임은 어찜이뇨"},{"n":7,"t":"슬프다 그 날이여 비할 데 없이 크니 이는 야곱의 환난의 때가 됨이로다마는 그가 이에서 구하여 냄을 얻으리로다"},{"n":8,"t":"만군의 여호와가 말하노라 그 날에 내가 네 목에서 그 멍에를 꺾어버리며 네 줄을 끊으리니 이방인이 다시는 너를 부리지 못할 것이며"},{"n":9,"t":"너희는 너희 하나님 나 여호와를 섬기며 내가 너희를 위하여 일으킬 너희 왕 다윗을 섬기리라"},{"n":10,"t":"그러므로 나 여호와가 말하노라 내 종 야곱아 두려워 말라 이스라엘아 놀라지 말라 내가 너를 원방에서 구원하고 네 자손을 포로된 땅에서 구원하리니 야곱이 돌아와서 태평과 안락을 얻을 것이라 너를 두렵게 할 자가 없으리라"},{"n":11,"t":"나 여호와가 말하노라 내가 너와 함께 하여 너를 구원할 것이라 내가 너를 흩었던 그 열방은 진멸한다 할지라도 너는 진멸하지 아니하리라 그러나 내가 공도로 너를 징책할 것이요 결코 무죄한 자로 여기지 아니하리라"},{"n":12,"t":"나 여호와가 말하노라 네 상처는 고칠 수 없고 네 창상은 중하도다"},{"n":13,"t":"네 송사를 변호할 자가 없고 네 상처를 싸맬 약이 없도다"},{"n":14,"t":"너를 사랑하던 자가 다 너를 잊고 찾지 아니하니 이는 네 허물이 크고 네 죄가 수다함을 인하여 내가 대적의 상하게 하는 그것으로 너를 상하게 하며 잔학한 자의 징계하는 그것으로 너를 징계함이어늘"},{"n":15,"t":"어찌하여 네 상처를 인하여 부르짖느뇨 네 고통이 낫지 못하리라 네 죄악의 큼과 죄의 수다함을 인하여 내가 네게 이 일을 행하였느니라"},{"n":16,"t":"그러나 무릇 너를 먹는 자는 먹히며 무릇 너를 치는 자는 다 포로가 되며 너를 탈취하는 자는 탈취를 당하며 무릇 너를 약탈하는 자는 내가 그로 약탈을 당하게 하리라"},{"n":17,"t":"나 여호와가 말하노라 그들이 쫓겨난 자라 하며 찾는 자가 없는 시온이라 한즉 내가 너를 치료하여 네 상처를 낫게 하리라"},{"n":18,"t":"나 여호와가 말하노라 보라 내가 포로된 야곱의 장막들을 돌이키고 그 거하는 곳들을 긍휼히 여길 것이라 그 성읍은 자기 산에 중건될 것이요 그 궁궐은 본래대로 거하는 곳이 될 것이며"},{"n":19,"t":"감사하는 소리와 즐거워하는 자의 목소리가 그 중에서 나오리라 내가 그들을 번성케 하리니 쇠잔치 아니하겠고 내가 그들을 영화롭게 하리니 비천하지 아니하겠으며"},{"n":20,"t":"그 자손은 여전하겠고 그 회중은 내 앞에 굳게 설 것이며 무릇 그를 압박하는 자는 내가 다 벌하리라"},{"n":21,"t":"그 왕은 그 본족에게서 날 것이요 그 통치자는 그들 중에서 나올 것이며 내가 그를 가까이 오게 하므로 그가 내게 접근하리라 그렇지 않고 담대히 내게 접근할 자가 누구뇨 여호와의 말이니라"},{"n":22,"t":"너희는 내 백성이 되겠고 나는 너희 하나님이 되리라"},{"n":23,"t":"보라 여호와의 노가 발하여 폭풍과 회리바람처럼 악인의 머리를 칠 것이라"},{"n":24,"t":"나 여호와의 진노는 내 마음의 뜻한 바를 행하여 이루기까지는 쉬지 아니하나니 너희가 말일에 그것을 깨달으리라"}],"kids":[{"n":1,"t":"여호와로부터 말씀이 예레미야에게 들려왔어요."},{"n":2,"t":"\\"이스라엘의 하나님 여호와께서 이렇게 말씀하셨다. \'내가 너에게 한 모든 말을 책에 기록하라.\'\\""},{"n":3,"t":"\\"\'나 여호와가 말한다. 내가 내 백성 이스라엘과 유다의 포로들을 돌아오게 할 때가 올 거야. 내가 그들을 그 조상에게 준 땅으로 돌아오게 할 것이고, 그들이 그 땅을 차지할 거야.\' 이것은 여호와의 말이야.\\""},{"n":4,"t":"여호와께서 이스라엘과 유다에 대해 하신 말씀은 이래요."},{"n":5,"t":"\\"여호와께서 이렇게 말씀하셨어. \'우리가 떨리는 소리를 들으니, 그것은 두려움이고 평안함이 아니로다.\'\\""},{"n":6,"t":"\\"\'너희는 자식을 낳는 남자가 있는지 물어 보아라. 어찌하여 모든 남자가 아기를 낳는 여인처럼 손으로 허리를 짚고, 얼굴빛이 창백하게 변해 있느냐?\'\\""},{"n":7,"t":"\\"\'슬프다, 그날이여! 비할 데 없이 큰 날이로다. 야곱(이스라엘)에게 큰 환난(어려움)의 때가 되겠지만, 그가 거기에서 구원을 얻을 거야.\'\\""},{"n":8,"t":"\\"\'만군의 여호와가 말한다. 그날에 내가 네 목에서 그 멍에를 꺾어 버리고 네 줄을 끊어 버릴 것이고, 외국인이 다시는 너를 부리지(종처럼) 못할 거야.\'\\""},{"n":9,"t":"\\"\'너희는 너희 하나님 나 여호와를 섬기고, 내가 너희를 위해 일으킬 너희의 왕 다윗(다윗 같은 새 왕, 곧 메시아)을 섬기게 될 거야.\'\\""},{"n":10,"t":"\\"\'그러므로 나 여호와가 말한다. 내 종 야곱아, 두려워하지 마라. 이스라엘아, 놀라지 마라. 내가 너를 먼 곳에서 구원하고, 네 자손을 사로잡혀 간 땅에서 구원할 것이니, 야곱이 돌아와서 평안과 안락(편안함)을 얻을 거야. 너를 두렵게 할 자가 없을 거야.\'\\""},{"n":11,"t":"\\"\'나 여호와가 말한다. 내가 너와 함께해서 너를 구원할 거야. 내가 너를 흩었던 그 모든 나라들을 멸한다고 해도, 너만은 멸하지 않을 거야. 그러나 내가 공의(바른 일)로 너를 가르칠(징계할) 것이고, 결코 죄가 없는 자처럼 그냥 두지는 않을 거야.\'\\""},{"n":12,"t":"\\"\'나 여호와가 말한다. 네 상처는 고칠 수 없고, 네 다친 것이 매우 심하구나.\'\\""},{"n":13,"t":"\\"\'네 송사(재판)에서 너를 변호해 줄 사람이 없고, 네 상처를 싸맬 약도 없구나.\'\\""},{"n":14,"t":"\\"\'너를 사랑하던 자들이 모두 너를 잊고 찾지 않아. 이는 네 잘못이 크고 네 죄가 많기 때문에 내가 적이 다치게 하듯 너를 다치게 했고, 잔인한 자가 가르치듯 너를 가르쳤기 때문이야.\'\\""},{"n":15,"t":"\\"\'네가 어찌하여 네 상처 때문에 부르짖느냐? 네 고통은 낫지 못해. 네 죄가 크고 죄가 많기 때문에 내가 너에게 이런 일을 행한 거란다.\'\\""},{"n":16,"t":"\\"\'그러나 너를 잡아먹는 자는 잡아먹힐 것이고, 너를 치는 자는 모두 사로잡힐 것이며, 너를 빼앗는 자는 빼앗기게 될 것이고, 너를 약탈하는 자는 내가 그를 약탈당하게 할 거야.\'\\""},{"n":17,"t":"\\"\'나 여호와가 말한다. 그들이 너를 보고 ‘쫓겨난 자’라고 하고, 시온을 ‘찾는 사람이 없는 자’라고 했지만, 내가 너를 치료해서 네 상처를 낫게 할 거야.\'\\""},{"n":18,"t":"\\"\'나 여호와가 말한다. 보아라, 내가 사로잡힌 야곱의 천막들을 돌이키고, 그들이 사는 곳을 불쌍히 여길 거야. 그 성은 자기 산 위에 다시 세워질 것이고, 그 궁궐은 본래 자리에 다시 들어설 거야.\'\\""},{"n":19,"t":"\\"\'감사하는 소리와 즐거워하는 자의 목소리가 그 가운데서 나올 거야. 내가 그들을 번성하게 해서 줄어들지 않게 할 것이고, 내가 그들을 영광스럽게 해서 천하지 않게 할 거야.\'\\""},{"n":20,"t":"\\"\'그 자손은 옛날처럼 될 것이고, 그 무리는 내 앞에 굳게 설 것이며, 그를 누르는(압박하는) 자는 내가 모두 벌할 거야.\'\\""},{"n":21,"t":"\\"\'그 왕은 그 자기 백성에게서 나올 것이고, 그 통치자는 그들 가운데서 나올 거야. 내가 그를 가까이 오게 할 것이고, 그가 내게 가까이 올 거야. 그렇지 않다면, 누가 자기 마음대로 내게 가까이 올 수 있겠느냐? 이것은 여호와의 말이야.\'\\""},{"n":22,"t":"\\"\'너희는 내 백성이 되고, 나는 너희의 하나님이 될 거야.\'\\""},{"n":23,"t":"\\"\'보아라, 여호와의 분노가 폭풍과 회오리바람처럼 일어나서 못된 자의 머리를 칠 거야.\'\\""},{"n":24,"t":"\\"\'나 여호와의 분노는 내 마음이 뜻한 일을 다 이루기까지 그치지 않을 거야. 너희가 마지막 날에 그것을 깨닫게 될 거야.\'\\""}]}},{"chapter":31,"title":"새 언약의 약속","verses":{"krv":[{"n":1,"t":"나 여호와가 말하노라 그 때에 내가 이스라엘 모든 가족의 하나님이 되고 그들은 내 백성이 되리라"},{"n":2,"t":"나 여호와가 이같이 말하노라 칼에서 벗어난 백성이 광야에서 은혜를 얻었나니 곧 내가 이스라엘로 안식을 얻게 하러 갈 때에라"},{"n":3,"t":"나 여호와가 옛적에 이스라엘에게 나타나 이르기를 내가 무궁한 사랑으로 너를 사랑하는 고로 인자함으로 너를 인도하였다 하였노라"},{"n":4,"t":"처녀 이스라엘아 내가 다시 너를 세우리니 네가 세움을 입을 것이요 네가 다시 소고로 너를 장식하고 즐거운 무리처럼 춤추며 나올 것이며"},{"n":5,"t":"네가 다시 사마리아 산들에 포도원을 심되 심는 자가 심고 그 과실을 먹으리라"},{"n":6,"t":"에브라임 산 위에서 파수꾼이 외치는 날이 이를 것이라 이르기를 너희는 일어나라 우리가 시온에 올라가서 우리 하나님 여호와께로 나아가자 하리라"},{"n":7,"t":"나 여호와가 이같이 말하노라 너희는 야곱을 위하여 기뻐 노래하며 만국의 머리 된 자를 위하여 외쳐 전파하며 찬양하며 이르기를 여호와여 주의 백성 이스라엘의 남은 자를 구원하소서 하라"},{"n":8,"t":"보라 내가 그들을 북편 땅에서 인도하며 땅 끝에서부터 모으리니 그들 중에는 소경과 절뚝발이와 잉태한 여인과 해산하는 여인이 함께 하여 큰 무리를 이루어 이곳으로 돌아오되"},{"n":9,"t":"울며 올 것이며 그들이 나의 인도함을 입고 간구할 때에 내가 그들로 넘어지지 아니하고 하숫가의 바른 길로 행하게 하리라 나는 이스라엘의 아비요 에브라임은 나의 장자니라"},{"n":10,"t":"열방이여 너희는 나 여호와의 말을 듣고 먼 섬에 전파하여 이르기를 이스라엘을 흩으신 자가 그를 모으시고 목자가 그 양무리에게 행함 같이 그를 지키시리로다"},{"n":11,"t":"여호와께서 야곱을 속량하시되 그들보다 강한 자의 손에서 구속하셨으니"},{"n":12,"t":"그들이 와서 시온의 높은 곳에서 찬송하며 여호와의 은사 곧 곡식과 새 포도주와 기름과 어린 양의 떼와 소의 떼에 모일 것이라 그 심령은 물댄 동산 같겠고 다시는 근심이 없으리로다 할지어다"},{"n":13,"t":"그 때에 처녀는 춤추며 즐거워하겠고 청년과 노인이 함께 즐거워하리니 내가 그들의 슬픔을 돌이켜 즐겁게 하며 그들을 위로하여 근심한 후에 기쁨을 얻게 할 것임이니라"},{"n":14,"t":"내가 기름으로 제사장들의 심령에 흡족케 하며 내 은혜로 내 백성에게 만족케 하리라 여호와의 말이니라"},{"n":15,"t":"나 여호와가 이같이 말하노라 라마에서 슬퍼하며 통곡하는 소리가 들리니 라헬이 그 자식을 위하여 애곡하는 것이라 그가 자식이 없으므로 위로 받기를 거절하는도다"},{"n":16,"t":"나 여호와가 이같이 말하노라 네 소리를 금하여 울지 말며 네 눈을 금하여 눈물을 흘리지 말라 네 일에 갚음을 받을 것인즉 그들이 그 대적의 땅에서 돌아오리라 여호와의 말이니라"},{"n":17,"t":"나 여호와가 말하노라 너의 최후에 소망이 있을 것이라 너의 자녀가 자기들의 경내로 돌아오리라"},{"n":18,"t":"에브라임이 스스로 탄식함을 내가 정녕히 들었노니 이르기를 주께서 나를 징벌하시매 멍에에 익숙지 못한 송아지 같은 내가 징벌을 받았나이다 주는 나의 하나님 여호와시니 나를 이끌어 돌이키소서 그리하시면 내가 돌아오겠나이다"},{"n":19,"t":"내가 돌이킴을 받은 후에 뉘우쳤고 내가 교훈을 받은 후에 내 볼기를 쳤사오니 이는 어렸을 때의 치욕을 진고로 부끄럽고 욕됨이니이다 하도다"},{"n":20,"t":"에브라임은 나의 사랑하는 아들 기뻐하는 자식이 아니냐 내가 그를 책망하여 말할 때마다 깊이 생각하노라 그러므로 그를 위하여 내 마음이 측은한즉 내가 반드시 그를 긍휼히 여기리라 여호와의 말이니라"},{"n":21,"t":"처녀 이스라엘아 너를 위하여 길표를 세우며 너를 위하여 표목을 만들고 대로 곧 네가 전에 가던 길에 착념하라 돌아오라 네 성읍들로 돌아오라"},{"n":22,"t":"패역한 딸아 네가 어느 때까지 방황하겠느냐 여호와가 새 일을 세상에 창조하였나니 곧 여자가 남자를 안으리라"},{"n":23,"t":"나 만군의 여호와 이스라엘의 하나님이 이같이 말하노라 내가 그 사로잡힌 자를 돌아오게 할 때에 그들이 유다 땅과 그 성읍들에서 다시 이 말을 쓰리니 곧 의로운 처소여, 거룩한 산이여, 여호와께서 네게 복 주시기를 원하노라 할 것이며"},{"n":24,"t":"유다와 그 모든 성읍의 농부와 양떼를 인도하는 자가 거기 함께 거하리니"},{"n":25,"t":"이는 내가 그 피곤한 심령을 만족케 하며 무릇 슬픈 심령을 상쾌케 하였음이니라 하시기로"},{"n":26,"t":"내가 깨어보니 내 잠이 달았더라"},{"n":27,"t":"여호와께서 가라사대 보라 내가 사람의 씨와 짐승의 씨를 이스라엘 집과 유다 집에 뿌릴 날이 이르리니"},{"n":28,"t":"내가 경성하여 그들을 뽑으며 훼파하며 전복하며 멸하며 곤란케 하던 것 같이 경성하여 그들을 세우며 심으리라 여호와의 말이니라"},{"n":29,"t":"그 때에 그들이 다시는 이르기를 아비가 신 포도를 먹었으므로 아들들의 이가 시다 하지 아니하겠고"},{"n":30,"t":"신 포도를 먹는 자마다 그 이가 심 같이 각기 자기 죄악으로만 죽으리라"},{"n":31,"t":"나 여호와가 말하노라 보라 날이 이르리니 내가 이스라엘 집과 유다 집에 새 언약을 세우리라"},{"n":32,"t":"나 여호와가 말하노라 이 언약은 내가 그들의 열조의 손을 잡고 애굽 땅에서 인도하여 내던 날에 세운 것과 같지 아니할 것은 내가 그들의 남편이 되었어도 그들이 내 언약을 파하였음이니라"},{"n":33,"t":"나 여호와가 말하노라 그러나 그 날 후에 내가 이스라엘 집에 세울 언약은 이러하니 곧 내가 나의 법을 그들의 속에 두며 그 마음에 기록하여 나는 그들의 하나님이 되고 그들은 내 백성이 될 것이라"},{"n":34,"t":"그들이 다시는 각기 이웃과 형제를 가리켜 이르기를 너는 여호와를 알라 하지 아니하리니 이는 작은 자로부터 큰 자까지 다 나를 앎이니라 내가 그들의 죄악을 사하고 다시는 그 죄를 기억지 아니하리라 여호와의 말이니라"},{"n":35,"t":"나 여호와는 해를 낮의 빛으로 주었고 달과 별들을 밤의 빛으로 규정하였고 바다를 격동시켜 그 파도로 소리치게 하나니 내 이름은 만군의 여호와니라 내가 말하노라"},{"n":36,"t":"이 규정이 내 앞에서 폐할진대 이스라엘 자손도 내 앞에서 폐함을 입어 영영히 나라가 되지 못하리라"},{"n":37,"t":"나 여호와가 이같이 말하노라 위로 하늘을 측량할 수 있으며 아래로 땅의 기초를 탐지할 수 있다면 내가 이스라엘 자손의 행한 모든 일을 인하여 그들을 다 버리리라 여호와의 말이니라"},{"n":38,"t":"나 여호와가 말하노라 보라 날이 이르리니 이 성을 하나넬 망대에서부터 모퉁이 문까지 여호와를 위하여 건축할 것이라"},{"n":39,"t":"측량줄이 곧게 가렙 산에 이르고 고아 방면으로 돌아"},{"n":40,"t":"시체와 재의 골짜기와 기드론 시내에 이르는 데까지와 동편 말문 모퉁이에 이르기까지의 모든 밭에 이르리니 다 여호와의 성지가 되고 영영히 다시는 뽑히거나 전복되지 아니하리라"}],"kids":[{"n":1,"t":"\\"나 여호와가 말한다. 그때에 내가 이스라엘의 모든 가족의 하나님이 되고, 그들은 내 백성이 될 거야.\\""},{"n":2,"t":"\\"나 여호와가 이렇게 말한다. 칼에서 살아남은 백성이 광야에서 은혜를 얻었어. 곧 내가 이스라엘에게 안식(쉼)을 주려고 갈 때에 말이야.\\""},{"n":3,"t":"\\"나 여호와가 옛적에 이스라엘에게 나타나서 말했어. \'내가 영원한 사랑으로 너를 사랑하기 때문에, 친절(인자함)로 너를 인도했단다.\'\\""},{"n":4,"t":"\\"처녀 이스라엘아, 내가 다시 너를 세울 것이니 네가 다시 세워질 거야. 네가 다시 소고(작은 북)로 자신을 꾸미고, 즐거워하는 무리처럼 춤추며 나올 거야.\\""},{"n":5,"t":"\\"네가 다시 사마리아 산들에 포도원을 심을 것이고, 심는 자가 그 열매를 먹게 될 거야.\\""},{"n":6,"t":"\\"에브라임 산 위에서 파수꾼(망보는 사람)이 외치는 날이 올 거야. \'너희는 일어나라, 우리가 시온에 올라가서 우리 하나님 여호와께 나아가자!\'\\""},{"n":7,"t":"\\"나 여호와가 이렇게 말한다. 너희는 야곱을 위해 기뻐 노래하고, 모든 나라의 머리(첫째)인 자를 위해 외치고 알리고 찬양해라. 그리고 \'여호와여, 주의 백성 이스라엘의 남은 자를 구원해 주세요\'라고 말해라.\\""},{"n":8,"t":"\\"보아라, 내가 그들을 북쪽 땅에서 인도하고 땅 끝에서부터 모을 거야. 그들 가운데는 소경(앞 못 보는 자)과 다리 저는 자(절뚝발이)와 임신한 여인과 아기 낳는 여인이 함께 있을 것이고, 큰 무리를 이루어 이곳으로 돌아올 거야.\\""},{"n":9,"t":"\\"그들이 울며 올 것이고, 내가 그들을 인도할 때 그들이 빌게 되며, 내가 그들을 넘어지지 않게 해서 강가의 바른 길로 행하게 할 거야. 나는 이스라엘의 아버지이고, 에브라임은 내 큰아들(장자)이란다.\\""},{"n":10,"t":"\\"나라들아, 너희는 나 여호와의 말을 듣고 먼 섬에 알려라. \'이스라엘을 흩으신 분이 그를 모으시고, 목자가 양 떼에게 행하는 것처럼 그를 지키실 거야.\'\\""},{"n":11,"t":"\\"여호와께서 야곱을 구해 주셨고, 그들보다 강한 자의 손에서 그들을 자유롭게(구속) 하셨어.\\""},{"n":12,"t":"\\"그들이 와서 시온의 높은 곳에서 찬송하며 여호와께서 주신 좋은 것 — 곡식과 새 포도주와 기름과 어린 양 떼와 소 떼 — 에 모일 거야. 그들의 마음(심령)은 물 댄 동산 같을 것이고, 다시는 슬픔이 없을 거야.\\""},{"n":13,"t":"\\"그때에 처녀들이 춤추며 즐거워하고, 청년과 노인이 함께 즐거워할 거야. 내가 그들의 슬픔을 즐거움으로 바꾸고, 그들을 위로해서 슬픔 후에 기쁨을 얻게 할 거야.\\""},{"n":14,"t":"\\"내가 좋은 것(기름)으로 제사장들의 마음을 만족하게 하고, 내 은혜로 내 백성에게 만족을 줄 거야. 이것은 여호와의 말이야.\\""},{"n":15,"t":"\\"나 여호와가 이렇게 말한다. 라마(라헬이 묻힌 곳)에서 슬퍼하며 통곡하는 소리가 들린다. 라헬이 자기 자식을 위해 슬피 울고 있어. 그가 자식이 없어서 위로받기를 거절하는구나.\\""},{"n":16,"t":"\\"나 여호와가 이렇게 말한다. 네 소리를 그쳐 울지 말고, 네 눈을 막아 눈물을 흘리지 마라. 네 일에 대한 보답을 받게 될 것이니, 그들이 적의 땅에서 돌아올 거야. 이것은 여호와의 말이야.\\""},{"n":17,"t":"\\"나 여호와가 말한다. 너의 마지막에는 소망이 있을 거야. 너의 자녀가 자기들의 땅으로 돌아올 거야.\\""},{"n":18,"t":"\\"내가 정말로 들었어. 에브라임이 한숨을 쉬며 말하기를, \'주께서 저를 벌하시니, 멍에에 익숙하지 못한 송아지처럼 제가 벌을 받았어요. 주는 저의 하나님 여호와이시니, 저를 이끌어 돌이켜 주세요. 그러면 제가 돌아오겠어요.\'\\""},{"n":19,"t":"\\"\'제가 돌이킨 후에 뉘우쳤고, 가르침을 받은 후에 제 허벅지를 쳤어요(부끄러워했어요). 이는 어렸을 때 부끄러운 일을 해서 부끄럽고 욕된 일을 당했기 때문이에요.\'\\""},{"n":20,"t":"\\"에브라임은 내가 사랑하는 아들이 아니냐? 내가 기뻐하는 자식이 아니냐? 내가 그를 책망하여 말할 때마다 그를 깊이 생각해. 그러므로 내가 그를 위해 마음이 측은해서, 반드시 그를 불쌍히 여길 거야. 이것은 여호와의 말이야.\\""},{"n":21,"t":"\\"처녀 이스라엘아, 너를 위해 길 표시(이정표)를 세우고, 너를 위해 표목(나무 기둥)을 세우고, 큰 길 곧 네가 전에 가던 길에 마음을 두어라. 돌아오너라! 너의 성으로 돌아오너라!\\""},{"n":22,"t":"\\"거역하는 딸아, 네가 언제까지 헤매겠느냐? 여호와가 세상에 새로운 일을 만들었다. 곧 여자가 남자를 둘러쌀(보호할) 거야.\\""},{"n":23,"t":"\\"나 만군의 여호와 이스라엘의 하나님이 이렇게 말한다. 내가 그 사로잡힌 자들을 돌아오게 할 때, 그들이 유다 땅과 그 성들에서 다시 이런 말을 쓰게 될 거야. \'의로운 처소여, 거룩한 산이여! 여호와께서 너에게 복 주시기를!\'\\""},{"n":24,"t":"\\"유다와 그 모든 성에 농부와 양 떼를 인도하는 사람이 함께 살게 될 거야.\\""},{"n":25,"t":"\\"이는 내가 피곤한 마음(심령)을 만족시키고, 슬픈 마음을 시원하게 했기 때문이야.\\""},{"n":26,"t":"\\"내가 깨어 보니, 내 잠이 달았어요(기분 좋았어요).\\""},{"n":27,"t":"\\"여호와께서 말씀하셨어. \'보아라, 내가 사람의 씨와 짐승의 씨를 이스라엘 집과 유다 집에 뿌릴 날이 올 거야.\'\\""},{"n":28,"t":"\\"\'내가 그들을 뽑고 부수고 엎고 멸하고 어렵게 만들었던 것처럼, 정성스레 그들을 세우고 심을 거야. 이것은 여호와의 말이야.\'\\""},{"n":29,"t":"\\"그때에 그들이 다시는 \'아버지가 신 포도를 먹었기 때문에 아들의 이가 시다\'라고 말하지 않을 거야.\\""},{"n":30,"t":"\\"신 포도를 먹는 자마다 그 이가 시게 되듯, 각자 자기 죄로만 죽게 될 거야.\\""},{"n":31,"t":"\\"나 여호와가 말한다. 보아라, 날이 올 거야. 그때에 내가 이스라엘 집과 유다 집에 새 언약(새 약속)을 세울 거야.\\""},{"n":32,"t":"\\"나 여호와가 말한다. 이 언약은 내가 그들의 조상의 손을 잡고 애굽 땅에서 이끌어 내던 날에 세운 그 언약과 같지 않을 거야. 내가 그들의 남편이 되었는데도 그들이 내 언약을 깨뜨렸기 때문이야.\\""},{"n":33,"t":"\\"나 여호와가 말한다. 그러나 그 날 후에 내가 이스라엘 집과 세울 언약은 이렇다. 곧 내가 내 법(가르침)을 그들의 속에 두고, 그들의 마음에 새겨 둘 거야. 그래서 나는 그들의 하나님이 되고, 그들은 내 백성이 될 거야.\\""},{"n":34,"t":"\\"그들이 다시는 각자 이웃과 형제에게 \'너는 여호와를 알라\'라고 가르치지 않을 거야. 이는 작은 자부터 큰 자까지 모두 나를 알게 될 것이기 때문이야. 내가 그들의 죄를 용서하고, 다시는 그 죄를 기억하지 않을 거야. 이것은 여호와의 말이야.\\""},{"n":35,"t":"\\"나 여호와는 해를 낮의 빛으로 주었고, 달과 별들을 밤의 빛으로 정해 주었으며, 바다를 흔들어 그 파도가 소리치게 한단다. 내 이름은 만군의 여호와야. 내가 말한다.\\""},{"n":36,"t":"\\"이 정해진 것이 내 앞에서 폐(없어짐)해질 수 있다면, 이스라엘 자손도 내 앞에서 폐해져 영원히 한 나라가 되지 못할 거야.\\""},{"n":37,"t":"\\"나 여호와가 이렇게 말한다. 위로 하늘을 측량할(잴) 수 있고, 아래로 땅의 기초를 알아낼 수 있다면, 내가 이스라엘 자손이 한 모든 일 때문에 그들을 모두 버릴 거야. 이것은 여호와의 말이야.\\""},{"n":38,"t":"\\"나 여호와가 말한다. 보아라, 날이 올 거야. 그때 이 성을 하나넬 망대(높은 탑)에서부터 모퉁이 문까지 여호와를 위해 다시 지을 거야.\\""},{"n":39,"t":"\\"측량줄(거리 재는 줄)이 곧장 가렙 산까지 이를 것이고, 고아 쪽으로 돌아\\""},{"n":40,"t":"\\"시체와 재의 골짜기와 기드론 시내까지의 모든 곳, 그리고 동쪽으로 말 문 모퉁이까지의 모든 밭이 다 여호와의 거룩한 곳이 될 것이고, 영원히 다시는 뽑히거나 무너지지 않을 거야.\\""}]}},{"chapter":32,"title":"밭을 사는 표적","verses":{"krv":[{"n":1,"t":"유다 왕 시드기야의 제십년 곧 느부갓네살의 제십팔년에 여호와의 말씀이 예레미야에게 임하니라"},{"n":2,"t":"때에 바벨론 군대는 예루살렘을 에워싸고 선지자 예레미야는 유다 왕의 궁중에 있는 시위대 뜰에 갇혔으니"},{"n":3,"t":"이는 그가 예언하기를 여호와의 말씀에 보라 내가 이 성을 바벨론 왕의 손에 붙이리니 그가 취할 것이며 유다 왕 시드기야는 갈대아 인의 손에서 벗어나지 못하고 반드시 바벨론 왕의 손에 붙이운 바 되리니 입이 입을 대하여 말하고 눈이 서로 볼 것이며"},{"n":4,"t":"그가 시드기야를 바벨론으로 끌어가리니 시드기야가 나의 권고할 때까지 거기 있으리라 나 여호와가 말하노라"},{"n":5,"t":"너희가 갈대아 인과 싸울지라도 승리치 못하리라 하셨다 하였더니 유다 왕 시드기야가 가로되 네가 어찌 이같이 예언하였느뇨 하고 그를 가두었음이었더라"},{"n":6,"t":"예레미야가 가로되 여호와의 말씀이 내게 임하였느니라 이르시기를"},{"n":7,"t":"보라 네 숙부 살룸의 아들 하나멜이 네게 와서 말하기를 너는 아나돗에 있는 내 밭을 사라 이 기업을 무를 권리가 네게 있느니라 하리라 하시더니"},{"n":8,"t":"여호와의 말씀 같이 나의 숙부의 아들 하나멜이 시위대 뜰 안 내게로 와서 이르되 청하노니 너는 베냐민 땅 아나돗에 있는 나의 밭을 사라 기업의 상속권이 네게 있고 무를 권리가 네게 있으니 너를 위하여 사라 하는지라 내가 이것이 여호와의 말씀인 줄 알았으므로"},{"n":9,"t":"내 숙부의 아들 하나멜의 아나돗에 있는 밭을 사는데 은 십칠 세겔을 달아 주되"},{"n":10,"t":"증서를 써서 인봉하고 증인을 세우고 은을 저울에 달아 주고"},{"n":11,"t":"법과 규례대로 인봉하고 인봉치 아니한 매매 증서를 내가 취하여"},{"n":12,"t":"나의 숙부의 아들 하나멜과 매매 증서에 인 친 증인의 앞과 시위대 뜰에 앉은 유다 모든 사람 앞에서 그 매매 증서를 마세야의 손자 네리야의 아들 바룩에게 부치며"},{"n":13,"t":"그들의 앞에서 바룩에게 명하여 이르되"},{"n":14,"t":"만군의 여호와 이스라엘의 하나님이 이같이 말씀하시기를 너는 이 증서 곧 인봉하고 인봉치 않은 매매증서를 취하여 토기에 담아 많은 날 동안 보존케 하라"},{"n":15,"t":"만군의 여호와 이스라엘의 하나님 내가 이같이 말하노라 사람이 이 땅에서 집과 밭과 포도원을 다시 사게 되리라 하셨다 하니라"},{"n":16,"t":"내가 매매 증서를 네리야의 아들 바룩에게 부친 후에 여호와께 기도하여 가로되"},{"n":17,"t":"슬프도소이다 주 여호와여 주께서 큰 능과 드신 팔로 천지를 지으셨사오니 주에게는 능치 못한 일이 없으시니이다"},{"n":18,"t":"주는 은혜를 천만인에게 베푸시며 아비의 죄악을 그 후 자손의 품에 갚으시오니 크고 능하신 하나님이시요 이름은 만군의 여호와시니이다"},{"n":19,"t":"주는 모략에 크시며 행사에 능하시며 인류의 모든 길에 주목하시며 그 길과 그 행위의 열매대로 보응하시나이다"},{"n":20,"t":"주께서 애굽 땅에서 징조와 기사로 행하셨고 오늘까지도 이스라엘과 외인 중에 그같이 행하사 주의 이름을 오늘과 같이 되게 하셨나이다"},{"n":21,"t":"주께서 징조와 기사와 강한 손과 드신 팔과 큰 두려움으로 주의 백성 이스라엘을 애굽 땅에서 인도하여 내시고"},{"n":22,"t":"그들에게 주시기로 그 열조에게 맹세하신 바 젖과 꿀이 흐르는 이 땅을 그들에게 주셨으므로"},{"n":23,"t":"그들이 들어가서 이를 차지하였거늘 주의 목소리를 청종치 아니하며 주의 도에 행치 아니하며 무릇 주께서 행하라 명하신 일을 행치 아니하였으므로 주께서 이 모든 재앙을 그들에게 내리셨나이다"},{"n":24,"t":"보옵소서 이 성을 취하려 하는 자가 와서 흉벽을 쌓았고 칼과 기근과 염병으로 인하여 이 성이 이를 치는 갈대아인의 손에 붙인 바 되었으니 주의 말씀대로 되었음을 주께서 보시나이다"},{"n":25,"t":"주 여호와여 주께서 내게 은으로 밭을 사며 증인을 세우라 하셨으나 이 성은 갈대아인의 손에 붙인 바 되었나이다"},{"n":26,"t":"때에 여호와의 말씀이 예레미야에게 임하여 이르시되"},{"n":27,"t":"나는 여호와요 모든 육체의 하나님이라 내게 능치 못한 일이 있겠느냐"},{"n":28,"t":"그러므로 나 여호와가 이같이 말하노라 보라 내가 이 성을 갈대아인의 손과 바벨론 왕 느부갓네살의 손에 붙일 것인즉 그가 취할 것이라"},{"n":29,"t":"이 성을 치는 갈대아인이 와서 이 성읍에 불을 놓아 성과 집 곧 그 지붕에서 바알에게 분향하며 다른 신들에게 전제를 드려 나를 격노케 한 집들을 사르리니"},{"n":30,"t":"이는 이스라엘 자손과 유다 자손이 예로부터 내 목전에 악만 행하였음이라 이스라엘 자손은 그 손으로 만든 것을 가지고 나를 격노케 한 것뿐이니라 나 여호와가 말하노라"},{"n":31,"t":"이 성이 건설된 날부터 오늘까지 나의 노와 분을 격발하므로 내가 내 앞에서 그것을 옮기려 하노니"},{"n":32,"t":"이는 이스라엘 자손과 유다 자손이 모든 악을 행하며 내 노를 격동하였음이라 그들과 그들의 왕들과 그 방백들과 그 제사장들과 그 선지자들과 유다 사람들과 예루살렘 거민들이 다 그러하였느니라"},{"n":33,"t":"그들이 등을 내게로 향하고 얼굴을 내게로 향치 아니하며 내가 그들을 가르치되 부지런히 가르칠지라도 그들이 교훈을 듣지 아니하며 받지 아니하고"},{"n":34,"t":"내 이름으로 일컬음을 받는 집에 자기들의 가증한 물건들을 세워서 그 집을 더럽게 하며"},{"n":35,"t":"힌놈의 아들의 골짜기에 바알의 산당을 건축하였으며 자기들의 자녀를 몰렉의 불에 지나가게 하였느니라 그들이 이런 가증한 일을 행하여 유다로 범죄케 한 것은 나의 명한 것도 아니요 내 마음에 둔 것도 아니니라"},{"n":36,"t":"그러나 이스라엘의 하나님 나 여호와가 너희의 말하는 바 칼과 기근과 염병으로 인하여 바벨론 왕의 손에 붙인 바 되었다 하는 이 성에 대하여 이같이 말하노라"},{"n":37,"t":"보라 내가 노와 분과 큰 분노로 그들을 쫓아 보내었던 모든 지방에서 그들을 모아내어 이곳으로 다시 인도하여 안전히 거하게 할 것이라"},{"n":38,"t":"그들은 내 백성이 되겠고 나는 그들의 하나님이 될 것이며"},{"n":39,"t":"내가 그들에게 한 마음과 한 도를 주어 자기들과 자기 후손의 복을 위하여 항상 나를 경외하게 하고"},{"n":40,"t":"내가 그들에게 복을 주기 위하여 그들을 떠나지 아니하리라 하는 영영한 언약을 그들에게 세우고 나를 경외함을 그들의 마음에 두어 나를 떠나지 않게 하고"},{"n":41,"t":"내가 기쁨으로 그들에게 복을 주되 정녕히 나의 마음과 정신을 다하여 그들을 이 땅에 심으리라"},{"n":42,"t":"나 여호와가 이같이 말하노라 내가 이 백성에게 이 큰 재앙을 내린 것 같이 허락한 모든 복을 그들에게 내리리라"},{"n":43,"t":"너희가 말하기를 황폐하여 사람이나 짐승이 없으며 갈대아인의 손에 붙인 바 되었다 하는 이 땅에서 사람들이 밭을 사되"},{"n":44,"t":"베냐민 땅과 예루살렘 사방과 유다 성읍들과 산지의 성읍들과 평지의 성읍들과 남방의 성읍들에 있는 밭을 은으로 사고 증서를 기록하여 인봉하고 증인을 세우리니 이는 내가 그들의 포로로 돌아오게 함이니라 여호와의 말이니라"}],"kids":[{"n":1,"t":"유다 왕 시드기야 10년, 곧 느부갓네살 18년에 여호와의 말씀이 예레미야에게 들려왔어요."},{"n":2,"t":"그때 바벨론 군대는 예루살렘을 둘러싸고 있었고, 선지자 예레미야는 유다 왕의 궁궐 안에 있는 시위대(왕을 지키는 군인) 뜰에 갇혀 있었어요."},{"n":3,"t":"이는 그가 이렇게 예언했기 때문이에요. \\"여호와께서 말씀하셨어요. \'보아라, 내가 이 성을 바벨론 왕의 손에 넘겨줄 것이고, 그가 이 성을 차지할 거야.\'\\""},{"n":4,"t":"\\"\'유다 왕 시드기야는 갈대아 사람의 손에서 벗어나지 못하고, 반드시 바벨론 왕의 손에 넘어갈 것이며, 그와 입을 맞대고 말하고 눈으로 서로 볼 거야.\'\\""},{"n":5,"t":"\\"\'그가 시드기야를 바벨론으로 끌고 갈 것이고, 시드기야는 내가 그를 돌볼 때까지 그곳에 있을 거야. 나 여호와가 말한다. 너희가 갈대아 사람과 싸워도 이기지 못할 거야.\'\\" 그래서 유다 왕 시드기야가 \\"네가 어찌하여 이렇게 예언하느냐?\\"라고 하면서 그를 가두었어요."},{"n":6,"t":"예레미야가 말했어요. \\"여호와의 말씀이 내게 들려왔어요.\\""},{"n":7,"t":"\\"\'보아라, 네 삼촌(숙부) 살룸의 아들 하나멜이 너에게 와서 〈너는 아나돗에 있는 내 밭을 사라. 이 가족의 땅(기업)을 살 권리(무를 권리)가 너에게 있다〉라고 말할 거야.\'\\""},{"n":8,"t":"\\"여호와의 말씀대로 내 삼촌의 아들 하나멜이 시위대 뜰 안 내게 와서 말했어요. \'청하건대 너는 베냐민 땅 아나돗에 있는 내 밭을 사. 가족의 땅(기업)에 대한 상속권이 너에게 있고 살 권리도 너에게 있으니, 너를 위해 그것을 사렴.\' 그래서 나는 이것이 여호와의 말씀인 줄 알게 되었어요.\\""},{"n":9,"t":"그래서 내가 내 삼촌의 아들 하나멜의 아나돗에 있는 밭을 사고, 은 17세겔(돈 단위)을 달아 주었어요."},{"n":10,"t":"증서를 써서 봉인하고(도장을 찍고) 증인을 세웠으며, 은을 저울에 달아 주었어요."},{"n":11,"t":"법과 규정대로 봉인한 매매 증서와 봉인하지 않은 매매 증서를 내가 가지고,"},{"n":12,"t":"내 삼촌의 아들 하나멜과 매매 증서에 도장을 찍은 증인 앞과 시위대 뜰에 앉아 있는 모든 유다 사람들 앞에서, 그 매매 증서를 마세야의 손자이며 네리야의 아들인 바룩에게 맡겼어요."},{"n":13,"t":"그들 앞에서 바룩에게 명령해서 말했어요."},{"n":14,"t":"\\"만군의 여호와 이스라엘의 하나님이 이렇게 말씀하셨어. \'너는 이 증서, 곧 봉인한 매매 증서와 봉인하지 않은 매매 증서를 가져다가 토기(흙 그릇)에 담아 오랫동안 보관해라.\'\\""},{"n":15,"t":"\\"\'만군의 여호와 이스라엘의 하나님인 내가 이렇게 말한다. 사람이 이 땅에서 집과 밭과 포도원을 다시 사게 될 거야.\' 이렇게 말씀하셨어.\\""},{"n":16,"t":"내가 매매 증서를 네리야의 아들 바룩에게 맡긴 후에 여호와께 기도했어요."},{"n":17,"t":"\\"아, 슬프다! 주 여호와여, 주께서 큰 능력과 펴신 팔로 하늘과 땅을 지으셨으니, 주께는 못하실 일이 없어요.\\""},{"n":18,"t":"\\"주는 천만 명에게 은혜를 베푸시고, 아버지의 죄를 그 후 자손에게 갚으시는 크고 강하신 하나님이세요. 그 이름은 만군의 여호와예요.\\""},{"n":19,"t":"\\"주는 큰 지혜(모략)가 있으시고, 행하시는 일에 능하시며, 사람의 모든 길을 살피시고, 그 길과 행한 열매에 따라 갚으세요.\\""},{"n":20,"t":"\\"주께서 애굽 땅에서 표적과 기적(기사)을 행하셨고, 오늘까지도 이스라엘과 외국인(외인) 중에 그렇게 행하셔서, 주의 이름을 오늘과 같이 유명하게 하셨어요.\\""},{"n":21,"t":"\\"주께서 표적과 기적과 강한 손과 펴신 팔과 큰 두려움으로 주의 백성 이스라엘을 애굽 땅에서 이끌어 내셨고,\\""},{"n":22,"t":"\\"그들에게 주시기로 그들의 조상에게 맹세하신 젖과 꿀이 흐르는 이 땅을 그들에게 주셨어요.\\""},{"n":23,"t":"\\"그들이 들어가 이 땅을 차지했지만, 주의 목소리를 듣지 않고, 주의 길로 가지 않으며, 주께서 행하라고 명령하신 일을 행하지 않았기 때문에, 주께서 이 모든 재앙을 그들에게 내리셨어요.\\""},{"n":24,"t":"\\"보세요, 이 성을 치려는 자가 와서 흙벽(공격용 흙더미)을 쌓았고, 칼과 기근(굶주림)과 염병(전염병) 때문에 이 성이 적인 갈대아 사람의 손에 넘겨졌어요. 주의 말씀대로 되었음을 주께서 보세요.\\""},{"n":25,"t":"\\"주 여호와여, 주께서 제게 \'은으로 밭을 사고 증인을 세워라\'라고 말씀하셨지만, 이 성은 이미 갈대아 사람의 손에 넘겨졌어요.\\""},{"n":26,"t":"그때 여호와의 말씀이 예레미야에게 들려왔어요."},{"n":27,"t":"\\"나는 여호와이고, 모든 육체(사람)의 하나님이다. 내게 못할 일이 있겠느냐?\\""},{"n":28,"t":"\\"그러므로 나 여호와가 이렇게 말한다. 보아라, 내가 이 성을 갈대아 사람의 손과 바벨론 왕 느부갓네살의 손에 넘겨줄 것이고, 그가 이 성을 차지할 거야.\\""},{"n":29,"t":"\\"이 성을 치는 갈대아 사람이 와서 이 성에 불을 놓을 것이고, 그 성과 집들 — 곧 그 지붕에서 바알에게 향을 피우고 다른 신들에게 술(전제)을 부어 나를 화나게 한 집들 — 을 태울 거야.\\""},{"n":30,"t":"\\"이는 이스라엘 자손과 유다 자손이 옛적부터 내 눈앞에서 못된 일만 했기 때문이야. 이스라엘 자손은 자기 손으로 만든 것을 가지고 나를 화나게만 한 것뿐이야. 나 여호와가 말한다.\\""},{"n":31,"t":"\\"이 성이 세워진 날부터 오늘까지 그들이 내 분노와 화를 일으켰으니, 내가 그것(이 성)을 내 앞에서 옮겨 버리려 한다.\\""},{"n":32,"t":"\\"이는 이스라엘 자손과 유다 자손이 온갖 못된 짓을 해서 내 분노를 일으켰기 때문이야. 그들과 그들의 왕들과 높은 사람들, 제사장들과 선지자들, 유다 사람들과 예루살렘 사람들이 모두 그랬어.\\""},{"n":33,"t":"\\"그들이 내게 등을 돌리고 얼굴을 향하지 않았으며, 내가 그들을 부지런히 가르쳐도 그들은 가르침을 듣지도 않고 받지도 않았어.\\""},{"n":34,"t":"\\"내 이름이 붙은 집(성전)에 자기들의 미운(가증한) 물건(우상)들을 세워서 그 집을 더럽혔어.\\""},{"n":35,"t":"\\"또 힌놈의 아들 골짜기에 바알의 산당(우상 단)을 짓고, 자기 자녀를 몰렉(거짓 신)의 불에 지나가게(태워 바치게) 했어. 그들이 이런 미운 짓을 해서 유다로 죄를 짓게 한 것은, 내가 명령한 일도 아니고 내 마음에 둔 일도 아니란다.\\""},{"n":36,"t":"\\"그러나 이스라엘의 하나님 나 여호와가, 너희가 \'칼과 기근과 염병 때문에 바벨론 왕의 손에 넘겨졌다\'라고 말하는 이 성에 대해 이렇게 말한다.\\""},{"n":37,"t":"\\"보아라, 내가 분노와 노여움과 큰 분노로 그들을 쫓아 보냈던 모든 지방에서 그들을 모아 이곳으로 다시 데려와 안전하게 살게 할 거야.\\""},{"n":38,"t":"\\"그들은 내 백성이 되고, 나는 그들의 하나님이 될 거야.\\""},{"n":39,"t":"\\"내가 그들에게 한 마음과 한 길(방향)을 주어, 자기들과 자기 후손의 복을 위해 늘 나를 두려워(경외)하게 하고,\\""},{"n":40,"t":"\\"내가 그들에게 복을 주려고 그들을 떠나지 않겠다는 영원한 언약을 그들과 세우고, 나를 두려워하는 마음을 그들의 마음에 두어 나를 떠나지 않게 할 거야.\\""},{"n":41,"t":"\\"내가 기뻐하며 그들에게 복을 줄 것이고, 정말 내 마음과 정신을 다해 그들을 이 땅에 심을 거야.\\""},{"n":42,"t":"\\"나 여호와가 이렇게 말한다. 내가 이 백성에게 이 큰 재앙을 내렸던 것처럼, 내가 약속한 모든 복을 그들에게 내릴 거야.\\""},{"n":43,"t":"\\"너희가 \'폐허가 되어 사람이나 짐승이 없고, 갈대아 사람의 손에 넘겨졌다\'라고 말하는 이 땅에서 사람들이 밭을 살 거야.\\""},{"n":44,"t":"\\"사람들이 베냐민 땅과 예루살렘 주변과 유다 성과 산지의 성과 평지(낮은 땅)의 성과 남쪽 지방의 성에 있는 밭을 은으로 사고, 증서를 기록해서 봉인하고 증인을 세울 거야. 이는 내가 그들의 포로(사로잡힌 자들)를 돌아오게 할 것이기 때문이야. 이것은 여호와의 말이야.\\""}]}},{"chapter":33,"title":"다윗 언약의 약속","verses":{"krv":[{"n":1,"t":"예레미야가 아직 시위대 뜰에 갇혔을 때에 여호와의 말씀이 그에게 임하니라 가라사대"},{"n":2,"t":"일을 행하는 여호와, 그것을 지어 성취하는 여호와, 그 이름을 여호와라 하는 자가 이같이 이르노라"},{"n":3,"t":"너는 내게 부르짖으라 내가 네게 응답하겠고 네가 알지 못하는 크고 비밀한 일을 네게 보이리라"},{"n":4,"t":"이스라엘의 하나님 여호와가 말하노라 무리가 이 성읍의 가옥과 유다 왕궁을 헐어서 갈대아인의 흉벽과 칼을 막아"},{"n":5,"t":"싸우려 하였으나 내가 나의 노와 분함으로 그들을 죽이고 그 시체로 이 성에 채우게 하였나니 이는 그들의 모든 악을 인하여 나의 얼굴을 가리워 이 성을 돌아보지 아니하였음이니라"},{"n":6,"t":"그러나 보라 내가 이 성을 치료하며 고쳐 낫게 하고 평강과 성실함에 풍성함을 그들에게 나타낼 것이며"},{"n":7,"t":"내가 유다의 포로와 이스라엘의 포로를 돌아오게 하여 그들을 처음과 같이 세울 것이며"},{"n":8,"t":"내가 그들을 내게 범한 그 모든 죄악에서 정하게 하며 그들의 내게 범하여 행한 모든 죄악을 사할 것이라"},{"n":9,"t":"이 성읍이 세계 열방 앞에서 내게 기쁜 이름이 될 것이며 찬송과 영광이 될 것이요 그들은 나의 이 백성에게 베푼 모든 복을 들을 것이요 나의 이 성읍에 베푼 모든 복과 모든 평강을 인하여 두려워하며 떨리라"},{"n":10,"t":"나 여호와가 이같이 말하노라 너희가 가리켜 말하기를 황폐하여 사람도 없고 짐승도 없다 하던 여기 곧 황폐하여 사람도 없고 주민도 없고 짐승도 없던 유다 성읍들과 예루살렘 거리에서 즐거워하는 소리, 기뻐하는 소리, 신랑의 소리, 신부의 소리와 및 만군의 여호와께 감사하라, 여호와는 선하시니 그 인자하심이 영원하다"},{"n":11,"t":"하는 소리와 여호와의 집에 감사제를 드리는 자들의 소리가 다시 들리리니 이는 내가 이 땅의 포로로 돌아와서 처음과 같이 되게 할 것이니라 여호와의 말이니라"},{"n":12,"t":"나 만군의 여호와가 이같이 말하노라 황폐하여 사람도 없고 짐승도 없던 이 곳과 그 모든 성읍에 다시 목자의 거할 곳이 있으리니 그 양무리를 눕게 할 것이라"},{"n":13,"t":"산지 성읍들과 평지 성읍들과 남방의 성읍들과 베냐민 땅과 예루살렘 사면과 유다 성읍들에서 양 무리가 다시 계수하는 자의 손 아래로 지나리라 여호와의 말이니라"},{"n":14,"t":"나 여호와가 말하노라 보라 내가 이스라엘 집과 유다 집에 대하여 이른 선한 말을 성취할 날이 이르리라"},{"n":15,"t":"그 날 그 때에 내가 다윗에게 한 의로운 가지가 나게 하리니 그가 이 땅에 공평과 정의를 실행할 것이라"},{"n":16,"t":"그 날에 유다가 구원을 얻겠고 예루살렘이 안전히 거할 것이며 그 성은 여호와 우리의 의라 일컬음을 입으리라"},{"n":17,"t":"나 여호와가 이같이 말하노라 이스라엘 집 위에 앉을 사람이 다윗에게 영영히 끊어지지 아니할 것이며"},{"n":18,"t":"내 앞에서 번제를 드리며 소제를 사르며 다른 제를 항상 드릴 레위 사람 제사장들도 끊어지지 아니하리라 하시니라"},{"n":19,"t":"여호와의 말씀이 예레미야에게 임하니라 가라사대"},{"n":20,"t":"나 여호와가 이같이 말하노라 너희가 능히 낮에 대한 나의 약정과 밤에 대한 나의 약정을 파하여 주야로 그 때를 잃게할 수 있을진대"},{"n":21,"t":"내 종 다윗에게 세운 나의 언약도 파하여 그로 그 위에 앉아 다스릴 아들이 없게 할 수 있겠으며 내가 나를 섬기는 레위인 제사장에게 세운 언약도 파할 수 있으리라"},{"n":22,"t":"하늘의 만상은 셀 수 없으며 바다의 모래는 측량할 수 없나니 내가 그와 같이 내 종 다윗의 자손과 나를 섬기는 레위인을 번성케 하리라 하시니라"},{"n":23,"t":"여호와의 말씀이 예레미야에게 임하니라 가라사대"},{"n":24,"t":"이 백성이 말하기를 여호와께서 그 택하신 두 족속을 버리셨다 한 것을 네가 생각지 아니하느냐 그들이 내 백성을 멸시하여 자기들 앞에서 나라로 인정치 아니하도다"},{"n":25,"t":"나 여호와가 이같이 말하노라 나의 주야의 약정이 서지 아니할 수 있다든지 천지의 규례가 정한 대로 되지 아니할 수 있다 할진대"},{"n":26,"t":"내가 야곱과 내 종 다윗의 자손을 버려서 다시는 다윗의 자손 중에서 아브라함과 이삭과 야곱의 자손을 다스릴 자를 택하지 아니하리라 내가 그 포로된 자로 돌아오게 하고 그를 긍휼히 여기리라"}],"kids":[{"n":1,"t":"예레미야가 아직 시위대(왕을 지키는 군인) 뜰에 갇혀 있을 때, 여호와의 말씀이 그에게 들려왔어요."},{"n":2,"t":"\\"일을 행하시는 여호와, 그것을 만들고 이루시는 여호와, 그 이름을 여호와라고 하는 분이 이렇게 말씀하셨어.\\""},{"n":3,"t":"\\"너는 내게 부르짖어라. 내가 너에게 응답할 것이고, 네가 알지 못하는 크고 비밀한 일을 너에게 보여 줄 거야.\\""},{"n":4,"t":"\\"이스라엘의 하나님 여호와가 말한다. 사람들이 이 성의 집들과 유다 왕궁을 헐어, 그것으로 갈대아 사람의 흙벽(공격용 흙더미)과 칼을 막으며,\\""},{"n":5,"t":"\\"싸우려 했지만, 내가 분노와 화로 그들을 죽이고 그 시체로 이 성을 채우게 했어. 이는 그들의 모든 못된 짓 때문에 내가 얼굴을 가리고 이 성을 돌아보지 않았기 때문이야.\\""},{"n":6,"t":"\\"그러나 보아라, 내가 이 성을 치료하고 고쳐 낫게 하며, 평안과 진실(성실)이 풍성하게 되는 것을 그들에게 보여 줄 거야.\\""},{"n":7,"t":"\\"내가 유다의 포로와 이스라엘의 포로를 돌아오게 하고, 그들을 처음과 같이 다시 세울 거야.\\""},{"n":8,"t":"\\"내가 그들이 내게 지은 모든 죄에서 그들을 깨끗하게 하고, 그들이 내게 지어 행한 모든 죄를 용서할 거야.\\""},{"n":9,"t":"\\"이 성이 세상 모든 나라 앞에서 내게 기쁜 이름이 될 것이고, 찬송과 영광이 될 거야. 그들은 내가 이 백성에게 베푼 모든 복을 들을 것이고, 내가 이 성에 베푼 모든 복과 모든 평안 때문에 두려워하며 떨 거야.\\""},{"n":10,"t":"\\"나 여호와가 이렇게 말한다. 너희가 \'폐허가 되어 사람도 없고 짐승도 없다\'라고 말하던 이곳, 곧 폐허가 되어 사람도 살지 않고 짐승도 없던 유다 성과 예루살렘 거리에서 즐거워하는 소리, 기뻐하는 소리, 신랑과 신부의 소리, 그리고 \'만군의 여호와께 감사하라, 여호와는 선하시고 그 사랑(인자)은 영원하다\'\\""},{"n":11,"t":"\\"라고 외치는 소리와 여호와의 집에 감사 제물을 드리는 자들의 소리가 다시 들리게 될 거야. 이는 내가 이 땅의 포로들을 돌아오게 해서 처음과 같이 되게 할 것이기 때문이야. 이것은 여호와의 말이야.\\""},{"n":12,"t":"\\"나 만군의 여호와가 이렇게 말한다. 폐허가 되어 사람도 없고 짐승도 없던 이곳과 그 모든 성에 다시 목자(양치는 사람)가 살 곳이 있을 것이고, 그 양 떼가 누워서 쉴 거야.\\""},{"n":13,"t":"\\"산지의 성과 평지(낮은 땅)의 성과 남쪽 지방의 성과 베냐민 땅과 예루살렘 주변과 유다 성에서, 양 떼가 다시 세는 자(양을 세는 사람)의 손 아래로 지나갈 거야. 이것은 여호와의 말이야.\\""},{"n":14,"t":"\\"나 여호와가 말한다. 보아라, 내가 이스라엘 집과 유다 집에 대해 한 좋은 말을 이루어 줄 날이 올 거야.\\""},{"n":15,"t":"\\"그날 그때에 내가 다윗에게 의로운 가지(메시아)가 나게 할 것이고, 그가 이 땅에 공평과 정의를 행할 거야.\\""},{"n":16,"t":"\\"그날에 유다가 구원을 얻고, 예루살렘이 안전히 살 것이며, 그 성은 \'여호와 우리의 의\'라고 불릴 거야.\\""},{"n":17,"t":"\\"나 여호와가 이렇게 말한다. 이스라엘 집의 자리(왕좌)에 앉을 사람이 다윗에게서 영원히 끊어지지 않을 거야.\\""},{"n":18,"t":"\\"내 앞에서 번제(불사르는 제물)를 드리고 소제(곡식 제물)를 태우며 다른 제물을 늘 드릴 레위 사람 제사장들도 끊어지지 않을 거야.\\""},{"n":19,"t":"여호와의 말씀이 예레미야에게 들려왔어요."},{"n":20,"t":"\\"나 여호와가 이렇게 말한다. 너희가 낮에 대한 내 약정과 밤에 대한 내 약정을 깨뜨려서 낮과 밤이 그 정해진 때를 잃게 할 수 있다면,\\""},{"n":21,"t":"\\"내 종 다윗과 세운 내 언약도 깨져서, 그 자리에 앉아 다스릴 아들이 그에게 없게 될 수도 있을 것이며, 또 나를 섬기는 레위 사람 제사장들과 세운 언약도 깨질 수 있을 거야.\\""},{"n":22,"t":"\\"하늘의 별들(만상)은 셀 수 없고 바다의 모래는 측량할 수 없는 것처럼, 내가 내 종 다윗의 자손과 나를 섬기는 레위 사람들을 그렇게 번성하게 할 거야.\\""},{"n":23,"t":"여호와의 말씀이 예레미야에게 들려왔어요."},{"n":24,"t":"\\"이 백성이 \'여호와께서 그분이 뽑으셨던 두 가족(이스라엘과 유다)을 버리셨다\'라고 말한 것을 너는 생각하지 않느냐? 그들이 내 백성을 무시해서, 자기들 앞에서 더 이상 한 나라로 인정하지 않는구나.\\""},{"n":25,"t":"\\"나 여호와가 이렇게 말한다. 만일 내가 낮과 밤에 대해 정한 약정이 서지 못한다면, 또 하늘과 땅의 정해진 규례가 그대로 되지 않는다면,\\""},{"n":26,"t":"\\"내가 야곱과 내 종 다윗의 자손을 버려서, 다시는 다윗의 자손 가운데서 아브라함과 이삭과 야곱의 자손을 다스릴 자를 뽑지 않을 거야. 내가 그들의 사로잡힌 자들을 돌아오게 하고, 그들을 불쌍히 여길 거야.\\""}]}},{"chapter":34,"title":"노예 해방의 어김","verses":{"krv":[{"n":1,"t":"바벨론 왕 느부갓네살과 그 모든 군대와 그 통치하에 있는 땅의 모든 나라와 모든 백성이 예루살렘과 그 모든 성읍을 칠 때에 말씀이 여호와께로서 예레미야에게 임하니라 가라사대"},{"n":2,"t":"이스라엘의 하나님 나 여호와가 이같이 말하노라 너는 가서 유다 왕 시드기야에게 고하여 이르기를 여호와의 말씀에 보라 내가 이 성을 바벨론 왕의 손에 붙이리니 그가 이 성을 불사를 것이라"},{"n":3,"t":"네가 그 손에서 벗어나지 못하고 반드시 사로잡혀 그 손에 붙임을 입고 네 눈은 바벨론 왕의 눈을 볼 것이며 그 입은 네 입을 마주 대하여 말할 것이요 너는 바벨론으로 가리라"},{"n":4,"t":"그러나 유다 왕 시드기야여 나 여호와의 말을 들으라 나 여호와가 네게 대하여 이같이 말하노라 네가 칼에 죽지 아니하고"},{"n":5,"t":"평안히 죽을 것이며 사람이 너보다 먼저 있은 네 열조 선왕에게 분향하던 일례로 네게 분향하며 너를 위하여 애통하기를 슬프다 주여 하리니 이는 내가 말하였음이니라 여호와의 말이니라"},{"n":6,"t":"선지자 예레미야가 이 모든 말씀을 예루살렘에서 유다 왕 시드기야에게 고하니라"},{"n":7,"t":"때에 바벨론 왕의 군대가 예루살렘과 유다의 남은 모든 성을 쳤으니 곧 라기스와 아세가라 유다의 견고한 성읍 중에 이것들만 남았음이더라"},{"n":8,"t":"시드기야 왕이 예루살렘에 있는 모든 백성과 언약하고 자유를 선언한 후에 여호와께로서 말씀이 예레미야에게 임하니라"},{"n":9,"t":"그 언약은 곧 사람으로 각기 히브리 남녀 노비를 놓아 자유케 하고 그 동족 유다인으로 종을 삼지 못하게 한 것이라"},{"n":10,"t":"이 언약에 참가한 방백들과 모든 백성이 각기 노비를 자유케하고 다시는 종을 삼지 말라 함을 듣고 순복하여 놓았더니"},{"n":11,"t":"후에 그들의 뜻이 변하여 자유케 하였던 노비를 끌어다가 다시 복종시켜 노비를 삼았더라"},{"n":12,"t":"그러므로 여호와의 말씀이 여호와께로서 예레미야에게 임하니라 가라사대"},{"n":13,"t":"이스라엘 하나님 나 여호와가 이같이 말하노라 내가 너희 선조를 애굽 땅 종 되었던 집에서 인도하여 낼 때에 그들과 언약을 세워 이르기를"},{"n":14,"t":"너희 형제 히브리 사람이 네게 팔렸거든 칠 년 만에 너희는 각기 놓으라 그가 육 년을 너를 섬겼은즉 그를 놓아 자유케 할지라 하였으나 너희 선조가 나를 듣지 아니하며 귀를 기울이지도 아니하였느니라"},{"n":15,"t":"그러나 너희는 이제 돌이켜 내 목전에 정당히 행하여 각기 이웃에게 자유를 선언하되 내 이름으로 일컬음을 받는 집에서 내 앞에서 언약을 세웠거늘"},{"n":16,"t":"너희가 뜻을 변하여 내 이름을 더럽히고 각기 놓아 그들의 마음대로 자유케 하였던 노비를 끌어다가 다시 너희에게 복종시켜서 너희 노비를 삼았도다"},{"n":17,"t":"그러므로 나 여호와가 이같이 말하노라 너희가 나를 듣지 아니하고 각기 형제와 이웃에게 자유를 선언한 것을 실행치 아니하였은즉 내가 너희에게 자유를 선언하여 너희를 칼과 염병과 기근에 붙이리라 나 여호와의 말이니라 내가 너희를 세계 열방 중에 흩어지게 할 것이며"},{"n":18,"t":"송아지를 둘에 쪼개고 그 두 사이로 지나서 내 앞에 언약을 세우고 그 말을 실행치 아니하여 내 언약을 범한 너희를"},{"n":19,"t":"곧 쪼갠 송아지 사이로 지난 유다 방백들과 예루살렘 백성들과 환관들과 제사장들과 이 땅 모든 백성을"},{"n":20,"t":"내가 너희 원수의 손과 너희 생명을 찾는 자의 손에 붙이리니 너희 시체가 공중의 새들과 땅 짐승의 식물이 될 것이며"},{"n":21,"t":"또 내가 유다 왕 시드기야와 그 방백들을 그 원수의 손과 그 생명을 찾는 자의 손과 너희에게서 떠나간 바벨론 왕의 군대의 손에 붙이리라"},{"n":22,"t":"나 여호와가 말하노라 보라 내가 그들에게 명하여 이 성에 다시 오게 하리니 그들이 이 성을 쳐서 취하여 불사를 것이라 내가 유다 성읍들로 황무하여 거민이 없게 하리라"}],"kids":[{"n":1,"t":"바벨론 왕 느부갓네살과 그 모든 군대와 그가 다스리는 땅의 모든 나라와 모든 백성이 예루살렘과 그 모든 성을 칠 때에, 여호와의 말씀이 예레미야에게 들려왔어요."},{"n":2,"t":"\\"이스라엘의 하나님 나 여호와가 이렇게 말한다. 너는 가서 유다 왕 시드기야에게 말해라. \'여호와께서 이렇게 말씀하셨다. 보아라, 내가 이 성을 바벨론 왕의 손에 넘겨줄 것이고, 그가 이 성을 불태울 거야.\'\\""},{"n":3,"t":"\\"\'네가 그의 손에서 벗어나지 못하고 반드시 사로잡혀 그의 손에 넘겨질 것이고, 네 눈이 바벨론 왕의 눈을 볼 것이며, 그의 입이 네 입을 마주 대고 말하게 될 거야. 그리고 너는 바벨론으로 가게 될 거야.\'\\""},{"n":4,"t":"\\"\'그러나 유다 왕 시드기야야, 나 여호와의 말을 들어라. 나 여호와가 너에 대해 이렇게 말한다. 네가 칼에 죽지는 않을 거야.\'\\""},{"n":5,"t":"\\"\'너는 평안히 죽을 거야. 사람들이 네 이전의 조상 왕들에게 향을 피우던 것처럼 너를 위해서도 향을 피우고, 너를 위해 〈슬프다 주여〉 하면서 슬피 울 거야. 이는 내가 말한 거야. 이것은 여호와의 말이야.\'\\""},{"n":6,"t":"선지자 예레미야가 이 모든 말씀을 예루살렘에서 유다 왕 시드기야에게 전했어요."},{"n":7,"t":"그때 바벨론 왕의 군대가 예루살렘과 유다에 남은 모든 성을 치고 있었는데, 곧 라기스와 아세가였어요. 유다의 단단한 성 가운데 이 두 곳만 남아 있었어요."},{"n":8,"t":"시드기야 왕이 예루살렘에 있는 모든 백성과 언약(약속)을 맺고 자유를 선포한 후에, 여호와로부터 말씀이 예레미야에게 들려왔어요."},{"n":9,"t":"그 언약은 곧 모든 사람이 자기 히브리 남녀 노예(노비)를 풀어 자유롭게 해 주고, 같은 동족 유다 사람을 종으로 삼지 않기로 한 것이었어요."},{"n":10,"t":"이 언약에 참여한 높은 사람들과 모든 백성이 각자 자기 노예를 자유롭게 해 주고 다시는 종으로 삼지 말자는 말을 듣고 따라서 풀어 주었어요."},{"n":11,"t":"그러나 후에 그들의 뜻이 바뀌어, 자유롭게 해 주었던 노예들을 끌어다가 다시 복종시켜 노예로 삼았어요."},{"n":12,"t":"그러므로 여호와의 말씀이 여호와로부터 예레미야에게 들려왔어요."},{"n":13,"t":"\\"이스라엘의 하나님 나 여호와가 이렇게 말한다. 내가 너희 조상을 애굽 땅, 종 되었던 집에서 이끌어 낼 때에 그들과 언약을 세우고 이렇게 말했어.\\""},{"n":14,"t":"\\"\'너희 형제인 히브리 사람이 너에게 팔리거든 7년째에는 각자 그를 놓아 주어라. 그가 6년 동안 너를 섬겼으니 그를 풀어 자유롭게 해 주어라.\' 그러나 너희 조상은 내 말을 듣지 않고 귀도 기울이지 않았어.\\""},{"n":15,"t":"\\"그런데 너희가 이제 돌이켜 내 눈앞에서 옳은 일을 행해서, 각자 이웃에게 자유를 선포하고 내 이름이 붙은 집에서 내 앞에서 언약을 맺었어.\\""},{"n":16,"t":"\\"그런데 너희가 뜻을 바꾸어 내 이름을 더럽히고, 각자 그들의 마음대로 풀어 자유롭게 해 주었던 노예들을 다시 끌어다가 너희에게 복종시켜 너희 노예로 삼았구나.\\""},{"n":17,"t":"\\"그러므로 나 여호와가 이렇게 말한다. 너희가 내 말을 듣지 않고 각자 형제와 이웃에게 자유를 선포한 것을 실행하지 않았으므로, 내가 너희에게 자유를 선포하노니 너희를 칼과 염병과 기근에 넘기겠다. 나 여호와의 말이야. 내가 너희를 세상 모든 나라에 흩어지게 할 거야.\\""},{"n":18,"t":"\\"송아지를 둘로 쪼개어 그 두 조각 사이로 지나가며 내 앞에서 언약을 맺고도, 그 말을 지키지 않아 내 언약을 깨뜨린 너희를,\\""},{"n":19,"t":"\\"곧 쪼갠 송아지 사이로 지나간 유다의 높은 사람들과 예루살렘 백성과 환관들과 제사장들과 이 땅의 모든 백성을,\\""},{"n":20,"t":"\\"내가 너희 적의 손과 너희 목숨을 노리는 자의 손에 넘겨줄 것이고, 너희 시체는 하늘의 새들과 땅의 짐승의 먹이가 될 거야.\\""},{"n":21,"t":"\\"또 내가 유다 왕 시드기야와 그 높은 사람들을 그들의 적의 손과 그들의 목숨을 노리는 자의 손과 너희에게서 떠나간 바벨론 왕의 군대의 손에 넘겨줄 거야.\\""},{"n":22,"t":"\\"나 여호와가 말한다. 보아라, 내가 그들에게 명령해서 이 성으로 다시 오게 할 것이고, 그들이 이 성을 쳐서 차지하고 불태울 거야. 내가 유다 성들을 폐허로 만들어 사는 사람이 없게 할 거야.\\""}]}},{"chapter":35,"title":"레갑 자손의 충성","verses":{"krv":[{"n":1,"t":"유다 왕 요시야의 아들 여호야김 때에 여호와께로서 말씀이 예레미야에게 임하니라 가라사대"},{"n":2,"t":"너는 레갑 족속에게 가서 그들에게 말하고 그들을 여호와의 집 한 방으로 데려다가 포도주를 마시우라"},{"n":3,"t":"이에 내가 하바시냐의 손자요 예레미야의 아들인 야아사냐와 그 형제와 그 모든 아들과 레갑 온 족속을 데리고"},{"n":4,"t":"여호와의 집에 이르러 익다랴의 아들 하나님의 사람 하난의 아들들의 방에 들였는데 그 방은 방백들의 방 곁이요 문을 지키는 살룸의 아들 마아세야의 방 위더라"},{"n":5,"t":"내가 레갑 족속 사람들 앞에 포도주가 가득한 사발과 잔을 놓고 마시라 권하매"},{"n":6,"t":"그들이 가로되 우리는 포도주를 마시지 아니하겠노라 레갑의 아들 우리 선조 요나답이 우리에게 명하여 이르기를 너희와 너희 자손은 영영히 포도주를 마시지 말며"},{"n":7,"t":"집도 짓지 말며 파종도 하지 말며 포도원도 재배치 말며 두지도 말고 너희 평생에 장막에 거처하라 그리하면 너희의 우거하는 땅에서 너희 생명이 길리라 하였으므로"},{"n":8,"t":"우리가 레갑의 아들 우리 선조 요나답의 우리에게 명한 모든 말을 순종하여 우리와 우리 아내와 자녀가 평생에 포도주를 마시지 아니하며"},{"n":9,"t":"거처할 집도 짓지 아니하며 포도원이나 밭이나 종자도 두지 아니하고"},{"n":10,"t":"장막에 거처하여 우리 선조 요나답의 우리에게 명한 대로 다 준행하였노라"},{"n":11,"t":"그러나 바벨론 왕 느부갓네살이 이 땅에 올라왔을 때에 우리가 말하기를 갈대아인의 군대와 수리아인의 군대가 두려운즉 예루살렘으로 가자 하고 우리가 예루살렘에 거하였노라"},{"n":12,"t":"때에 여호와의 말씀이 예레미야에게 임하여 가라사대"},{"n":13,"t":"만군의 여호와 이스라엘의 하나님이 이같이 말하노라 너는 가서 유다 사람들과 예루살렘 거민에게 이르기를 여호와의 말씀에 너희가 내 말을 들으며 교훈을 받지 아니하겠느냐"},{"n":14,"t":"레갑의 아들 요나답이 그 자손에게 포도주를 마시지 말라 한 그 명령은 실행되도다 그들은 그 선조의 명령을 순종하여 오늘까지 마시지 아니하거늘 내가 너희에게 말하고 부지런히 말하여도 너희는 나를 듣지 아니하도다"},{"n":15,"t":"나도 내 종 모든 선지자를 너희에게 보내고 부지런히 보내며 이르기를 너희는 이제 각기 악한 길에서 돌이켜 행위를 고치고 다른 신을 좇아 그를 섬기지 말라 그리하면 너희가 나의 너희와 너희 선조에게 준 이 땅에 거하리라 하여도 너희가 귀를 기울이지 아니하며 나를 듣지 아니하였느니라"},{"n":16,"t":"레갑의 아들 요나답의 자손은 그 선조가 그들에게 명한 그 명령을 준행하나 이 백성은 나를 듣지 아니하도다"},{"n":17,"t":"그러므로 나 만군의 여호와 이스라엘의 하나님이 이같이 말하노라 보라 내가 유다와 예루살렘 모든 거민에게 나의 그들에게 대하여 선포한 모든 재앙을 내리리니 이는 내가 그들에게 말하여도 듣지 아니하며 불러도 대답지 아니함이니라 하셨다 하라"},{"n":18,"t":"예레미야가 레갑 족속에게 이르되 만군의 여호와 이스라엘의 하나님이 이같이 말씀하시기를 너희가 너희 선조 요나답의 명령을 준종하여 그 모든 훈계를 지키며 그가 너희에게 명한 것을 행하였도다"},{"n":19,"t":"그러므로 나 만군의 여호와 이스라엘의 하나님이 이같이 말하노라 레갑의 아들 요나답에게서 내 앞에 설 사람이 영영히 끊어지지 아니하리라"}],"kids":[{"n":1,"t":"유다 왕 요시야의 아들 여호야김 때에 여호와로부터 말씀이 예레미야에게 들려왔어요."},{"n":2,"t":"\\"너는 레갑 족속(레갑의 자손들)에게 가서 그들에게 말하고, 여호와의 집(성전)의 한 방으로 데려와 포도주를 마시게 해라.\\""},{"n":3,"t":"그래서 내가 하바시냐의 손자이며 예레미야의 아들인 야아사냐와 그 형제와 그의 모든 아들과 레갑 온 족속을 데리고,"},{"n":4,"t":"여호와의 집에 이르러서 익다랴의 아들이며 하나님의 사람인 하난의 아들들의 방으로 들어갔어요. 그 방은 높은 사람들의 방 옆에 있었고, 문을 지키는 살룸의 아들 마아세야의 방 위에 있었어요."},{"n":5,"t":"내가 레갑 족속 사람들 앞에 포도주가 가득한 사발과 잔을 놓고 마시라고 권했어요."},{"n":6,"t":"그러나 그들이 말했어요. \\"우리는 포도주를 마시지 않을 거예요. 레갑의 아들 우리 조상 요나답이 우리에게 명령해서 말하기를, \'너희와 너희 자손은 영원히 포도주를 마시지 마라.\'\\""},{"n":7,"t":"\\"\'또 집도 짓지 말고, 씨앗을 뿌리지도 말고, 포도원을 가꾸거나 가지지도 말고, 평생 천막에서 살아라. 그러면 너희가 사는 땅에서 너희 생명이 길어질 것이다\'라고 했어요.\\""},{"n":8,"t":"\\"그래서 우리는 레갑의 아들 우리 조상 요나답이 우리에게 명령한 모든 말을 따라, 우리와 우리 아내와 자녀들이 평생 포도주를 마시지 않고,\\""},{"n":9,"t":"\\"살 집도 짓지 않으며, 포도원이나 밭이나 씨앗도 가지지 않고,\\""},{"n":10,"t":"\\"천막에서 살면서 우리 조상 요나답이 우리에게 명령한 대로 다 따라 했어요.\\""},{"n":11,"t":"\\"그러나 바벨론 왕 느부갓네살이 이 땅에 올라왔을 때 우리가 \'갈대아 사람의 군대와 수리아(시리아) 사람의 군대가 무서우니 예루살렘으로 가자\'라고 하고는 예루살렘에 살게 되었어요.\\""},{"n":12,"t":"그때 여호와의 말씀이 예레미야에게 들려왔어요."},{"n":13,"t":"\\"만군의 여호와 이스라엘의 하나님이 이렇게 말한다. 너는 가서 유다 사람들과 예루살렘에 사는 사람들에게 이렇게 말해라. \'여호와께서 이렇게 말씀하셨다. 너희가 내 말을 듣고 가르침을 받지 않겠느냐?\'\\""},{"n":14,"t":"\\"\'레갑의 아들 요나답이 그 자손에게 포도주를 마시지 말라고 한 그 명령은 잘 지켜지고 있어. 그들은 그 조상의 명령을 따라 오늘까지 마시지 않는데, 내가 너희에게 부지런히 말해도 너희는 내 말을 듣지 않는구나.\'\\""},{"n":15,"t":"\\"\'나도 내 종 모든 선지자를 너희에게 부지런히 보내어 〈너희는 이제 각자 못된 길에서 돌이켜 행동을 고치고, 다른 신을 따라가서 섬기지 마라. 그러면 너희가 너희와 너희 조상에게 준 이 땅에서 살게 될 거야〉라고 했지만, 너희가 귀를 기울이지도 않고 내 말을 듣지도 않았어.\'\\""},{"n":16,"t":"\\"\'레갑의 아들 요나답의 자손은 그 조상이 명령한 그 명령을 잘 지키지만, 이 백성은 내 말을 듣지 않는구나.\'\\""},{"n":17,"t":"\\"\'그러므로 나 만군의 여호와 이스라엘의 하나님이 이렇게 말한다. 보아라, 내가 유다와 예루살렘 모든 백성에게 그들에 대해 선포한 모든 재앙을 내릴 거야. 이는 내가 그들에게 말해도 듣지 않고 불러도 대답하지 않았기 때문이야.\' 이렇게 말해라.\\""},{"n":18,"t":"예레미야가 레갑 족속에게 말했어요. \\"만군의 여호와 이스라엘의 하나님이 이렇게 말씀하셨어요. \'너희가 너희 조상 요나답의 명령을 따라 그 모든 가르침을 지키고, 그가 너희에게 명령한 것을 잘 행했구나.\'\\""},{"n":19,"t":"\\"\'그러므로 나 만군의 여호와 이스라엘의 하나님이 이렇게 말한다. 레갑의 아들 요나답에게는 내 앞에 설 사람이 영원히 끊어지지 않을 거야.\'\\""}]}},{"chapter":36,"title":"여호야김이 두루마리를 태움","verses":{"krv":[{"n":1,"t":"유다 왕 요시야의 아들 여호야김 사년에 여호와께로서 예레미야에게 말씀이 임하니라 가라사대"},{"n":2,"t":"너는 두루마리 책을 취하여 내가 네게 말하던 날 곧 요시야의 날부터 오늘까지 이스라엘과 유다와 열방에 대하여 나의 네게 이른 모든 말을 그것에 기록하라"},{"n":3,"t":"유다 족속이 내가 그들에게 내리려한 모든 재앙을 듣고 각기 악한 길에서 돌이킬듯 하니라 그리하면 내가 그 악과 죄를 사하리라"},{"n":4,"t":"이에 예레미야가 네리야의 아들 바룩을 부르매 바룩이 예레미야의 구전대로 여호와께서 그에게 이르신 모든 말씀을 두루마리 책에 기록하니라"},{"n":5,"t":"예레미야가 바룩을 명하여 가로되 나는 감금을 당한지라 여호와의 집에 들어갈 수 없은즉"},{"n":6,"t":"너는 들어가서 나의 구전대로 두루마리에 기록한 여호와의 말씀을 금식일에 여호와의 집에 있는 백성의 귀에 낭독하고 유다 모든 성에서 온 자들의 귀에도 낭독하라"},{"n":7,"t":"그들이 여호와 앞에 기도를 드리며 각기 악한 길을 떠날듯 하니라 여호와께서 이 백성에 대하여 선포하신 노와 분이 크니라"},{"n":8,"t":"네리야의 아들 바룩이 무릇 선지자 예레미야의 자기에게 명한 대로 하여 여호와의 집에서 책에 있는 여호와의 말씀을 낭독하니라"},{"n":9,"t":"유다 왕 요시야의 아들 여호야김의 오년 구월에 예루살렘 모든 백성과 유다 성읍들에서 예루살렘에 이른 모든 백성이 여호와 앞에서 금식을 선포한지라"},{"n":10,"t":"바룩이 여호와의 집 윗뜰 곧 여호와의 집 새문 어귀의 곁에 있는 사반의 아들 서기관 그마랴의 방에서 그 책에 있는 예레미야의 말을 낭독하여 모든 백성에게 들리니라"},{"n":11,"t":"사반의 손자요 그마랴의 아들인 미가야가 그 책에 있는 여호와의 말씀을 다 듣고"},{"n":12,"t":"왕궁에 내려가서 서기관의 방에 들어가니 모든 방백 곧 서기관 엘리사마와 스마야의 아들 들라야와 악볼의 아들 엘라단과 사반의 아들 그마랴와 하나냐의 아들 시드기야와 모든 방백이 거기 앉았는지라"},{"n":13,"t":"미가야가 바룩의 백성의 귀에 책을 낭독할 때에 들은 모든 말로 그들에게 고하매"},{"n":14,"t":"이에 모든 방백이 구시의 증손 셀레먀의 손자 느다냐의 아들 여후디를 바룩에게 보내어 이르되 너는 백성의 귀에 낭독한 두루마리를 손에 가지고 오라 네리야의 아들 바룩이 두루마리를 손에 가지고 그들에게로 가매"},{"n":15,"t":"그들이 바룩에게 이르되 앉아서 이를 귀에 낭독하라 바룩이 그들 귀에 낭독하매"},{"n":16,"t":"그들이 그 모든 말씀을 듣고 놀라서 서로 보며 바룩에게 이르되 우리가 이 모든 말을 왕에게 고하리라"},{"n":17,"t":"그들이 또 바룩에게 물어 가로되 네가 그 구전하는 이 모든 말을 어떻게 기록하였느뇨 청컨대 우리에게 이르라"},{"n":18,"t":"바룩이 대답하되 그가 그 입으로 이 모든 말을 내게 베풀기로 내가 먹으로 책에 기록하였노라"},{"n":19,"t":"이에 방백들이 바룩에게 이르되 너는 가서 예레미야와 함께 숨고 너희 있는 곳을 사람에게 알리지 말라 하니라"},{"n":20,"t":"그들이 두루마리를 서기관 엘리사마의 방에 두고 뜰에 들어가 왕께 나아가서 이 모든 말로 왕의 귀에 고하니"},{"n":21,"t":"왕이 여후디를 보내어 두루마리를 가져오게 하매 여후디가 서기관 엘리사마의 방에서 가져다가 왕과 왕의 곁에 선 모든 방백의 귀에 낭독하니"},{"n":22,"t":"때는 구월이라 왕이 겨울궁전에 앉았고 그 앞에는 불 피운 화로가 있더라"},{"n":23,"t":"여후디가 삼편 사편을 낭독하면 왕이 소도로 그것을 연하여 베어 화로 불에 던져서 온 두루마리를 태웠더라"},{"n":24,"t":"왕과 그 신하들이 이 모든 말을 듣고도 두려워하거나 그 옷을 찢지 아니하였고"},{"n":25,"t":"엘라단과 들라야와 그마랴가 왕께 두루마리를 사르지 말기를 간구하여도 왕이 듣지 아니하였으며"},{"n":26,"t":"왕이 왕의 아들 여라므엘과 아스리엘의 아들 스라야와 압디엘의 아들 셀레먀를 명하여 서기관 바룩과 선지자 예레미야를 잡으라 하였으나 여호와께서 그들을 숨기셨더라"},{"n":27,"t":"왕이 두루마리와 바룩이 예레미야의 구전으로 기록한 말씀을 불사른 후에 여호와의 말씀이 예레미야에게 임하니라 가라사대"},{"n":28,"t":"너는 다시 다른 두루마리를 가지고 유다 왕 여호야김의 불사른 첫 두루마리의 모든 말을 기록하고"},{"n":29,"t":"또 유다 왕 여호야김에 대하여 이같이 말하기를 여호와의 말씀에 그가 이 두루마리를 불사르며 말하기를 네가 어찌하여 바벨론 왕이 정녕히 와서 이 땅을 멸하고 사람과 짐승을 이 땅에서 없어지게 하리라 하는 말을 이 두루마리에 기록하였느뇨 하도다"},{"n":30,"t":"그러므로 나 여호와가 유다 왕 여호야김에 대하여 이같이 말하노라 그에게 다윗의 위에 앉을 자가 없게 될 것이요 그 시체는 버림을 입어서 낮에는 더위, 밤에는 추위를 당하리라"},{"n":31,"t":"또 내가 그와 그 자손과 신하들을 그들의 죄악을 인하여 벌할 것이라 내가 일찍 그들과 예루살렘 거민과 유다 사람에게 선포하였으나 그들이 듣지 아니한 그 모든 재앙을 내리리라 하셨다 하라"},{"n":32,"t":"이에 예레미야가 다른 두루마리를 취하여 네리야의 아들 서기관 바룩에게 주매 그가 유다 왕 여호야김의 불사른 책의 모든 말을 예레미야의 구전대로 기록하고 그 외에도 그 같은 말을 많이 더 하였더라"}],"kids":[{"n":1,"t":"유다 왕 요시야의 아들 여호야김 4년에, 여호와로부터 말씀이 예레미야에게 들려왔어요."},{"n":2,"t":"\\"너는 두루마리(둘둘 말린 책)를 가져다가, 내가 너에게 말하던 날, 곧 요시야의 날부터 오늘까지 이스라엘과 유다와 모든 나라에 대해 너에게 한 모든 말을 거기에 기록해라.\\""},{"n":3,"t":"\\"유다 집안이 내가 그들에게 내리려는 모든 재앙을 듣고, 각자 못된 길에서 돌이킬지도 모른다. 그러면 내가 그들의 잘못과 죄를 용서할 거야.\\""},{"n":4,"t":"그래서 예레미야가 네리야의 아들 바룩을 불렀고, 바룩이 예레미야가 입으로 불러 주는 대로(구전대로) 여호와께서 그에게 말씀하신 모든 말씀을 두루마리에 기록했어요."},{"n":5,"t":"예레미야가 바룩에게 명령해서 말했어요. \\"나는 갇혀 있어서 여호와의 집에 들어갈 수 없어.\\""},{"n":6,"t":"\\"너는 들어가서 내가 부르는 대로 두루마리에 기록한 여호와의 말씀을 금식하는 날(밥을 먹지 않고 기도하는 날)에 여호와의 집에 있는 백성의 귀에 읽어 주고, 또 유다의 모든 성에서 온 사람들의 귀에도 읽어 줘.\\""},{"n":7,"t":"\\"그들이 여호와 앞에 기도를 드리고 각자 못된 길에서 돌이킬지도 몰라. 여호와께서 이 백성에 대해 선포하신 분노와 화가 정말 크단다.\\""},{"n":8,"t":"네리야의 아들 바룩이 선지자 예레미야가 자기에게 명령한 대로 다 해서, 여호와의 집에서 책에 있는 여호와의 말씀을 읽었어요."},{"n":9,"t":"유다 왕 요시야의 아들 여호야김 5년 9월에, 예루살렘의 모든 백성과 유다 성에서 예루살렘에 온 모든 백성이 여호와 앞에서 금식을 선포했어요."},{"n":10,"t":"바룩이 여호와의 집 위쪽 뜰, 곧 여호와의 집 새 문 입구 옆에 있는 사반의 아들 서기관(글 쓰는 일을 맡은 관리) 그마랴의 방에서 그 책에 있는 예레미야의 말을 읽어 모든 백성에게 들려주었어요."},{"n":11,"t":"사반의 손자이며 그마랴의 아들인 미가야가 그 책에 있는 여호와의 말씀을 다 듣고,"},{"n":12,"t":"왕궁에 내려가서 서기관의 방으로 들어갔어요. 거기에는 모든 높은 사람들, 곧 서기관 엘리사마와 스마야의 아들 들라야, 악볼의 아들 엘라단, 사반의 아들 그마랴, 하나냐의 아들 시드기야와 모든 높은 사람들이 앉아 있었어요."},{"n":13,"t":"미가야가 바룩이 백성의 귀에 책을 읽을 때 들은 모든 말을 그들에게 알렸어요."},{"n":14,"t":"그러자 모든 높은 사람들이 구시의 증손이며 셀레먀의 손자이며 느다냐의 아들인 여후디를 바룩에게 보내 \\"네가 백성의 귀에 읽어 준 두루마리를 가지고 오너라\\"라고 하니, 네리야의 아들 바룩이 두루마리를 손에 들고 그들에게 갔어요."},{"n":15,"t":"그들이 바룩에게 말했어요. \\"앉아서 이것을 우리 귀에 읽어 줘.\\" 바룩이 그들의 귀에 읽어 주었어요."},{"n":16,"t":"그들이 그 모든 말씀을 듣고 놀라서 서로를 보며 바룩에게 말했어요. \\"우리가 이 모든 말을 왕에게 알려야겠소.\\""},{"n":17,"t":"그들이 또 바룩에게 물었어요. \\"네가 그 입으로 불러 준 이 모든 말을 어떻게 기록했는지 우리에게 말해 줘.\\""},{"n":18,"t":"바룩이 대답했어요. \\"그가 그 입으로 이 모든 말을 내게 불러 주어서, 내가 먹으로 책에 기록한 거예요.\\""},{"n":19,"t":"그러자 높은 사람들이 바룩에게 말했어요. \\"너는 가서 예레미야와 함께 숨고, 너희가 있는 곳을 아무에게도 알리지 마라.\\""},{"n":20,"t":"그들이 두루마리를 서기관 엘리사마의 방에 두고, 뜰에 들어가 왕에게 나아가서 이 모든 말을 왕의 귀에 알렸어요."},{"n":21,"t":"왕이 여후디를 보내 두루마리를 가져오게 했어요. 여후디가 서기관 엘리사마의 방에서 두루마리를 가져다가 왕과 왕 옆에 서 있는 모든 높은 사람들의 귀에 읽어 주었어요."},{"n":22,"t":"때는 9월이었기 때문에 왕이 겨울 궁전에 앉아 있었고, 그 앞에는 불을 피운 화로(난로)가 있었어요."},{"n":23,"t":"여후디가 두루마리를 서너 단(글의 칸)씩 읽으면, 왕이 작은 칼로 그것을 잘라 화로 불에 던져서, 결국에는 두루마리 전체를 다 태워 버렸어요."},{"n":24,"t":"왕과 그 신하들이 이 모든 말을 듣고도 두려워하지 않고, 옷을 찢지도 않았어요(슬퍼하지 않았어요)."},{"n":25,"t":"엘라단과 들라야와 그마랴가 왕에게 두루마리를 태우지 말라고 빌었지만, 왕이 듣지 않았어요."},{"n":26,"t":"왕이 왕의 아들 여라므엘과 아스리엘의 아들 스라야와 압디엘의 아들 셀레먀에게 명령해서 서기관 바룩과 선지자 예레미야를 잡으라고 했지만, 여호와께서 그들을 숨겨 주셨어요."},{"n":27,"t":"왕이 두루마리와, 바룩이 예레미야의 구전으로 기록한 말씀을 불태운 후에, 여호와의 말씀이 예레미야에게 들려왔어요."},{"n":28,"t":"\\"너는 다른 두루마리를 다시 가져다가, 유다 왕 여호야김이 태워 버린 첫 두루마리의 모든 말을 거기에 기록해라.\\""},{"n":29,"t":"\\"또 유다 왕 여호야김에 대해 이렇게 말해라. \'여호와께서 이렇게 말씀하셨다. 네가 이 두루마리를 태우면서 말하기를 ‘네가 어찌하여 바벨론 왕이 분명히 와서 이 땅을 멸하고 사람과 짐승을 이 땅에서 없어지게 할 거라고 이 두루마리에 기록했느냐?’라고 했지.\'\\""},{"n":30,"t":"\\"\'그러므로 나 여호와가 유다 왕 여호야김에 대해 이렇게 말한다. 그에게는 다윗의 자리(왕좌)에 앉을 자가 없게 될 것이고, 그의 시체는 버려져서 낮에는 더위에, 밤에는 추위에 시달릴 거야.\'\\""},{"n":31,"t":"\\"\'또 내가 그와 그 자손과 신하들을 그들의 죄 때문에 벌할 거야. 내가 일찍이 그들과 예루살렘 백성과 유다 사람들에게 선포했지만 그들이 듣지 않은 모든 재앙을 내릴 거야.\' 이렇게 말해라.\\""},{"n":32,"t":"그래서 예레미야가 다른 두루마리를 가져다가 네리야의 아들 서기관 바룩에게 주었고, 바룩이 유다 왕 여호야김이 태워 버린 책의 모든 말을 예레미야의 구전대로 기록하고, 그 외에도 그와 같은 말을 많이 더 적었어요."}]}},{"chapter":37,"title":"시드기야의 마지막 부탁","verses":{"krv":[{"n":1,"t":"요시야의 아들 시드기야가 여호야김의 아들 고니야를 대신하여 왕이 되었으니 이는 바벨론 왕 느부갓네살이 그로 유다 땅의 왕을 삼음이었더라"},{"n":2,"t":"그와 그 신하와 그 땅 백성이 여호와께서 선지자 예레미야로 하신 말씀을 듣지 아니하니라"},{"n":3,"t":"시드기야 왕이 셀레먀의 아들 여후갈과 마아세야의 아들 제사장 스바냐를 선지자 예레미야에게 보내어 청하되 너는 우리를 위하여 우리 하나님 여호와께 기도하라 하였으니"},{"n":4,"t":"때에 예레미야가 갇히지 아니하였으므로 백성 가운데 출입하는 중이었더라"},{"n":5,"t":"바로의 군대가 애굽에서 나오매 예루살렘을 에워쌌던 갈대아인이 그 소문을 듣고 예루살렘에서 떠났더라"},{"n":6,"t":"여호와의 말씀이 선지자 예레미야에게 임하여 가라사대"},{"n":7,"t":"이스라엘의 하나님 나 여호와가 이같이 말하노라 너희를 보내어 내게 구하게 한 유다 왕에게 이르라 너희를 도우려고 나왔던 바로의 군대는 자기 땅 애굽으로 돌아가겠고"},{"n":8,"t":"갈대아인이 다시 와서 이 성을 쳐서 취하여 불사르리라"},{"n":9,"t":"나 여호와가 이같이 말하노라 너희는 스스로 속여 말하기를 갈대아인이 반드시 우리를 떠나리라 하지 말라 그들이 떠나지 아니하리라"},{"n":10,"t":"가령 너희가 너희를 치는 갈대아인의 온 군대를 쳐서 그 중에 부상자만 남긴다 할지라도 그들이 각기 장막에서 일어나 이 성을 불사르리라"},{"n":11,"t":"갈대아인의 군대가 바로의 군대를 두려워하여 예루살렘에서 떠나매"},{"n":12,"t":"예레미야가 베냐민 땅에서 백성 중 분깃을 받으려고 예루살렘을 떠나 그리로 가려하여"},{"n":13,"t":"베냐민 문에 이른즉 하나냐의 손자요 셀레먀의 아들인 이리야라 이름하는 문지기의 두목이 선지자 예레미야를 붙잡아 가로되 네가 갈대아인에게 항복하려 하는도다"},{"n":14,"t":"예레미야가 가로되 망령되다 나는 갈대아인에게 항복하려 하지 아니하노라 이리야가 듣지 아니하고 예레미야를 잡아 방백들에게로 끌어가매"},{"n":15,"t":"방백들이 노하여 예레미야를 때려서 서기관 요나단의 집에 가두었으니 이는 그들이 이 집으로 옥을 삼았음이더라"},{"n":16,"t":"예레미야가 토굴 옥 음실에 들어간지 여러 날 만에"},{"n":17,"t":"시드기야 왕이 보내어 그를 이끌어 내고 왕궁에서 그에게 비밀히 물어 가로되 여호와께로서 받은 말씀이 있느뇨 예레미야가 대답하되 있나이다 또 가로되 왕이 바벨론 왕의 손에 붙임을 입으리이다"},{"n":18,"t":"예레미야가 다시 시드기야 왕에게 이르되 내가 왕에게나 왕의 신하에게나 이 백성에게 무슨 죄를 범하였관대 나를 옥에 가두었나이까"},{"n":19,"t":"바벨론 왕이 와서 왕과 이 땅을 치지 아니하리라고 예언한 왕의 선지자들이 이제 어디 있나이까"},{"n":20,"t":"내 주 왕이여 이제 청컨대 나를 들으시며 나의 탄원을 받으사 나를 서기관 요나단의 집으로 돌려 보내지 마옵소서 내가 거기서 죽을까 두려워하나이다"},{"n":21,"t":"이에 시드기야 왕이 명하여 예레미야를 시위대 뜰에 두고 떡 만드는 자의 거리에서 매일 떡 한덩이씩 그에게 주게 하매 성중에 떡이 다할 때까지 이르니라 예레미야가 시위대 뜰에 머무니라"}],"kids":[{"n":1,"t":"요시야의 아들 시드기야가 여호야김의 아들 고니야(여호야긴)를 대신해 왕이 되었어요. 이는 바벨론 왕 느부갓네살이 그를 유다 땅의 왕으로 세웠기 때문이에요."},{"n":2,"t":"그와 그의 신하들과 그 땅의 백성이 여호와께서 선지자 예레미야로 하신 말씀을 듣지 않았어요."},{"n":3,"t":"시드기야 왕이 셀레먀의 아들 여후갈과 마아세야의 아들 제사장 스바냐를 선지자 예레미야에게 보내 부탁했어요. \\"우리를 위해 우리 하나님 여호와께 기도해 주세요.\\""},{"n":4,"t":"그때 예레미야가 아직 갇히지 않아서 백성 가운데서 자유롭게 다닐 수 있었어요."},{"n":5,"t":"바로(애굽 왕)의 군대가 애굽에서 나오자, 예루살렘을 둘러싸고 있던 갈대아 사람들이 그 소문을 듣고 예루살렘에서 떠났어요."},{"n":6,"t":"여호와의 말씀이 선지자 예레미야에게 들려왔어요."},{"n":7,"t":"\\"이스라엘의 하나님 나 여호와가 이렇게 말한다. 너희를 보내어 내게 빌게 한 유다 왕에게 이렇게 말해라. \'너희를 도우러 나왔던 바로의 군대는 자기 땅 애굽으로 돌아갈 거야.\'\\""},{"n":8,"t":"\\"\'갈대아 사람이 다시 와서 이 성을 쳐서 차지하고 불태울 거야.\'\\""},{"n":9,"t":"\\"\'나 여호와가 이렇게 말한다. 너희가 스스로 속아서 ‘갈대아 사람이 반드시 우리에게서 떠날 것이다’라고 말하지 마라. 그들은 떠나지 않을 거야.\'\\""},{"n":10,"t":"\\"\'설령 너희가 너희를 치는 갈대아 사람의 모든 군대를 쳐서 그 가운데 다친 자들만 남겨 둔다 해도, 그들이 각자 천막에서 일어나 이 성을 불태울 거야.\'\\""},{"n":11,"t":"갈대아 사람의 군대가 바로의 군대를 두려워해 예루살렘에서 떠났을 때,"},{"n":12,"t":"예레미야가 베냐민 땅에서 백성 중 자기 몫(분깃)을 받으려고 예루살렘을 떠나 그곳으로 가려고 했어요."},{"n":13,"t":"베냐민 문에 이르렀을 때, 하나냐의 손자이며 셀레먀의 아들인 이리야라는 문지기의 우두머리가 선지자 예레미야를 붙잡고 말했어요. \\"네가 갈대아 사람에게 항복하려고 하는구나!\\""},{"n":14,"t":"예레미야가 말했어요. \\"그건 거짓말이에요! 저는 갈대아 사람에게 항복하려는 게 아니에요.\\" 그러나 이리야가 듣지 않고 예레미야를 잡아 높은 사람들에게 끌고 갔어요."},{"n":15,"t":"높은 사람들이 화가 나서 예레미야를 때리고, 서기관 요나단의 집에 가두었어요. 그들이 그 집을 감옥(옥)으로 만들었기 때문이에요."},{"n":16,"t":"예레미야가 토굴(땅 밑) 감옥의 음실(어두운 방)에 들어간 지 여러 날이 지난 후에,"},{"n":17,"t":"시드기야 왕이 사람을 보내 그를 데려와서, 왕궁에서 그에게 비밀스레 물었어요. \\"여호와로부터 받은 말씀이 있느냐?\\" 예레미야가 대답했어요. \\"있어요.\\" 그리고 또 말했어요. \\"왕이 바벨론 왕의 손에 넘겨질 거예요.\\""},{"n":18,"t":"예레미야가 다시 시드기야 왕에게 말했어요. \\"제가 왕이나 왕의 신하나 이 백성에게 무슨 죄를 지었기에 저를 감옥에 가두었나요?\\""},{"n":19,"t":"\\"\'바벨론 왕이 와서 왕과 이 땅을 치지 않을 거예요\'라고 예언하던 왕의 선지자들은 이제 어디 있어요?\\""},{"n":20,"t":"\\"제 주 왕이여, 이제 청하건대 제 말을 들어주시고 제 부탁(탄원)을 받아 주세요. 저를 서기관 요나단의 집으로 다시 보내지 마세요. 제가 거기서 죽을까 두려워요.\\""},{"n":21,"t":"그래서 시드기야 왕이 명령해서 예레미야를 시위대 뜰에 두고, 떡 만드는 자의 거리에서 매일 떡 한 덩이씩 그에게 주게 했어요. 성 안에 떡이 다 떨어질 때까지 그렇게 했어요. 예레미야는 시위대 뜰에 머물렀어요."}]}},{"chapter":38,"title":"구덩이에 갇힌 예레미야","verses":{"krv":[{"n":1,"t":"맛단의 아들 스바댜와 바스훌의 아들 그다랴와 셀레먀의 아들 유갈과 밀기야의 아들 바스훌이 예레미야의 모든 백성에게 이르는 말을 들은즉 이르기를"},{"n":2,"t":"여호와께서 이같이 말씀하시되 이 성에 머무는 자는 칼과 기근과 염병에 죽으리라 그러나 갈대아인에게 항복하는 자는 살리니 그의 생명이 노략물을 얻음 같이 살리라"},{"n":3,"t":"나 여호와가 이같이 말하노라 이 성이 반드시 바벨론 왕의 군대의 손에 붙이우리니 그가 취하리라 하셨다 하는지라"},{"n":4,"t":"이에 그 방백들이 왕께 고하되 이 사람이 백성의 평안을 구치 아니하고 해를 구하오니 청컨대 이 사람을 죽이소서 그가 이같이 말하여 이 성에 남은 군사의 손과 모든 백성의 손을 약하게 하나이다"},{"n":5,"t":"시드기야 왕이 가로되 보라 그가 너희 손에 있느니라 왕은 조금도 너희를 거스릴 수 없느니라"},{"n":6,"t":"그들이 예레미야를 취하여 시위대 뜰에 있는 왕의 아들 말기야의 구덩이에 던져 넣을 때에 예레미야를 줄로 달아내리웠는데 그 구덩이에는 물이 없고 진흙뿐이므로 예레미야가 진흙 중에 빠졌더라"},{"n":7,"t":"왕궁 환관 구스인 에벳멜렉이 그들의 예레미야를 구덩이에 던져넣었음을 들으니라 때에 왕이 베냐민 문에 앉았더니"},{"n":8,"t":"에벳멜렉이 왕궁에서 나와 왕께 고하여 가로되"},{"n":9,"t":"내 주 왕이여 저 사람들이 선지자 예레미야에게 행한 모든 일은 악하니이다 성 중에 떡이 떨어졌거늘 그들이 그를 구덩이에 던져 넣었으니 그가 거기서 주려 죽으리이다"},{"n":10,"t":"왕이 구스인 에벳멜렉에게 명하여 가로되 너는 여기서 삼십 명을 데리고 가서 선지자 예레미야의 죽기 전에 그를 구덩이에서 끌어내라"},{"n":11,"t":"에벳멜렉이 사람들을 데리고 왕궁 곳간 밑 방에 들어가서 거기서 헝겊과 낡은 옷을 취하고 그것을 구덩이에 있는 예레미야에게 줄로 내리우며"},{"n":12,"t":"구스인 에벳멜렉이 예레미야에게 이르되 너는 이 헝겊과 낡은 옷을 네 겨드랑이에 대고 줄을 그 아래 대라 예레미야가 그대로 하매"},{"n":13,"t":"그들이 줄로 예레미야를 구덩이에서 끌어낸지라 예레미야가 시위대 뜰에 머무니라"},{"n":14,"t":"시드기야 왕이 보내어 선지자 예레미야를 여호와의 집 제삼문으로 데려오게 하고 왕이 예레미야에게 이르되 내가 네게 한 일을 물으리니 일호도 내게 숨기지 말라"},{"n":15,"t":"예레미야가 시드기야에게 이르되 내가 이 일을 왕에게 아시게 하여도 왕이 단정코 나를 죽이지 아니하시리이까 가령 내가 왕을 권한다 할지라도 왕이 듣지 아니하시리이다"},{"n":16,"t":"시드기야 왕이 비밀히 예레미야에게 맹세하여 가로되 우리에게 이 영혼을 지으신 여호와께서 사시거니와 내가 너를 죽이지도 아니하겠고 네 생명을 찾는 그 사람들의 손에 붙이지도 아니하리라"},{"n":17,"t":"예레미야가 시드기야에게 이르되 만군의 하나님이신 이스라엘 하나님 여호와께서 이같이 말씀하시되 네가 만일 바벨론 왕의 방백들에게 항복하면 네 생명이 살겠고 이 성이 불사름을 입지 아니하겠고 너와 네 가족이 살려니와"},{"n":18,"t":"네가 만일 나가서 바벨론 왕의 방백들에게 항복하지 아니하면 이 성이 갈대아인의 손에 붙이우리니 그들이 이 성을 불사를 것이며 너는 그들의 손을 벗어나지 못하리라 하셨나이다"},{"n":19,"t":"시드기야 왕이 예레미야에게 이르되 나는 갈대아인에게 항복한 유다인을 두려워하노라 염려컨대 갈대아인이 나를 그들의 손에 붙이면 그들이 나를 조롱할까 하노라"},{"n":20,"t":"예레미야가 가로되 그 무리가 왕을 그들에게 붙이지 아니하리이다 원하옵나니 내가 왕에게 고한 바 여호와의 목소리를 청종하소서 그리하면 왕이 복을 받아 생명을 보존하시리이다"},{"n":21,"t":"그러나 만일 항복하기를 거절하시면 여호와께서 내게 보이신 말씀대로 되리이다"},{"n":22,"t":"곧 유다 왕궁에 남아 있는 모든 여자가 바벨론 왕의 방백들에게로 끌려갈 것이요 그들은 네게 말하기를 네 친구들이 너를 꾀어 이기고 네 발이 진흙에 빠짐을 보고 물러갔도다 하리라"},{"n":23,"t":"네 아내들과 자녀는 갈대아인에게로 끌어냄을 입겠고 너는 그들의 손에서 벗어나지 못하고 바벨론 왕의 손에 잡히리라 또 네가 이 성으로 불사름을 입게 하리라 하셨나이다"},{"n":24,"t":"시드기야가 예레미야에게 이르되 너는 이 말을 사람으로 알게 하지 말라 그리하면 네가 죽지 아니하리라"},{"n":25,"t":"만일 방백들이 내가 너와 말하였다 함을 듣고 와서 네게 말하기를 네가 왕에게 말씀한 것을 우리에게 고하라 우리에게 숨기지 말라 그리하면 우리가 너를 죽이지 아니하리라 또 왕이 네게 말씀한 것을 고하라 하거든"},{"n":26,"t":"그들에게 대답하되 내가 왕의 앞에 간구하기를 나를 요나단의 집으로 도로 보내지 말아서 거기서 죽지 않게 하옵소서 하였다 하라 하니라"},{"n":27,"t":"모든 방백이 예레미야에게 와서 물으매 그가 왕의 명한 모든 말대로 대답하였으므로 일이 탄로치 아니하였고 그들은 더불어 말하기를 그쳤더라"},{"n":28,"t":"예레미야가 예루살렘이 함락되는 날까지 시위대 뜰에 머물렀더라"}],"kids":[{"n":1,"t":"맛단의 아들 스바댜와 바스훌의 아들 그다랴와 셀레먀의 아들 유갈과 말기야의 아들 바스훌이 예레미야가 모든 백성에게 하는 말을 들었어요. 그가 말하기를,"},{"n":2,"t":"\\"여호와께서 이렇게 말씀하셨어요. \'이 성에 머무는 자는 칼과 기근(굶주림)과 염병(전염병)에 죽을 거야. 그러나 갈대아 사람에게 항복하는 자는 살아남을 것이고, 그의 생명은 약탈물(노략물)을 얻은 것처럼 살게 될 거야.\'\\""},{"n":3,"t":"\\"\'나 여호와가 이렇게 말한다. 이 성이 반드시 바벨론 왕의 군대 손에 넘겨질 것이고, 그가 그것을 차지할 거야.\' 라고 말씀하셨다.\\""},{"n":4,"t":"그러자 그 높은 사람들이 왕에게 말했어요. \\"이 사람이 백성의 평안을 구하지 않고 해를 끼치니, 청하건대 이 사람을 죽이세요. 그가 이렇게 말해서 이 성에 남아 있는 군인들의 손과 모든 백성의 손을 약하게 만들고 있어요.\\""},{"n":5,"t":"시드기야 왕이 말했어요. \\"보아라, 그가 너희 손에 있다. 왕은 너희를 거스를 수 없다.\\""},{"n":6,"t":"그들이 예레미야를 잡아다가 시위대 뜰에 있는 왕의 아들 말기야의 구덩이에 던져 넣었어요. 그때 예레미야를 줄로 매달아 내려뜨렸는데, 그 구덩이에는 물이 없고 진흙뿐이어서 예레미야가 진흙 속에 빠졌어요."},{"n":7,"t":"왕궁의 환관 에티오피아 사람(구스인) 에벳멜렉이, 그들이 예레미야를 구덩이에 던져 넣은 일을 들었어요. 그때 왕은 베냐민 문에 앉아 있었어요."},{"n":8,"t":"에벳멜렉이 왕궁에서 나와 왕에게 말했어요."},{"n":9,"t":"\\"제 주 왕이여, 저 사람들이 선지자 예레미야에게 한 모든 일이 못된 짓이에요. 성 안에 떡이 떨어졌는데도 그를 구덩이에 던져 넣었으니, 그가 거기서 굶어 죽을 거예요.\\""},{"n":10,"t":"왕이 에티오피아 사람 에벳멜렉에게 명령했어요. \\"너는 여기서 30명을 데리고 가서, 선지자 예레미야가 죽기 전에 그를 구덩이에서 끌어내라.\\""},{"n":11,"t":"에벳멜렉이 사람들을 데리고 왕궁 창고(곳간) 아래의 방에 들어가서 거기서 헝겊과 낡은 옷을 가져와, 줄에 매달아 구덩이에 있는 예레미야에게 내려보냈어요."},{"n":12,"t":"에티오피아 사람 에벳멜렉이 예레미야에게 말했어요. \\"이 헝겊과 낡은 옷을 네 겨드랑이에 대고, 줄을 그 아래에 대.\\" 예레미야가 그대로 했어요."},{"n":13,"t":"그들이 줄로 예레미야를 구덩이에서 끌어냈고, 예레미야는 시위대 뜰에 머물렀어요."},{"n":14,"t":"시드기야 왕이 사람을 보내 선지자 예레미야를 여호와의 집(성전) 제3문으로 데려오게 하고, 왕이 예레미야에게 말했어요. \\"내가 너에게 한 가지를 물어보겠다. 한 마디도 내게 숨기지 마라.\\""},{"n":15,"t":"예레미야가 시드기야에게 말했어요. \\"제가 이 일을 왕께 알려드리면, 왕께서 정말로 저를 죽이지 않으시겠어요? 또 제가 왕께 좋은 말을 드려도 왕께서 듣지 않으실 거예요.\\""},{"n":16,"t":"시드기야 왕이 비밀스레 예레미야에게 맹세해 말했어요. \\"우리에게 이 영혼을 지으신 여호와께서 살아 계심을 두고 맹세한다. 내가 너를 죽이지도 않고, 네 목숨을 노리는 그 사람들의 손에 너를 넘겨주지도 않을 거야.\\""},{"n":17,"t":"예레미야가 시드기야에게 말했어요. \\"만군의 하나님이신 이스라엘의 하나님 여호와께서 이렇게 말씀하셨어요. \'네가 만일 바벨론 왕의 높은 사람들에게 항복하면, 네 목숨이 살 것이고 이 성이 불에 타지 않을 것이며, 너와 네 가족이 살게 될 거야.\'\\""},{"n":18,"t":"\\"\'그러나 네가 만일 나가서 바벨론 왕의 높은 사람들에게 항복하지 않으면, 이 성이 갈대아 사람의 손에 넘어갈 것이고, 그들이 이 성을 불태울 것이며, 너는 그들의 손에서 벗어나지 못할 거야.\'\\""},{"n":19,"t":"시드기야 왕이 예레미야에게 말했어요. \\"나는 갈대아 사람에게 이미 항복한 유다 사람들이 두려워. 갈대아 사람이 나를 그들의 손에 넘기면 그들이 나를 비웃을까봐 걱정돼.\\""},{"n":20,"t":"예레미야가 말했어요. \\"그들이 왕을 그들에게 넘기지 않을 거예요. 청하건대 제가 왕께 말씀드린 여호와의 목소리에 따라 행하세요. 그러면 왕께서 복을 받고 목숨을 살게 될 거예요.\\""},{"n":21,"t":"\\"그러나 만일 항복하기를 거절하시면, 여호와께서 제게 보여 주신 말씀대로 될 거예요.\\""},{"n":22,"t":"\\"곧 유다 왕궁에 남아 있는 모든 여자가 바벨론 왕의 높은 사람들에게 끌려갈 것이고, 그 여자들이 왕에게 이렇게 말할 거예요. \'왕의 친구들(원래 의지하던 사람들)이 왕을 꾀어 이기고, 왕의 발이 진흙에 빠진 것을 보고 도망갔구나.\'\\""},{"n":23,"t":"\\"또 왕의 아내들과 자녀들은 갈대아 사람에게 끌려갈 것이고, 왕은 그들의 손에서 벗어나지 못하고 바벨론 왕의 손에 잡힐 거예요. 또 왕 때문에 이 성이 불에 타게 될 거예요.\\""},{"n":24,"t":"시드기야가 예레미야에게 말했어요. \\"너는 이 말을 어느 누구에게도 알리지 마라. 그러면 네가 죽지 않을 거야.\\""},{"n":25,"t":"\\"만일 높은 사람들이 내가 너와 이야기한 것을 듣고 와서 너에게 ‘네가 왕에게 무슨 말을 했는지 우리에게 알려라. 우리에게 숨기지 마라. 그러면 우리가 너를 죽이지 않을 것이다. 또 왕이 너에게 무슨 말을 했는지도 알려라’라고 하면,\\""},{"n":26,"t":"\\"너는 그들에게 대답해라. ‘제가 왕 앞에 부탁드리기를, 저를 요나단의 집으로 다시 보내 거기서 죽지 않게 해 달라고 했어요’라고 하라.\\""},{"n":27,"t":"모든 높은 사람들이 예레미야에게 와서 물었고, 그가 왕이 명령한 모든 말대로 대답했으므로 일이 새어 나가지 않았고, 그들은 그와 더 이상 이야기하지 않았어요."},{"n":28,"t":"예레미야는 예루살렘이 함락되는(적에게 무너지는) 날까지 시위대 뜰에 머물러 있었어요."}]}},{"chapter":39,"title":"예루살렘의 함락","verses":{"krv":[{"n":1,"t":"유다 왕 시드기야의 구년 시월에 바벨론 왕 느부갓네살과 그 모든 군대가 와서 예루살렘을 에워싸고 치더니"},{"n":2,"t":"시드기야의 제십일년 사월 구일에 성이 함락되니라 예루살렘이 함락되매"},{"n":3,"t":"바벨론 왕의 모든 방백이 이르러 중문에 앉으니 곧 네르갈사레셀과 삼갈르보와 환관장 살스김과 박사장 네르갈사레셀과 바벨론 왕의 기타 모든 방백들이었더라"},{"n":4,"t":"유다 왕 시드기야와 모든 군사가 그들을 보고 도망하되 밤에 왕의 동산길로 좇아 두 담 샛문을 통하여 성읍을 벗어나서 아라바로 갔더니"},{"n":5,"t":"갈대아인의 군대가 그들을 따라 여리고 평원에서 시드기야에게 미쳐 그를 잡아서 데리고 하맛 땅 립나에 있는 바벨론 왕 느부갓네살에게로 올라가매 왕이 그를 심문하였더라"},{"n":6,"t":"바벨론 왕이 립나에서 시드기야의 목전에서 그 아들들을 죽였고 왕이 또 유다의 모든 귀인을 죽였으며"},{"n":7,"t":"왕이 또 시드기야의 눈을 빼게 하고 바벨론으로 옮기려 하여 사슬로 결박하였더라"},{"n":8,"t":"갈대아인들이 왕궁과 백성의 집을 불사르며 예루살렘 성벽을 헐었고"},{"n":9,"t":"시위대장 느부사라단이 성 중에 남아 있는 백성과 자기에게 항복한 자와 그 외의 남은 백성을 바벨론으로 잡아 옮겼으며"},{"n":10,"t":"시위대장 느부사라단이 아무 소유가 없는 빈민을 유다 땅에 남겨두고 그 날에 포도원과 밭을 그들에게 주었더라"},{"n":11,"t":"바벨론 왕 느부갓네살이 예레미야에 대하여 시위대장 느부사라단에게 명하여 가로되"},{"n":12,"t":"그를 데려다가 선대하고 해하지 말며 그가 네게 말하는 대로 행하라"},{"n":13,"t":"이에 시위대장 느부사라단과 환관장 느부사스반과 박사장 네르갈사레셀과 바벨론 왕의 모든 장관이"},{"n":14,"t":"보내어 예레미야를 시위대 뜰에서 취하여 내어 사반의 손자 아히감의 아들 그다랴에게 붙여서 그를 집으로 데려가게 하매 그가 백성 중에 거하니라"},{"n":15,"t":"예레미야가 시위대 뜰에 갇혔을 때에 여호와의 말씀이 그에게 임하니라 가라사대"},{"n":16,"t":"너는 가서 구스인 에벳멜렉에게 말하기를 만군의 여호와 이스라엘의 하나님의 말씀에 내가 이 성에 재앙을 내리고 복을 내리지 아니하리라 한 나의 말이 그 날에 네 목전에 이루리라"},{"n":17,"t":"나 여호와가 말하노라 내가 그 날에 너를 구원하리니 네가 그 두려워하는 사람들의 손에 붙이우지 아니하리라"},{"n":18,"t":"내가 단정코 너를 구원할 것인즉 네가 칼에 죽지 아니하고 네 생명이 노략물을 얻음 같이 되리니 이는 네가 나를 신뢰함이니라 여호와의 말이니라"}],"kids":[{"n":1,"t":"유다 왕 시드기야 9년 10월에 바벨론 왕 느부갓네살과 그의 모든 군대가 와서 예루살렘을 둘러싸고 쳤어요."},{"n":2,"t":"시드기야 11년 4월 9일에 그 성이 함락(적에게 무너짐)되었어요."},{"n":3,"t":"바벨론 왕의 모든 높은 사람들이 와서 가운데 문(중문)에 앉았는데, 곧 네르갈사레셀과 삼갈르보와 환관장(환관의 우두머리) 살스김과 박사장(박사들의 우두머리) 네르갈사레셀과 바벨론 왕의 다른 모든 높은 사람들이었어요."},{"n":4,"t":"유다 왕 시드기야와 모든 군인들이 그들을 보고 도망쳤어요. 밤에 왕의 동산 길을 따라 두 담 사이의 작은 문을 통해 성을 빠져나가 아라바(요단 강 평지)로 갔어요."},{"n":5,"t":"갈대아 사람의 군대가 그들을 쫓아가서 여리고 평원에서 시드기야를 따라잡아 잡았어요. 그를 끌고 하맛 땅 립나에 있는 바벨론 왕 느부갓네살에게 데리고 갔어요. 왕이 그를 심문(질문)했어요."},{"n":6,"t":"바벨론 왕이 립나에서 시드기야가 보는 앞에서 그의 아들들을 죽였고, 또 유다의 모든 귀한 사람들도 죽였어요."},{"n":7,"t":"왕이 또 시드기야의 눈을 빼게 하고, 바벨론으로 끌고 가려고 그를 사슬(쇠줄)로 묶었어요."},{"n":8,"t":"갈대아 사람들이 왕궁과 백성의 집을 불태웠고, 예루살렘 성벽을 무너뜨렸어요."},{"n":9,"t":"시위대장(왕의 호위대 우두머리) 느부사라단이 성 안에 남아 있는 백성과 자기에게 항복한 자들과 그 외에 남은 백성을 바벨론으로 잡아갔어요."},{"n":10,"t":"시위대장 느부사라단이 아무것도 가지지 못한 가난한 사람들(빈민)은 유다 땅에 남겨 두고, 그날에 포도원과 밭을 그들에게 주었어요."},{"n":11,"t":"바벨론 왕 느부갓네살이 예레미야에 대해 시위대장 느부사라단에게 명령했어요."},{"n":12,"t":"\\"그를 데려다가 잘 대해 주고 해치지 말며, 그가 네게 말하는 대로 해 주어라.\\""},{"n":13,"t":"그래서 시위대장 느부사라단과 환관장 느부사스반과 박사장 네르갈사레셀과 바벨론 왕의 모든 장관들이"},{"n":14,"t":"사람을 보내 예레미야를 시위대 뜰에서 데리고 와, 사반의 손자이며 아히감의 아들인 그다랴에게 맡겨 그를 집으로 데려가게 했어요. 그래서 예레미야는 백성 가운데서 살게 되었어요."},{"n":15,"t":"예레미야가 시위대 뜰에 갇혀 있을 때 여호와의 말씀이 그에게 들려왔어요."},{"n":16,"t":"\\"너는 가서 에티오피아 사람(구스인) 에벳멜렉에게 말해라. \'만군의 여호와 이스라엘의 하나님이 이렇게 말씀하셨다. 내가 이 성에 재앙을 내리고 복을 내리지 않을 거라고 한 내 말이 그날에 네 눈앞에서 이루어질 거야.\'\\""},{"n":17,"t":"\\"\'나 여호와가 말한다. 내가 그날에 너를 구원할 것이고, 네가 두려워하는 사람들의 손에 넘겨지지 않을 거야.\'\\""},{"n":18,"t":"\\"\'내가 정말로 너를 구원할 것이니, 네가 칼에 죽지 않고 네 목숨이 약탈물(노략물)을 얻은 것처럼 살게 될 거야. 이는 네가 나를 신뢰했기 때문이야. 이것은 여호와의 말이야.\'\\""}]}},{"chapter":40,"title":"그달리야의 죽음","verses":{"krv":[{"n":1,"t":"시위대장 느부사라단이 예루살렘과 유다 포로를 바벨론으로 옮기는 중에 예레미야도 잡혀 사슬로 결박되어 가다가 라마에서 해방된 후에 말씀이 여호와께로서 예레미야에게 임하니라"},{"n":2,"t":"시위대장이 예레미야를 불러다가 이르되 네 하나님 여호와께서 이곳에 재앙을 선포하시더니"},{"n":3,"t":"여호와께서 그 말씀하신 대로 행하셨으니 이는 너희가 여호와께 범죄하고 그 목소리를 청종치 아니하였으므로 이 일이 너희에게 임한 것이니라"},{"n":4,"t":"보라 내가 오늘 네 손의 사슬을 풀어 너를 해방하노니 만일 네가 나와 함께 바벨론으로 가는 것을 선히 여기거든 오라 내가 너를 선대하리라 만일 나와 함께 바벨론으로 가는 것을 좋지 않게 여기거든 그만 두라 보라 온 땅이 네 앞에 있나니 네가 선히 여기는 대로 가하게 여기는 곳으로 갈지니라"},{"n":5,"t":"예레미야가 아직 돌이키기 전에 그가 다시 이르되 너는 바벨론 왕이 유다 성읍들의 총독으로 세우신 사반의 손자 아히감의 아들 그다랴에게로 돌아가서 그와 함께 백성 중에 거하거나 너의 가하게 여기는 곳으로 가거나 할지니라 하고 그 시위대장이 그에게 양식과 선물을 주어 보내매"},{"n":6,"t":"예레미야가 미스바로 가서 아히감의 아들 그다랴에게로 나아가서 그 땅에 남아 있는 백성 중에서 그와 함께 거하니라"},{"n":7,"t":"들에 있는 군대장관들과 그들의 사람들이 바벨론 왕이 아히감의 아들 그다랴를 이 땅 총독으로 세우고 남녀와 유아와 바벨론으로 옮기지 아니한 빈민을 그에게 위임하였다 함을 듣고"},{"n":8,"t":"그들 곧 느다냐의 아들 이스마엘과 가레아의 두 아들 요하난과 요나단과 단후멧의 아들 스라야와 느도바 사람 에배의 아들들과 마아가 사람의 아들 여사냐와 그들의 사람들이 미스바로 가서 그다랴에게 이르니"},{"n":9,"t":"사반의 손자 아히감의 아들 그다랴가 그들과 그들의 사람들에게 맹세하며 가로되 너희는 갈대아인 섬기기를 두려워하지 말고 이 땅에 거하여 바벨론 왕을 섬기라 그리하면 너희에게 유익하리라"},{"n":10,"t":"나는 미스바에 거하여 우리에게로 오는 갈대아인을 섬기리니 너희는 포도주와 여름 실과와 기름을 모아 그릇에 저축하고 너희의 얻은 성읍들에 거하라 하니라"},{"n":11,"t":"모압과 암몬 자손 중과 에돔과 모든 지방에 있는 유다인도 바벨론 왕이 유다에 사람을 남겨 둔 것과 사반의 손자 아히감의 아들 그다랴를 그들의 위에 세웠다 함을 듣고"},{"n":12,"t":"그 모든 유다인이 쫓겨났던 각처에서 돌아와 유다 땅 미스바 그다랴에게 이르러 포도주와 여름 실과를 심히 많이 모으니라"},{"n":13,"t":"가레아의 아들 요하난과 들에 있던 군대장관들이 미스바 그다랴에게 이르러"},{"n":14,"t":"그에게 이르되 암몬 자손의 왕 바알리스가 네 생명을 취하려 하여 느다냐의 아들 이스마엘을 보낸 줄 네가 아느냐 하되 아히감의 아들 그다랴가 믿지 아니한지라"},{"n":15,"t":"가레아의 아들 요하난이 미스바에서 그다랴에게 비밀히 말하여 가로되 청하노니 나로 가서 사람이 모르게 느다냐의 아들 이스마엘을 죽이게 하라 어찌하여 그로 네 생명을 취케 하여 네게 모인 모든 유다인으로 흩어지며 유다의 남은 자로 멸망을 당케 하랴"},{"n":16,"t":"그러나 아히감의 아들 그다랴가 가레아의 아들 요하난에게 이르되 네가 이 일을 행치 말 것이니라 너의 이스마엘에 대한 말은 진정이 아니니라 하니라"}],"kids":[{"n":1,"t":"시위대장 느부사라단이 예루살렘과 유다의 포로들을 바벨론으로 끌고 갈 때, 예레미야도 잡혀서 사슬로 묶여 가다가 라마에서 풀려난 후에, 여호와로부터 말씀이 예레미야에게 들려왔어요."},{"n":2,"t":"시위대장이 예레미야를 불러다가 말했어요. \\"너의 하나님 여호와께서 이곳에 재앙을 내리겠다고 선포하셨고,\\""},{"n":3,"t":"\\"여호와께서 그 말씀하신 대로 행하셨다. 이는 너희가 여호와께 죄를 짓고 그분의 목소리를 듣지 않았기 때문에 이 일이 너희에게 닥친 거야.\\""},{"n":4,"t":"\\"보아라, 내가 오늘 네 손의 사슬을 풀어 너를 자유롭게 해 주겠다. 만일 네가 나와 함께 바벨론으로 가는 것이 좋다면 가자. 내가 너를 잘 대해 주겠다. 만일 나와 함께 바벨론으로 가는 것이 좋지 않다면 가지 마라. 보아라, 온 땅이 네 앞에 있으니 네가 좋다고 여기는 곳, 옳다고 여기는 곳으로 가라.\\""},{"n":5,"t":"예레미야가 아직 돌아가기 전에 그가 다시 말했어요. \\"너는 바벨론 왕이 유다 성들의 총독(다스리는 사람)으로 세우신 사반의 손자 아히감의 아들 그다랴에게 돌아가서 그와 함께 백성 가운데 머물거나, 네가 옳다고 여기는 곳으로 가도 된다.\\" 그러면서 시위대장이 예레미야에게 양식과 선물을 주어 보냈어요."},{"n":6,"t":"예레미야가 미스바로 가서 아히감의 아들 그다랴에게 갔고, 그 땅에 남아 있는 백성 가운데 그와 함께 살았어요."},{"n":7,"t":"들에 있는 군대장관(군대 우두머리)들과 그들의 부하들이, 바벨론 왕이 아히감의 아들 그다랴를 그 땅의 총독으로 세웠고 남녀와 어린아이(유아)와 바벨론으로 끌려가지 않은 가난한 사람들을 그에게 맡겼다는 소식을 들었어요."},{"n":8,"t":"그들, 곧 느다냐의 아들 이스마엘과 가레아의 두 아들 요하난과 요나단, 단후멧의 아들 스라야, 느도바 사람 에배의 아들들, 마아가 사람의 아들 여사냐와 그들의 부하들이 미스바로 가서 그다랴에게 갔어요."},{"n":9,"t":"사반의 손자 아히감의 아들 그다랴가 그들과 그들의 부하들에게 맹세하며 말했어요. \\"여러분은 갈대아 사람을 섬기는 것을 두려워하지 말고, 이 땅에 살면서 바벨론 왕을 섬기세요. 그러면 여러분에게 좋을 거예요.\\""},{"n":10,"t":"\\"저는 미스바에 살면서 우리에게 오는 갈대아 사람을 섬기겠어요. 여러분은 포도주와 여름 과일과 기름을 모아 그릇에 담아 두고, 여러분이 얻은 성에 머무세요.\\""},{"n":11,"t":"모압과 암몬 자손 중에 있는 사람들과 에돔과 모든 지방에 있는 유다 사람들도, 바벨론 왕이 유다에 사람을 남겨 두고 사반의 손자 아히감의 아들 그다랴를 그들 위에 세웠다는 소식을 들었어요."},{"n":12,"t":"그래서 모든 유다 사람이 쫓겨갔던 각처에서 돌아와 유다 땅 미스바의 그다랴에게 이르러 포도주와 여름 과일을 매우 많이 모았어요."},{"n":13,"t":"가레아의 아들 요하난과 들에 있던 군대장관들이 미스바의 그다랴에게 와서"},{"n":14,"t":"그에게 말했어요. \\"암몬 자손의 왕 바알리스가 당신의 목숨을 빼앗으려고 느다냐의 아들 이스마엘을 보낸 것을 당신이 알고 있어요?\\" 그러나 아히감의 아들 그다랴는 그 말을 믿지 않았어요."},{"n":15,"t":"가레아의 아들 요하난이 미스바에서 그다랴에게 비밀스레 말했어요. \\"청하건대 제가 가서 아무도 모르게 느다냐의 아들 이스마엘을 죽이게 해 주세요. 어찌하여 그가 당신의 목숨을 빼앗아서, 당신에게 모인 모든 유다 사람들이 흩어지고 유다의 남은 자들이 멸망당하게 하시려고 하나요?\\""},{"n":16,"t":"그러나 아히감의 아들 그다랴가 가레아의 아들 요하난에게 말했어요. \\"너는 그렇게 하지 마라. 네가 이스마엘에 대해 한 말은 사실이 아니다.\\""}]}},{"chapter":41,"title":"이스마엘의 살인","verses":{"krv":[{"n":1,"t":"칠월에 왕의 종친 엘리사마의 손자 느다냐의 아들 왕의 장관 이스마엘이 열 사람과 함께 미스바로 가서 아히감의 아들 그다랴에게 이르러 미스바에서 함께 떡을 먹다가"},{"n":2,"t":"느다냐의 아들 이스마엘과 그와 함께 한 열 사람이 일어나서 바벨론 왕의 그 땅 총독으로 세운 바 사반의 손자 아히감의 아들 그다랴를 칼로 쳐죽였고"},{"n":3,"t":"이스마엘이 또 미스바에서 그다랴와 함께한 모든 유다인과 거기 있는 갈대아 군사를 죽였더라"},{"n":4,"t":"그가 그다랴를 죽인 지 이틀이 되었어도 이를 아는 사람이 없었더라"},{"n":5,"t":"때에 사람 팔십 명이 그 수염을 깎고 옷을 찢고 몸을 상하고 손에 소제물과 유향을 가지고 세겜과 실로와 사마리아에서부터 와서 여호와의 집으로 나아가려 한지라"},{"n":6,"t":"느다냐의 아들 이스마엘이 그들을 영접하러 미스바에서 나와서 울며 행하다가 그들을 만나 아히감의 아들 그다랴에게로 가자 하여"},{"n":7,"t":"그들이 성 중앙에 이를 때에 느다냐의 아들 이스마엘이 자기와 함께 한 사람들로 더불어 그들을 죽여 구덩이에 던지니라"},{"n":8,"t":"그 중에 열 사람은 이스마엘에게 이르기를 우리가 밀과 보리와 기름과 꿀을 밭에 감추었으니 우리를 죽이지 말라 하였으므로 그가 그치고 그들을 그 형제와 함께 죽이지 아니하였더라"},{"n":9,"t":"이스마엘이 그다랴에게 속한 사람들을 죽이고 그 시체를 던진 구덩이는 아사 왕이 이스라엘 왕 바아사를 두려워하여 팠던 것이라 느다냐의 아들 이스마엘이 그 죽인 시체로 거기 채우고"},{"n":10,"t":"미스바에 남아 있는 왕의 딸들과 모든 백성 곧 시위대장 느부사라단이 아히감의 아들 그다랴에게 위임하였던 바 미스바에 남아 있는 모든 백성을 사로잡되 곧 느다냐의 아들 이스마엘이 그들을 사로잡고 암몬 자손에게로 가려 하여 떠나니라"},{"n":11,"t":"가레아의 아들 요하난과 그와 함께 있는 모든 군대장관이 느다냐의 아들 이스마엘의 행한 모든 악을 듣고"},{"n":12,"t":"모든 사람을 데리고 느다냐의 아들 이스마엘과 싸우러 가다가 기브온 큰 물가에서 그를 만나매"},{"n":13,"t":"이스마엘과 함께 있던 모든 백성이 가레아의 아들 요하난과 그와 함께 한 모든 군대장관을 보고 기뻐한지라"},{"n":14,"t":"이에 미스바에서 이스마엘에게 포로되었던 그 모든 백성이 돌이켜 가레아의 아들 요하난에게로 돌아가니"},{"n":15,"t":"느다냐의 아들 이스마엘이 여덟 사람과 함께 요하난을 피하여 암몬 자손에게로 가니라"},{"n":16,"t":"가레아의 아들 요하난과 그와 함께하는 모든 군대장관이 느다냐의 아들 이스마엘이 아히감의 아들 그다랴를 죽이고 미스바에서 잡아간 모든 남은 백성 곧 군사와 여인과 유아와 환관을 기브온에서 빼앗아 가지고 돌아와서"},{"n":17,"t":"애굽으로 가려 하여 떠나 베들레헴 근처에 있는 게롯김함에 머무렀으니"},{"n":18,"t":"이는 느다냐의 아들 이스마엘이 바벨론 왕의 그 땅 총독으로 세운 아히감의 아들 그다랴을 죽였으므로 그들이 갈대아인을 두려워함이었더라"}],"kids":[{"n":1,"t":"7월에 왕의 친척이며 엘리사마의 손자이고 느다냐의 아들이며 왕의 장관인 이스마엘이 열 사람과 함께 미스바로 가서 아히감의 아들 그다랴에게 갔어요. 그들이 미스바에서 함께 떡(빵)을 먹다가,"},{"n":2,"t":"느다냐의 아들 이스마엘과 그와 함께 있던 열 사람이 일어나서 바벨론 왕이 그 땅의 총독(다스리는 사람)으로 세운, 사반의 손자 아히감의 아들 그다랴를 칼로 쳐서 죽였어요."},{"n":3,"t":"이스마엘이 또 미스바에서 그다랴와 함께 있던 모든 유다 사람과 거기 있던 갈대아 군인을 다 죽였어요."},{"n":4,"t":"그가 그다랴를 죽인 지 이틀이 지났는데도 이를 아는 사람이 아무도 없었어요."},{"n":5,"t":"그때 사람 80명이 수염을 깎고 옷을 찢고 몸을 다치게 한 채(슬픔의 표시), 손에 소제물(곡식 제물)과 유향(좋은 향)을 가지고 세겜과 실로와 사마리아에서부터 와서 여호와의 집으로 가려고 했어요."},{"n":6,"t":"느다냐의 아들 이스마엘이 그들을 맞으러 미스바에서 나와 울며 가다가, 그들을 만나서 \\"아히감의 아들 그다랴에게로 가자\\"라고 말했어요."},{"n":7,"t":"그들이 성 한가운데에 이르렀을 때, 느다냐의 아들 이스마엘이 자기와 함께 있는 사람들과 함께 그들을 죽이고 구덩이에 던졌어요."},{"n":8,"t":"그러나 그 가운데 열 사람은 이스마엘에게 말했어요. \\"우리가 밀과 보리와 기름과 꿀을 밭에 감춰 놓았으니, 우리를 죽이지 마세요.\\" 그래서 이스마엘이 멈추고 그들을 그 형제들과 함께 죽이지 않았어요."},{"n":9,"t":"이스마엘이 그다랴에게 속한 사람들을 죽이고 그 시체를 던진 구덩이는 옛날 아사 왕이 이스라엘 왕 바아사를 무서워해서 팠던 것이었어요. 느다냐의 아들 이스마엘이 그 죽인 시체로 거기를 채웠어요."},{"n":10,"t":"이스마엘이 미스바에 남아 있는 왕의 딸들과 모든 백성, 곧 시위대장 느부사라단이 아히감의 아들 그다랴에게 맡긴 미스바에 남아 있는 모든 백성을 사로잡아, 암몬 자손에게로 가려고 떠났어요."},{"n":11,"t":"가레아의 아들 요하난과 그와 함께 있는 모든 군대장관(군대 우두머리)들이 느다냐의 아들 이스마엘이 한 모든 못된 짓을 들었어요."},{"n":12,"t":"그래서 모든 사람을 데리고 느다냐의 아들 이스마엘과 싸우러 가다가, 기브온 큰 못가에서 그를 만났어요."},{"n":13,"t":"이스마엘과 함께 있던 모든 백성이 가레아의 아들 요하난과 그와 함께 있는 모든 군대장관들을 보고 기뻐했어요."},{"n":14,"t":"그래서 미스바에서 이스마엘에게 사로잡혀 갔던 모든 백성이 돌이켜 가레아의 아들 요하난에게로 돌아갔어요."},{"n":15,"t":"느다냐의 아들 이스마엘은 여덟 사람과 함께 요하난을 피해 암몬 자손에게로 갔어요."},{"n":16,"t":"가레아의 아들 요하난과 그와 함께 있는 모든 군대장관들이, 느다냐의 아들 이스마엘이 아히감의 아들 그다랴를 죽이고 미스바에서 잡아간 모든 남은 백성, 곧 군인들과 여인들과 어린아이(유아)와 환관들을 기브온에서 다시 빼앗아 와서,"},{"n":17,"t":"애굽으로 가려고 떠나, 베들레헴 가까이에 있는 게롯김함에 머물렀어요."},{"n":18,"t":"이는 느다냐의 아들 이스마엘이 바벨론 왕이 그 땅의 총독으로 세운 아히감의 아들 그다랴를 죽였기 때문에, 그들이 갈대아 사람들을 무서워했기 때문이에요."}]}},{"chapter":42,"title":"애굽으로 가지 말라","verses":{"krv":[{"n":1,"t":"이에 모든 군대의 장관과 가레아의 아들 요하난과 호사야의 아들 여사냐와 백성의 작은 자로부터 큰 자까지 다 나아와"},{"n":2,"t":"선지가 예레미야에게 이르되 당신은 우리의 간구를 들으시고 이 남아 있는 모든 자를 위하여 당신의 하나님 여호와께 기도하소서 당신이 목도하시거니와 우리는 많은 중에서 조금만 남았사오니"},{"n":3,"t":"당신의 하나님 여호와께서 우리의 마땅히 갈 길과 할 일을 보이시기를 원하나이다"},{"n":4,"t":"선지자 예레미야가 그들에게 이르되 내가 너희 말을 들었은즉 너희 말대로 너희 하나님 여호와께 기도하고 무릇 여호와께서 너희에게 응답하시는 것을 숨김이 없이 너희에게 고하리라"},{"n":5,"t":"그들이 예레미야에게 이르되 우리가 당신의 하나님 여호와께서 당신을 보내사 우리에게 이르시는 모든 말씀대로 행하리이다 여호와는 우리 중에 진실 무망한 증인이 되시옵소서"},{"n":6,"t":"우리가 당신을 우리 하나님 여호와께 보냄은 그의 목소리가 우리에게 좋고 좋지 아니함을 물론하고 청종하려 함이라 우리가 우리 하나님 여호와의 목소리를 청종하면 우리에게 복이 있으리이다"},{"n":7,"t":"십 일 후에 여호와의 말씀이 예레미야에게 임하니"},{"n":8,"t":"그가 가레아의 아들 요하난과 그와 함께 있는 모든 군대장관과 백성의 작은 자로부터 큰 자까지 다 부르고"},{"n":9,"t":"그들에게 이르되 너희가 나를 보내어 너희의 간구를 이스라엘의 하나님 여호와께 드리게 하지 아니하였느냐 그가 가라사대"},{"n":10,"t":"너희가 이 땅에 여전히 거하면 내가 너희를 세우고 헐지 아니하며 너희를 심고 뽑지 아니하리니 이는 내가 너희에게 내린 재앙에 대하여 뜻을 돌이킴이니라"},{"n":11,"t":"나 여호와가 말하노라 너희는 그 두려워하는 바벨론 왕을 두려워 말라 내가 너희와 함께 하여 너희를 구원하며 그의 손에서 너희를 건지리니 두려워 말라"},{"n":12,"t":"내가 너희를 긍휼히 여기리니 그로도 너희를 긍휼히 여기게 하여 너희를 너희 본향으로 돌려 보내게 하리라 하셨느니라"},{"n":13,"t":"그러나 만일 너희가 너희 하나님 여호와의 말씀을 순복지 아니하고 말하기를 우리는 이 땅에 거하지 아니하리라 하며"},{"n":14,"t":"또 말하기를 우리는 전쟁도 보이지 아니하며 나팔소리도 들리지 아니하며 식물의 핍절도 당치 아니하는 애굽 땅으로 결단코 들어가 거하리라 하면 잘못되리라"},{"n":15,"t":"너희 유다의 남은 자여 이제 여호와의 말씀을 들으라 만군의 여호와 이스라엘의 하나님이 이같이 말씀하시되 너희가 만일 애굽에 들어가서 거기 거하기로 고집하면"},{"n":16,"t":"너희의 두려워하는 칼이 애굽 땅으로 따라가서 너희에게 미칠 것이요 너희의 두려워하는 기근이 애굽으로 급히 따라가서 너희에게 임하리니 너희가 거기서 죽을 것이라"},{"n":17,"t":"무릇 애굽으로 들어가서 거기 우거하기로 고집하는 모든 사람은 이같이 되리니 곧 칼과 기근과 염병에 죽을 것인즉 내가 그들에게 내리는 재앙을 벗어나서 남을 자 없으리라"},{"n":18,"t":"만군의 여호와 이스라엘의 하나님이 이같이 말씀하시되 나의 노와 분을 예루살렘 거민에게 부은 것 같이 너희가 애굽에 이른 때에 나의 분을 너희에게 부으리니 너희가 가증함과 놀램과 저주와 치욕거리가 될 것이라 너희가 다시는 이 땅을 보지 못하리라 하시도다"},{"n":19,"t":"유다의 남은 자들아 여호와께서 너희 일로 하신 말씀에 너희는 애굽으로 가지 말라 하셨고 나도 오늘날 너희에게 경계한 것을 너희는 분명히 알라"},{"n":20,"t":"너희가 나를 너희 하나님 여호와께 보내며 이르기를 우리를 위하여 우리 하나님 여호와께 기도하고 우리 하나님 여호와께서 말씀하신 대로 우리에게 고하라 우리가 이를 행하리라 하여 너희 마음을 속였느니라"},{"n":21,"t":"너희 하나님 여호와께서 나를 보내사 너희에게 명하신 말씀을 내가 오늘날 너희에게 고하였어도 너희가 그 목소리를 도무지 순종치 아니하였은즉"},{"n":22,"t":"너희가 가서 우거하려 하는 곳에서 칼과 기근과 염병에 죽을줄 분명히 알지니라"}],"kids":[{"n":1,"t":"그때 모든 군대장관들과 가레아의 아들 요하난과 호사야의 아들 여사냐와 백성의 작은 자부터 큰 자까지 모두 나아와,"},{"n":2,"t":"선지자 예레미야에게 말했어요. \\"당신은 우리의 부탁(간구)을 들으시고 남아 있는 이 모든 사람을 위해 당신의 하나님 여호와께 기도해 주세요. 당신이 보시다시피, 우리는 많은 중에서 조금만 남았어요.\\""},{"n":3,"t":"\\"당신의 하나님 여호와께서 우리가 가야 할 길과 해야 할 일을 보여 주시기를 원해요.\\""},{"n":4,"t":"선지자 예레미야가 그들에게 말했어요. \\"내가 여러분의 말을 들었어요. 여러분 말대로 여러분 하나님 여호와께 기도하고, 여호와께서 여러분에게 응답하시는 것을 모두 숨김없이 알려 드릴게요.\\""},{"n":5,"t":"그들이 예레미야에게 말했어요. \\"우리는 당신 하나님 여호와께서 당신을 보내셔서 우리에게 하시는 모든 말씀대로 행하겠어요. 여호와께서는 우리 가운데서 진실하고 흔들림 없는 증인이 되어 주세요.\\""},{"n":6,"t":"\\"우리가 당신을 우리 하나님 여호와께 보내는 것은, 그분의 목소리가 좋든 좋지 않든 따르려고 하는 거예요. 우리가 우리 하나님 여호와의 목소리를 따르면 우리에게 복이 있을 거예요.\\""},{"n":7,"t":"열흘 후에 여호와의 말씀이 예레미야에게 들려왔어요."},{"n":8,"t":"그가 가레아의 아들 요하난과 그와 함께 있는 모든 군대장관들과 백성의 작은 자부터 큰 자까지 모두 불러 모았어요."},{"n":9,"t":"그들에게 말했어요. \\"여러분이 저를 보내어 여러분의 부탁을 이스라엘의 하나님 여호와께 드리게 하지 않았나요? 그분이 이렇게 말씀하셨어요.\\""},{"n":10,"t":"\\"\'너희가 이 땅에 그대로 살면, 내가 너희를 세우고 헐지 않으며, 너희를 심고 뽑지 않을 것이야. 이는 내가 너희에게 내린 재앙에 대해 마음을 돌이킬 것이기 때문이야.\'\\""},{"n":11,"t":"\\"\'나 여호와가 말한다. 너희가 두려워하는 바벨론 왕을 무서워하지 마라. 내가 너희와 함께해서 너희를 구원하고 그의 손에서 너희를 건질 것이니 무서워하지 마라.\'\\""},{"n":12,"t":"\\"\'내가 너희를 불쌍히 여길 것이고, 그(바벨론 왕)도 너희를 불쌍히 여기게 해서 너희를 너희 고향으로 돌려보내게 할 거야.\'\\""},{"n":13,"t":"\\"그러나 만일 여러분이 여러분 하나님 여호와의 말씀에 따르지 않고 ‘우리는 이 땅에 살지 않을 거예요’ 하며,\\""},{"n":14,"t":"\\"또 ‘우리는 전쟁도 보지 않고 나팔 소리도 들리지 않으며 양식이 부족한 일도 없는 애굽 땅으로 들어가 살겠어요’라고 한다면 잘못된 거예요.\\""},{"n":15,"t":"\\"유다의 남은 자들아, 이제 여호와의 말씀을 들어라. 만군의 여호와 이스라엘의 하나님이 이렇게 말씀하셨다. \'너희가 만일 애굽에 들어가 거기에 머물기로 고집하면,\\""},{"n":16,"t":"\\"\'너희가 두려워하는 칼이 애굽 땅까지 따라가서 너희에게 닥칠 것이고, 너희가 두려워하는 기근이 애굽으로 급히 따라가서 너희에게 임할 것이며, 너희가 거기서 죽게 될 거야.\'\\""},{"n":17,"t":"\\"\'애굽으로 들어가서 거기에 머물기로 고집하는 모든 사람은 이렇게 될 거야. 곧 칼과 기근과 염병에 죽을 것이고, 내가 그들에게 내리는 재앙에서 벗어나 살아남을 자가 없을 거야.\'\\""},{"n":18,"t":"\\"만군의 여호와 이스라엘의 하나님이 이렇게 말씀하셨다. \'내 분노와 화를 예루살렘에 사는 사람들에게 부은 것처럼, 너희가 애굽에 이를 때 내 분노를 너희에게 부을 거야. 너희가 미운(가증한) 것과 놀람과 저주와 부끄러움(치욕)거리가 될 것이고, 너희가 다시는 이 땅을 보지 못할 거야.\'\\""},{"n":19,"t":"\\"유다의 남은 자들아, 여호와께서 너희 일에 대해 말씀하시기를 ‘너희는 애굽으로 가지 마라’라고 하셨고, 나도 오늘 너희에게 경고했음을 분명히 알아라.\\""},{"n":20,"t":"\\"여러분이 저를 여러분 하나님 여호와께 보내면서 ‘우리를 위해 우리 하나님 여호와께 기도하고, 우리 하나님 여호와께서 말씀하신 대로 우리에게 알려 주세요. 그러면 우리가 그것을 행하겠어요’라고 해서 여러분 마음을 속였어요.\\""},{"n":21,"t":"\\"여러분 하나님 여호와께서 저를 보내셔서 여러분에게 명하신 말씀을 제가 오늘 알려드렸는데도, 여러분이 그 목소리에 전혀 따르지 않았어요.\\""},{"n":22,"t":"\\"그러므로 여러분이 가서 살려고 하는 그곳에서 칼과 기근과 염병에 죽을 것을 분명히 알아 두세요.\\""}]}},{"chapter":43,"title":"애굽에 내려간 백성","verses":{"krv":[{"n":1,"t":"예레미야가 모든 백성에게 그들의 하나님 여호와의 말씀 곧 그들의 하나님 여호와께서 자기를 보내사 그들에게 이르게 하신 이 모든 말씀을 다 말하매"},{"n":2,"t":"호사야의 아들 아사랴와 가레아의 아들 요하난과 및 모든 교만한 자가 예레미야에게 말하여 가로되 네가 거짓을 말하는도다 우리 하나님 여호와께서는 너희는 애굽에 거하려고 그리로 가지 말라고 너를 보내어 말하게 하지 아니하셨느니라"},{"n":3,"t":"이는 네리야의 아들 바룩이 너를 꼬드겨서 우리를 대적하여 갈대아인의 손에 붙여 죽이며 바벨론으로 잡아가게 하려 함이니라 하고"},{"n":4,"t":"이에 가레아의 아들 요하난과 모든 군대 장관과 모든 백성이 유다 땅에 거하라 하시는 여호와의 목소리를 청종치 아니하고"},{"n":5,"t":"가레아의 아들 요하난과 모든 군대장관이 유다의 남은 자 곧 쫓겨났던 열방 중에서 유다 땅에 거하려하여 돌아온 자"},{"n":6,"t":"곧 남자와 여자와 유아와 왕의 딸들과 시위대장 느부사라단이 사반의 손자 아히감의 아들 그다랴에게 넘겨 둔 모든 사람과 선지자 예레미야와 네리야의 아들 바룩을 영솔하고"},{"n":7,"t":"애굽 땅에 들어가 다바네스에 이르렀으니 그들이 여호와의 목소리를 청종치 아니함이 이러하였더라"},{"n":8,"t":"다바네스에서 여호와의 말씀이 예레미야에게 임하여 가라사대"},{"n":9,"t":"너는 유다 사람의 목전에서 네 손으로 큰 돌들을 가져다가 다바네스 바로의 집 어귀의 벽돌 깔린 곳에 진흙으로 감추고"},{"n":10,"t":"그들에게 이르기를 만군의 여호와 이스라엘의 하나님이 이같이 말씀하시되 보라 내가 내 종 바벨론 왕 느부갓네살을 불러오리니 그가 그 보좌를 내가 감추게 한 이 돌 위에 두고 또 그 화려한 장막을 그 위에 치리라"},{"n":11,"t":"그가 와서 애굽 땅을 치고 죽일 자는 죽이고 사로잡을 자는 사로잡고 칼로 칠 자는 칼로 칠 것이라"},{"n":12,"t":"내가 애굽 신들의 집에 불을 놓을 것인즉 느부갓네살이 그들을 불사르며 그들을 사로잡을 것이요 목자가 그 몸에 옷을 두름 같이 애굽 땅을 자기 몸에 두르고 평안히 그곳을 떠날 것이며"},{"n":13,"t":"그가 또 애굽 땅 벧세메스의 주상들을 깨뜨리고 애굽 신들의 집을 불사르리라 하셨다 할지니라"}],"kids":[{"n":1,"t":"예레미야가 모든 백성에게 그들의 하나님 여호와의 말씀, 곧 그들의 하나님 여호와께서 자기를 보내셔서 그들에게 전하라고 하신 이 모든 말씀을 다 전했어요."},{"n":2,"t":"그러자 호사야의 아들 아사랴와 가레아의 아들 요하난과 모든 교만한 자들이 예레미야에게 말했어요. \\"네가 거짓말을 하고 있어. 우리 하나님 여호와께서 ‘너희는 애굽에 살러 가지 마라’라고 너를 보내 말하게 하지 않으셨어.\\""},{"n":3,"t":"\\"이는 네리야의 아들 바룩이 너를 꼬드겨서, 우리를 갈대아 사람의 손에 넘겨 죽이거나 바벨론으로 끌고 가게 하려고 하는 것이야.\\""},{"n":4,"t":"그래서 가레아의 아들 요하난과 모든 군대장관과 모든 백성이 \\"유다 땅에 머물라\\"고 하시는 여호와의 목소리에 따르지 않았어요."},{"n":5,"t":"가레아의 아들 요하난과 모든 군대장관이 유다의 남은 자, 곧 쫓겨났던 모든 나라에서 유다 땅에 살려고 돌아온 자들,"},{"n":6,"t":"곧 남자와 여자와 어린아이(유아)와 왕의 딸들과, 시위대장 느부사라단이 사반의 손자 아히감의 아들 그다랴에게 맡겨 둔 모든 사람과 선지자 예레미야와 네리야의 아들 바룩을 데리고,"},{"n":7,"t":"애굽 땅에 들어가 다바네스에 이르렀어요. 그들이 여호와의 목소리에 따르지 않은 것이 이렇게 된 거예요."},{"n":8,"t":"다바네스에서 여호와의 말씀이 예레미야에게 들려왔어요."},{"n":9,"t":"\\"너는 유다 사람들이 보는 앞에서 네 손으로 큰 돌들을 가져다가, 다바네스 바로(애굽 왕)의 집 입구의 벽돌 깔린 곳에 진흙으로 묻어 감춰 두어라.\\""},{"n":10,"t":"\\"그리고 그들에게 말해라. \'만군의 여호와 이스라엘의 하나님이 이렇게 말씀하셨다. 보아라, 내가 내 종 바벨론 왕 느부갓네살을 데려올 것이고, 그가 그 보좌(왕의 자리)를 내가 감추게 한 이 돌 위에 놓고, 또 그의 화려한 천막을 그 위에 칠 거야.\'\\""},{"n":11,"t":"\\"\'그가 와서 애굽 땅을 칠 것이고, 죽일 자는 죽이고, 사로잡을 자는 사로잡고, 칼로 칠 자는 칼로 칠 거야.\'\\""},{"n":12,"t":"\\"\'내가 애굽 신들의 집(우상 신전)에 불을 놓을 것이니 느부갓네살이 그것들을 불태우고 그들을 사로잡을 거야. 마치 목자가 자기 몸에 옷을 두르듯이 그가 애굽 땅을 자기 몸에 두르고 평안히 그곳을 떠날 거야.\'\\""},{"n":13,"t":"\\"\'그가 또 애굽 땅 벧세메스의 주상(석상, 돌 우상)들을 깨뜨리고 애굽 신들의 집을 불태울 거야.\' 이렇게 말해라.\\""}]}},{"chapter":44,"title":"애굽에 임할 심판","verses":{"krv":[{"n":1,"t":"애굽 땅에 거하는 모든 유다인 곧 믹돌과 다바네스와 놉과 바드로스 지방에 거하는 자에 대하여 말씀이 예레미야에게 임하니라 가라사대"},{"n":2,"t":"만군의 여호와 이스라엘의 하나님이 이같이 말하노라 너희가 예루살렘과 유다 모든 성읍에 내린 나의 모든 재앙을 보았느니라 보라 오늘날 그것들이 황무지가 되었고 거하는 사람이 없나니"},{"n":3,"t":"이는 그들이 자기나 너희나 너희 열조의 알지 못하는 다른 신들에게 나아가 분향하여 섬겨서 나의 노를 격동한 악행을 인함이라"},{"n":4,"t":"내가 나의 모든 종 선지자들을 그들에게 보내되 부지런히 보내어 이르기를 너희는 나의 미워하는 이 가증한 일을 행치 말라 하였어도"},{"n":5,"t":"그들이 듣지 아니하며 귀를 기울이지 아니하고 다를 신들에게 여전히 분향하여 그 악에서 둘이키지 아니하였으므로"},{"n":6,"t":"나의 분과 나의 노를 쏟아서 유다 성읍들과 예루살렘 거리를 살랐더니 그것들이 오늘과 같이 황폐하고 적막하였느니라"},{"n":7,"t":"나 만군의 하나님 이스라엘의 하나님 여호와가 이같이 말하노라 너희가 어찌하여 큰 악을 행하여 자기 영혼을 해하며 유다 중에서 너희의 남자와 여자와 아이와 젖먹는 자를 멸절하여 하나도 남기지 않게 하려느냐"},{"n":8,"t":"어찌하여 너희가 너희 손의 소위로 나의 노를 격동하여 너희의 가서 우거하는 애굽 땅에서 다른 신들에게 분향함으로 끊어버림을 당하여 세계 열방 중에서 저주와 모욕거리가 되고자 하느냐"},{"n":9,"t":"너희가 유다 땅과 예루살렘 거리에서 행한 너희 열조의 악과 유다 왕들의 악과 왕비들의 악과 너희의 악과 너희 아내들의 악을 잊었느냐"},{"n":10,"t":"그들이 오늘까지 겸비치 아니하며 두려워하지도 아니하고 내가 너희와 너희 열조 앞에 세운 나의 법과 나의 율례를 준행치 아니하느니라"},{"n":11,"t":"그러므로 나 만군의 여호와 이스라엘의 하나님이 이같이 말하노라 보라 내가 얼굴을 너희에게로 향하여 재앙을 내리고 온 유다를 끊어 버릴 것이며"},{"n":12,"t":"내가 또 애굽 땅에 우거하기로 고집하고 그리로 들어간 유다의 남은 자들을 취하리니 그들이 다 멸망하여 애굽 땅에서 엎드러질 것이라 그들이 칼과 기근에 망하되 작은 자로부터 큰 자까지 칼과 기근에 죽어서 가증함과 놀램과 저주와 모욕거리가 되리라"},{"n":13,"t":"내가 예루살렘을 벌한 것 같이 애굽 땅에 거하는 자들을 칼과 기근과 염병으로 벌하리니"},{"n":14,"t":"애굽 땅에 들어가서 거기 우거하는 유다의 남은 자 중에 피하거나 남아서 그 사모하여 돌아와서 거하려는 유다 땅에 돌아올 자가 없을 것이라 도피하는 자들 외에는 돌아올 자가 없으리라 하셨느니라"},{"n":15,"t":"때에 자기 아내들이 다른 신들에게 분향하는 줄을 아는 모든 남자와 곁에 섰던 모든 여인 곧 애굽 땅 바드로스에 거하는 모든 백성의 큰 무리가 예레미야에게 대답하여 가로되"},{"n":16,"t":"네가 여호와의 이름으로 우리에게 하는 말을 우리가 듣지 아니하고"},{"n":17,"t":"우리 입에서 낸 모든 말을 정녕히 실행하여 우리의 본래 하던 것 곧 우리와 우리 선조와 우리 왕들과 우리 방백들이 유다 성읍들과 예루살렘 거리에서 하던 대로 하늘 여신에게 분향하고 그 앞에 전제를 드리리라 대저 그 때에는 우리가 식물이 풍부하며 복을 받고 재앙을 만나지 아니하였더니"},{"n":18,"t":"우리가 하늘 여신에게 분향하고 그 앞에 전제 드리던 것을 폐한 후부터는 모든 것이 핍절하고 칼과 기근에 멸망을 당하였느니라 하며"},{"n":19,"t":"여인들은 가로되 우리가 하늘 여신에게 분향하고 그 앞에 전제를 드릴 때에 어찌 우리 남편의 허락이 없이 그에게 경배하는 과자를 만들어 놓고 전제를 드렸느냐"},{"n":20,"t":"예레미야가 남녀 모든 무리 곧 이 말로 대답하는 모든 백성에게 일러 가로되"},{"n":21,"t":"너희가 너희 선조와 너희 왕들과 방백들과 유다 땅 백성이 유다 성읍들과 예루살렘 거리들에서 분향한 일을 여호와께서 기억지 아니하셨느냐 생각지 아니하셨느냐"},{"n":22,"t":"여호와께서 너희 악행과 가증한 소위를 더 참으실 수 없으셨으므로 너희 땅이 오늘과 같이 황무하며 놀램과 저줏거리가 되어 거민이 없게 되었나니"},{"n":23,"t":"너희가 분향하여 여호와께 범죄하였으며 여호와의 목소리를 청종치 아니하고 여호와의 법과 율례와 증거대로 행치 아니하였으므로 이 재앙이 오늘과 같이 너희에게 미쳤느니라"},{"n":24,"t":"예레미야가 다시 모든 백성과 모든 여인에게 말하되 애굽 땅에서 사는 모든 유다여 여호와의 말씀을 들으라"},{"n":25,"t":"만군의 여호와 이스라엘의 하나님이 이같이 말씀하시되 너희와 너희 아내들이 입으로 말하고 손으로 이루려 하여 이르기를 우리가 서원한 대로 반드시 이행하여 하늘 여신에게 분향하고 전제를 드리리라 하였은즉 너희 서원을 성립하며 너희 서원을 이행하라 하시느니라"},{"n":26,"t":"그러므로 애굽 땅에서 사는 모든 유다여 여호와의 말씀을 들으라 여호와께서 말씀하시되 내가 나의 큰 이름으로 맹세하였은즉 애굽 온 땅에 거하는 유다 사람들의 입에서 다시는 내 이름을 일컬어서 주 여호와의 사심으로 맹세하노라 하는 자가 없게 되리라"},{"n":27,"t":"보라 내가 경성하여 그들에게 재앙을 내리고 복을 내리지 아니하리니 애굽 땅에 있는 유다 모든 사람이 칼과 기근에 망하여 멸절되리라"},{"n":28,"t":"그런즉 칼을 피한 소수의 사람이 애굽 땅에서 나와 유다 땅으로 돌아오리니 애굽 땅에 들어가서 거기 우거하는 유다의 모든 남은 자가 내 말이 성립되었는지, 자기들의 말이 성립되었는지 알리라"},{"n":29,"t":"나 여호와가 말하노라 내가 이곳에서 너희를 벌할 표징이 이것이라 내가 너희에게 내앙을 내리리라 한 말이 단정코 성립될 것을 그것으로 알게 하리라"},{"n":30,"t":"보라 내가 유다 왕 시드기야를 그 원수 곧 그 생명을 찾는 바벨론 왕 느부갓네살의 손에 붙인 것 같이 애굽 왕 바로 호브라를 그 원수들 곧 그 생명을 찾는 자들의 손에 붙이리라 나 여호와가 이같이 말하였느니라 하시니라"}],"kids":[{"n":1,"t":"애굽 땅에 사는 모든 유다 사람, 곧 믹돌과 다바네스와 놉과 바드로스 지방에 사는 사람들에 대해 말씀이 예레미야에게 들려왔어요."},{"n":2,"t":"\\"만군의 여호와 이스라엘의 하나님이 이렇게 말한다. 너희가 예루살렘과 유다 모든 성에 내린 내 모든 재앙을 보았어. 보아라, 오늘날 그것들이 폐허가 되었고 사는 사람이 없어.\\""},{"n":3,"t":"\\"이는 그들이 자기들이나 너희나 너희 조상이 알지 못하는 다른 신들에게 가서 향을 피우고 섬겨서 내 분노를 일으킨 못된 짓 때문이야.\\""},{"n":4,"t":"\\"내가 내 모든 종 선지자들을 그들에게 부지런히 보내서 ‘너희는 내가 미워하는 이 미운(가증한) 일을 하지 마라’라고 했지만,\\""},{"n":5,"t":"\\"그들이 듣지 않고 귀를 기울이지도 않으며 다른 신들에게 계속 향을 피우면서 그 못된 길에서 돌이키지 않았어.\\""},{"n":6,"t":"\\"그래서 내 분노와 화를 쏟아 유다 성과 예루살렘 거리를 태웠고, 그것들이 오늘과 같이 폐허가 되어 적막해(조용해)졌단다.\\""},{"n":7,"t":"\\"이제 만군의 하나님 이스라엘의 하나님 여호와가 이렇게 말한다. 너희가 어찌하여 큰 못된 짓을 해서 자기 영혼을 해치며, 유다 가운데서 너희의 남자와 여자와 아이와 젖먹이까지 다 멸해서 한 명도 남기지 않으려 하느냐?\\""},{"n":8,"t":"\\"어찌하여 너희가 너희 손이 한 일로 내 분노를 일으키며, 너희가 가서 사는 애굽 땅에서 다른 신들에게 향을 피워 너희가 끊어지고, 세상의 모든 나라 가운데서 저주거리와 모욕거리가 되려 하느냐?\\""},{"n":9,"t":"\\"너희가 유다 땅과 예루살렘 거리에서 행한 너희 조상의 못된 짓과, 유다 왕들의 못된 짓과, 왕비들의 못된 짓과, 너희의 못된 짓과, 너희 아내들의 못된 짓을 잊었느냐?\\""},{"n":10,"t":"\\"그들이 오늘까지 자기 자신을 낮추지 않고, 두려워하지도 않으며, 내가 너희와 너희 조상 앞에 세운 내 법과 내 규례를 따라 행하지 않는구나.\\""},{"n":11,"t":"\\"그러므로 나 만군의 여호와 이스라엘의 하나님이 이렇게 말한다. 보아라, 내가 얼굴을 너희에게로 향해 재앙을 내리고 온 유다를 끊어 버릴 거야.\\""},{"n":12,"t":"\\"내가 또 애굽 땅에 머물러 살기로 고집하고 그곳에 들어간 유다의 남은 자들을 사로잡을 것이고, 그들이 다 멸망해서 애굽 땅에서 쓰러질 거야. 그들이 칼과 기근에 망할 것이고, 작은 자부터 큰 자까지 칼과 기근에 죽어서 미운 것과 놀람과 저주와 모욕거리가 될 거야.\\""},{"n":13,"t":"\\"내가 예루살렘을 벌한 것처럼 애굽 땅에 사는 자들을 칼과 기근과 염병으로 벌할 것이고,\\""},{"n":14,"t":"\\"애굽 땅에 들어가 거기 사는 유다의 남은 자 중에서 피하거나 살아남아, 그토록 그리워하며 돌아가 살려고 하는 유다 땅으로 돌아올 자가 없을 거야. 도망쳐 간 몇몇 사람 외에는 돌아올 자가 없을 거야.\\""},{"n":15,"t":"그때 자기 아내들이 다른 신들에게 향을 피우는 것을 아는 모든 남자와 옆에 서 있던 모든 여인, 곧 애굽 땅 바드로스에 사는 모든 백성의 큰 무리가 예레미야에게 대답해 말했어요."},{"n":16,"t":"\\"당신이 여호와의 이름으로 우리에게 하는 말을 우리는 듣지 않을 거예요.\\""},{"n":17,"t":"\\"우리 입에서 나온 모든 말을 반드시 행해서, 우리의 본래 하던 것, 곧 우리와 우리 조상과 우리 왕들과 우리 높은 사람들이 유다 성과 예루살렘 거리에서 하던 대로 하늘 여신(거짓 여신)에게 향을 피우고 그 앞에 술(전제)을 드리겠어요. 그때에는 우리가 양식이 풍부하고 복을 받고 재앙을 만나지 않았어요.\\""},{"n":18,"t":"\\"그런데 우리가 하늘 여신에게 향을 피우고 그 앞에 술을 드리던 것을 그만둔 후부터는 모든 것이 부족해지고 칼과 기근에 멸망을 당했어요.\\""},{"n":19,"t":"여인들이 말했어요. \\"우리가 하늘 여신에게 향을 피우고 그 앞에 술을 드릴 때, 어찌 우리 남편의 허락 없이 그에게 절하는 과자를 만들어 두고 술을 드렸겠어요?\\""},{"n":20,"t":"예레미야가 남녀 모든 무리, 곧 이렇게 대답하는 모든 백성에게 말했어요."},{"n":21,"t":"\\"여러분과 여러분 조상과 왕들과 높은 사람들과 유다 땅 백성이 유다 성과 예루살렘 거리에서 향을 피운 일을 여호와께서 기억하지 못하셨겠어요? 마음에 두지 않으셨겠어요?\\""},{"n":22,"t":"\\"여호와께서 여러분의 못된 행동과 미운 짓을 더 참으실 수 없으셨기 때문에, 여러분의 땅이 오늘과 같이 폐허가 되고 놀람과 저주거리가 되어 사는 사람이 없게 된 거예요.\\""},{"n":23,"t":"\\"여러분이 향을 피워서 여호와께 죄를 지었고, 여호와의 목소리에 따르지 않으며, 여호와의 법과 규례와 증거대로 행하지 않았기 때문에, 이 재앙이 오늘과 같이 여러분에게 닥친 거예요.\\""},{"n":24,"t":"예레미야가 다시 모든 백성과 모든 여인에게 말했어요. \\"애굽 땅에 사는 모든 유다 사람들이여, 여호와의 말씀을 들으세요.\\""},{"n":25,"t":"\\"만군의 여호와 이스라엘의 하나님이 이렇게 말씀하셨어요. \'너희와 너희 아내들이 입으로 말하고 손으로 이루려고 하면서 〈우리가 서원한(약속한) 대로 반드시 행해서 하늘 여신에게 향을 피우고 술을 드리겠다〉라고 했으니, 너희 서원을 잘 세워서 너희 서원을 잘 이행해 봐라.\'\\""},{"n":26,"t":"\\"그러므로 애굽 땅에 사는 모든 유다 사람들이여, 여호와의 말씀을 들으세요. 여호와께서 말씀하셨어요. \'내가 내 큰 이름으로 맹세하노니, 애굽 온 땅에 사는 유다 사람들의 입에서 다시는 내 이름을 부르며 〈주 여호와의 살아 계심으로 맹세한다〉라고 하는 자가 없게 될 거야.\'\\""},{"n":27,"t":"\\"\'보아라, 내가 그들에게 재앙을 내리고 복을 내리지 않을 것이니, 애굽 땅에 있는 모든 유다 사람이 칼과 기근에 망해 멸망당할 거야.\'\\""},{"n":28,"t":"\\"\'그러나 칼을 피한 소수의 사람이 애굽 땅에서 나와 유다 땅으로 돌아올 것이고, 애굽 땅에 들어가 거기 사는 유다의 모든 남은 자가, 내 말이 이루어졌는지 자기들의 말이 이루어졌는지 알게 될 거야.\'\\""},{"n":29,"t":"\\"\'나 여호와가 말한다. 내가 이곳에서 너희를 벌할 표징(징조)이 이것이다. 내가 너희에게 재앙을 내리겠다고 한 말이 반드시 이루어질 것임을 그것으로 알게 할 거야.\'\\""},{"n":30,"t":"\\"\'보아라, 내가 유다 왕 시드기야를 그 적, 곧 그의 목숨을 노리는 바벨론 왕 느부갓네살의 손에 넘긴 것처럼, 애굽 왕 바로 호브라를 그 적들, 곧 그의 목숨을 노리는 자들의 손에 넘겨 줄 거야. 나 여호와가 이렇게 말한다.\'\\""}]}},{"chapter":45,"title":"바룩에게 주신 약속","verses":{"krv":[{"n":1,"t":"유다 왕 요시야의 아들 여호야김 제사년에 네리야의 아들 바룩이 예레미야의 구전대로 이 모든 말을 책에 기록하니라 때에 선지자 예레미야가 그에게 말하여 가로되"},{"n":2,"t":"바룩아 이스라엘의 하나님 여호와께서 네게 이같이 말씀하시되"},{"n":3,"t":"네가 일찍 말하기를 슬프다 여호와께서 나의 고통에 슬픔을 더하셨으니 나는 나의 탄식으로 피곤하여 평안치 못하다 하도다 하셨고"},{"n":4,"t":"또 내게 이르시기를 너는 그에게 이르라 여호와께서 이같이 말씀하시기를 보라 나는 나의 세운 것을 헐기도 하며 나의 심은 것을 뽑기도 하나니 온 땅에 이러하거늘"},{"n":5,"t":"네가 너를 위하여 대사를 경영하느냐 그것을 경영하지 말라 보라 내가 모든 육체에게 재앙을 내리리라 그러나 너의 가는 모든 곳에서는 내가 너로 생명 얻기를 노략물을 얻는 것 같게 하리라 여호와의 말이니라 하셨느니라"}],"kids":[{"n":1,"t":"유다 왕 요시야의 아들 여호야김 4년에, 네리야의 아들 바룩이 예레미야가 입으로 불러 주는 대로 이 모든 말을 책에 기록할 때, 선지자 예레미야가 그에게 이런 말을 했어요."},{"n":2,"t":"\\"바룩아, 이스라엘의 하나님 여호와께서 너에게 이렇게 말씀하셨어.\\""},{"n":3,"t":"\\"\'네가 일찍이 〈슬프다, 여호와께서 내 고통에 슬픔을 더하셨으니 나는 한숨으로 피곤해서 평안하지 못하다〉라고 했지.\'\\""},{"n":4,"t":"\\"또 내게 말씀하시기를 ‘너는 그에게 말해라. 여호와께서 이렇게 말씀하셨다. 보아라, 내가 세운 것을 헐기도 하고 내가 심은 것을 뽑기도 한다. 온 땅이 다 이러한데,\\""},{"n":5,"t":"\\"네가 너 자신을 위해 큰 일을 꾀하느냐? 그렇게 하지 마라. 보아라, 내가 모든 사람에게 재앙을 내릴 거야. 그러나 네가 가는 모든 곳에서는 내가 네 목숨을 약탈물(노략물)을 얻은 것 같이 살게 해 주겠다. 이것은 여호와의 말이야.\'\\""}]}},{"chapter":46,"title":"애굽에 대한 경고","verses":{"krv":[{"n":1,"t":"열국에 대하여 선지자 예레미아에 임한 여호와의 말씀이라"},{"n":2,"t":"애굽을 논한 것이니 곧 유다 왕 요시야의 아들 여호야김 제사년에 유부라데 하숫가 갈그미스에서 바벨론 왕 느부갓네살에게 패한 애굽 왕 바로느고의 군대에 대한 말씀이라"},{"n":3,"t":"너희는 큰 방패, 작은 방패를 예비하고 나가서 싸우라"},{"n":4,"t":"너희 기병이여 말에 안장을 지워 타며 투구를 쓰고 나서며 창을 갈며 갑옷을 입으라"},{"n":5,"t":"여호와께서 가라사대 내가 본즉 그들이 놀라 물러가며 그들의 용사는 패하여 급히 도망하며 뒤를 돌아보지 아니함은 어찜인고 두려움이 그들의 사방에 있음이로다 하셨나니"},{"n":6,"t":"발이 빠른 자도 도망하지 못하며 용맹이 있는 자도 피하지 못하고 그들이 다 북방에서 유브라데 하숫가에 넘어지며 엎드러지는도다"},{"n":7,"t":"저 나일의 창일함과 강물의 흉용함 같은 자 누구뇨"},{"n":8,"t":"애굽이 나일의 창일함과 강물의 흉용함 같도다 그가 가로되 내가 일어나 땅을 덮어 성읍들과 그 거민을 멸할 것이라"},{"n":9,"t":"말들아 달리라 병거들아 급히 동하라 용사여 나오라 방패 잡은 구스인과 붓인과 활을 당기는 루딤인이여 나올지니라 하거니와"},{"n":10,"t":"그 날은 주 만군의 여호와께서 그 대적에게 원수 갚는 보수일이라 칼이 배부르게 삼키며 그들의 피를 가득히 마시리니 주 만군의 여호와께서 북편 유브라데 하숫가에서 희생을 내실 것임이로다"},{"n":11,"t":"처녀 딸 애굽이여 길르앗으로 올라가서 유향을 취하라 네가 많은 의약을 쓸지라도 무효하여 낫지 못하리라"},{"n":12,"t":"네 수치가 열방에 들렸고 네 부르짖음은 땅에 가득하였나니 용사가 용사에게 부딪쳐 둘이 함께 엎드러졌음이니라"},{"n":13,"t":"바벨론 왕 느부갓네살이 와서 애굽 땅을 칠 일에 대하여 선지자 예레미아에게 이르신 여호와의 말씀이라"},{"n":14,"t":"너희는 애굽에 선포하며 믹돌과 놉과 다바네스에 선포하여 말하기를 너희는 굳게 서서 예비하라 네 사방이 칼에 삼키웠느니라"},{"n":15,"t":"너희 장사들이 쓰러짐은 어찜이뇨 그들의 서지 못함은 여호와께서 그들을 몰아내신 연고니라"},{"n":16,"t":"그가 많은 자로 넘어지게 하시매 사람이 사람 위에 엎드러지며 이르되 일어나라 우리가 포악한 칼을 피하여 우리 민족에게로, 우리 고토로 돌아가자 하며"},{"n":17,"t":"거기서 부르짖기를 애굽 왕 바로가 망하였도다 그가 시기를 잃었도다"},{"n":18,"t":"만군의 여호와라 일컫는 왕이 가라사대 나의 삶으로 맹세하노니 그가 과연 산들 중의 다볼 같이, 해변의 갈멜 같이 오리라"},{"n":19,"t":"애굽에 사는 딸이여 너는 너를 위하여 포로의 행리를 준비하라 놉이 황무하며 불에 타서 거민이 없을 것임이니라"},{"n":20,"t":"애굽은 심히 아름다운 암송아지라도 북에서부터 멸망에 이르렀고 이르렀느니라"},{"n":21,"t":"또 그 중의 고용꾼은 외양간의 송아지 같아서 돌이켜 함께 도망하고 서지 못하였나니 재난의 날이 이르렀고 벌 받는 때가 왔음이라"},{"n":22,"t":"애굽의 소리가 뱀의 소리 같으리니 이는 그들의 군대가 벌목하는 자 같이 도끼를 가지고 올 것임이니라"},{"n":23,"t":"나 여호와가 말하노라 그들이 황충보다 많고 계수할 수 없으므로 조사할 수 없는 그의 수풀을 찍을 것이라"},{"n":24,"t":"딸 애굽이 수치를 당하여 북방 백성의 손에 붙임을 입으리로다"},{"n":25,"t":"나 만군의 여호와 이스라엘의 하나님이 말하노라 보라 내가 노의 아몬과 바로와 애굽과 애굽 신들과 왕들 곧 바로와 및 그를 의지하는 자들을 벌할 것이라"},{"n":26,"t":"내가 그들의 생명을 찾는 자의 손 곧 바벨론 왕 느부갓네살의 손과 그 신하들의 손에 붙이리라 그럴지라도 그 후에는 그 땅이 여전히 사람 살 곳이 되리라 여호와의 말이니라"},{"n":27,"t":"내 종 야곱아 두려워 말라 이스라엘아 놀라지 말라 보라 내가 너를 원방에서 구원하며 네 자손을 포로된 땅에서 구원하리니 야곱이 돌아와서 평안히, 정온히 거할것이라 그를 두렵게 할 자 없으리라"},{"n":28,"t":"나 여호와가 말하노라 내 종 야곱아 내가 너와 함께 하나니 두려워 말라 내가 너를 흩었던 그 열방은 다 멸할지라도 너는 아주 멸하지 아니하리라 내가 너를 공도로 징책할 것이요 결코 무죄한 자로 여기지 아니하리라"}],"kids":[{"n":1,"t":"여러 나라들에 대해 선지자 예레미야에게 들려온 여호와의 말씀이에요."},{"n":2,"t":"애굽에 대해 한 말씀인데, 곧 유다 왕 요시야의 아들 여호야김 4년에 유브라데 강가 갈그미스에서 바벨론 왕 느부갓네살에게 진(진 = 졌어요) 애굽 왕 바로 느고의 군대에 대한 말씀이에요."},{"n":3,"t":"\\"너희는 큰 방패와 작은 방패를 준비하고 나가서 싸워라.\\""},{"n":4,"t":"\\"너희 기마병들아, 말에 안장을 얹고 올라타며, 투구를 쓰고 나서며, 창을 갈고 갑옷을 입어라.\\""},{"n":5,"t":"\\"여호와께서 말씀하셨어. \'내가 보니 그들이 놀라 물러가고, 그들의 용사(군인)는 패해서 급히 도망치며 뒤를 돌아보지 않는 것이 어찌 된 일이냐? 두려움이 그들의 사방에 있구나.\'\\""},{"n":6,"t":"\\"발이 빠른 자도 도망하지 못하고 힘 있는 자도 피하지 못해, 그들 모두가 북쪽 유브라데 강가에서 넘어지고 쓰러지는구나.\\""},{"n":7,"t":"\\"저 나일 강이 넘쳐 오르는 것 같고, 강물이 거세게 흐르는 것 같은 자가 누구냐?\\""},{"n":8,"t":"\\"애굽이 나일 강이 넘치는 것 같고 강물이 거세게 흐르는 것 같구나. 애굽이 말하기를 \'내가 일어나 땅을 덮고, 성과 그 안의 사람들을 멸할 거야\'라고 한다.\\""},{"n":9,"t":"\\"말들아, 달려라! 병거(전쟁용 마차)들아, 빨리 움직여라! 용사들아, 나오라! 방패를 든 에티오피아 사람(구스인)과 붓 사람과 활을 당기는 루딤 사람들아, 나오라!\\""},{"n":10,"t":"\\"그날은 주 만군의 여호와께서 그 적에게 갚으시는 보복의 날이야. 칼이 배부르게 삼키고 그들의 피를 가득히 마실 거야. 주 만군의 여호와께서 북쪽 유브라데 강가에서 희생 제물을 드리실 거야.\\""},{"n":11,"t":"\\"처녀 딸 애굽아, 길르앗으로 올라가서 유향(좋은 약)을 가져와라. 네가 많은 약을 써도 소용이 없어 낫지 못할 거야.\\""},{"n":12,"t":"\\"네 부끄러움이 모든 나라에 들렸고, 네 부르짖음이 땅에 가득하구나. 용사가 용사에게 부딪쳐 둘이 함께 쓰러졌기 때문이야.\\""},{"n":13,"t":"바벨론 왕 느부갓네살이 와서 애굽 땅을 칠 날에 대해 선지자 예레미야에게 하신 여호와의 말씀이에요."},{"n":14,"t":"\\"너희는 애굽에 선포하고, 믹돌과 놉과 다바네스에 선포하여 말해라. \'너희는 굳게 서서 준비하라. 네 사방이 칼에 삼켜졌단다.\'\\""},{"n":15,"t":"\\"너희 군인(장사)들이 쓰러진 이유는 무엇이냐? 그들이 서지 못한 것은 여호와께서 그들을 몰아내셨기 때문이야.\\""},{"n":16,"t":"\\"그가 많은 사람을 넘어지게 해서 사람이 사람 위에 쓰러지면서 말하기를, \'일어나라, 우리가 사나운 칼을 피해 우리 민족에게로, 우리 고향(고토)으로 돌아가자!\' 한다.\\""},{"n":17,"t":"\\"그곳에서 그들이 외쳐, \'애굽 왕 바로가 망했다. 그가 좋은 때를 놓쳤다\'라고 한다.\\""},{"n":18,"t":"\\"만군의 여호와라 불리는 왕이 말씀하셨어. \'내 삶을 두고 맹세하노니, 그(바벨론 왕)는 정말로 산들 중에 다볼 산처럼, 해변의 갈멜 산처럼 (우뚝 서서) 올 거야.\'\\""},{"n":19,"t":"\\"애굽에 사는 딸아, 너는 너 자신을 위해 포로로 끌려갈 짐(행리)을 챙겨라. 놉이 황폐해서 불에 타고 사는 사람이 없게 될 거야.\\""},{"n":20,"t":"\\"애굽은 정말 아름다운 암송아지라도, 북쪽에서부터 멸망이 와서 닥쳤어.\\""},{"n":21,"t":"\\"또 그 가운데 고용꾼(외국 용병)들은 외양간의 살찐 송아지 같아서, 돌이켜 함께 도망치고 서지 못했어. 재난의 날이 그들에게 왔고, 벌 받을 때가 왔기 때문이야.\\""},{"n":22,"t":"\\"애굽의 소리는 뱀의 소리 같을 거야. 이는 그들(적군)이 나무 베는 자처럼 도끼를 가지고 올 것이기 때문이야.\\""},{"n":23,"t":"\\"나 여호와가 말한다. 그들이 메뚜기(황충)보다 많고 셀 수 없을 만큼 많으므로 조사할 수 없는 그의 숲(군대)을 찍어 낼 거야.\\""},{"n":24,"t":"\\"딸 애굽이 부끄러움을 당하고 북쪽 백성의 손에 넘겨질 거야.\\""},{"n":25,"t":"\\"나 만군의 여호와 이스라엘의 하나님이 말한다. 보아라, 내가 노(애굽의 도시)의 아몬(거짓 신)과 바로와 애굽과 애굽의 신들과 왕들, 곧 바로와 그를 의지하는 자들을 벌할 거야.\\""},{"n":26,"t":"\\"내가 그들을, 그들의 목숨을 노리는 자의 손, 곧 바벨론 왕 느부갓네살의 손과 그 신하들의 손에 넘기겠다. 그러나 그 후에는 그 땅이 다시 사람이 살 곳이 될 거야. 이것은 여호와의 말이야.\\""},{"n":27,"t":"\\"내 종 야곱아, 두려워하지 마라. 이스라엘아, 놀라지 마라. 보아라, 내가 너를 먼 곳에서 구원하고 네 자손을 사로잡힌 땅에서 구원할 것이니, 야곱이 돌아와 평안히 조용히 살게 될 거야. 그를 두렵게 할 자가 없을 거야.\\""},{"n":28,"t":"\\"나 여호와가 말한다. 내 종 야곱아, 내가 너와 함께하니 두려워하지 마라. 내가 너를 흩었던 그 모든 나라는 다 멸한다 해도, 너만은 완전히 멸하지 않을 거야. 내가 너를 공의로 가르치겠지만, 결코 너를 죄가 없는 자로 여기지는 않을 거야.\\""}]}},{"chapter":47,"title":"블레셋에 대한 경고","verses":{"krv":[{"n":1,"t":"바로가 가사를 치기 전에 블레셋 사람에 대하여 선지자 예레미야에게 임한 여호와의 말씀이라"},{"n":2,"t":"여호와께서 이같이 말씀하시되 보라 물이 북방에서 일어나 창일하는 시내를 이루어 그 땅과 그 중에 있는 모든 것과 그 성읍과 거기 거하는 자들을 엄몰시키리니 사람들이 부르짖으며 그 땅 모든 거민이 애곡할 것이라"},{"n":3,"t":"힘센 것의 굽치는 소리와 달리는 병거 바퀴의 울리는 소리에 아비의 손이 풀려서 그 자녀를 돌아보지 못하리니"},{"n":4,"t":"이는 블레셋 사람을 진멸하시며 두로와 시돈에 남아 있는 바 도와 줄 자를 다 끊어 버리시는 날이 이름이라 여호와께서 갑돌 섬에 남아 있는 블레셋 사람을 멸하시리라"},{"n":5,"t":"가사가 삭발되었고 아스글론과 그들에게 남아 있는 평지가 멸망되었나니 네가 네 몸 베기를 어느 때까지 하겠느냐"},{"n":6,"t":"여호와의 칼이여 네가 언제까지 쉬지 않겠느냐 네 집에 들어가서 가만히 쉴지어다"},{"n":7,"t":"여호와께서 이를 명하셨은즉 어떻게 쉬겠느냐 아스글론과 해변을 치려 하여 그가 명정하셨느니라"}],"kids":[{"n":1,"t":"바로(애굽 왕)가 가사를 치기 전에, 블레셋 사람에 대해 선지자 예레미야에게 들려온 여호와의 말씀이에요."},{"n":2,"t":"\\"여호와께서 이렇게 말씀하셨어. \'보아라, 물이 북쪽에서 일어나 넘쳐 흐르는 시내가 되어, 그 땅과 그 안에 있는 모든 것과 성과 거기 사는 사람들을 잠기게 할 것이다. 사람들이 부르짖고, 그 땅 모든 사람이 슬피 울 거야.\'\\""},{"n":3,"t":"\\"힘센 말발굽 소리와 달리는 병거(전쟁용 마차) 바퀴의 시끄러운 소리에 아버지의 손이 풀려서, 자녀를 돌아보지 못하게 될 거야.\\""},{"n":4,"t":"\\"이는 블레셋 사람을 멸하시고, 두로와 시돈에 남아서 도와줄 자를 다 끊어 버리실 날이 왔기 때문이야. 여호와께서 갑돌 섬에 남아 있는 블레셋 사람을 멸하실 거야.\\""},{"n":5,"t":"\\"가사가 삭발되었고(머리를 밀었고 - 슬픔의 표시), 아스글론과 그들에게 남아 있는 평지(낮은 땅)가 멸망당했으니, 네가 네 몸을 베는 일을 언제까지 하겠느냐?\\""},{"n":6,"t":"\\"여호와의 칼이여, 네가 언제까지 쉬지 않겠느냐? 네 칼집에 들어가서 가만히 쉬어라.\\""},{"n":7,"t":"\\"여호와께서 이를 명령하셨는데, 어찌 쉴 수 있겠느냐? 아스글론과 해변을 치라고 정해져 있단다.\\""}]}},{"chapter":48,"title":"모압에 대한 경고","verses":{"krv":[{"n":1,"t":"모압에 대한 말씀이라 만군의 여호와 이스라엘의 하나님이 이같이 말씀하시되 슬프다 느보여 그것이 황폐되었도다 기랴다임이 수치를 당하여 점령되었고 미스갑이 수치를 당하여 파괴되었으니"},{"n":2,"t":"모압의 칭송이 없어졌도다 헤스본에서 무리가 그를 모해하여 이르기를 와서 그를 끊어서 나라를 이루지 못하게 하자 하는도다 맛멘이여 너도 적막하게 되리니 칼이 너를 따르리로다"},{"n":3,"t":"호로나임에서 부르짖는 소리여 황무와 큰 파멸이로다"},{"n":4,"t":"모압이 멸망을 당하여 그 영아들의 부르짖음이 들리는도다"},{"n":5,"t":"그들이 울고 울며 루힛 언덕으로 올라감이여 호로나임 내려가는 데서 참패를 부즈짖는 고통이 들리도다"},{"n":6,"t":"도망하여 네 생명을 구원하여 광야의 떨기나무 같이 될지어다"},{"n":7,"t":"네가 네 공작과 보물을 의뢰하므로 너도 취함을 당할 것이요 그모스는 그 제사장들과 방백들과 함께 포로되어 갈 것이라"},{"n":8,"t":"파멸하는 자가 각 성에 이를 것인즉 한 성도 면치 못할 것이며 골짜기는 훼파되며 평원은 파멸되어 여호와의 말씀과 같으리로다"},{"n":9,"t":"모압에 날개를 주어 날아 피하게 하라 그 성읍들이 황무하여 거기 거하는 자 없으리로다"},{"n":10,"t":"여호와의 일을 태만히 하는 자는 저주를 받을 것이요 자기 칼을 금하여 피를 흘리지 아니하는 자도 저주를 당할 것이로다"},{"n":11,"t":"모압은 예로부터 평안하고 포로도 되지 아니하였으므로 마치 술의 그 찌끼 위에 있고 이 그릇에서 저 그릇으로 옮기지 않음 같아서 그 맛이 남아 있고 냄새가 변치 아니하였도다"},{"n":12,"t":"그러므로 나 여호와가 말하노라 날이 이르리니 내가 그 그릇을 기울일 자를 보낼 것이라 그들이 기울여서 그 그릇을 비게 하고 그 병들을 부수리니"},{"n":13,"t":"이스라엘 집이 벧엘을 의뢰하므로 수치를 당한 것 같이 모압이 그모스로 인하여 수치를 당하리로다"},{"n":14,"t":"너희가 어찌하여 말하기를 우리는 용사요 전쟁의 맹사라 하느뇨"},{"n":15,"t":"만군의 여호와라 일컫는 왕이 이같이 말하노라 모압이 황폐되었도다 그 성읍들은 연기가 되어 올라가고 그 택한 청년들은 내려가서 살륙을 당하니"},{"n":16,"t":"모압의 재난이 가까웠고 그 고난이 속히 임하리로다"},{"n":17,"t":"그의 사면에 있는 모든 자여, 그 이름을 아는 모든 자여, 그를 위하여 탄식하여 말하기를 어찌하여 강한 막대기, 아름다운 지팡이가 부러졌는고 할지니라"},{"n":18,"t":"디본에 거하는 딸아 네 영광 자리에서 내려 메마른 데 앉으라 모압을 파멸하는 자가 올라와서 너를 쳐서 네 요새를 파하였음이로다"},{"n":19,"t":"아로엘에 거하는 여인이여 길곁에 서서 지키며 도망하는 자와 피하는 자에게 일이 어찌 되었는가 물을지어다"},{"n":20,"t":"모압이 패하여 수치를 받나니 너희는 곡하며 부르짖으며 아르논가에서 이르기를 모압이 황무하였다 할지어다"},{"n":21,"t":"심판이 평지에 임하였나니 곧 홀론과 야사와 메바앗과"},{"n":22,"t":"디본과 느보와 벧디불라다임과"},{"n":23,"t":"기랴다임과 벧가물과 벧므온과"},{"n":24,"t":"그리욧과 보스라와 모압 땅 원근 모든 성에로다"},{"n":25,"t":"모압의 뿔이 찍혔고 그 팔이 부러졌도다 여호와의 말이니라"},{"n":26,"t":"모압으로 취하게 할지어다 이는 그가 나 여호와를 거스려 자만함이라 그가 그 토한 것에서 굴므로 조롱거리가 되리로다"},{"n":27,"t":"네가 이스라엘을 조롱하지 아니하였느냐 그가 도적 중에서 발견되었느냐 네가 그를 말할 때마다 네 머리를 흔드는도다"},{"n":28,"t":"모압 거민들아 너희는 성읍을 떠나 바위 사이에 거할지어다 깊은 골짜기 어귀에 깃들이는 비둘기 같이 할지어다"},{"n":29,"t":"우리가 모압의 교만을 들었나니 심한 교만 곧 그 자고와 오만과 자긍과 그 마음의 거만이로다"},{"n":30,"t":"나 여호와가 말하노라 내가 그 노함의 허탄함을 아노니 그가 자긍하여도 아무 것도 성취치 못하였도다"},{"n":31,"t":"그러므로 내가 모압을 위하여 울며 온 모압을 위하여 부르짖으리니 무리가 길헤레스 사람을 위하여 슬퍼하리로다"},{"n":32,"t":"십마의 포도나무여 너의 가지가 바다를 넘어 야셀 바다까지 뻗었더니 너의 여름 실과와 포도에 파멸하는 자가 이르렀으니 내가 너를 위하여 곡하기를 야셀의 곡함보다 더하리로다"},{"n":33,"t":"기쁨과 즐거움이 옥토와 모압 땅에서 빼앗겼도다 내가 포도주틀에 포도주가 없게 하리니 외치며 밟는 자가 없을 것이라 그 외침은 즐거운 외침이 되지 못하리로다"},{"n":34,"t":"헤스본에서 엘르알레를 지나 야하스까지와 소알에서 호로나임을 지나 에글랏셀리시야까지의 사람들이 소리를 발하여 부르짖음은 니므림의 물도 말랐음이로다"},{"n":35,"t":"나 여호와가 말하노라 모압 산당에서 제사하며 그 신들에게 분향하는 자를 내가 그치게 하리라"},{"n":36,"t":"그러므로 나의 마음이 모압을 위하여 피리 같이 소리하며 나의 마음이 길헤레스 사람들을 위하여 피리 같이 소리하나니 이는 그 모았던 재물이 없어졌음이니라"},{"n":37,"t":"각 사람의 두발이 밀렸고 수염이 깎였으며 손이 베어졌으며 허리에 굵은 베가 둘렸고"},{"n":38,"t":"모압의 모든 지붕에서와 거리 각처에서 애곡함이 있으니 내가 모압을 재미 없는 그릇 같이 깨뜨렸음이니라 여호와의 말이니라"},{"n":39,"t":"아하 모압이 파괴되었도다 그들이 애곡하는도다 모압이 부끄러워서 등을 돌이켰도다 그런즉 모압이 그 사방 모든 자의 조롱거리와 두려움이 되리로다"},{"n":40,"t":"나 여호와가 이같이 말하노라 보라 그가 독수리 같이 날아와서 모압 위에 그 날개를 펴리라"},{"n":41,"t":"성읍들이 취함을 당하며 요새가 함락되는 날에 모압 용사의 마음이 구로하는 여인 같을 것이라"},{"n":42,"t":"모압이 여호와를 거스려 자만하였으므로 멸망하고 다시 나라를 이루지 못하리라"},{"n":43,"t":"나 여호와가 말하노라 모압 거민아 두려움과 함정과 올무가 네게 임하나니"},{"n":44,"t":"두려움에서 도망하는 자는 함정에 떨어지겠고 함정에서 나오는 자는 올무에 걸리리니 이는 내가 모압의 벌 받을 해로 임하게 할 것임이니라 여호와의 말이니라"},{"n":45,"t":"도망하는 자들이 기진하여 헤스본 그늘 아래 서니 이는 불이 헤스본에서 발하며 화염이 시혼의 속에서 나서 모압의 살쩍과 훤화하는 자들의 정수리를 사름이로다"},{"n":46,"t":"모압이여 네게 화 있도다 그모스 백성이 망하였도다 네 아들들은 사로잡혀 갔고 네 딸들은 포로가 되었도다"},{"n":47,"t":"그러나 내가 말일에 모압의 포로로 돌아오게 하리라 여호와의 말이니라 하시니라 모압을 심판하는 말씀이 이에 그쳤느니라"}],"kids":[]}},{"chapter":49,"title":"암몬·에돔에 대한 경고","verses":{"krv":[{"n":1,"t":"암몬 자손에 대한 말씀이라 여호와께서 이같이 말씀하시되 이스라엘이 무자하냐 상속자가 없느냐 말감이 갓을 점령하며 그 백성이 그 성읍들에 거함은 어찜이뇨"},{"n":2,"t":"그러므로 나 여호와가 말하노라 보라 날이 이르리니 내가 전쟁소리로 암몬 자손의 랍바에 들리게 할 것이라 랍바는 거친 무더기가 되겠고 그 촌락들은 불에 탈 것이며 그 때에 이스라엘은 자기를 점령하였던 자를 점령하리라 여호와의 말이니라"},{"n":3,"t":"헤스본아 애곡할지어다 아이가 황폐하였도다 너희 랍바의 딸들아 부르짖을지어다 굵은 베를 감고 애통하며 울타리 가운데서 앞뒤로 달릴지어다 말감과 그 제사장들과 그 방백들이 다 사로잡혀 가리로다"},{"n":4,"t":"타락한 딸아 어찌하여 골짜기 곧 네 흐르는 골짜기로 자랑하느냐 네가 어찌하여 재물을 의뢰하여 말하기를 누가 내게 오리요 하느냐"},{"n":5,"t":"주 만군의 여호와가 말하노라 보라 내가 두려움을 네 사방에서 네게 오게 하리니 너희 각 사람이 쫓겨서 바로 나갈 것이요 도망하는 자들을 모을 자가 없으리라"},{"n":6,"t":"그러나 그 후에 내가 암몬 자손의 포로로 돌아오게 하리라 여호와의 말이니라"},{"n":7,"t":"에돔에 대한 말씀이라 만군의 여호와께서 이같이 말씀하시되 데만에 다시는 지혜가 없게 되었느냐 명철한 자에게 모략이 끊어졌느냐 그들의 지혜가 없어졌느냐"},{"n":8,"t":"드단 거민아 돌이켜 도망할지어다 깊은 데 숨을지어다 내가 에서의 재난을 그에게 임하게 하여 그를 벌할 때가 이르게 하리로다"},{"n":9,"t":"포도를 거두는 자들이 네게 이르면 약간의 열매도 남기지 아니하겠고 밤에 도적이 오면 그 욕심이 차기까지 멸하느니라"},{"n":10,"t":"대저 내가 에서로 적신이 되게 하여 그 비밀한 곳들이 드러나게 하였나니 그가 그 몸을 숨길 수 없을 것이라 그 자손과 형제와 이웃이 멸망하였은즉 그가 없어졌느니라"},{"n":11,"t":"네 고아들을 남겨 두라 내가 그들을 살려 두리라 네 과부들은 나를 의지할 것이니라"},{"n":12,"t":"나 여호와가 이같이 말하노라 보라 이 잔을 마시지 않을 자도 마시지 않지 못하겠거늘 네가 형벌을 온전히 면하겠느냐 면하지 못하고 반드시 마시리라"},{"n":13,"t":"나 여호와가 말하노라 내가 나로 맹세하노니 보스라가 놀램과 수욕거리와 황폐함과 저줏거리가 될 것이요 그 모든 성읍이 영영히 황폐하리라"},{"n":14,"t":"내가 여호와에게서부터 오는 소식을 들었노라 사자를 열방 중에 보내어 이르시되 너희는 모여와서 그를 치며 일어나서 싸우라 하시도다"},{"n":15,"t":"여호와께서 가라사대 내가 너를 열방 중에 작게 하였고 사람들 중에 멸시를 받게 하였느니라"},{"n":16,"t":"바위 틈에 거하며 산꼭대기를 점령한 자여 스스로 두려운 자인줄로 여김과 네 마음의 교만이 너를 속였도다 네가 독수리 같이 보금자리를 높이 지었을지라도 내가 거기서 너를 끌어 내리리라 여호와의 말이니라"},{"n":17,"t":"에돔이 놀라운 것이 되리니 그리로 지나는 자마다 놀라며 그 모든 재앙을 인하여 비웃으리로다"},{"n":18,"t":"나 여호와가 말하노라 소돔과 고모라와 그 이웃 성읍들의 멸망된 것 같이 거기 거하는 사람이 없으며 그 중에 우거할 아무 인자가 없으리라"},{"n":19,"t":"보라 사자가 요단의 수풀에서 올라오는 것 같이 그가 와서 견고한 처소를 칠 것이라 내가 즉시 그들을 거기서 쫓아내고 택한 자를 내가 그 위에 세우리니 나와 같는 자 누구며 나로 더불어 다툴 자 누구며 내 앞에 설 목자가 누구뇨"},{"n":20,"t":"그런즉 에돔에 대한 나 여호와의 도모와 데만 거민에 대하여 경영한 나 여호와의 뜻을 들으라 양떼의 어린 것들을 그들이 반드시 끌어가고 그 처소로 황무케 하리니"},{"n":21,"t":"그 넘어지는 소리에 땅이 진동하며 그 부르짖는 소리는 홍해에 들리리라"},{"n":22,"t":"보라 원수가 독수리 같이 날아와서 그 날개를 보스라 위에 펴는 그 날에 에돔 용사의 마음이 구로하는 여인 같으리라"},{"n":23,"t":"다메섹에 대한 말씀이라 하맛과 아르밧이 수치를 당하리니 이는 흉한 소문을 듣고 낙담함이라 바닷가에 슬픔이 있고 평안이 없도다"},{"n":24,"t":"다메섹이 피곤하여 몸을 돌이켜 달아나려 하니 떨림이 그를 움켰고 해산하는 여인 같이 고통과 슬픔이 그를 잡았도다"},{"n":25,"t":"찬송의 성읍, 나의 즐거운 성읍이 어찌 버린 것이 되지 않겠느냐"},{"n":26,"t":"나 만군의 여호와가 말하노라 그런즉 그 날에 그의 청년들은 그 거리에 엎드러지겠고 모든 군사는 멸절될 것이며"},{"n":27,"t":"내가 다메섹의 성벽에 불을 놓으리니 벤하닷의 궁전이 살라지리라"},{"n":28,"t":"바벨론 왕 느부갓네살에게 공격된 바 게달과 하솔 나라들에 대한 말씀이라 여호와께서 이같이 말씀하시되 너희는 일어나 게달로 올라가서 동방 자손들을 멸하라"},{"n":29,"t":"너희는 그 장막과 양떼를 취하며 휘장과 모든 기구와 약대를 빼앗아다가 소유를 삼고 그들을 향하여 외치기를 두려움이 사방에 있다 할지니라"},{"n":30,"t":"나 여호와가 말하노라 하솔 거민아 도망하라 멀리 가서 깊은 데 거하라 이는 바벨론 왕 느부갓네살이 너를 칠 모략과 너를 칠 계책을 정하였음이니라"},{"n":31,"t":"나 여호와가 말하노라 너는 일어나 저 평안하고 염려없이 거하는 백성 곧 성문이나 문빗장이 없이 홀로 거하는 국민을 치라"},{"n":32,"t":"그들의 약대들은 노략되겠고 그 많은 가축은 탈취를 당할것이라 내가 그 머리털을 모지게 깎는 자들을 사면에 흩고 그 재난을 각 방에서 오게 하리라 여호와의 말이니라"},{"n":33,"t":"하솔은 시랑의 거처가 되어 영원히 황무하리니 거기 거하는 사람이나 그 중에 우거하는 아무 인자가 없게 되리라"},{"n":34,"t":"유다 왕 시드기야의 즉위한지 오래지 아니하여서 엘람에 대한 여호와의 말씀이 선지자 예레미야에게 임하니라 가라사대"},{"n":35,"t":"나 만군의 여호와가 이같이 말하노라 보라 내가 엘람의 힘의 으뜸되는 활을 꺽을 것이요"},{"n":36,"t":"하늘의 사방에서부터 사방 바람을 엘람에 이르게 하여 그들을 사방으로 흩으리니 엘람에서 쫓겨난 자의 이르지 아니하는 나라가 없으리라"},{"n":37,"t":"나 여호와가 말하노라 내가 엘람으로 그 원수의 앞, 그 생명을 찾는 자의 앞에서 놀라게 할 것이며 내가 재앙 곧 나의 진노를 그 위에 내릴 것이며 내가 또 그 뒤로 칼을 보내어 그를 진멸하기까지 할 것이라"},{"n":38,"t":"내가 나의 위를 엘림에 베풀고 왕과 족장들을 그곳에서 멸하리라 여호와의 말이니라"},{"n":39,"t":"그러나 끝날에 이르러는 내가 엘람의 포로를 돌아오게 하리라 여호와의 말이니라"}],"kids":[]}},{"chapter":50,"title":"바벨론에 대한 경고","verses":{"krv":[{"n":1,"t":"여호와께서 선지자 예레미야로 바벨론과 갈대아인의 땅에 대하여 하신 말씀이라"},{"n":2,"t":"너희는 열방 중에 광고하라 공포하라 기를 세우라 숨김이 없이 공포하여 이르라 바벨론이 함락되고 벨이 수치를 당하며 므로닥이 부스러지며 그 신상들은 수치를 당하며 우상들은 부스러진다 하라"},{"n":3,"t":"이는 한 나라가 북방에서 나와서 그를 쳐서 그 땅으로 황폐케하여 그 중에 거하는 자가 없게 함이라 사람이나 짐승이 다 도망하여 가느니라"},{"n":4,"t":"나 여호와가 말하노라 그 날 그 때에 이스라엘 자손이 돌아오며 그와 함께 유다 자손이 돌아오되 그들이 울며 그 길을 행하며 그 하나님 여호와께 구할 것이며"},{"n":5,"t":"그들이 그 얼굴을 시온으로 향하여 그 길을 물으며 말하기를 너희는 오라 잊어 버리지 아니할 영영한 언약으로 여호와와 연합하자 하리라"},{"n":6,"t":"내 백성은 잃어 버린 양떼로다 그 목자들이 그들을 곁길로 가게하여 산으로 돌이키게 하였으므로 그들이 산에서 작은 산으로 돌아다니며 쉴 곳을 잊었도다"},{"n":7,"t":"그들을 만나는 자들은 그들을 삼키며 그 대적은 말하기를 그들은 여호와 곧 의로운 처소시며 그 열조의 소망이신 여호와께 범죄하였음인즉 우리는 무죄하다 하였느니라"},{"n":8,"t":"너희는 바벨론 가운데서 도망하라 갈대아인의 땅에서 나오라 떼에 앞서 가는 수염소 같이 하라"},{"n":9,"t":"보라 내가 큰 연합국으로 북방에서 일어나 나와서 바벨론을 치게 하리니 그들이 항오를 벌이고 쳐서 취할 것이라 그들의 화살은 연숙한 용사의 화살 같아서 헛되이 돌아오지 아니하리로다"},{"n":10,"t":"갈대아가 약탈을 당할 것이라 그를 약탈하는 자마다 만족하리라 여호와의 말이니라"},{"n":11,"t":"나의 산업을 노략하는 자여 너희가 즐거워하며 기뻐하며 곡식을 가는 송아지 같이 뛰며 힘센 말 같이 울도다"},{"n":12,"t":"그러므로 너희의 어미가 온전히 수치를 당하리라 너희를 낳은 자가 치욕을 당하리라 보라 그가 열방의 말째와 광야와 마른 땅과 사막이 될 것이며"},{"n":13,"t":"여호와의 진노로 인하여 거민이 없는 온전한 황무지가 될 것이라 바벨론으로 지나는 자마다 그 모든 재앙을 놀라며 비웃으리로다"},{"n":14,"t":"바벨론을 둘러 항오를 벌이고 활을 당기는 모든 자여 화살을 아끼지 말고 쏘라 그가 여호와께 범죄하였음이니라"},{"n":15,"t":"그 사면에서 소리질러 칠지어다 그가 항복하였고 그 보장은 무너졌고 그 성벽은 훼파되었으니 이는 여호와의 보수하시는 것이라 그의 행한 대로 그에게 행하여 보수하라"},{"n":16,"t":"파종하는 자와 추수 때에 낫을 잡은 자를 바벨론에서 끊어버리라 사람들이 그 압박하는 칼을 두려워하여 각기 동족에게로 돌아가며 고향으로 도망하리라"},{"n":17,"t":"이스라엘은 흩어진 양이라 사자들이 그를 따르도다 처음에는 앗수르 왕이 먹었고 다음에는 바벨론 왕 느부갓네살이 그 뼈를 꺾도다"},{"n":18,"t":"그러므로 나 만군의 여호와 이스라엘의 하나님이 이같이 말하노라 보라 내가 앗수르 왕을 벌한 것 같이 바벨론 왕과 그 땅을 벌하고"},{"n":19,"t":"이스라엘을 다시 그 목장으로 돌아오게 하리니 그가 갈멜과 바산에서 먹을 것이며 그 마음이 에브라임과 길르앗 산에서 만족하리라"},{"n":20,"t":"나 여호와가 말하노라 그 날 그 때에는 이스라엘의 죄악을 찾을지라도 없겠고 유다의 죄를 찾을지라도 발견치 못하리니 이는 내가 나의 남긴 자를 사할 것임이니라"},{"n":21,"t":"나 여호와가 말하노라 너희는 올라가서 므라다임의 땅을 치며 브곳의 거민을 쳐서 진멸하되 내가 너희에게 명한 대로 다하라"},{"n":22,"t":"그 땅에 싸움의 소리와 큰 파멸의 소리가 있으리라"},{"n":23,"t":"온 세계의 방망이가 어찌 그리 꺾여 부숴졌는고 바벨론이 어찌 그리 열방 중에 황무지가 되었는고"},{"n":24,"t":"바벨론아 내가 너를 잡으려고 올무를 놓았더니 네가 깨닫지 못하고 걸렸고 네가 나 여호와와 다투었으므로 만난바 되어 잡혔도다"},{"n":25,"t":"나 여호와가 그 병고를 열고 분노의 병기를 냄은 주 만군의 여호와 내가 갈대아인의 땅에 행할 일이 있음이라"},{"n":26,"t":"먼 데 있는 너희는 와서 그를 치고 그 곳간을 열고 그것을 쌓아 무더기 같게 하라 그를 진멸하고 남기지 말라"},{"n":27,"t":"그 황소를 다 죽이라 도수장으로 내려가게 하라 그들에게 화있도다 그들의 날, 그 벌받는 때가 이르렀음이로다"},{"n":28,"t":"바벨론 땅에서 도피한 자의 소리여 시온에서 우리 하나님 여호와의 보수하시는 것, 그 성전의 보수하시는 것을 선포하는 소리로다"},{"n":29,"t":"활 쏘는 자를 바벨론에 소집하라 무릇 활을 당기는 자여 그 사면으로 진을 치고 쳐서 피하는 자가 없게 하라 그 일한 대로 갚고 그 행한 대로 그에게 행하라 그가 이스라엘의 거룩한 자 여호와를 향하여 교만하였음이니라"},{"n":30,"t":"그러므로 그 날에 청년들이 그 거리에 엎드러지겠고 군사들이 멸절되리라 여호와의 말이니라"},{"n":31,"t":"주 만군의 여호와가 말하노라 교만하 자여 보라 내가 너를 대적하나니 네 날 곧 너를 벌할 때가 이르렀음이라"},{"n":32,"t":"교만한 자가 걸려 넘어지겠고 그를 일으킬 자가 없을 것이며 내가 그 성읍들에 불을 놓으리니 그 사면에 있는 것이 다 살라지리라"},{"n":33,"t":"나 만군의 여호와가 이같이 말하노라 이스라엘 자손과 유다 자손이 함께 학대를 받는도다 그들을 사로잡은 자는 다 그들을 엄히 지켜 놓아주지 아니하거니와"},{"n":34,"t":"그들의 구속자는 강하니 그 이름은 만군의 여호와라 결코 그들의 원을 펴서 그 땅에 평안함을 주고 바벨론 거민으로 불안케 하리라"},{"n":35,"t":"나 여호와가 말하노라 칼이 갈대아인의 위에와 바벨론 거민의 위에와 그 방백들과 지혜로운 자의 위에 임하며"},{"n":36,"t":"칼이 자긍하는 자의 위에 임하리니 그들이 어리석게 될 것이며 칼이 용사의 위에 임하리니 그들이 놀랄 것이며"},{"n":37,"t":"칼이 그들의 말들과 병거들과 그들 중에 있는 잡족의 위에 임하리니 그들이 부녀 같이 될 것이며 칼이 보물 위에 임하리니 그것이 노략될 것이요"},{"n":38,"t":"가뭄이 물 위에 그것을 말리우리니 이는 그 땅이 조각한 신상의 땅이요 그들은 우상에 미쳤음이니라"},{"n":39,"t":"그러므로 사막의 들짐승이 시랑과 함께 거기 거하겠고 타조도 그 중에 깃들일 것이요 영영히 거민이 없으며 대대에 거할 자가 없으리라"},{"n":40,"t":"나 여호와가 말하노라 나 하나님이 소돔과 고모라와 그 이웃 성읍들을 무너지게 한 것 같이 거기 거하는 사람이 없게 하며 그 중에 우거하는 아무 인자가 없게 하리라"},{"n":41,"t":"보라 한 족속이 북방에서 오고 큰 나라와 여러 왕이 격동을 받아 땅끝에서 오나니"},{"n":42,"t":"그들은 활과 창을 가진 자라 잔인하며 긍휼히 여기지 아니하며 그 목소리는 파도가 흉용함 같도다 딸 바벨론아 그들이 말을 타고 무사 같이 각기 항오를 벌여 너를 칠 것이라"},{"n":43,"t":"바벨론 왕이 그 소문을 듣고 손이 약하여지며 고통에 잡혀 해산하는 여인의 구로함 같도다"},{"n":44,"t":"보라 사자가 요단의 수풀에서 올라오는 것 같이 그가 와서 견고한 처소를 칠 것이라 내가 즉시 그들을 거기서 쫓아내고 택한 자를 내가 그 위에 세우리니 나와 같은 자 누구며 나로 더불어 다툴 자 누구며 내 앞에 설 목자가 누구뇨"},{"n":45,"t":"그런즉 바벨론에 대한 나 여호와의 도모와 갈대아인의 땅에 대하여 경영한 나 여호와의 뜻을 들으라 양떼의 어린 것들을 그들이 반드시 끌어가고 그 처소로 황무케 하리니"},{"n":46,"t":"바벨론의 함락하는 소리에 땅이 진동하며 그 부르짖음이 열방 중에 들리리라 하시도다"}],"kids":[]}},{"chapter":51,"title":"바벨론의 멸망","verses":{"krv":[{"n":1,"t":"여호와께서 이같이 말씀하시되 보라 내가 멸망시키는 자의 마음을 일으켜 바벨론을 치고 또 나를 대적하는 자 중에 처하는 자를 치되"},{"n":2,"t":"내가 타국인을 바벨론에 보내어 키질하여 그 땅을 비게 하리니 재앙의 날에 그를 에워 치리로다"},{"n":3,"t":"활을 당기는 자를 향하며 갑주를 갖추고 선 자를 향하여 쏘는 자는 그 활을 당길 것이라 그 청년들을 아끼지 말며 그 군대를 진멸하라"},{"n":4,"t":"무리가 갈대아인의 땅에서 죽임을 당하여 엎드러질 것이요 그 거리에서 찔림을 당한 자가 엎드러지리라 하시도다"},{"n":5,"t":"대저 이스라엘과 유다가 이스라엘의 거룩하신 자를 거역하므로 죄과가 땅에 가득하나 그 하나님 만군의 여호와에게 버림을 입지 아니하였나니"},{"n":6,"t":"바벨론 가운데서 도망하여 나와서 각기 생명을 구원하고 그의 죄악으로 인하여 끊침을 보지 말지어다 이는 여호와의 보수의 때니 그에게 보복하시리라"},{"n":7,"t":"바벨론은 여호와의 수중의 온 세계로 취케 하는 금잔이라 열방이 그 포도주를 마시고 인하여 미쳤도다"},{"n":8,"t":"바벨론이 졸지에 넘어져 파멸되니 이로 인하여 울라 그 창상을 인하여 유향을 구하라 혹 나으리로다"},{"n":9,"t":"우리가 바벨론을 치료하려 하여도 낫지 아니한즉 버리고 각기 고토로 돌아가자 그 화가 하늘에 미쳤고 궁창에 달하였음이로다"},{"n":10,"t":"여호와께서 우리 의를 드러내셨으니 오라 시온에서 우리 하나님 여호와의 일을 선포하자"},{"n":11,"t":"화살을 갈며 방패를 굳게 잡으라 여호와께서 메대 왕들의 마음을 격발하사 바벨론을 멸하기로 뜻하시나니 이는 여호와의 보수하시는 것 곧 그 성전의 보수하시는 것이라"},{"n":12,"t":"바벨론 성벽을 향하여 기를 세우고 튼튼히 지키며 파수꾼을 세우며 복병을 베풀어 방비하라 이는 여호와께서 바벨론 거민에 대하여 말씀하신 대로 경영하시고 행하심이로다"},{"n":13,"t":"많은 물 가에 거하여 재물이 많은 자여 네 탐남의 한정, 네 결국이 이르렀도다"},{"n":14,"t":"만군의 여호와께서 자기로 맹세하시되 내가 진실로 사람을 황충 같이 네게 가득히 하리니 그들이 너를 향하여 소리를 높이리라 하시도다"},{"n":15,"t":"여호와께서 그 권능으로 땅을 지으셨고 그 지혜로 세계를 세우셨고 그 명철로 하늘들을 펴셨으며"},{"n":16,"t":"그가 목소리를 발하신즉 하늘에 많은 물이 생기나니 그는 땅끝에서 구름이 오르게 하시며 비를 위하여 번개하게 하시며 그 곳간에서 바람을 내시거늘"},{"n":17,"t":"사람마다 우준하고 무식하도다 금장색마다 자기의 만든 신상으로 인하여 수치를 당하나니 이는 그 부어만든 우상은 거짓이요 그 속에 생기가 없음이라"},{"n":18,"t":"그것들은 헛것이요 망령되이 만든 것인즉 징벌하시는 때에 멸망할 것이나"},{"n":19,"t":"야곱의 분깃은 이같지 아니하시니 그는 만물의 조성자요 이스라엘은 그 산업의 지파라 그 이름은 만군의 여호와시니라"},{"n":20,"t":"여호와께서 가라사대 너는 나의 철퇴 곧 병기라 내가 너로 열방을 파하며 너로 국가들을 멸하며"},{"n":21,"t":"내가 너로 말과 그 탄 자를 부수며 너로 병거와 그 탄 자를 부수며"},{"n":22,"t":"너로 남자와 여자를 부수며 너로 노년과 유년을 부수며 너로 청년과 처녀를 부수며"},{"n":23,"t":"너로 목자와 그 양떼를 부수며 너로 농부와 그 멍엣소를 부수며 너로 방백들과 두령들을 부수리로다"},{"n":24,"t":"그들이 너희 목전에 시온에서 모든 악을 행한 대로 내가 바벨론과 갈대아 모든 거민에게 갚으리라 여호와의 말이니라"},{"n":25,"t":"나 여호와가 말하노라 온 세계를 멸한 멸망의 산아 보라 나는 네 대적이라 나의 손을 네 위에 펴서 너를 바위에서 굴리고 너로 불 탄 산이 되게 할 것이니"},{"n":26,"t":"사람이 네게서 집 모퉁이 돌이나 기초돌을 취하지 아니할 것이요 너는 영영히 황무지가 될 것이니라 여호와의 말이니라"},{"n":27,"t":"땅에 기를 세우며 열방 중에 나팔을 불어서 열국을 예비시켜 그를 치며 아라랏과 민니와 아스그나스 나라를 불러 모아 그를 치며 대장으로 세우고 그를 치되 사나운 황충 같이 그 말들을 몰아오게 하라"},{"n":28,"t":"열국 곧 메대인의 왕들과 그 방백들과 그 모든 두령과 그 관할하는 모든 땅을 예비시켜 그를 치게 하라"},{"n":29,"t":"땅이 진동하며 고통하나니 이는 나 여호와가 바벨론을 쳐서 그 땅으로 황무하여 거민이 없게 할 경영이 섰음이라"},{"n":30,"t":"바벨론의 용사는 싸움을 그치고 그 요새에 머무르나 기력이 쇠하여 여인 같이 되며 그 거처는 불타고 그 문빗장은 부러졌으며"},{"n":31,"t":"보발꾼이 달려 만나고 사자가 달려 만나서 바벨론 왕에게 고하기를 그 성읍 사방이 함락되었으며"},{"n":32,"t":"모든 나루는 빼앗겼으며 갈밭이 불탔으며 군사들이 두려워하더이다 하리라"},{"n":33,"t":"만군의 여호와 이스라엘의 하나님이 이같이 말씀하시되 딸 바벨론은 때가 이른 타작마당과 같은지라 미구에 추수 때가 이르리라 하시도다"},{"n":34,"t":"바벨론 왕 느부갓네살이 나를 먹으며 나를 멸하며 나로 빈 그릇이 되게 하며 용 같이 나를 삼키며 나의 좋은 음식으로 그 배를 채우고 나를 쫓아내었으니"},{"n":35,"t":"나와 내 육체에 대한 잔학이 바벨론에 돌아가기를 원한다고 시온 거민이 말할 것이요 내 피 흘린 죄가 갈대아 거민에게로 돌아가기를 원한다고 예루살렘이 말하리라"},{"n":36,"t":"그러므로 여호와께서 이같이 말씀하시되 보라 내가 네 송사를 듣고 너를 위하여 보수하여 그 바다를 말리며 그 샘을 말리리니"},{"n":37,"t":"바벨론이 황폐한 무더기가 되어서 시랑의 거처와 놀람과 치솟거리가 되고 거민이 없으리라"},{"n":38,"t":"그들이 다 사자 같이 소리하며 어린 사자 같이 부르짖으며"},{"n":39,"t":"열정이 일어날 때에 내가 연회를 베풀고 그들로 취하여 기뻐하다가 영영히 잠들어 깨지 못하게 하리라 여호와의 말이니라"},{"n":40,"t":"내가 그들을 끌어 내려서 어린 양과 수양과 수염소가 도수장으로 가는 것 같게 하리라"},{"n":41,"t":"슬프다 세삭이 함락되었도다 온 세상의 칭찬 받는 성이 빼앗겼도다 슬프다 바벨론이 열방 중에 황폐하였도다"},{"n":42,"t":"바다가 바벨론에 넘침이여 그 많은 파도가 그것에 덮였도다"},{"n":43,"t":"그 성읍들은 황폐하여 마른 땅과 사막과 거민이 없는 땅이 되었으니 그리로 지나가는 인자가 없도다"},{"n":44,"t":"내가 벨을 바벨론에서 벌하고 그 삼킨 것을 그 입에서 끌어 내리니 열방이 다시는 그에게로 흘러가지 아니하겠고 바벨론 성벽은 무너지리로다"},{"n":45,"t":"나의 백성아 너희는 그 중에서 나와 각기 나 여호와의 진노에서 스스로 구원하라"},{"n":46,"t":"너희 마음을 겁약하게 말며 이 땅에서 들리는 풍설을 인하여 두려워 말라 풍설은 이 해에도 있었고 저 해에도 있으리라 경내에는 강포함이 있어 관원끼리 서로 치리라"},{"n":47,"t":"그러므로 보라 날이 이르리니 내가 바벨론의 조각한 신상들을 벌할 것이라 그 온 땅이 치욕을 당하겠고 그 살육당한 모든 자가 그 가운데 엎드러질 것이며"},{"n":48,"t":"하늘과 땅과 그 중의 모든 것이 바벨론을 인하여 기뻐 노래하리니 이는 파멸시키는 자가 북방에서 그에게 옴이니라 여호와의 말이니라"},{"n":49,"t":"바벨론이 이스라엘 사람을 살육하여 엎드러뜨림 같이 온 땅 사람이 바벨론에서 살육을 당하여 엎드러지리라 하시도다"},{"n":50,"t":"칼을 면한 자들이여 서지 말라 행하라 원방에서 여호와를 생각하며 예루살렘을 너희 마음에 두라"},{"n":51,"t":"이방인이 여호와의 집 성소에 들어가므로 우리가 책망을 들으며 수치를 당하여 부끄러움이 우리 얼굴에 덮였느니라"},{"n":52,"t":"그러므로 여호와께서 가라사대 보라 날이 이르리니 내가 그 조각한 신상을 벌할 것이라 상함을 입은 자들이 그 땅에서 신음하리라"},{"n":53,"t":"가령 바벨론이 하늘까지 솟아오른다 하자 멸망시킬 자가 내게서부터 그들에게 임하리라 여호와의 말이니라"},{"n":54,"t":"바벨론에서 부르짖는 소리여 갈대아인의 땅에 큰 파멸의 소리로다"},{"n":55,"t":"이는 여호와께서 바벨론을 황폐케 하사 그 떠드는 소리를 끊으심이로다 그 대적이 많은 물의 요동함 같이 요란한 소리를 발하니"},{"n":56,"t":"곧 멸망시키는 자가 바벨론에 임함이라 그 용사들이 사로 잡히고 그들의 활이 꺾이도다 여호와는 보복의 하나님이시니 반드시 보응하시리로다"},{"n":57,"t":"만군의 여호와라 일컫는 왕이 이같이 말씀하시되 내가 그 방백들과 박사들과 감독들과 관장들과 용사들로 취하게 하리니 그들이 영영히 자고 깨지 못하리라"},{"n":58,"t":"만군의 여호와가 이같이 말하노라 바벨론의 넓은 성벽은 온전히 무너지겠고 그 높은 문들은 불에 탈 것이며 백성들의 수고는 헛될 것이요 민족들의 수고는 불탈 것인즉 그들이 쇠패하리라 하시니라"},{"n":59,"t":"유다와 시드기야 사년에 마세야의 손자 네리야의 아들 스라야가 왕과 함께 바벨론으로 갈 때에 선지자 예레미야가 그에게 말씀을 명하니 스라야는 시종장이더라"},{"n":60,"t":"예레미야가 바벨론에 임한 모든 재앙 곧 바벨론에 대하여 기록한 이 모든 말씀을 한 책에 기록하고"},{"n":61,"t":"예레미야가 스라야에게 이르되 너는 바벨론에 이르거든 삼가 이 모든 말씀을 읽고"},{"n":62,"t":"말하기를 여호와여 주께서 이곳에 대하여 말씀하시기를 이 땅을 멸하여 사람이나 짐승이 거기 거하지 못하게 하고 영영히 황폐케 하리라 하셨나이다 하라"},{"n":63,"t":"너는 이 책 읽기를 다한 후에 책에 돌을 매어 유브라데 하수 속에 던지며"},{"n":64,"t":"말하기를 바벨론이 나의 재앙 내림을 인하여 이같이 침륜하고 다시 일어나지 못하리니 그들이 쇠패하리라 하라 하니라 예레미야의 말이 이에 마치니라"}],"kids":[]}},{"chapter":52,"title":"예루살렘의 함락 보고","verses":{"krv":[{"n":1,"t":"시드기야가 위에 나아갈 때에 나이 이십일 세라 예루살렘에서 십일 년을 치리하니라"},{"n":2,"t":"시드기야가 여호야김의 모든 행위를 본받아 여호와 보시기에 악을 행한지라"},{"n":3,"t":"여호와께서 예루살렘과 유다를 진노하심이 그들을 그 앞에서 쫓아내시기까지 이르렀더라 시드기야가 바벨론 왕을 배반하매"},{"n":4,"t":"시드기야 구년 시월 십일에 바벨론 왕 느부갓네살이 그 모든 군대를 거느리고 예루살렘을 치러 올라와서 그 성을 대하여 진을 치고 사면으로 흉벽을 쌓으매"},{"n":5,"t":"성이 시드기야 왕 십일년까지 에워싸였더니"},{"n":6,"t":"그 사월 구일에 성중에 기근이 심하여 그 땅 백성의 식물이 진하였더라"},{"n":7,"t":"갈대아인이 그 성읍을 에워쌌더니 성벽을 깨뜨리매 모든 군사가 밤 중에 두 성벽 사이 왕의 동산 곁문 길로 도망하여 아라바 길로 가더니"},{"n":8,"t":"갈대아인의 군대가 시드기야 왕을 쫓아가서 여리고 평지에서 미치매 왕의 모든 군대가 그를 떠나 흩어진지라"},{"n":9,"t":"그들이 왕을 잡아가지고 하맛 땅 립나에 있는 바벨론 왕에게로 끌고가매 그를 신문하니라"},{"n":10,"t":"바벨론 왕이 시드기야의 아들들을 그의 목전에서 죽이고 또 립나에서 유다의 모든 방백을 죽이며"},{"n":11,"t":"시드기야의 두 눈을 빼고 사슬로 결박하여 바벨론으로 끌어다가 그 죽는 날까지 옥에 두었더라"},{"n":12,"t":"바벨론 왕 느부갓네살의 십구년 오월 십일에 바벨론 왕의 어전 시위대 장관 느부사라단이 예루살렘에 이르러"},{"n":13,"t":"여호와의 전과 왕궁을 불사르고 예루살렘의 모든 집을 귀인의 집까지 불살랐으며"},{"n":14,"t":"시위대 장관을 좇는 갈대아인의 온 군대가 예루살렘 사면 성벽을 헐었으며"},{"n":15,"t":"시위대 장관 느부사라단이 백성 중 빈한한 자와 성중에 남아있는 백성과 바벨론 왕에게 항복한 자와 무리의 남은 자를 사로잡아 옮겨가고"},{"n":16,"t":"비천한 국민을 남겨두어 포도원을 다스리는 자와 농부가 되게 하였더라"},{"n":17,"t":"갈대아인이 또 여호와의 전의 두 놋기둥과 받침들과 여호와의 전의 놋바다를 깨뜨려 그 놋을 바벨론으로 가져갔고"},{"n":18,"t":"또 가마들과 부삽들과 불집게들과 주발들과 숟가락들과 섬길 때에 쓰는 모든 놋그릇을 다 가져 갔으며"},{"n":19,"t":"시위대 장관이 또 잔들과 화로들과 주발들과 솥들과 촛대들과 숟가락들과 바리들 곧 금물의 금과 은물의 은을 가져갔는데"},{"n":20,"t":"솔로몬 왕이 여호와의 전을 위하여 만든 두 기둥과 한 바다와 그 받침 아래 있는 열두 놋소 곧 이 모든 기구의 놋 중수를 헤아릴 수 없었더라"},{"n":21,"t":"그 기둥은 한 기둥의 고가 십팔 규빗이요 그 주위는 십이 규빗이며 그 속이 비었고 그 두께는 사지놓이며"},{"n":22,"t":"기둥 위에 놋머리가 있어 그 고가 다섯 규빗이요 머리 사면으로 돌아가며 꾸민 그물과 석류가 다 놋이며 또 다른 기둥에도 이런 모든 것과 석류가 있었으며"},{"n":23,"t":"그 사면에 있는 석류는 구십륙이요 그 기둥에 둘린 그물 위에 있는 석류는 도합이 일백이었더라"},{"n":24,"t":"시위대 장관이 대제사장 스라야와 부제사장 스바냐와 전 문지기 세 사람을 잡고"},{"n":25,"t":"또 성중에서 사람을 잡았으니 곧 군사를 거느린 장관 하나와 또 성중에서 만난 바 왕의 시종 칠 인과 국민을 초모하는 군대장관의 서기관 하나와 성중에서 만난 바 국민 육십 명이라"},{"n":26,"t":"시위대 장관 느부사라단이 그들을 잡아가지고 립나 바벨론 왕에게 나아가매"},{"n":27,"t":"바벨론 왕이 하맛 땅 립나에서 다 쳐죽였더라 이와 같이 유다가 사로잡혀 본토에서 떠났더라"},{"n":28,"t":"느부갓네살의 사로잡아 옮긴 백성이 이러하니라 제칠년에 유다인이 삼천이십삼이요"},{"n":29,"t":"느부갓네살의 십팔년에 예루살렘에서 사로잡아 옮긴 자가 팔백삼십이 인이요"},{"n":30,"t":"느부갓네살의 이십삼년에 시위대 장관 느부사라단이 사로잡아 옮긴 유다인이 칠백사십오 인이니 그 총수가 사천육백 인이었더라"},{"n":31,"t":"유다 왕 여호야긴이 사로잡혀간지 삼십칠년 곧 바렙론 왕 에윌므로닥의 즉위 원년 십이월 이십오일에 그가 유다 왕 여호야긴을 옥에서 내어놓아 그 머리를 들게 하고"},{"n":32,"t":"그에게 선히 말하고 그의 위를 그와 함께 바벨론에 있는 왕들의 위보다 높이고"},{"n":33,"t":"그 죄수의 의복을 바꾸게 하고 그 일평생에 항상 왕의 앞에서 먹게 하였으며"},{"n":34,"t":"그의 쓸 것은 날마다 바벨론 왕에게서 받는 정수가 있어서 죽는 날까지 곧 종신토록 끊이지 아니하였더라"}],"kids":[]}}]}');

